-- Poems batch 72
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('af9b3bdf-3a13-4a53-80b3-79db38baa63e','荅馮魯秀才','韋應物','唐','唐诗','tang','','[]','晨坐枉瓊藻，知子返中林。',84,'全唐诗/poet.tang.9000.json','["晨坐枉瓊藻，知子返中林。", "澹然山景晏，泉谷響幽禽。", "髣髴謝塵跡，逍遙舒道心。", "顧我腰間綬，端爲華髮侵。", "簿書勞應對，篇翰曠不尋。", "薄田失鋤耨，生苗安可任。", "徒令慙所問，想望東山岑。"]'),
('259a141b-a49b-48de-b42d-b9e48b4293b0','荅崔主簿問兼簡溫上人','韋應物','唐','唐诗','tang','','[]','緣情生衆累，晚悟依道流。',72,'全唐诗/poet.tang.9000.json','["緣情生衆累，晚悟依道流。", "諸境一已寂，了將身世浮。", "閑居澹無味，忽復四時周。", "靡靡芳草積，稍稍新篁抽。", "即此抱餘素，塊然誠寡儔。", "自適一忻意，愧蒙君子憂。"]'),
('3b13cbd3-192d-498c-b0f2-b74ce33b51eb','清都觀荅幼遐','韋應物','唐','唐诗','tang','','[]','逍遙仙家子，日夕朝玉皇。',108,'全唐诗/poet.tang.9000.json','["逍遙仙家子，日夕朝玉皇。", "興高清露沒，渴飲瓊華漿。", "解組一來款，披衣拂天香。", "粲然顧我笑，綠簡發新章。", "泠泠如玉音，馥馥若蘭芳。", "浩意坐盈此，月華殊未央。", "却念諠譁日，何由得清涼。", "疎松抗高殿，密竹陰長廊。", "榮名等糞土，攜手隨風翔。"]'),
('a8871bec-db52-46d1-a273-dab7a92facb6','善福精舍荅韓司錄清都觀會宴見憶','韋應物','唐','唐诗','tang','','[]','弱志厭衆紛，抱素寄精廬。',120,'全唐诗/poet.tang.9000.json','["弱志厭衆紛，抱素寄精廬。", "皦皦仰時彥，悶悶獨爲愚。", "之子亦辭秩，高蹤罷馳驅。", "忽因西飛禽，贈我以瓊琚。", "始表仙都集，復言歡樂殊。", "人生各有因，契闊不獲俱。", "一來田野中，日與人事疎。", "水木澄秋景，逍遙清賞餘。", "枉駕懷前諾，引領豈斯須。", "無爲便高翔，邈矣不可迂。"]'),
('a0ded4bd-f117-4093-8688-11e7c941584d','荅長安丞裴說','韋應物','唐','唐诗','tang','','[]','出身忝時士，於世本無機。',108,'全唐诗/poet.tang.9000.json','["出身忝時士，於世本無機。", "爰以林壑趣，遂成頑鈍姿。", "臨流意已淒，采菊露未稀。", "舉頭見秋山，萬事都若遺。", "獨踐幽人蹤，邈將親友違。", "髦士佐京邑，懷念枉貞詞。", "久雨積幽抱，清罇宴良知。", "從容操劇務，文翰方見推。", "安能戢羽翼，顧此林栖時。"]'),
('5538a5de-fd0f-49ec-9874-f5ce4bc6d4f3','奉酬處士叔見示','韋應物','唐','唐诗','tang','','[]','挂纓守貧賤，積雪臥郊園。',48,'全唐诗/poet.tang.9000.json','["挂纓守貧賤，積雪臥郊園。", "叔父親降趾，壺觴攜到門。", "高齋樂宴罷，清夜道心存。", "即此同疎氏，可以一忘言。"]'),
('ebfdfb31-da55-4dff-85a4-f77dbb7c463d','荅庫部韓郎中','韋應物','唐','唐诗','tang','','[]','高士不羈世，頗將榮辱齊。',96,'全唐诗/poet.tang.9000.json','["高士不羈世，頗將榮辱齊。", "適委華冕去，欲還幽林栖。", "雖懷承明戀，忻與物累暌。", "逍遙觀運流，誰復職端倪。", "而我豈高致，偃息平門西。", "愚者世所遺，沮溺共耕犂。", "風雪積深夜，園田掩荒蹊。", "幸蒙相思札，款曲期見攜。"]'),
('985cec73-e2e6-4e53-8537-4b9062faecd4','荅暢校書當','韋應物','唐','唐诗','tang','','[]','偶然棄官去，投跡在田中。',108,'全唐诗/poet.tang.9000.json','["偶然棄官去，投跡在田中。", "日出照茅屋，園林養愚蒙。", "雖云無一資，罇酌會不空。", "且忻百穀成，仰嘆造化功。", "出入與民伍，作事靡不同。", "時伐南澗竹，夜還灃水東。", "貧蹇自成退，豈爲高人蹤。", "覽君金玉篇，彩色發我容。", "日月欲爲報，方春已徂冬。"]'),
('fb371632-bded-4588-b79b-85c1ce20a66d','荅崔都水','韋應物','唐','唐诗','tang','','[]','深夜竹亭雪，孤燈案上書。',24,'全唐诗/poet.tang.9000.json','["深夜竹亭雪，孤燈案上書。", "不遇無爲化，誰復得閒居。"]'),
('1935ba54-4c61-4c59-a93c-342a2739f4be','酬令狐司錄善福精舍見贈','韋應物','唐','唐诗','tang','','[]','野寺望山雪，空齋對竹林。',24,'全唐诗/poet.tang.9000.json','["野寺望山雪，空齋對竹林。", "我以養愚地，生君道者心。"]'),
('85cca48b-b0fd-4138-b418-4abcc54cf059','灃上精舍荅趙氏外生伉','韋應物','唐','唐诗','tang','','[]','遠跡出塵表，寓身雙樹林。',96,'全唐诗/poet.tang.9000.json','["遠跡出塵表，寓身雙樹林。", "如何小子伉，亦有超世心。", "擔書從我遊，攜手廣川陰。", "雲開夏郊綠，景晏青山沈。", "對榻遇清夜，獻詩合雅音。", "所推苟禮數，於性道豈深。", "隱拙在沖默，經世昧古今。", "無爲率爾言，可以致華簪。"]'),
('4441ab65-d881-4dbd-9373-e74cabefada0','荅趙氏生伉','韋應物','唐','唐诗','tang','','[]','暫與雲林別，忽陪鴛鷺翔。',24,'全唐诗/poet.tang.9000.json','["暫與雲林別，忽陪鴛鷺翔。", "看山不得去，知爾獨相望。"]'),
('8658fafb-4052-4470-a0bf-fd33ecfa5b19','荅端','韋應物','唐','唐诗','tang','','[]','郊園夏雨歇，閑院綠陰生。',48,'全唐诗/poet.tang.9000.json','["郊園夏雨歇，閑院綠陰生。", "職事方無効，幽賞獨違情。", "物色坐如見，離抱悵多盈。", "況感夕涼氣，聞此亂蟬鳴。"]'),
('f857d1f6-f37c-4a5f-8ef6-a0ad7c18bb40','答史館張學士段柳庶子學士集賢院看花見寄兼呈柳學士','韋應物','唐','唐诗','tang','','[]','班楊秉文史，對院自爲鄰。',48,'全唐诗/poet.tang.9000.json','["班楊秉文史，對院自爲鄰。", "餘香掩閣去，遲日看花頻。", "似雪飄閶闔，從風點近臣。", "南宮有芳樹，不竝禁垣春。"]'),
('f6be3940-625e-46ff-a41f-85b4a1224c59','荅王郎中','韋應物','唐','唐诗','tang','','[]','臥閣枉芳藻，覽旨悵秋晨。',96,'全唐诗/poet.tang.9000.json','["臥閣枉芳藻，覽旨悵秋晨。", "守郡猶羈寓，無以慰嘉賓。", "野曠歸雲盡，天清曉露新。", "池荷涼已至，牕梧落漸頻。", "風物殊京國，邑里但荒榛。", "賦繁屬軍興，政拙媿斯人。", "髦士久臺閣，中路一漂淪。", "歸當列盛朝，豈念臥淮濱。"]'),
('fbf024e4-019c-4f23-a353-f66b09ee9a71','荅崔都水','韋應物','唐','唐诗','tang','','[]','亭亭心中人，迢迢居秦關。',204,'全唐诗/poet.tang.9000.json','["亭亭心中人，迢迢居秦關。", "常緘素札去，適枉華章還。", "憶在灃郊時，攜手望秋山。", "久嫌官府勞，初喜罷秩閑。", "終年不事業，寢食長慵頑。", "不知爲時來，名籍挂郎間。", "攝衣辭田里，華簪耀頹顏。", "卜居又依仁，日夕正追攀。", "牧人本無術，命至苟復遷。", "離念積歲序，歸途眇山川。", "郡齋有佳月，園林含清泉。", "同心不在宴，罇酒徒盈前。", "覽君陳迹遊，詞意俱悽妍。", "忽忽已終日，將詶不能宣。", "甿稅況重疊，公門極熬煎。", "責逋甘首免，歲晏當歸田。", "勿厭守窮轍，慎爲名所牽。"]'),
('dd77939c-160a-4e39-b1b8-9eda59edac02','荅王卿送別','韋應物','唐','唐诗','tang','','[]','去馬嘶春草，歸人立夕陽。',24,'全唐诗/poet.tang.9000.json','["去馬嘶春草，歸人立夕陽。", "元知數日別，要使兩情傷。"]'),
('9bb8d209-bc18-45e3-a830-de8f2bb280a9','荅裴丞說歸京所獻','韋應物','唐','唐诗','tang','','[]','執事頗勤久，行去亦傷乖。',60,'全唐诗/poet.tang.9000.json','["執事頗勤久，行去亦傷乖。", "家貧無僮僕，吏卒升寢齋。", "衣服藏內篋，藥草曝前階。", "誰復知次第，濩落且安排。", "還期在歲晏，何以慰吾懷。"]'),
('fe7871be-193b-403d-aad0-28f45382a706','答裴處士','韋應物','唐','唐诗','tang','','[]','遺民愛精舍，乘犢入青山。',48,'全唐诗/poet.tang.9000.json','["遺民愛精舍，乘犢入青山。", "來署高陽里，不遇白衣還。", "禮賢方化俗，聞風自款關。", "況子逸羣士，栖息蓬蒿間。"]'),
('0a71baa5-b301-49a9-bde3-e2f8d58d4f7f','荅楊奉禮','韋應物','唐','唐诗','tang','','[]','多病守山郡，自得接嘉賓。',108,'全唐诗/poet.tang.9000.json','["多病守山郡，自得接嘉賓。", "不見三四日，曠若十餘旬。", "臨觴獨無味，對榻已生塵。", "一詠舟中作，灑雪忽驚新。", "煙波見棲旅，景物具昭陳。", "秋塘唯落葉，野寺不逢人。", "白事廷吏簡，閑居文墨親。", "高天池閣靜，寒菊霜露頻。", "應當整孤棹，歸來展殷勤。"]'),
('e8c02f23-7c33-4add-a393-76973740b247','答端','韋應物','唐','唐诗','tang','','[]','坐憶故園人已老，寧知遠郡雁還來。',32,'全唐诗/poet.tang.9000.json','["坐憶故園人已老，寧知遠郡雁還來。", "長瞻西北是歸路，獨上城樓日幾廻。"]'),
('dc9a12e5-1eac-43fb-b7d0-1c63bbe73ab5','答僴奴重陽二甥','韋應物','唐','唐诗','tang','','[]','棄職曾守拙，翫幽遂忘喧。',180,'全唐诗/poet.tang.9000.json','["棄職曾守拙，翫幽遂忘喧。", "山澗依磽𥕂，竹樹蔭清源。", "貧居煙火濕，歲熟梨棗繁。", "風雨飄茅屋，蒿草沒瓜園。", "羣屬相歡悅，不覺過朝昏。", "有時看禾黍，落日上秋原。", "飲酒任真性，揮筆肆狂言。", "一朝忝蘭省，三載居遠藩。", "復與諸弟子，篇翰每相敦。", "西園休習射，南池對芳樽。", "山藥經雨碧，海榴凌霜飜。", "念爾不同此，悵然復一論。", "重陽守故家，僴子旅湘沅。", "俱有緘中藻，惻惻動離魂。", "不知何日見，衣上淚空存。"]'),
('e78c70a9-0564-4e80-ad88-b90367a3a3a7','荅重陽','韋應物','唐','唐诗','tang','','[]','省札陳往事，愴憶數年中。',96,'全唐诗/poet.tang.9000.json','["省札陳往事，愴憶數年中。", "一身朝北闕，家累守田農。", "望山亦臨水，暇日每來同。", "性情一疎散，園林多清風。", "忽復隔淮海，夢想在灃東。", "病來經時節，起見秋塘空。", "城郭連榛嶺，鳥雀噪溝叢。", "坐使驚霜鬢，撩亂已如蓬。"]'),
('9c58ce66-5ac2-43c0-9fc7-0aaeb70233f4','酬劉侍郎使君','韋應物','唐','唐诗','tang','','[]','瓊樹凌霜雪，葱蒨如芳春。',144,'全唐诗/poet.tang.9000.json','["瓊樹凌霜雪，葱蒨如芳春。", "英賢雖出守，本自玉階人。", "宿昔陪郎署，出入仰清塵。", "孰云俱列郡，比德豈爲鄰。", "風雨飄海氣，清涼悅心神。", "重門深夏晝，賦詩延衆賓。", "方以歲月舊，每蒙君子親。", "繼作郡齋什，遠贈荆山珍。", "高閑庶務理，遊眺景物新。", "朋友亦遠集，燕酌在佳辰。", "始唱已慙拙，將酬益難伸。", "濡毫意僶俛，一用寫悁勤。"]'),
('f6c7f892-832a-48cc-a422-d92193ee965c','答令狐侍郎','韋應物','唐','唐诗','tang','','[]','一凶廼一吉，一是復一非。',120,'全唐诗/poet.tang.9000.json','["一凶廼一吉，一是復一非。", "孰能逃斯理，亮在識其微。", "三黜故無慍，高賢當庶幾。", "但以親交戀，音容邈難希。", "況昔別離久，俱忻藩守歸。", "朝宴方陪廁，山川又乖違。", "吳門冒海霧，峽路凌連磯。", "同會在京國，相望涕沾衣。", "明時重英才，當復列彤闈。", "白玉雖塵垢，拂拭還光輝。"]'),
('fbbb6458-ed8f-487b-b1e4-7004ceb16664','酬張協律','韋應物','唐','唐诗','tang','','[]','昔人鬻舂地，今人復一賢。',180,'全唐诗/poet.tang.9000.json','["昔人鬻舂地，今人復一賢。", "屬余藩守日，方君臥病年。", "麗思阻文宴，芳蹤闕賓筵。", "經時豈不懷，欲往事屢牽。", "公府適煩倦，開緘瑩新篇。", "非將握中寶，何以比其妍。", "感茲棲寓詞，想復痾瘵纏。", "空宇風霜交，幽居情思綿。", "當以貧非病，孰云白未玄。", "邑中有其人，憔倅即我愆。", "由來牧守重，英俊得薦延。", "匪人等鴻毛，斯道何由宣。", "遭時無早晚，蘊器俟良緣。", "觀文心未衰，勿藥疾當痊。", "晨期簡牘罷，馳慰子忡然。"]'),
('51a4cedc-8d1a-4e65-a56d-d2c860170b47','荅秦十四校書','韋應物','唐','唐诗','tang','','[]','知掩山扉三十秋，魚須翠碧棄牀頭。',32,'全唐诗/poet.tang.9000.json','["知掩山扉三十秋，魚須翠碧棄牀頭。", "莫道謝公方在郡，五言今日爲君休。"]'),
('c56fd4e5-6626-4929-a750-c5effd4ee24f','答賓','韋應物','唐','唐诗','tang','','[]','斜月纔鑒帷，凝霜偏冷枕。',24,'全唐诗/poet.tang.9000.json','["斜月纔鑒帷，凝霜偏冷枕。", "持情須耿耿，故作單牀寢。"]'),
('3bf0ded8-eead-4432-a0f4-02e8a016a916','答鄭騎曹青橘絕句','韋應物','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','憐君臥病思新橘，試摘猶酸亦未黃。',32,'全唐诗/poet.tang.9000.json','["憐君臥病思新橘，試摘猶酸亦未黃。", "書後欲題三百顆，洞庭須待滿林霜。"]'),
('5ff790ee-593a-4159-94ea-4cb9b1268053','奉和聖製重陽日賜宴','韋應物','唐','唐诗','tang','','[]','聖心憂萬國，端居在穆清。',74,'全唐诗/poet.tang.9000.json','["聖心憂萬國，端居在穆清。", "玄功致海[晏]，錫讌表文明。", "恩屬重陽節，雨應此時晴。", "寒菊生池苑，高樹出宮城。", "捧藻千官處，垂戒百王程。", "復覩開元日，臣愚獻頌聲。"]'),
('ebd1c24e-24ab-4e22-aeae-c57006fb686d','和吳舍人早春歸沐西亭言志','韋應物','唐','唐诗','tang','','[]','曉漏戒中禁，清香肅朝衣。',96,'全唐诗/poet.tang.9000.json','["曉漏戒中禁，清香肅朝衣。", "一門雙掌誥，伯侍仲言歸。", "亭高性情曠，職密交遊稀。", "賦詩樂無事，解帶偃南扉。", "陽春美時澤，旭霽望山暉。", "幽禽響未轉，東原綠猶微。", "名雖列僊爵，心已遣塵機。", "即事同巖隱，聖渥良難違。"]'),
('0be19f42-dc52-4568-a481-71b06b3698d8','奉和張大夫戲示青山郎','韋應物','唐','唐诗','tang','','[]','天生逸世姿，竹馬不曾騎。',48,'全唐诗/poet.tang.9000.json','["天生逸世姿，竹馬不曾騎。", "覽卷冰將釋，援毫露欲垂。", "金貂傳幾葉，玉樹長新枝。", "榮祿何妨早，甘羅亦小兒。"]'),
('f054775c-a53a-41cf-a84d-7bc8512e86a5','答河南李士巽題香山寺','韋應物','唐','唐诗','tang','','[]','洛都遊宦日，少年攜手行。',192,'全唐诗/poet.tang.9000.json','["洛都遊宦日，少年攜手行。", "投杯起芳席，總轡振華纓。", "關塞有佳氣，巖開伊水清。", "攀林憩佛寺，登高望都城。", "蹉跎二十載，世務各所營。", "茲賞長在夢，故人安得幷。", "前歲守九江，恩詔赴咸京。", "因塗再登歷，山河屬晴明。", "寂寞僧侶少，蒼茫林木成。", "牆宇或崩剝，不見舊題名。", "舊遊況存歿，獨此淚交橫。", "交橫誰與同，書壁貽友生。", "今茲守吳郡，綿思方未平。", "子復經陳迹，一感我深情。", "遠蒙惻愴篇，中有金玉聲。", "反覆終難答，金玉尚爲輕。"]'),
('5881aabb-0474-441a-9e3d-4a02066332b5','答故人見諭','韋應物','唐','唐诗','tang','','[]','素寡名利心，自非周圓器。',96,'全唐诗/poet.tang.9000.json','["素寡名利心，自非周圓器。", "徒以歲月資，屢蒙藩條寄。", "時風重書札，物情敦貨遺。", "機杼十縑單，慵疎百函愧。", "常負交親責，且爲一官累。", "況本濩落人，歸無置錐地。", "省己已知非，枉書見深致。", "雖欲效區區，何由枉其志。"]'),
('9523181c-d141-4550-845a-09ed9616ef26','酬閻員外陟','韋應物','唐','唐诗','tang','','[]','寒夜阻良覿，叢竹想幽居。',50,'全唐诗/poet.tang.9000.json','["寒夜阻良覿，叢竹想幽居。", "虎符[予]已誤，金丹子何如。", "讌集觀農暇，笙歌聽訟餘。", "雖蒙一言教，自愧道情疎。"]'),
('ed16a128-a7dc-4797-bc73-271e30e1d8d0','酬秦徵君徐少府春日見寄','韋應物','唐','唐诗','tang','','[]','終日愧無政，與君聊散襟。',48,'全唐诗/poet.tang.9000.json','["終日愧無政，與君聊散襟。", "城根山半腹，亭影水中心。", "朗詠竹牕靜，野情花逕深。", "那能有餘興，不作剡溪尋。"]'),
('d170f81a-a576-430d-b179-56b1a8b8b5ec','冬夜宿司空曙野居因寄酬贈','韋應物','唐','唐诗','tang','','[]','南北與山鄰，蓬庵庇一身。',48,'全唐诗/poet.tang.9000.json','["南北與山鄰，蓬庵庇一身。", "繁霜疑有雪，荒草似無人。", "遂性在耕稼，所交唯賤貧。", "何掾張椽傲，每重德璋親。"]'),
('b8ae44b3-ba8d-42d3-85a7-a70aa8608379','長安遇馮著','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53d9\u4e8b", "\u540c\u60c5", "\u6292\u60c5", "\u4e94\u8a00\u53e4\u8bd7"]','客從東方來，衣上灞陵雨。',48,'全唐诗/poet.tang.9000.json','["客從東方來，衣上灞陵雨。", "問客何爲來，采山因買斧。", "冥冥花正開，颺颺燕新乳。", "昨別今已春，鬢絲生幾縷。"]'),
('6b30084e-e8b8-44a4-8a2f-82a233246c22','將發楚州經寶應縣訪李二忽於州館相遇月夜書事因簡李寶應','韋應物','唐','唐诗','tang','','[]','孤舟欲夜發，祗爲訪情人。',48,'全唐诗/poet.tang.9000.json','["孤舟欲夜發，祗爲訪情人。", "此地忽相遇，留連意更新。", "停杯嗟別久，對月言家貧。", "一問臨邛令，如何待上賓。"]'),
('96c532ca-b3a3-4ec9-ba5e-6fed23c1b8cd','廣陵遇孟九雲卿','韋應物','唐','唐诗','tang','','[]','雄藩本帝都，遊士多俊賢。',96,'全唐诗/poet.tang.9000.json','["雄藩本帝都，遊士多俊賢。", "夾河樹鬱鬱，華館千里連。", "新知雖滿堂，中意頗未宣。", "忽逢翰林友，歡樂斗酒前。", "高文激頹波，四海靡不傳。", "西施且一笑，衆女安得妍。", "明月滿淮海，哀鴻逝長天。", "所念京國遠，我來君欲還。"]'),
('540559c4-5be0-42ee-adfc-1e409af2728f','淮上遇洛陽李主簿','韋應物','唐','唐诗','tang','','["\u611f\u6168", "\u5199\u4eba", "\u6292\u6000", "\u5199\u4eba\u8bd7"]','結茅臨古渡，臥見長淮流。',48,'全唐诗/poet.tang.9000.json','["結茅臨古渡，臥見長淮流。", "窗裏人將老，門前樹已秋。", "寒山獨過雁，暮雨遠來舟。", "日夕逢歸客，那能忘舊遊。"]'),
('36d8f6f1-a652-4bc1-b03f-364e8442170b','路逢崔元二侍御避馬見招以詩見贈','韋應物','唐','唐诗','tang','','[]','一臺稱二妙，歸路望行塵。',48,'全唐诗/poet.tang.9000.json','["一臺稱二妙，歸路望行塵。", "俱是攀龍客，空爲避馬人。", "見招翻跼蹐，相問良殷勤。", "日日吟趨府，彈冠豈有因。"]'),
('2ade3c28-5e17-4a15-b3d3-f11c3387e4e7','逢楊開府','韋應物','唐','唐诗','tang','','[]','少事武皇帝，無賴恃恩私。',144,'全唐诗/poet.tang.9000.json','["少事武皇帝，無賴恃恩私。", "身作里中橫，家藏亡命兒。", "朝持樗蒲局，暮竊東鄰姬。", "司隸不敢捕，立在白玉墀。", "驪山風雪夜，長楊羽獵時。", "一字都不識，飲酒肆頑癡。", "武皇升仙去，憔悴被人欺。", "讀書事已晚，把筆學題詩。", "兩府始收跡，南宮謬見推。", "非才果不容，出守撫惸嫠。", "忽逢楊開府，論舊涕俱垂。", "坐客何由識，惟有故人知。"]'),
('e05ab52a-1d72-4de5-8637-2d2119952375','休暇日訪王侍御不遇','韋應物','唐','唐诗','tang','','[]','九日驅馳一日閑，尋君不遇又空還。',32,'全唐诗/poet.tang.9000.json','["九日驅馳一日閑，尋君不遇又空還。", "怪來詩思清人骨，門對寒流雪滿山。"]'),
('6743f5d8-d939-489f-a735-e48e2a98230b','因省風俗訪道士姪不見題壁','韋應物','唐','唐诗','tang','','[]','去年澗水今亦流，去年杏花今又拆。',32,'全唐诗/poet.tang.9000.json','["去年澗水今亦流，去年杏花今又拆。", "山人歸來問是誰，還是去年行春客。"]'),
('20ff955d-ecbb-4082-8893-58b710d28809','有所思','韋應物','唐','唐诗','tang','','[]','借問堤上柳，青青爲誰春。',48,'全唐诗/poet.tang.9000.json','["借問堤上柳，青青爲誰春。", "空遊昨日地，不見昨日人。", "繚繞萬家井，往來車馬塵。", "莫道無相識，要非心所親。"]'),
('00a93092-6174-4ab1-9ba5-ec5b7fdbf7ec','暮相思','韋應物','唐','唐诗','tang','','[]','朝出自不還，暮歸花盡發。',36,'全唐诗/poet.tang.9000.json','["朝出自不還，暮歸花盡發。", "豈無終日會，惜此花間月。", "空館忽相思，微鐘坐來歇。"]'),
('bb4f76a6-5150-45c9-9266-b49b2f44d15b','夏夜憶盧嵩','韋應物','唐','唐诗','tang','','[]','靄靄高館暮，開軒滌煩襟。',72,'全唐诗/poet.tang.9000.json','["靄靄高館暮，開軒滌煩襟。", "不知湘雨來，瀟灑在幽林。", "炎月得涼夜，芳樽誰與斟。", "故人南北居，累月間徽音。", "人生無閑日，歡會當在今。", "反側候天旦，層城苦沈沈。"]'),
('8d931b83-a688-4c13-8179-eb7026c792ba','春思','韋應物','唐','唐诗','tang','','["\u6625\u5929", "\u6000\u5ff5"]','野花如雪繞江城，坐見年芳憶帝京。',32,'全唐诗/poet.tang.9000.json','["野花如雪繞江城，坐見年芳憶帝京。", "閶闔曉開凝碧樹，曾陪鴛鷺聽流鶯。"]'),
('55166723-0b1a-439e-a7ca-0ebf4207c401','春中憶元二','韋應物','唐','唐诗','tang','','[]','雨歇萬井春，柔條已含緑。',48,'全唐诗/poet.tang.9000.json','["雨歇萬井春，柔條已含緑。", "徘徊洛陽陌，惆悵杜陵曲。", "遊絲正高下，啼鳥還斷續。", "有酒今不同，思君瑩如玉。"]'),
('4cc60243-6e9d-4466-ac08-c8fa58756676','懷素友子西','韋應物','唐','唐诗','tang','','[]','廣陌竝遊騎，公堂接華襟。',84,'全唐诗/poet.tang.9000.json','["廣陌竝遊騎，公堂接華襟。", "方歡遽見別，永日獨沈吟。", "階暝流暗駛，氣疎露已侵。", "層城湛深夜，片月生幽林。", "往款良未遂，來覿曠無音。", "恆當清觴宴，思子玉山岑。", "耿耿何以寫，密言空委心。"]'),
('d439dc72-e979-4ca3-a6b8-514b8b0b0be7','對韓少尹所贈硯有懷','韋應物','唐','唐诗','tang','','[]','故人謫遐遠，留硯寵斯文。',48,'全唐诗/poet.tang.9000.json','["故人謫遐遠，留硯寵斯文。", "白水浮香墨，清池滿夏雲。", "念離心已永，感物思徒紛。", "未有桂陽使，裁書一報君。"]'),
('2d630fa1-1b1b-4417-8dab-ba7000623bfa','月晦憶去年與親友曲水遊讌','韋應物','唐','唐诗','tang','','[]','晦賞念前歲，京國結良儔。',72,'全唐诗/poet.tang.9000.json','["晦賞念前歲，京國結良儔。", "騎出宣平里，飲對曲池流。", "今朝隔天末，空園傷獨遊。", "雨歇林光變，塘緑鳥聲幽。", "凋甿積逋稅，華鬢集新秋。", "誰言戀虎符，終當還舊丘。"]'),
('b1bb6051-4abe-4ecb-8eee-78661873e42d','清明日憶諸弟','韋應物','唐','唐诗','tang','','[]','冷食方多病，開襟一忻然。',48,'全唐诗/poet.tang.9000.json','["冷食方多病，開襟一忻然。", "終令思故郡，煙火滿晴川。", "杏粥猶堪食，榆羹已稍煎。", "唯恨乖親燕，坐度此芳年。"]'),
('2470747c-cea0-4400-bf4b-a86c91c36825','池上懷王卿','韋應物','唐','唐诗','tang','','[]','幽居捐世事，佳雨散園芳。',72,'全唐诗/poet.tang.9000.json','["幽居捐世事，佳雨散園芳。", "入門靄已緑，水禽鳴春塘。", "重雲始成夕，忽霽尚殘陽。", "輕舟因風泛，郡閣望蒼蒼。", "私燕阻外好，臨歡一停觴。", "茲遊無時盡，旭日願相將。"]'),
('bf080b73-083d-44da-9a15-8d6825f67ca4','立夏日憶京師諸弟','韋應物','唐','唐诗','tang','','[]','改序念芳辰，煩襟倦日永。',48,'全唐诗/poet.tang.9000.json','["改序念芳辰，煩襟倦日永。", "夏木已成陰，公門晝恆靜。", "長風始飄閣，疊雲纔吐嶺。", "坐想離居人，還當惜徂景。"]'),
('803c6b6d-d87e-4db2-8a72-43cdc11c63a3','曉至園中憶諸弟崔都水','韋應物','唐','唐诗','tang','','[]','山郭恆悄悄，林月亦娟娟。',48,'全唐诗/poet.tang.9000.json','["山郭恆悄悄，林月亦娟娟。", "景清神已澄，事簡慮絕牽。", "秋塘徧衰草，曉露洗紅蓮。", "不見心所愛，茲賞豈爲妍。"]'),
('0d0ad700-6de7-4b62-944a-7093762ce2d3','懷瑯琊深標二釋子','韋應物','唐','唐诗','tang','','[]','白雲埋大壑，陰崖滴夜泉。',24,'全唐诗/poet.tang.9000.json','["白雲埋大壑，陰崖滴夜泉。", "應居西石室，月照山蒼然。"]'),
('94eb2668-bdc3-4233-9f57-024577ea25bc','雨夜感懷','韋應物','唐','唐诗','tang','','[]','微雨灑高林，塵埃自蕭散。',48,'全唐诗/poet.tang.9000.json','["微雨灑高林，塵埃自蕭散。", "耿耿心未平，沈沈夜方半。", "獨驚長簟冷，遽覺愁鬢換。", "誰能當此夕，不有盈襟歎。"]'),
('27835d80-c1fd-4459-987c-4d490aa97370','雲陽館懷谷口','韋應物','唐','唐诗','tang','','[]','清泚階下流，云自谷口源。',96,'全唐诗/poet.tang.9000.json','["清泚階下流，云自谷口源。", "念昔白衣士，結廬在石門。", "道高杳無累，景靜得忘言。", "山夕綠陰滿，世移清賞存。", "吏役豈遑暇，幽懷復朝昏。", "雲泉非所濯，蘿月不可援。", "長往遂真性，暫遊恨卑喧。", "出身既事世，高躅難等論。"]'),
('5e77e1d4-d8f0-4b71-a115-52b099922a69','憶灃上幽居','韋應物','唐','唐诗','tang','','[]','一來當復去，猶此厭樊籠。',36,'全唐诗/poet.tang.9000.json','["一來當復去，猶此厭樊籠。", "況我林栖子，朝服坐南宮。", "唯獨問啼鳥，還如灃水東。"]'),
('70376567-a76a-4843-bd94-918e120f4274','重九登滁城樓憶前歲九日歸灃上赴崔都水及諸弟讌集悽然懷舊','韋應物','唐','唐诗','tang','','[]','今日重九讌，去歲在京師。',72,'全唐诗/poet.tang.9000.json','["今日重九讌，去歲在京師。", "聊廻出省步，一赴郊園期。", "嘉節始云邁，周辰已及茲。", "秋山滿清景，當賞屬乖離。", "凋散民里闊，摧翳衆木衰。", "樓中一長嘯，惻愴起涼颸。"]'),
('db3e1589-dd63-42b7-9c3a-6f7021a5a6e0','始夏南園思舊里','韋應物','唐','唐诗','tang','','[]','夏首雲物變，雨餘草木繁。',48,'全唐诗/poet.tang.9000.json','["夏首雲物變，雨餘草木繁。", "池荷初帖水，林花已掃園。", "縈叢蝶尚亂，依閣鳥猶喧。", "對此殘芳月，憶在漢陵原。"]'),
('1c458581-b581-4091-8b33-f4328cbfe77a','登蒲塘驛沿路見泉谷邨墅忽想京師舊居追懷昔年','韋應物','唐','唐诗','tang','','[]','青山導騎遶，春風行斾舒。',96,'全唐诗/poet.tang.9000.json','["青山導騎遶，春風行斾舒。", "均徭視屬城，問疾躬里閭。", "煙水依泉谷，川陸散樵漁。", "忽念故園日，復憶驪山居。", "荏苒斑鬢及，夢寢婚宦初。", "不覺平生事，咄嗟二紀餘。", "存歿闊已永，悲多歡自疎。", "高秩非爲美，闌干淚盈裾。"]'),
('7f5f13a5-457e-4f6f-8632-dc3f9084d444','經函谷關','韋應物','唐','唐诗','tang','','[]','洪河絕山根，單軌出其側。',134,'全唐诗/poet.tang.9000.json','["洪河絕山根，單軌出其側。", "萬古爲要樞，往來何時息。", "秦皇即恃險，海內被吞食。", "及嗣同覆顛，咽喉莫能塞。", "炎靈詎西駕，婁子非經國。", "徒欲扼諸侯，不知恢至德。", "聖朝及天寶，豺虎起東北。", "下沈戰死魂，上結窮冤色。", "古今雖共守，成敗良可識。", "藩屏無俊賢，金湯獨何力。", "[馳]車一登眺，感慨中自惻。"]'),
('f2ddc157-c7e1-4db6-8105-e446db952408','經武功舊宅','韋應物','唐','唐诗','tang','','[]','茲邑昔所遊，嘉會常在目。',84,'全唐诗/poet.tang.9000.json','["茲邑昔所遊，嘉會常在目。", "歷載俄二九，始往今來復。", "慼慼居人少，茫茫野田綠。", "風雨經舊墟，毀垣迷往躅。", "門臨川流駛，樹有羇雌宿。", "多累恆悲往，長年覺時速。", "欲去中復留，徘徊結心曲。"]'),
('7e279de3-f4f4-4332-8d44-293a756fbf6c','往雲門郊居塗經廻流作','韋應物','唐','唐诗','tang','','[]','茲晨乃休暇，適往田家廬。',72,'全唐诗/poet.tang.9000.json','["茲晨乃休暇，適往田家廬。", "原谷徑塗澀，春陽草木敷。", "纔遵板橋曲，復此清澗紆。", "崩壑方見射，廻流忽已舒。", "明滅泛孤景，杳靄含夕虛。", "無將爲邑志，一酌澄波餘。"]'),
('5f13975d-017d-4852-b0c8-bbd3253db811','乘月過西郊渡','韋應物','唐','唐诗','tang','','[]','遠山含紫氛，春野靄云暮。',84,'全唐诗/poet.tang.9000.json','["遠山含紫氛，春野靄云暮。", "值此歸時月，留連西澗渡。", "謬當文墨會，得與羣英遇。", "賞逐亂流翻，心將清景悟。", "行車儼未轉，芳草空盈步。", "已舉候亭火，猶愛村原樹。", "還當守故扃，悵恨秉幽素。"]'),
('489dc6c0-12d8-4fac-aaca-7d2cf80e6788','晚歸灃川','韋應物','唐','唐诗','tang','','[]','凌霧朝閶闔，落日返清川。',96,'全唐诗/poet.tang.9000.json','["凌霧朝閶闔，落日返清川。", "簪組方暫解，臨水一翛然。", "昆弟忻來集，童稚滿眼前。", "適意在無事，攜手望秋田。", "南嶺橫爽氣，高林繞遙阡。", "野廬不鋤理，翳翳起荒煙。", "名秩斯逾分，廉退媿不全。", "已想平門路，晨騎復言旋。"]'),
('5e63342d-fded-4f63-8ec3-e5d27b8d1518','授衣還田里','韋應物','唐','唐诗','tang','','[]','公門懸甲令，澣濯遂其私。',72,'全唐诗/poet.tang.9000.json','["公門懸甲令，澣濯遂其私。", "晨起懷愴恨，野田寒露時。", "氣收天地廣，風淒草木衰。", "山明始重疊，川淺更逶迤。", "煙火生閭里，禾黍積東菑。", "終然可樂業，時節一來斯。"]'),
('11424603-9a22-4564-89a4-95e1766f9685','夕次盱眙縣','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u5199\u666f", "\u6292\u60c5", "\u601d\u4e61"]','落帆逗淮鎮，停舫臨孤驛。',48,'全唐诗/poet.tang.9000.json','["落帆逗淮鎮，停舫臨孤驛。", "浩浩風起波，冥冥日沈夕。", "人歸山郭暗，雁下蘆洲白。", "獨夜憶秦關，聽鐘未眠客。"]'),
('43df1a55-ad97-4ce0-b258-2d72bedded72','春月觀省屬城始憩東西林精舍','韋應物','唐','唐诗','tang','','[]','因時省風俗，布惠迨高年。',168,'全唐诗/poet.tang.9000.json','["因時省風俗，布惠迨高年。", "建隼出潯陽，整駕遊山川。", "白雲斂晴壑，羣峰列遙天。", "嶔㟢石門狀，杳靄香爐烟。", "榛荒屢罥罣，偪側殆覆顛。", "方臻釋氏廬，時物屢華妍。", "曇遠昔經始，於茲閟幽玄。", "東西竹林寺，灌注寒澗泉。", "人事即云泯，歲月復已綿。", "殿宇餘丹紺，磴閣峭欹懸。", "佳士亦棲息，善身絕塵緣。", "今我蒙朝寄，教化敷里鄽。", "道妙茍爲得，出處理無偏。", "心當同所尚，跡豈辭纏牽。"]'),
('826e6955-873f-463b-81a5-0bfe87c4fe72','自蒲塘驛廻駕經歷山水','韋應物','唐','唐诗','tang','','[]','館宿風雨滯，始晴行蓋轉。',96,'全唐诗/poet.tang.9000.json','["館宿風雨滯，始晴行蓋轉。", "潯陽山水多，草木俱紛衍。", "崎嶇緣碧澗，蒼翠踐苔蘚。", "高樹夾潺湲，崩石橫陰巘。", "野杏依寒拆，餘雲冒嵐淺。", "性愜形豈勞，境殊路遺緬。", "憶昔終南下，佳遊亦屢展。", "時禽下流暮，紛思何由遣。"]'),
('ba66664f-2966-4538-abc4-2f2f23b37fd3','山行積雨歸途始霽','韋應物','唐','唐诗','tang','','[]','攬轡窮登降，陰雨遘二旬。',84,'全唐诗/poet.tang.9000.json','["攬轡窮登降，陰雨遘二旬。", "但見白雲合，不睹巖中春。", "急澗豈易揭，峻塗良難遵。", "深林猿聲冷，沮洳虎跡新。", "始霽升陽景，山水閱清晨。", "雜花積如霧，百卉萋已陳。", "鳴騶屢驤首，歸路自忻忻。"]'),
('247c2821-fa45-466c-a71f-86f2e5f49f0a','傷逝','韋應物','唐','唐诗','tang','','[]','染白一爲黑，焚木盡成灰。',144,'全唐诗/poet.tang.9000.json','["染白一爲黑，焚木盡成灰。", "念我室中人，逝去亦不廻。", "結髮二十載，賓敬如始來。", "提攜屬時屯，契闊憂患災。", "柔素亮爲表，禮章夙所該。", "仕公不及私，百事委令才。", "一旦入閨門，四屋滿塵埃。", "斯人既已矣，觸物但傷摧。", "單居移時節，泣涕撫嬰孩。", "知妄謂當遣，臨感要難裁。", "夢想忽如睹，驚起復徘徊。", "此心良無已，遶屋生蒿萊。"]'),
('9fcbd019-d995-4f89-b0ac-0a30177598bd','往富平傷懷','韋應物','唐','唐诗','tang','','[]','晨起凌嚴霜，慟哭臨素帷。',120,'全唐诗/poet.tang.9000.json','["晨起凌嚴霜，慟哭臨素帷。", "駕言百里塗，惻愴復何爲。", "昨者仕公府，屬城常載馳。", "出門無所憂，返室亦熙熙。", "今者掩筠扉，但聞童稚悲。", "丈夫須出入，顧爾內無依。", "銜恨已酸骨，何況苦寒時。", "單車路蕭條，廻首長逶遲。", "飄風忽截野，嘹唳雁起飛。", "昔時同往路，獨往今詎知。"]'),
('b2770c58-172a-4fac-a11b-621636f5378e','出還','韋應物','唐','唐诗','tang','','[]','昔出喜還家，今還獨傷意。',72,'全唐诗/poet.tang.9000.json','["昔出喜還家，今還獨傷意。", "入室掩無光，銜哀寫虛位。", "悽悽動幽幔，寂寂驚寒吹。", "幼女復何知，時來庭下戲。", "咨嗟日復老，錯莫身如寄。", "家人勸我飡，對案空垂淚。"]'),
('eb8f7ff9-1b81-4b54-af1f-afa455e3cb02','冬夜','韋應物','唐','唐诗','tang','','[]','杳杳日云夕，鬱結誰爲開。',96,'全唐诗/poet.tang.9000.json','["杳杳日云夕，鬱結誰爲開。", "單衾自不暖，霜霰已皚皚。", "晚歲淪夙志，驚鴻感深哀。", "深哀當何爲，桃李忽凋摧。", "幃悵徒自設，冥寞豈復來。", "平生雖恩重，遷去託窮埃。", "抱此女曹恨，顧非高世才。", "振衣中夜起，河漢尚裴回。"]'),
('d9c1fb01-6bc6-4294-b4a4-24904ded5347','送終','韋應物','唐','唐诗','tang','','[]','奄忽逾時節，日月獲其良。',144,'全唐诗/poet.tang.9000.json','["奄忽逾時節，日月獲其良。", "蕭蕭車馬悲，祖載發中堂。", "生平同此居，一旦異存亡。", "斯須亦何益，終復委山岡。", "行出國南門，南望鬱蒼蒼。", "日入乃云造，慟哭宿風霜。", "晨遷俯玄廬，臨訣但遑遑。", "方當永潛翳，仰視白日光。", "俯仰遽終畢，封樹已荒涼。", "獨留不得還，欲去結中腸。", "童稚知所失，啼號捉我裳。", "既事猶倉卒，歲月始難忘。"]'),
('f5ba5fc0-d422-4c0b-9077-51e4c0014ffb','除日','韋應物','唐','唐诗','tang','','[]','思懷耿如昨，季月已云暮。',48,'全唐诗/poet.tang.9000.json','["思懷耿如昨，季月已云暮。", "忽驚年復新，獨恨人成故。", "冰池始泮綠，梅楥還飄素。", "淑景方轉延，朝朝自難度。"]'),
('7399c34e-d3b6-4144-a107-d0f78c7d24bb','對芳樹','韋應物','唐','唐诗','tang','','[]','迢迢芳園樹，列映清池曲。',48,'全唐诗/poet.tang.9000.json','["迢迢芳園樹，列映清池曲。", "對此傷人心，還如故時綠。", "風條灑餘靄，露葉承新旭。", "佳人不再攀，下有往來躅。"]'),
('252b2da5-2293-4e34-ab81-63f40b6a0a4a','月夜','韋應物','唐','唐诗','tang','','[]','皓月流春城，華露積芳草。',36,'全唐诗/poet.tang.9000.json','["皓月流春城，華露積芳草。", "坐念綺窗空，翻傷清景好。", "清景終若斯，傷多人自老。"]'),
('109d9834-dd55-43cd-bfe5-e217edb52998','歎楊花','韋應物','唐','唐诗','tang','','[]','空蒙不自定，況值暄風度。',48,'全唐诗/poet.tang.9000.json','["空蒙不自定，況值暄風度。", "舊賞逐流年，新愁忽盈素。", "纔縈下苑曲，稍滿東城路。", "人意有悲歡，時芳獨如故。"]'),
('58f77bbc-5b43-424e-8fc6-cdb7e6c947a5','過昭國里故第','韋應物','唐','唐诗','tang','','[]','不復見故人，一來過故宅。',144,'全唐诗/poet.tang.9000.json','["不復見故人，一來過故宅。", "物變知景暄，心傷覺時寂。", "池荒野筠合，庭綠幽草積。", "風散花意謝，鳥還山光夕。", "宿昔方同賞，詎知今念昔。", "緘室在東廂，遺器不忍覿。", "柔翰全分意，芳巾尚染澤。", "殘工委筐篋，餘素經刀尺。", "收此還我家，將還復愁惕。", "永絕攜手歡，空存舊行迹。", "冥冥獨無語，杳杳將何適。", "唯思今古同，時緩傷與戚。"]'),
('a3a4c119-f237-47de-a859-e1f451aa6186','夏日','韋應物','唐','唐诗','tang','','[]','已謂心苦傷，如何日方永。',48,'全唐诗/poet.tang.9000.json','["已謂心苦傷，如何日方永。", "無人不晝寢，獨坐山中靜。", "悟澹將遣慮，學空庶遺境。", "積俗易爲侵，愁來復難整。"]'),
('73ec24aa-b952-41d5-8420-9b0ac8d95b7e','端居感懷','韋應物','唐','唐诗','tang','','[]','沈沈積素抱，婉婉屬之子。',108,'全唐诗/poet.tang.9000.json','["沈沈積素抱，婉婉屬之子。", "永日獨無言，忽驚振衣起。", "方如在幃室，復悟永終已。", "稚子傷恩絕，盛時若流水。", "暄涼同寡趣，朗晦俱無理。", "寂性常喻人，滯情今在己。", "空房欲云暮，巢燕亦來止。", "夏木遽成陰，綠苔誰復履。", "感至竟何方，幽獨長如此。"]'),
('6b6ae415-b03d-45a0-bd06-0ad1cc66eca2','悲紈扇','韋應物','唐','唐诗','tang','','[]','非關秋節至，詎是恩情改。',36,'全唐诗/poet.tang.9000.json','["非關秋節至，詎是恩情改。", "掩嚬人已無，委篋涼空在。", "何言永不發，暗使銷光彩。"]'),
('12da597b-33fa-461f-b87b-9b70d55bce1d','閑齋對雨','韋應物','唐','唐诗','tang','','[]','幽獨自盈抱，陰淡亦連朝。',48,'全唐诗/poet.tang.9000.json','["幽獨自盈抱，陰淡亦連朝。", "空齋對高樹，疎雨共蕭條。", "巢燕翻泥濕，蕙花依砌消。", "端居念往事，倏忽苦驚飆。"]'),
('40d0f9ac-7869-4c65-89e1-86c4a0dabdee','林園晚霽','韋應物','唐','唐诗','tang','','[]','雨歇見青山，落日照林園。',60,'全唐诗/poet.tang.9000.json','["雨歇見青山，落日照林園。", "山多煙鳥亂，林清風景翻。", "提攜唯子弟，蕭散在琴言。", "同遊不同意，耿耿獨傷魂。", "寂寞鐘已盡，如何還入門。"]'),
('7d969486-7e76-47dc-8b5e-5ab10e6f5004','秋夜二首 一','韋應物','唐','唐诗','tang','','[]','庭樹轉蕭蕭，陰蟲還戚戚。',48,'全唐诗/poet.tang.9000.json','["庭樹轉蕭蕭，陰蟲還戚戚。", "獨向高齋眠，夜聞寒雨滴。", "微風時動牖，殘燈尚留壁。", "惆悵平生懷，偏來委今夕。"]'),
('8dd43a36-3214-4bcc-aaf5-f21ccaa3ba96','秋夜二首 二','韋應物','唐','唐诗','tang','','[]','霜露已淒淒，星漢復昭回。',48,'全唐诗/poet.tang.9000.json','["霜露已淒淒，星漢復昭回。", "朔風中夜起，驚鴻千里來。", "蕭條涼葉下，寂寞清砧哀。", "歲晏仰空宇，心事若寒灰。"]'),
('d1864282-6380-457e-8032-dc54346bcc7f','感夢','韋應物','唐','唐诗','tang','','[]','歲月轉蕪漫，形影長寂寥。',48,'全唐诗/poet.tang.9000.json','["歲月轉蕪漫，形影長寂寥。", "髣髴覯微夢，感嘆起中宵。", "綿思靄流月，驚魂颯廻飆。", "誰念茲夕永，坐令顏鬢凋。"]'),
('7914d8f2-bae0-4a50-b0fe-9e9e44b4294e','同德精舍舊居傷懷','韋應物','唐','唐诗','tang','','[]','洛京十載別，東林訪舊扉。',48,'全唐诗/poet.tang.9000.json','["洛京十載別，東林訪舊扉。", "山河不可望，存沒意多違。", "時遷跡尚在，同去獨來歸。", "還見窗中鴿，日暮遶庭飛。"]'),
('3c7d8111-fbc8-4d65-8819-217e6054d537','悲故交','韋應物','唐','唐诗','tang','','[]','白璧衆求瑕，素絲易成汙。',72,'全唐诗/poet.tang.9000.json','["白璧衆求瑕，素絲易成汙。", "萬里顛沛還，高堂已長暮。", "積憤方盈抱，纏哀忽逾度。", "念子從此終，黃泉竟誰訴。", "一爲時事感，豈獨平生故。", "唯見荒丘原，野草塗朝露。"]'),
('4f71d29d-cb3b-4334-99d5-827ae9e07044','張彭州前與緱氏馮少府各惠寄一篇多故未答張已云沒因追哀敘事兼遠簡馮生','韋應物','唐','唐诗','tang','','[]','君昔掌文翰，西垣復石渠。',144,'全唐诗/poet.tang.9000.json','["君昔掌文翰，西垣復石渠。", "朱衣乘白馬，輝光照里閭。", "余時忝南省，接讌媿空虛。", "一別守茲郡，蹉跎歲再除。", "長懷關河表，永日簡牘餘。", "郡中有方塘，涼閣對紅蕖。", "金玉蒙遠貺，篇詠見吹噓。", "未答平生意，已沒九原居。", "秋風吹寢門，長慟涕漣如。", "覆視緘中字，奄爲昔人書。", "髮鬢已云白，交友日彫疎。", "馮生遠同恨，憔悴在田廬。"]'),
('b4813a27-9cc6-491d-a5a0-70acfca1b278','東林精舍見故殿中鄭侍御題詩追舊書情涕泗橫集因寄呈閻澧州馮少府','韋應物','唐','唐诗','tang','','[]','仲月景氣佳，東林一登歷。',144,'全唐诗/poet.tang.9000.json','["仲月景氣佳，東林一登歷。", "中有故人詩，淒涼在高壁。", "精思長懸世，音容已歸寂。", "墨澤傳灑餘，磨滅親翰跡。", "平生忽如夢，百事皆成昔。", "結騎京華年，揮文篋笥積。", "朝廷重英彥，時輩分珪璧。", "永謝柏梁陪，獨闕金門籍。", "方嬰存歿感，豈暇林泉適。", "雨餘山景寒，風散花光夕。", "新知雖滿堂，故情誰能覿。", "唯當同時友，緘寄空悽慼。"]'),
('a3daa8e6-47ec-44c8-b7cf-af3a659292a1','同李二過亡友鄭子故第','韋應物','唐','唐诗','tang','','[]','客車名未滅，沒世恨應長。',48,'全唐诗/poet.tang.9000.json','["客車名未滅，沒世恨應長。", "斜月知何照，幽林判自芳。", "故人驚逝水，寒雀噪空牆。", "不是平生舊，遺蹤要可傷。"]'),
('64616ec2-5d11-4c67-908a-d2c582ced6e8','話舊','韋應物','唐','唐诗','tang','','[]','存亡三十載，事過悉成空。',24,'全唐诗/poet.tang.9000.json','["存亡三十載，事過悉成空。", "不惜霑衣淚，併話一宵中。"]'),
('9e983caa-b744-4629-b53e-fd5100a6c8c7','至開化里壽春公故宅','韋應物','唐','唐诗','tang','','[]','寧知府中吏，故宅一徘徊。',48,'全唐诗/poet.tang.9000.json','["寧知府中吏，故宅一徘徊。", "歷階存往敬，瞻位泣餘哀。", "廢井沒荒草，陰牖生緑笞。", "門前車馬散，非復昔時來。"]'),
('ac97f9d6-469c-4f3c-a56e-8de7bf65bfad','睢陽感懷','韋應物','唐','唐诗','tang','','[]','豺虎犯天綱，昇平無內備。',144,'全唐诗/poet.tang.9000.json','["豺虎犯天綱，昇平無內備。", "長驅陰山卒，略踐三河地。", "張侯本忠烈，濟世有深智。", "堅壁梁宋間，遠籌吳楚利。", "窮年方絕輸，鄰援皆攜貳。", "使者哭其庭，救兵終不至。", "重圍雖可越，藩翰諒難棄。", "飢喉待危巢，懸命中路墜。", "甘從鋒刃斃，莫奪堅貞志。", "宿將降賊庭，儒生獨全義。", "空城唯白骨，同往無賤貴。", "哀哉豈獨今，千載當歔欷。"]'),
('6492e4a6-90ae-4eab-a798-4f131e6d6cc2','廣德中洛陽作','韋應物','唐','唐诗','tang','','[]','生長太平日，不知太平歡。',96,'全唐诗/poet.tang.9000.json','["生長太平日，不知太平歡。", "今還洛陽中，感此方苦酸。", "飲藥本攻病，毒腸翻自殘。", "王師涉河洛，玉石俱不完。", "時節屢遷斥，山河長鬱盤。", "蕭條孤煙絕，日入空城寒。", "蹇劣乏高步，緝遺守微官。", "西懷咸陽道，躑躅心不安。"]'),
('1bede934-9155-45bb-94b2-a38ce07ef9a9','閶門懷古','韋應物','唐','唐诗','tang','','[]','獨鳥下高樹，遙知吳苑園。',24,'全唐诗/poet.tang.9000.json','["獨鳥下高樹，遙知吳苑園。", "淒涼千古事，日暮倚閶門。"]'),
('bbaa0e54-ffcb-4b49-b9a6-80382bd8ba39','感事','韋應物','唐','唐诗','tang','','[]','霜雪皎素絲，何意墜墨池。',48,'全唐诗/poet.tang.9000.json','["霜雪皎素絲，何意墜墨池。", "青蒼猶可濯，黑色不可移。", "女工再三嘆，委棄當此時。", "歲寒雖無褐，機杼誰肯施。"]'),
('a58685ef-7d57-4757-a9a2-b554f05f7dd4','感鏡','韋應物','唐','唐诗','tang','','[]','鑄鏡廣陵市，菱花匣中發。',60,'全唐诗/poet.tang.9000.json','["鑄鏡廣陵市，菱花匣中發。", "夙昔嘗許人，鏡成人已沒。", "如冰結圓器，類璧無絲髮。", "形影終不臨，清光殊不歇。", "一感平生言，松枝樹秋月。"]'),
('229e2652-f547-4d3f-8186-23c80c23601c','歎白髮','韋應物','唐','唐诗','tang','','[]','還同一葉落，對此孤鏡曉。',36,'全唐诗/poet.tang.9000.json','["還同一葉落，對此孤鏡曉。", "絲縷乍難分，楊花復相遶。", "時役人易衰，吾年白猶少。"]'),
('9b149500-5d1e-4293-b983-02c90f8c28a9','登高望洛城作','韋應物','唐','唐诗','tang','','[]','高臺造雲端，遐瞰周四垠。',192,'全唐诗/poet.tang.9000.json','["高臺造雲端，遐瞰周四垠。", "雄都定鼎地，勢據萬國尊。", "河岳出雲雨，土圭酌乾坤。", "舟通南越貢，城背北邙原。", "帝宅夾清洛，丹霞捧朝暾。", "葱蘢瑤臺榭，𥦖窱雙闕門。", "十載構屯難，兵戈若雲屯。", "膏腴滿榛蕪，比屋空毀垣。", "聖主乃東眷，俾賢拯元元。", "熙熙居守化，泛泛太府恩。", "至損當受益，苦寒必生溫。", "平明四城開，稍見市井喧。", "坐感理亂迹，永懷經濟言。", "吾生自不達，空鳥何翩翻。", "天高水流遠，日晏城郭昏。", "裴回訖旦夕，聊用寫憂煩。"]'),
('fa97a948-1c29-45d1-83a8-64da43bb091b','同德寺閣集眺','韋應物','唐','唐诗','tang','','[]','芳節欲云晏，遊遨樂相從。',120,'全唐诗/poet.tang.9000.json','["芳節欲云晏，遊遨樂相從。", "高閣照丹霞，飀飀含遠風。", "寂寥氛氳廓，超忽神慮空。", "旭日霽皇州，岧嶢見兩宮。", "嵩少多秀色，羣山莫與崇。", "三川浩東注，瀍澗亦來同。", "陰陽降大和，宇宙得其中。", "舟車滿川陸，四國靡不通。", "舊堵今即葺，庶甿亦已豐。", "周覽思自奮，行當遇時邕。"]'),
('d509c4a0-7006-4196-b7a5-48039cc8815c','登寶意寺上方舊遊','韋應物','唐','唐诗','tang','','[]','翠嶺香臺出半天，萬家煙樹滿晴川。',32,'全唐诗/poet.tang.9000.json','["翠嶺香臺出半天，萬家煙樹滿晴川。", "諸僧近住不相識，坐聽微鐘記往年。"]'),
('3a3d996c-77cd-4643-9916-433373a3442d','登樂遊廟作','韋應物','唐','唐诗','tang','','[]','高原出東城，鬱鬱見咸陽。',108,'全唐诗/poet.tang.9000.json','["高原出東城，鬱鬱見咸陽。", "上有千載事，乃自漢宣皇。", "頹壖久凌遲，陳迹翳丘荒。", "春草雖復綠，驚風但飄揚。", "周覽京城內，雙闕起中央。", "微鐘何處來，暮色忽蒼蒼。", "歌吹喧萬井，車馬塞康莊。", "昔人豈不爾，百世同一傷。", "歸當守沖漠，跡寓心自忘。"]'),
('e5430a72-f4b3-4125-af34-0d17fbf18205','登西南岡卜居遇雨尋竹浪至灃壖縈帶數里清流茂樹雲物可賞','韋應物','唐','唐诗','tang','','[]','登高創危構，林表見川流。',84,'全唐诗/poet.tang.9000.json','["登高創危構，林表見川流。", "微雨颯已至，蕭條川氣秋。", "下尋密竹盡，忽曠沙際遊。", "紆曲水分野，綿延稼盈疇。", "寒花明廢墟，樵牧笑榛丘。", "雲水成陰澹，竹樹更清幽。", "適自戀佳賞，復茲永日留。"]'),
('0b78d7c8-d837-4dad-9ee3-fec6df093258','灃上與幼遐月夜登西岡翫花','韋應物','唐','唐诗','tang','','[]','置酒臨高隅，佳人自城闕。',36,'全唐诗/poet.tang.9000.json','["置酒臨高隅，佳人自城闕。", "已翫滿川花，還看滿川月。", "花月方浩然，賞心何由歇。"]'),
('81fffa4c-c387-4b4f-86c0-e7f3cbcf7034','臺上遲客','韋應物','唐','唐诗','tang','','[]','高臺一悄望，遠樹間朝暉。',48,'全唐诗/poet.tang.9000.json','["高臺一悄望，遠樹間朝暉。", "但見東西騎，坐令心賞違。", "始霽郊原綠，暮春啼鳥稀。", "徒然對芳物，何能獨醉歸。"]'),
('2640c9b3-65aa-4dc8-9d84-da78d0221f6a','登樓','韋應物','唐','唐诗','tang','','[]','茲樓日登眺，流歲暗蹉跎。',24,'全唐诗/poet.tang.9000.json','["茲樓日登眺，流歲暗蹉跎。", "坐厭淮南守，秋山紅樹多。"]'),
('c74aa20f-950b-49f9-8bf6-20ec2d133667','善福寺閣','韋應物','唐','唐诗','tang','','[]','殘霞照高閣，青山出遠林。',24,'全唐诗/poet.tang.9000.json','["殘霞照高閣，青山出遠林。", "晴明一登望，瀟灑此幽襟。"]'),
('5702e4da-f721-4fff-a5c6-b1e7c9826b5a','樓中月夜','韋應物','唐','唐诗','tang','','[]','端令倚懸檻，長望抱沈憂。',48,'全唐诗/poet.tang.9000.json','["端令倚懸檻，長望抱沈憂。", "寧知故園月，今夕在茲樓。", "衰蓮送餘馥，華露湛新秋。", "坐見蒼林變，清輝愴已休。"]'),
('21e05ef0-2aa7-40fa-a13b-39de50c10cff','寒食後北樓作','韋應物','唐','唐诗','tang','','[]','園林過新節，風花亂高閣。',24,'全唐诗/poet.tang.9000.json','["園林過新節，風花亂高閣。", "遙聞擊鼓聲，蹴鞠軍中樂。"]'),
('402994cd-8330-4f36-a896-75a5a6bedf89','西樓','韋應物','唐','唐诗','tang','','[]','高閣一長望，故園何日歸？煙塵擁函谷，秋雁過來稀。',24,'全唐诗/poet.tang.9000.json','["高閣一長望，故園何日歸？煙塵擁函谷，秋雁過來稀。"]'),
('ee656cfd-badc-47b4-85fd-d84919bd7284','夜望','韋應物','唐','唐诗','tang','','[]','南樓夜已寂，暗鳥動林間。',24,'全唐诗/poet.tang.9000.json','["南樓夜已寂，暗鳥動林間。", "不見城郭事，沈沈唯四山。"]'),
('ce76ed51-7f1c-44cf-9188-d497b0dde5c8','晚登郡閣','韋應物','唐','唐诗','tang','','[]','悵然高閣望，已掩東城關。',24,'全唐诗/poet.tang.9000.json','["悵然高閣望，已掩東城關。", "春風偏送柳，夜景欲沈山。"]'),
('43734036-7c61-4b39-ac7b-e95bb3729fc7','登重玄寺閣','韋應物','唐','唐诗','tang','','[]','時暇陟雲構，晨霽澄景光。',96,'全唐诗/poet.tang.9000.json','["時暇陟雲構，晨霽澄景光。", "始見吳都大，十里鬱蒼蒼。", "山川表明麗，湖海吞大荒。", "合沓臻水陸，駢闐會四方。", "俗繁節又暄，雨順物亦康。", "禽魚各翔泳，草木遍芬芳。", "於茲省甿俗，一用勸農桑。", "誠知虎符忝，但恨歸路長。"]'),
('34165368-96b3-4f84-be05-f910951ea0a8','觀早朝','韋應物','唐','唐诗','tang','','[]','伐鼓通嚴城，車馬溢廣躔。',120,'全唐诗/poet.tang.9000.json','["伐鼓通嚴城，車馬溢廣躔。", "煌煌列明燭，朝服照華鮮。", "金門杳深沈，尚聽清漏傳。", "河漢忽已沒，司閽啓晨關。", "丹殿據龍首，崔嵬對南山。", "寒生千門裏，日照雙闕間。", "禁旅下成列，爐香起中天。", "輝輝覩明聖，濟濟行俊賢。", "媿無鴛鷺姿，短翮空飛還。", "誰當假毛羽，雲路相追攀。"]'),
('2a583296-983c-467a-93e4-65baf25eabb5','陪元侍御春遊','韋應物','唐','唐诗','tang','','[]','何處醉春風，長安西復東。',48,'全唐诗/poet.tang.9000.json','["何處醉春風，長安西復東。", "不因俱罷職，豈得此時同。", "貰酒宣平里，尋芳下苑中。", "往來楊柳陌，猶避昔年驄。"]'),
('1124e7cb-2599-4515-9e0a-094809f749f8','遊龍門香山泉','韋應物','唐','唐诗','tang','','[]','山水本自佳，遊人已忘慮。',84,'全唐诗/poet.tang.9000.json','["山水本自佳，遊人已忘慮。", "碧泉更幽絕，賞愛未能去。", "潺湲寫幽磴，繚繞帶嘉樹。", "激轉忽殊流，歸泓又同注。", "羽觴自成翫，永日亦延趣。", "靈草有時香，仙源不知處。", "還當候圓月，攜手重遊寓。"]'),
('29b560ec-71fe-43e8-887a-891037f3900c','龍門遊眺','韋應物','唐','唐诗','tang','','[]','鑿山導伊流，中斷若天闢。',96,'全唐诗/poet.tang.9000.json','["鑿山導伊流，中斷若天闢。", "都門遙相望，佳氣生朝夕。", "素懷出塵意，適有攜手客。", "精舍遶層阿，千龕鄰峭壁。", "緣雲路猶緬，憩澗鐘已寂。", "花樹發煙華，淙流散石脈。", "長嘯招遠風，臨潭漱金碧。", "日落望都城，人間何役役。"]'),
('9f6bec03-68a6-4d27-bb32-e0cb3781d7a8','洛都遊寓','韋應物','唐','唐诗','tang','','[]','東風日已和，元化亮無私。',96,'全唐诗/poet.tang.9000.json','["東風日已和，元化亮無私。", "草木同時植，生條有高卑。", "罷官守園廬，豈不懷渴飢。", "窮通非所干，跼促當何爲。", "佳辰幸可遊，親友亦相追。", "朝從華林宴，暮返東城期。", "掇英出蘭臯，翫月步川坻。", "軒冕誠可慕，所憂在縶維。"]'),
('a786ee09-19c4-400f-94cd-8c94e4b4033d','再遊龍門懷舊侶','韋應物','唐','唐诗','tang','','[]','兩山鬱相對，晨策方上干。',72,'全唐诗/poet.tang.9000.json','["兩山鬱相對，晨策方上干。", "靄靄眺都城，悠悠俯清瀾。", "邈矣二三子，茲焉屢遊盤。", "良時忽已周，獨往念前歡。", "好鳥始云至，衆芳亦未闌。", "遇物豈殊昔，慨傷自有端。"]'),
('fb044022-3be0-4f46-bd69-fb2843c29177','莊嚴精舍遊集','韋應物','唐','唐诗','tang','','[]','良遊因時暇，乃在西南隅。',96,'全唐诗/poet.tang.9000.json','["良遊因時暇，乃在西南隅。", "綠煙凝層城，豐草滿通衢。", "精舍何崇曠，煩跼一弘舒。", "架虹施廣蔭，構雲眺八區。", "既此塵境遠，忽聞幽鳥殊。", "新林泛景光，叢綠含露濡。", "永日亮難遂，平生少歡娛。", "誰能遽還歸，幸與高士俱。"]'),
('5a590925-4d9a-4908-8d97-a772dec87f2c','府舍月遊','韋應物','唐','唐诗','tang','','[]','官舍耿深夜，佳月喜同遊。',48,'全唐诗/poet.tang.9000.json','["官舍耿深夜，佳月喜同遊。", "橫河俱半落，泛露忽驚秋。", "散彩疎羣樹，分規澄素流。", "心期與浩景，蒼蒼殊未收。"]'),
('8158bd33-908f-495f-916f-b67989e941b1','任鄠令渼陂遊眺','韋應物','唐','唐诗','tang','','[]','野水灩長塘，煙花亂晴日。',48,'全唐诗/poet.tang.9000.json','["野水灩長塘，煙花亂晴日。", "氤氳綠樹多，蒼翠千山出。", "遊魚時可見，新荷尚未密。", "屢往心獨閑，恨無理人術。"]'),
('85ed84a6-08c4-4ae2-b737-90ef9f5ad1ea','西郊遊矚','韋應物','唐','唐诗','tang','','[]','東風散餘沍，陂水淡已綠。',48,'全唐诗/poet.tang.9000.json','["東風散餘沍，陂水淡已綠。", "煙芳何處尋，杳藹春山曲。", "新禽哢暄節，晴光泛嘉木。", "一與諸君遊，華觴忻見屬。"]'),
('2c63d844-6e67-4732-a686-cd05f7c31f3f','再遊西郊渡','韋應物','唐','唐诗','tang','','[]','水曲一追遊，遊人重懷戀。',48,'全唐诗/poet.tang.9000.json','["水曲一追遊，遊人重懷戀。", "嬋娟昨夜月，還向波中見。", "驚禽棲不定，流芳寒未徧。", "攜手更何時，佇看花似霰。"]'),
('af7dbdeb-86c3-4e10-84ec-717a2c02698a','月溪與幼遐君貺同遊','韋應物','唐','唐诗','tang','','[]','岸篠覆廻溪，廻溪曲如月。',60,'全唐诗/poet.tang.9000.json','["岸篠覆廻溪，廻溪曲如月。", "沈沈水容綠，寂寂流鶯歇。", "淺石方凌亂，遊禽時出沒。", "半雨夕陽霏，緣源雜花發。", "明晨重來此，同心應已闕。"]'),
('aa6c4f3e-fbd4-463c-99d7-9a4d046426d4','與幼遐君貺兄弟同遊白家竹潭','韋應物','唐','唐诗','tang','','[]','清賞非素期，偶遊方自得。',72,'全唐诗/poet.tang.9000.json','["清賞非素期，偶遊方自得。", "前登絕嶺險，下視深潭黑。", "密竹已成暮，歸雲殊未極。", "春鳥依谷暄，紫蘭含幽色。", "已將芳景遇，復款平生憶。", "終念一歡別，臨風還默默。"]'),
('086523dd-928a-45d2-a46c-5ca57d3a73d7','秋夕西齋與僧神靜遊','韋應物','唐','唐诗','tang','','[]','晨登西齋望，不覺至夕曛。',84,'全唐诗/poet.tang.9000.json','["晨登西齋望，不覺至夕曛。", "正當秋夏交，原野起煙氛。", "坐聽涼飆舉，華月稍披雲。", "漠漠山猶隱，灩灩川始分。", "物幽夜更殊，境靜興彌臻。", "息機非傲世，于時乏嘉聞。", "究空自爲理，況與釋子羣。"]'),
('f13be7dc-460e-46a2-b0a3-cd7a81586439','觀田家','韋應物','唐','唐诗','tang','','["\u7530\u56ed", "\u751f\u6d3b", "\u519c\u6c11"]','微雨衆卉新，一雷驚蟄始。',84,'全唐诗/poet.tang.9000.json','["微雨衆卉新，一雷驚蟄始。", "田家幾日閑，耕種從此起。", "丁壯俱在野，場圃亦就理。", "歸來景常晏，飲犢西澗水。", "飢劬不自苦，膏澤且爲喜。", "倉廩無宿儲，徭役猶未已。", "方慙不耕者，祿食出閭里。"]'),
('007f3468-83fc-4af8-b110-d2c4c1b90e10','園亭覽物','韋應物','唐','唐诗','tang','','[]','積雨時物變，夏綠滿園新。',36,'全唐诗/poet.tang.9000.json','["積雨時物變，夏綠滿園新。", "殘花已落實，高笋半成筠。", "守此幽棲地，自是忘機人。"]'),
('a49dfa1a-df22-4eec-908e-0af156ecc93c','觀灃水漲','韋應物','唐','唐诗','tang','','[]','夏雨萬壑湊，灃漲暮渾渾。',72,'全唐诗/poet.tang.9000.json','["夏雨萬壑湊，灃漲暮渾渾。", "草木盈川谷，澶漫一平吞。", "槎梗方瀰泛，濤沫亦洪翻。", "北來注涇渭，所過無安源。", "雲嶺同昏黑，觀望悸心魂。", "舟人空斂棹，風波正自奔。"]'),
('c813c27c-1464-4161-8f83-f53a7f6620df','陪王卿郎中遊南池','韋應物','唐','唐诗','tang','','[]','鵷鴻俱失侶，同爲此地遊。',72,'全唐诗/poet.tang.9000.json','["鵷鴻俱失侶，同爲此地遊。", "露浥荷花氣，風散柳園秋。", "煙草凝衰嶼，星漢泛歸流。", "林高初上月，塘深未轉舟。", "清言屢往復，華樽始獻酬。", "終憶秦川賞，端坐起離憂。"]'),
('248cc277-fcbe-42b9-92f1-70dbe1176dd9','南園陪王卿遊矚','韋應物','唐','唐诗','tang','','[]','形跡雖拘檢，世事澹無心。',72,'全唐诗/poet.tang.9000.json','["形跡雖拘檢，世事澹無心。", "郡中多山水，日夕聽幽禽。", "几閣文墨暇，園林春景深。", "雜花芳意散，綠池暮色沈。", "君子有高躅，相攜在幽尋。", "一酌何爲貴，可以寫沖襟。"]'),
('9ba16aca-23f9-4c2d-bb57-0fd331e2cc43','遊西山','韋應物','唐','唐诗','tang','','[]','時事方擾擾，幽賞獨悠悠。',48,'全唐诗/poet.tang.9000.json','["時事方擾擾，幽賞獨悠悠。", "弄泉朝涉澗，采石夜歸州。", "揮翰題蒼峭，下馬歷嵌丘。", "所愛唯山水，到此即淹留。"]'),
('3f6ae131-6af9-47b3-b28f-bb8b90b971c4','春遊南亭','韋應物','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u6000", "\u5199\u666f"]','川明氣已變，巖寒雲尚擁。',48,'全唐诗/poet.tang.9000.json','["川明氣已變，巖寒雲尚擁。", "南亭草心綠，春塘泉脈動。", "景煦聽禽響，雨餘看柳重。", "逍遙池館華，益媿專城寵。"]'),
('45b83b39-8af2-408f-b8a8-26094f83f8f3','再遊西山','韋應物','唐','唐诗','tang','','[]','南譙古山郡，信是高人居。',108,'全唐诗/poet.tang.9000.json','["南譙古山郡，信是高人居。", "自歎乏弘量，終朝親簿書。", "於時忽命駕，秋野正蕭疎。", "積逋誠待責，尋山亦有餘。", "測測石泉冷，曖曖煙谷虛。", "中有釋門子，種果結茅廬。", "出身厭名利，遇境即躊躇。", "守直雖多忤，視險方晏如。", "況將塵埃外，襟抱從此舒。"]'),
('df7f4d4c-df44-4218-9223-79b4a3ab8ccf','遊靈巖寺','韋應物','唐','唐诗','tang','','[]','始入松路永，獨忻山寺幽。',84,'全唐诗/poet.tang.9000.json','["始入松路永，獨忻山寺幽。", "不知臨絕檻，乃見西江流。", "吳岫分煙景，楚甸散林丘。", "方悟關塞眇，重軫故園愁。", "聞鐘戒歸騎，憩澗惜良遊。", "地疎泉谷狹，春深草木稠。", "茲焉賞未極，清景期杪秋。"]'),
('863ed1f7-902b-495a-85ef-4689dd9e6f8d','與盧陟同遊永定寺北池僧齋','韋應物','唐','唐诗','tang','','[]','密竹行已遠，子歸啼更深。',48,'全唐诗/poet.tang.9000.json','["密竹行已遠，子歸啼更深。", "綠池芳草氣，閑齋春樹陰。", "晴蝶飄蘭逕，遊蜂遶花心。", "不遇君攜手，誰復此幽尋。"]'),
('b92e84d3-e5c6-4585-bceb-a98938cd65cd','遊溪','韋應物','唐','唐诗','tang','','[]','野水煙鶴唳，楚天雲雨空。',48,'全唐诗/poet.tang.9000.json','["野水煙鶴唳，楚天雲雨空。", "翫舟清景晚，垂釣綠蒲中。", "落花飄旅衣，歸流澹清風。", "緣源不可極，遠樹但青葱。"]'),
('b3ef4353-90d7-4664-8c2d-5862c783dabb','遊開元精舍','韋應物','唐','唐诗','tang','','[]','夏衣始輕體，遊步愛僧居。',48,'全唐诗/poet.tang.9000.json','["夏衣始輕體，遊步愛僧居。", "果園新雨後，香臺照日初。", "綠陰生晝靜，孤花表春餘。", "符竹方爲累，形跡一來疎。"]'),
('61d273c9-0b05-4d91-8c24-e523cf331a38','襄武館遊眺','韋應物','唐','唐诗','tang','','[]','州民知禮讓，訟簡得遨遊。',96,'全唐诗/poet.tang.9000.json','["州民知禮讓，訟簡得遨遊。", "高亭憑古地，山川當暮秋。", "是時秔稻熟，西望盡田疇。", "仰恩慙政拙，念勞喜歲收。", "澹泊風景晏，繚繞雲樹幽。", "節往情惻惻，天高思悠悠。", "嘉賓幸雲集，芳罇始淹留。", "還希習池賞，聊以駐鳴騶。"]'),
('97d31218-4617-4343-8057-201b421dd53f','秋景詣瑯瑘精舍','韋應物','唐','唐诗','tang','','[]','屢訪塵外跡，未窮幽賞情。',72,'全唐诗/poet.tang.9000.json','["屢訪塵外跡，未窮幽賞情。", "高秋天景遠，始見山水清。", "上陟巖殿憩，暮看雲壑平。", "蒼茫寒色起，迢遞晚鐘鳴。", "意有清夜戀，身爲符守嬰。", "悟言緇衣子，蕭灑中林行。"]'),
('e51f05a4-83e7-4f94-afa5-656c1cbd39ae','同韓郎中閑庭南望秋景','韋應物','唐','唐诗','tang','','[]','朝下抱餘素，地高心本閑。',48,'全唐诗/poet.tang.9000.json','["朝下抱餘素，地高心本閑。", "如何趨府客，罷秩見秋山。", "疎樹共寒意，遊禽同暮還。", "因君悟清景，西望一開顏。"]'),
('6accabcd-5b81-4828-b8b3-20b9e41424ea','慈恩精舍南池作','韋應物','唐','唐诗','tang','','[]','清境豈云遠，炎氛忽如遺。',84,'全唐诗/poet.tang.9000.json','["清境豈云遠，炎氛忽如遺。", "重門布綠陰，菡萏滿廣池。", "石髮散清淺，林光動漣漪。", "緣崖摘紫房，扣檻集靈龜。", "浥浥餘露氣，馥馥幽襟披。", "積喧忻物曠，耽玩覺景馳。", "明晨復趨府，幽賞當反思。"]'),
('c642fc85-d3cf-4f39-a9ad-854e6da968f6','雨夜宿清都觀','韋應物','唐','唐诗','tang','','[]','靈飆動閶闔，微雨灑瑤林。',84,'全唐诗/poet.tang.9000.json','["靈飆動閶闔，微雨灑瑤林。", "復此新秋夜，高閣正沈沈。", "曠歲恨殊跡，茲夕一披襟。", "洞戶含涼氣，網軒構層陰。", "況自展良友，芳罇遂盈斟。", "適悟委前妄，清言怡道心。", "豈戀腰間綬，如彼籠中禽。"]'),
('f41e1521-e39e-4cfb-8367-c6450c8e765a','善福精舍秋夜遲諸君','韋應物','唐','唐诗','tang','','[]','廣庭獨閑步，夜色方湛然。',96,'全唐诗/poet.tang.9000.json','["廣庭獨閑步，夜色方湛然。", "丹閣已排雲，皓月更高懸。", "繁露降秋節，蒼林鬱芊芊。", "仰觀天氣涼，高詠古人篇。", "撫己亮無庸，結交賴羣賢。", "屬予翹思時，方子中夜眠。", "相去隔城闕，佳期屢徂遷。", "如何日夕待，見月三四圓。"]'),
('3e0e1d96-c249-47c4-b16d-4d91dd6e7cce','東郊','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6625\u5929", "\u751f\u6d3b"]','吏舍跼終年，出郊曠清曙。',72,'全唐诗/poet.tang.9000.json','["吏舍跼終年，出郊曠清曙。", "楊柳散和風，青山澹吾慮。", "依叢適自憩，緣澗還復去。", "微雨靄芳原，春鳩鳴何處？", "樂幽心屢止，遵事跡猶遽。", "終罷斯結廬，慕陶真可庶。"]'),
('0b1d232d-0a36-4825-bb31-60de152516df','秋郊作','韋應物','唐','唐诗','tang','','[]','清露澄境遠，旭日照林初。',48,'全唐诗/poet.tang.9000.json','["清露澄境遠，旭日照林初。", "一望秋山淨，蕭條形迹疎。", "登原忻時稼，采菊行故墟。", "方願沮溺耦，淡泊守田廬。"]'),
('dd40c02c-fb97-4ef0-86a5-6139361f4e10','行寬禪師院','韋應物','唐','唐诗','tang','','[]','北望極長廊，斜扉映藂竹。',36,'全唐诗/poet.tang.9000.json','["北望極長廊，斜扉映藂竹。", "亭午一來尋，院幽僧亦獨。", "唯聞山鳥啼，愛此林下宿。"]'),
('c2358b8a-e1d3-43a6-bc2d-539361208678','神靜師院','韋應物','唐','唐诗','tang','','[]','青苔幽巷徧，新林露氣微。',48,'全唐诗/poet.tang.9000.json','["青苔幽巷徧，新林露氣微。", "經聲在深竹，高齋獨掩扉。", "憩樹愛嵐嶺，聽禽悅朝暉。", "方耽靜中趣，自與塵事違。"]'),
('f3fe373c-e5d3-4e7e-a9ba-4afa919be279','精舍納涼','韋應物','唐','唐诗','tang','','[]','山景寂已晦，野寺變蒼蒼。',48,'全唐诗/poet.tang.9000.json','["山景寂已晦，野寺變蒼蒼。", "夕風吹高殿，露葉散林光。", "清鐘始戒夜，幽禽尚歸翔。", "誰復掩扉臥，不詠南軒涼。"]'),
('41a75f78-8df0-4416-be59-ac16227d7366','藍嶺精舍','韋應物','唐','唐诗','tang','','[]','石壁精舍高，排雲聊直上。',84,'全唐诗/poet.tang.9000.json','["石壁精舍高，排雲聊直上。", "佳遊愜始願，忘險得前賞。", "崖傾景方晦，谷轉川如掌。", "綠林含蕭條，飛閣起弘敞。", "道人上方至，清夜還獨往。", "日落羣山陰，天秋百泉響。", "所嗟累已成，安得長偃仰。"]'),
('5e9a5fb6-7b01-42a0-a191-f1238e52ae76','道晏寺主院','韋應物','唐','唐诗','tang','','[]','北鄰有幽竹，潛筠穿我廬。',48,'全唐诗/poet.tang.9000.json','["北鄰有幽竹，潛筠穿我廬。", "往來地已密，心樂道者居。", "殘花廻往節，輕條蔭夏初。", "聞鐘北牕起，嘯傲永日餘。"]'),
('22b19f0d-9cb0-48ba-b19b-0f0772251744','義演法師西齋','韋應物','唐','唐诗','tang','','[]','結茅臨絕岸，隔水聞清磬。',48,'全唐诗/poet.tang.9000.json','["結茅臨絕岸，隔水聞清磬。", "山水曠蕭條，登臨散情性。", "稍指緣原騎，還尋汲澗逕。", "長嘯倚亭樹，悵然川光暝。"]'),
('9d03dbb9-f762-4b92-b8af-a8f0edfdeb54','澄秀上座院','韋應物','唐','唐诗','tang','','[]','繚繞西南隅，鳥聲轉幽靜。',36,'全唐诗/poet.tang.9000.json','["繚繞西南隅，鳥聲轉幽靜。", "秀公今不在，獨禮高僧影。", "林下器未收，何人適煮茗。"]'),
('e75b6194-8ba8-4435-9699-50bfce30ee44','至西峰蘭若受田婦饋','韋應物','唐','唐诗','tang','','[]','攀崖復緣澗，遂造幽人居。',72,'全唐诗/poet.tang.9000.json','["攀崖復緣澗，遂造幽人居。", "鳥鳴泉谷暖，土起萌甲舒。", "聊登石樓憩，下翫潭中魚。", "田婦有嘉獻，潑撒新歲餘。", "常怪投錢飲，事與賢達疎。", "今我何爲答，鰥寡欲焉如。"]'),
('10d289c3-96db-4323-8456-b25f5899746d','曇智禪師院','韋應物','唐','唐诗','tang','','[]','高年不復出，門徑衆草生。',48,'全唐诗/poet.tang.9000.json','["高年不復出，門徑衆草生。", "時夏方新雨，果藥發餘榮。", "疎澹下林景，流暮幽禽情。", "身名兩俱遣，獨此野寺行。"]'),
('1904b716-cabb-4e23-b9a0-0d2e792364e6','起度律師同居東齋院','韋應物','唐','唐诗','tang','','[]','釋子喜相偶，幽林俱避喧。',48,'全唐诗/poet.tang.9000.json','["釋子喜相偶，幽林俱避喧。", "安居同僧夏，清夜諷道言。", "對閣景恆晏，步庭陰始繁。", "逍遙無一事，松風入南軒。"]'),
('fe72db9a-b75f-423a-a43f-fa94b600b921','遊瑯瑘山寺','韋應物','唐','唐诗','tang','','[]','受命恤人隱，茲遊久未遑。',108,'全唐诗/poet.tang.9000.json','["受命恤人隱，茲遊久未遑。", "鳴騶響幽澗，前旌耀崇岡。", "青冥臺砌寒，綠褥草木香。", "填壑躋花界，疊石構雲房。", "經製隨巖轉，繚繞豈定方。", "新泉泄陰壁，高蘿蔭綠塘。", "攀林一栖止，飲水得清涼。", "物累誠可遣，疲甿終未忘。", "還歸坐郡閣，但見山蒼蒼。"]'),
('25972724-9ff7-431e-8f18-b3441b737eaa','同越瑯瑘山','韋應物','唐','唐诗','tang','','[]','石門有雪無形跡，松壑凝烟滿衆香。',32,'全唐诗/poet.tang.9000.json','["石門有雪無形跡，松壑凝烟滿衆香。", "餘食施庭寒鳥下，破衣挂樹老僧亡。"]'),
('3d13ec4e-3205-490d-b8a6-26ef3624ff45','詣西山深師','韋應物','唐','唐诗','tang','','[]','曹溪舊弟子，何緣住此山。',48,'全唐诗/poet.tang.9000.json','["曹溪舊弟子，何緣住此山。", "世有征戰事，心將流水閑。", "埽林驅虎出，宴坐一林間。", "藩守寧爲重，擁騎造雲關。"]'),
('f821abbf-1288-4fa9-923e-8a6a8a4b31aa','尋簡寂觀瀑布','韋應物','唐','唐诗','tang','','[]','躡石欹危過急澗，攀崖迢遞弄懸泉。',32,'全唐诗/poet.tang.9000.json','["躡石欹危過急澗，攀崖迢遞弄懸泉。", "猶將虎竹爲身累，欲付歸人絕世緣。"]'),
('3e0297a3-575e-44a5-8c2a-01c3753092de','簡寂觀西澗瀑布下作','韋應物','唐','唐诗','tang','','[]','淙流絕壁散，虛煙翠澗深。',72,'全唐诗/poet.tang.9000.json','["淙流絕壁散，虛煙翠澗深。", "叢際松風起，飄來灑塵襟。", "窺蘿翫猿鳥，解組傲雲林。", "茶果邀真侶，觴酌洽同心。", "曠歲懷茲賞，行春始重尋。", "聊將橫吹笛，一寫山水音。"]'),
('1239635e-cd7a-4632-9904-3ea28507fce1','遊南齋','韋應物','唐','唐诗','tang','','[]','池上鳴佳禽，僧齋日幽寂。',48,'全唐诗/poet.tang.9000.json','["池上鳴佳禽，僧齋日幽寂。", "高林晚露清，紅藥無人摘。", "春水不生煙，荒岡筠翳石。", "不應朝夕遊，良爲蹉跎客。"]'),
('0bca204e-f51f-41b6-8684-6d715a5ddbab','南園','韋應物','唐','唐诗','tang','','[]','清露夏天曉，荒園野氣通。',48,'全唐诗/poet.tang.9000.json','["清露夏天曉，荒園野氣通。", "水禽遙泛雪，池蓮迥披紅。", "幽林詎知暑，環舟似不窮。", "頓灑塵喧意，長嘯滿襟風。"]'),
('3fe489c9-2e12-4a1f-b78d-ea48f44a958d','西亭','韋應物','唐','唐诗','tang','','[]','亭宇麗朝景，簾牖散暄風。',48,'全唐诗/poet.tang.9000.json','["亭宇麗朝景，簾牖散暄風。", "小山初構石，珍樹正然紅。", "弱藤已扶樹，幽蘭欲成叢。", "芳心幸如此，佳人時不同。"]'),
('0298a038-c7e0-45b0-8cad-1689bb3355fe','夏景園廬','韋應物','唐','唐诗','tang','','[]','羣木晝陰靜，北牕涼氣多。',48,'全唐诗/poet.tang.9000.json','["羣木晝陰靜，北牕涼氣多。", "閑居逾時節，夏雲已嵯峨。", "搴葉愛繁綠，緣澗弄驚波。", "豈爲論夙志，對此青山阿。"]'),
('c44cf36d-2166-4118-b8cc-c9c7b15dedd4','夏至避暑北池','韋應物','唐','唐诗','tang','','[]','晝晷已云極，宵漏自此長。',96,'全唐诗/poet.tang.9000.json','["晝晷已云極，宵漏自此長。", "未及施政教，所憂變炎涼。", "公門日多暇，是月農稍忙。", "高居念田里，苦熱安可當。", "亭午息羣物，獨遊愛方塘。", "門閉陰寂寂，城高樹蒼蒼。", "綠筠尚含粉，圓荷始散芳。", "於焉灑煩抱，可以對華觴。"]'),
('9f4b3d1f-d4e5-4d55-bef4-ea5694503cae','題從姪成緒西林精舍書齋','韋應物','唐','唐诗','tang','','[]','棲身齒多暮，息心君獨少。',120,'全唐诗/poet.tang.9000.json','["棲身齒多暮，息心君獨少。", "慕謝始精文，依僧欲觀妙。", "冽泉前堦注，清池北窗照。", "果藥雜芬敷，松筠疎蒨峭。", "屢躋幽人境，每肆芳辰眺。", "採栗玄猿窟，擷芝丹林嶠。", "紵衣豈寒禦，蔬食非飢療。", "雖甘巷北單，豈塞青紫耀。", "郡有優賢榻，朝編貢士詔。", "欲同朱輪載，勿憚移文誚。"]'),
('eb529fe1-c20a-4fd8-b1f8-b6bbc0fec755','題鄭弘憲侍御遺愛草堂','韋應物','唐','唐诗','tang','','[]','居士近依僧，青山結茅屋。',48,'全唐诗/poet.tang.9000.json','["居士近依僧，青山結茅屋。", "疎松映嵐晚，春池含苔綠。", "繁華冒陽嶺，新禽響幽谷。", "長嘯攀喬林，慕茲高世躅。"]'),
('c6a0d747-9e56-46cb-90b1-06573d212f2d','同元錫題瑯瑘寺','韋應物','唐','唐诗','tang','','[]','適從郡邑喧，又茲三伏熱。',96,'全唐诗/poet.tang.9000.json','["適從郡邑喧，又茲三伏熱。", "山中清景多，石罅寒泉潔。", "花香天界事，松竹人間別。", "殿分嵐嶺明，磴臨懸壑絕。", "昏旭窮陟降，幽顯盡披閱。", "嶔駭風雨區，寒知龍蛇穴。", "情虛澹泊生，境寂塵妄滅。", "經世豈非道，無爲厭車轍。"]'),
('4cb57be5-3ccc-4c2e-98f8-29706f8e8890','題鄭拾遺草堂','韋應物','唐','唐诗','tang','','[]','借地結茅棟，橫竹掛朝衣。',48,'全唐诗/poet.tang.9000.json','["借地結茅棟，橫竹掛朝衣。", "秋園雨中綠，幽居塵事違。", "陰井夕蟲亂，高林霜果稀。", "子有白雲意，構此想巖扉。"]'),
('32837f33-ad10-4bcb-b647-891ed0870c8a','詠玉','韋應物','唐','唐诗','tang','','[]','乾坤有精物，至寶無文章。',24,'全唐诗/poet.tang.9000.json','["乾坤有精物，至寶無文章。", "雕琢爲世器，真性一朝傷。"]'),
('1c28cdd9-7ee2-49c1-bbc9-6ada013ae310','詠露珠','韋應物','唐','唐诗','tang','','[]','秋荷一滴露，清夜墜玄天。',24,'全唐诗/poet.tang.9000.json','["秋荷一滴露，清夜墜玄天。", "將來玉盤上，不定始知圓。"]'),
('3280eb8f-c126-4b93-bab0-8cec8ecb76cb','詠水精','韋應物','唐','唐诗','tang','','[]','映物隨顏色，含空無表裏。',24,'全唐诗/poet.tang.9000.json','["映物隨顏色，含空無表裏。", "持來向明月，的皪愁成水。"]'),
('a67197b8-91d0-49bc-b9f6-d23f6100a6cc','詠珊瑚','韋應物','唐','唐诗','tang','','[]','絳樹無花葉，非石亦非瓊。',24,'全唐诗/poet.tang.9000.json','["絳樹無花葉，非石亦非瓊。", "世人何處得，蓬萊石上生。"]'),
('ac0d8793-4a20-431c-a7bb-739e17489286','詠瑠璃','韋應物','唐','唐诗','tang','','[]','有色同寒冰，無物隔纖塵。',24,'全唐诗/poet.tang.9000.json','["有色同寒冰，無物隔纖塵。", "象筵看不見，堪將對玉人。"]'),
('026b233d-4b5a-44ba-adfd-b1fe7709f78f','詠琥珀','韋應物','唐','唐诗','tang','','[]','曾爲老茯神，本是寒松液。',24,'全唐诗/poet.tang.9000.json','["曾爲老茯神，本是寒松液。", "蚊蚋落其中，千年猶可覿。"]'),
('8d29beed-bbb0-445a-9158-dfbef0ff65f6','詠曉','韋應物','唐','唐诗','tang','','[]','軍中始吹角，城上河初落。',24,'全唐诗/poet.tang.9000.json','["軍中始吹角，城上河初落。", "深沈猶隱帷，晃朗先分閣。"]'),
('19ddf4a4-2fc0-45a6-baea-49c76fdbf21f','詠夜','韋應物','唐','唐诗','tang','','[]','明從何處去，暗從何處來。',24,'全唐诗/poet.tang.9000.json','["明從何處去，暗從何處來。", "但覺年年老，半是此中催。"]'),
('0a38ea35-f915-4eaf-ab3e-67c933b1b486','詠聲','韋應物','唐','唐诗','tang','','[]','萬物自生聽，太空恆寂寥。',24,'全唐诗/poet.tang.9000.json','["萬物自生聽，太空恆寂寥。", "還從靜中起，却向靜中消。"]'),
('f888bd99-3f5e-4554-8fbf-23e41e4ae7d8','任洛陽丞請告一首','韋應物','唐','唐诗','tang','','[]','方鑿不受圓，直木不爲輪。',108,'全唐诗/poet.tang.9000.json','["方鑿不受圓，直木不爲輪。", "揆材各有用，反性生苦辛。", "折腰非吾事，飲水非吾貧。", "休告臥空館，養病絕囂塵。", "遊魚自成族，野鳥亦有羣。", "家園杜陵下，千歲心氛氳。", "天晴嵩山高，雪後河洛春。", "喬木猶未芳，百草日已新。", "著書復何爲，當去東臯耘。"]'),
('16bddda4-c09b-4054-8980-e38436d46645','縣齋','韋應物','唐','唐诗','tang','','[]','仲春時景好，草木漸舒榮。',72,'全唐诗/poet.tang.9000.json','["仲春時景好，草木漸舒榮。", "公門且無事，微雨園林清。", "決決水泉動，忻忻衆鳥鳴。", "閑齋始延矚，東作興庶甿。", "既事翫文墨，抱沖披道經。", "於焉日淡泊，徒使芳尊盈。"]'),
('82bad0de-9226-492b-9280-c7cd9c2e8b14','晚出府舍與獨孤兵曹令狐士曹南尋朱雀街歸里第','韋應物','唐','唐诗','tang','','[]','分曹幸同簡，聯騎方愜素。',72,'全唐诗/poet.tang.9000.json','["分曹幸同簡，聯騎方愜素。", "還從廣陌歸，不覺青山暮。", "翻翻鳥未沒，杳杳鐘猶度。", "尋草遠無人，望山多枉路。", "聊參世士跡，嘗得靜者顧。", "出入雖見牽，忘身緣所晤。"]'),
('c887f524-fb07-44ef-a726-451575abd917','休暇東齋','韋應物','唐','唐诗','tang','','[]','由來束帶士，請謁無朝暮。',84,'全唐诗/poet.tang.9000.json','["由來束帶士，請謁無朝暮。", "公暇及私身，何能獨閑步。", "摘葉愛芳在，捫竹憐粉汚。", "岸幘偃東齋，夏天清曉露。", "懷仙閱真誥，貽友題幽素。", "榮達頗知疎，恬然自成度。", "綠苔日已滿，幽寂誰來顧。"]'),
('8f98be4f-fd25-4757-ba84-9e7f5f30d0fc','夜直省中','韋應物','唐','唐诗','tang','','[]','河漢有秋意，南宮生早涼。',48,'全唐诗/poet.tang.9000.json','["河漢有秋意，南宮生早涼。", "玉漏殊杳杳，雲闕更蒼蒼。", "華燈發新燄，輕煙浮夕香。", "顧跡知爲忝，束帶愧周行。"]'),
('4c635d5a-3cb8-49d4-9ab1-1f839cad2b05','郡內閑居','韋應物','唐','唐诗','tang','','["\u5e90\u5c71"]','棲息絕塵侶，孱鈍得自怡。',72,'全唐诗/poet.tang.9000.json','["棲息絕塵侶，孱鈍得自怡。", "腰懸竹使符，心與廬山緇。", "永日一酣寢，起坐兀無思。", "長廊獨看雨，衆藥發幽姿。", "今夕已云罷，明晨復如斯。", "何事能爲累，寵辱豈要辭。"]'),
('ecc776cd-93a9-4bd4-9b81-4335f7702f6f','燕居即事','韋應物','唐','唐诗','tang','','[]','蕭條竹林院，風雨叢蘭折。',48,'全唐诗/poet.tang.9000.json','["蕭條竹林院，風雨叢蘭折。", "幽鳥林上啼，青苔人跡絕。", "燕居日已永，夏木紛成結。", "几閣積羣書，時來北窗閱。"]'),
('ca3440c9-892b-4df3-8fad-6aaf987d1f94','幽居','韋應物','唐','唐诗','tang','','[]','貴賤雖異等，出門皆有營。',72,'全唐诗/poet.tang.9000.json','["貴賤雖異等，出門皆有營。", "獨無外物牽，遂此幽居情。", "微雨夜來過，不知春草生。", "青山忽已曙，鳥雀繞舍鳴。", "時與道人偶，或隨樵者行。", "自當安蹇劣，誰謂薄世榮。"]'),
('8991e2c7-d6b0-473c-9ccf-3394d16a4a6e','野居書情','韋應物','唐','唐诗','tang','','[]','世事日可見，身名良蹉跎。',24,'全唐诗/poet.tang.9000.json','["世事日可見，身名良蹉跎。", "尚瞻白雲嶺，聊作負薪歌。"]'),
('e063821c-3ee7-4aeb-b11d-06ca7dd96277','郊居言志','韋應物','唐','唐诗','tang','','[]','負暄衡門下，望雲歸遠山。',96,'全唐诗/poet.tang.9000.json','["負暄衡門下，望雲歸遠山。", "但要尊中物，餘事豈相關。", "交無是非責，且得任疎頑。", "日夕臨清澗，逍遙思慮閑。", "出去唯空屋，弊簀委窗間。", "何異林棲鳥，戀此復來還。", "世榮斯獨已，頹志亦何攀。", "唯當歲豐熟，閭里一歡顏。"]'),
('bb73d925-bf57-4697-9fd3-86cbb24e3da9','夏景端居即事','韋應物','唐','唐诗','tang','','[]','北齋有涼氣，嘉樹對層城。',48,'全唐诗/poet.tang.9000.json','["北齋有涼氣，嘉樹對層城。", "重門永日掩，清池夏雲生。", "遇此庭訟簡，始聞蟬初鳴。", "逾懷故園愴，默默以緘情。"]'),
('25b3c434-d88b-4b82-8700-b23c20d062ee','始至郡','韋應物','唐','唐诗','tang','','[]','湓城古雄郡，橫江千里馳。',120,'全唐诗/poet.tang.9000.json','["湓城古雄郡，橫江千里馳。", "高樹上迢遞，峻堞繞欹危。", "井邑煙火晚，郊原草樹滋。", "洪流蕩北阯，崇嶺鬱南圻。", "斯民本樂生，逃逝竟何爲。", "旱歲屬荒歉，舊逋積如坻。", "到郡方逾月，終朝理亂絲。", "賓朋未及讌，簡牘已云疲。", "昔賢播高風，得守愧無施。", "豈待干戈戢，且願撫惸嫠。"]'),
('9cabb29e-c387-4968-8062-7e1a9b363cf6','郡中西齋','韋應物','唐','唐诗','tang','','[]','似與塵境絕，蕭條齋舍秋。',48,'全唐诗/poet.tang.9000.json','["似與塵境絕，蕭條齋舍秋。", "寒花獨經雨，山禽時到州。", "清觴養真氣，玉書示道流。", "豈將符守戀，幸已棲心幽。"]'),
('50958d41-0e54-47f7-a739-3d04c7e0badd','新理西齋','韋應物','唐','唐诗','tang','','[]','方將甿訟理，久翳西齋居。',84,'全唐诗/poet.tang.9000.json','["方將甿訟理，久翳西齋居。", "草木無行次，閑暇一芟除。", "春陽土脉起，膏澤發生初。", "養條刊朽枿，護藥鋤穢蕪。", "稍稍覺林聳，歷歷忻竹疎。", "始見庭宇曠，頓令煩抱舒。", "茲焉即可愛，何必是吾廬。"]'),
('49f30a36-14b1-4321-8ccc-67966a670d38','曉坐西齋','韋應物','唐','唐诗','tang','','[]','鼕鼕城鼓動，稍稍林鵶去。',60,'全唐诗/poet.tang.9000.json','["鼕鼕城鼓動，稍稍林鵶去。", "柳意不勝春，巖光已知曙。", "寢齋有單祶，靈藥爲朝茹。", "盥漱忻景清，焚香澄神慮。", "公門自常事，道心寧易處。"]'),
('dcd6b747-8c65-4538-b55a-68365c12c5b1','郡齋臥疾絕句','韋應物','唐','唐诗','tang','','[]','香爐宿火滅，蘭燈宵影微。',24,'全唐诗/poet.tang.9000.json','["香爐宿火滅，蘭燈宵影微。", "秋齋獨臥病，誰與覆寒衣。"]'),
('92a8c771-a237-4c5c-98fb-967493203d8c','寓居永定精舍','韋應物','唐','唐诗','tang','','[]','政拙忻罷守，閑居初理生。',72,'全唐诗/poet.tang.9000.json','["政拙忻罷守，閑居初理生。", "家貧何由往，夢想在京城。", "野寺霜露月，農興羈旅情。", "聊租二頃田，方課子弟耕。", "眼暗文字廢，身閑道心精。", "即與人羣遠，豈謂是非嬰。"]'),
('a357da09-a6e3-4dd0-aa52-e4226e1e263a','永定寺喜辟強夜至','韋應物','唐','唐诗','tang','','[]','子有新歲慶，獨此苦寒歸。',48,'全唐诗/poet.tang.9000.json','["子有新歲慶，獨此苦寒歸。", "夜叩竹林寺，山行雪滿衣。", "深爐正燃火，空齋共掩扉。", "還將一尊對，無言百事違。"]'),
('30baebaf-f18c-403f-93c1-225270bc30a4','野居','韋應物','唐','唐诗','tang','','[]','結髮屢辭秩，立身本疎慢。',72,'全唐诗/poet.tang.9000.json','["結髮屢辭秩，立身本疎慢。", "今得罷守歸，幸無世欲患。", "棲止且偏僻，嬉遊無早晏。", "逐兔上坡岡，捕魚緣赤澗。", "高歌意氣在，貰酒貧居慣。", "時啓北窗扉，豈將文墨間。"]'),
('b7edbb6e-06a3-431b-91e5-5961bfb76ac4','同襃子秋齋獨宿','韋應物','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','山月皎如燭，風霜時動竹。',24,'全唐诗/poet.tang.9000.json','["山月皎如燭，風霜時動竹。", "夜半鳥驚栖，窗間人獨宿。"]'),
('7c0858f4-ce2a-4b15-bbe3-409613818c98','餌黃精','韋應物','唐','唐诗','tang','','[]','靈藥出西山，服食採其根。',72,'全唐诗/poet.tang.9000.json','["靈藥出西山，服食採其根。", "九蒸換凡骨，經著上世言。", "候火起中夜，馨香滿南軒。", "齋居感衆靈，藥術啓妙門。", "自懷物外心，豈與俗士論。", "終期脫印綬，永與天壤存。"]'),
('a295e311-8d1a-42c7-ab13-e4a0528c14a1','昭國里第聽元老師彈琴','韋應物','唐','唐诗','tang','','[]','竹林高宇霜露清，朱絲玉徽多故情。',32,'全唐诗/poet.tang.9000.json','["竹林高宇霜露清，朱絲玉徽多故情。", "暗識啼烏與別鶴，秪緣中有斷腸聲。"]'),
('3d40a304-5843-4354-b487-bc3b59546be4','野次聽元昌奏橫吹','韋應物','唐','唐诗','tang','','[]','立馬蓮塘吹橫笛，微風動柳生水波。',32,'全唐诗/poet.tang.9000.json','["立馬蓮塘吹橫笛，微風動柳生水波。", "北人聽罷淚將落，南朝曲中怨更多。"]'),
('05984348-1969-42a8-9bbd-d6290dcd3faa','樓中閱清管','韋應物','唐','唐诗','tang','','[]','山陽遺韻在，林端橫吹驚。',48,'全唐诗/poet.tang.9000.json','["山陽遺韻在，林端橫吹驚。", "響迥憑高閣，曲怨繞秋城。", "淅瀝危葉振，蕭瑟涼氣生。", "始遇茲管賞，已懷故園情。"]'),
('deb47270-36fd-46b0-a155-9575a6e6cbef','寒食','韋應物','唐','唐诗','tang','','[]','晴明寒食好，春園百卉開。',48,'全唐诗/poet.tang.9000.json','["晴明寒食好，春園百卉開。", "綵繩拂花去，輕毬度閣來。", "長歌送落日，緩吹逐殘杯。", "非關無燭罷，良爲羈思催。"]'),
('6c406f7c-f09f-4904-b008-ab635a437edc','七夕','韋應物','唐','唐诗','tang','','[]','人世拘形跡，別去間山川。',48,'全唐诗/poet.tang.9000.json','["人世拘形跡，別去間山川。", "豈意靈仙偶，相望亦彌年。", "夕衣清露濕，晨駕秋風前。", "臨歡定不住，當爲何所牽。"]'),
('e08720d2-988a-410f-8bb1-517c5d45ba8e','九日','韋應物','唐','唐诗','tang','','[]','今朝把酒復惆悵，憶在杜陵田舍時。',32,'全唐诗/poet.tang.9000.json','["今朝把酒復惆悵，憶在杜陵田舍時。", "明年九日知何處，世難還家未有期。"]'),
('126db7d2-e538-4d47-8598-e4ba1846a5e7','秋夜','韋應物','唐','唐诗','tang','','[]','暗窗涼葉動，秋天寢席單。',48,'全唐诗/poet.tang.9000.json','["暗窗涼葉動，秋天寢席單。", "憂人半夜起，明月在林端。", "一與清景遇，每憶平生歡。", "如何方惻愴，披衣露更寒。"]'),
('e727d000-c6e9-4958-83cf-d00f5b5d007f','秋夜一絕','韋應物','唐','唐诗','tang','','[]','高閣漸凝露，涼葉稍飄闈。',24,'全唐诗/poet.tang.9000.json','["高閣漸凝露，涼葉稍飄闈。", "憶在南宮直，夜長鐘漏稀。"]'),
('70fb7b8b-138f-4840-8d35-ea1c51de8661','滁城對雪','韋應物','唐','唐诗','tang','','[]','晨起滿闈雪，憶朝閶闔時。',60,'全唐诗/poet.tang.9000.json','["晨起滿闈雪，憶朝閶闔時。", "玉座分曙早，金爐上煙遲。", "飄散雲臺下，凌亂桂樹姿。", "廁跡鴛鷺末，蹈舞豐年期。", "今朝覆山郡，寂寥復何爲。"]'),
('7b06600c-dbed-4c17-8c33-4d1311fc18e5','雪中','韋應物','唐','唐诗','tang','','[]','空堂歲已晏，密室獨安眠。',48,'全唐诗/poet.tang.9000.json','["空堂歲已晏，密室獨安眠。", "厭篠夜偏積，覆閣曉逾妍。", "連山暗古郡，驚風散一川。", "此時騎馬出，忽省京華年。"]'),
('ce495d54-3376-4a50-8bdc-fcdb1ddf7ff3','詠春雪','韋應物','唐','唐诗','tang','','[]','裴回輕雪意，似惜豔陽時。',24,'全唐诗/poet.tang.9000.json','["裴回輕雪意，似惜豔陽時。", "不悟風花冷，翻令梅柳遲。"]'),
('c6214b9e-aaff-4901-8e33-9ffabe1d18c9','對春雪','韋應物','唐','唐诗','tang','','[]','蕭屑杉松聲，寂寥寒夜慮。',48,'全唐诗/poet.tang.9000.json','["蕭屑杉松聲，寂寥寒夜慮。", "州貧人吏稀，雪滿山城曙。", "春塘看幽谷，栖禽愁未去。", "開闈正亂流，寧辨花枝處。"]'),
('63a73bbf-80a8-4f7d-8a31-374cabf68739','對殘燈','韋應物','唐','唐诗','tang','','[]','獨照碧窗久，欲隨寒燼滅。',24,'全唐诗/poet.tang.9000.json','["獨照碧窗久，欲隨寒燼滅。", "幽人將遽眠，解帶翻成結。"]'),
('e0f1ddfc-486d-4bdd-8348-abf7def5f66b','對芳尊','韋應物','唐','唐诗','tang','','[]','對芳尊，醉來百事何足論。',30,'全唐诗/poet.tang.9000.json','["對芳尊，醉來百事何足論。", "遙見青山始一醒，欲著接[䍦]還復昏。"]'),
('b85cc556-4a81-4703-b084-0e165c508679','夜對流螢作','韋應物','唐','唐诗','tang','','[]','月暗竹亭幽，螢光拂席流。',48,'全唐诗/poet.tang.9000.json','["月暗竹亭幽，螢光拂席流。", "還思故園夜，更度一年秋。", "自愜觀書興，何慙秉燭遊。", "府中徒冉冉，明發好歸休。"]'),
('df7f8307-25e1-4af1-ab07-30304bec7c89','對新篁','韋應物','唐','唐诗','tang','','[]','新綠苞初解，嫩氣筍猶香。',36,'全唐诗/poet.tang.9000.json','["新綠苞初解，嫩氣筍猶香。", "含露漸舒葉，抽叢稍自長。", "清晨止亭下，獨愛此幽篁。"]'),
('8aec5dce-dcbc-453e-8a75-cf99e538e220','夏花明','韋應物','唐','唐诗','tang','','["\u590f\u5929", "\u5199\u82b1", "\u82b1"]','夏條綠已密，朱蕚綴明鮮。',48,'全唐诗/poet.tang.9000.json','["夏條綠已密，朱蕚綴明鮮。", "炎炎日正午，灼灼火俱燃。", "翻風適自亂，照水復成妍。", "歸視窗間字，熒煌滿眼前。"]'),
('25829246-2d17-47b3-a5d9-d65c2229e9b7','對萱草','韋應物','唐','唐诗','tang','','[]','何人樹萱草，對此郡齋幽。',48,'全唐诗/poet.tang.9000.json','["何人樹萱草，對此郡齋幽。", "本是忘憂物，今夕重生憂。", "叢疎露始滴，芳餘蝶尚留。", "還思杜陵圃，離披風雨秋。"]'),
('14ffd597-66f5-4b0a-ad5f-8c0c78fd3b90','見紫荆花','韋應物','唐','唐诗','tang','','[]','雜英紛已積，含芳獨暮春。',24,'全唐诗/poet.tang.9000.json','["雜英紛已積，含芳獨暮春。", "還如故園樹，忽憶故園人。"]'),
('a407b18e-4101-475c-9c5b-1bb11966de48','翫螢火','韋應物','唐','唐诗','tang','','[]','時節變衰草，物色近新秋。',24,'全唐诗/poet.tang.9000.json','["時節變衰草，物色近新秋。", "度月影纔斂，繞竹光復流。"]'),
('a96176eb-6c69-48b0-a89f-afc99b4d7f27','對雜花','韋應物','唐','唐诗','tang','','[]','朝紅爭景新，夕素含露翻。',48,'全唐诗/poet.tang.9000.json','["朝紅爭景新，夕素含露翻。", "妍姿如有意，流芳復滿園。", "單棲守遠郡，永日掩重門。", "不與花爲偶，終遣與誰言。"]'),
('78a79604-a632-4896-9e5c-02d7ca200b03','種藥','韋應物','唐','唐诗','tang','','[]','好讀神農書，多識藥草名。',84,'全唐诗/poet.tang.9000.json','["好讀神農書，多識藥草名。", "持縑購山客，移蒔羅衆英。", "不改幽澗色，宛如此地生。", "汲井既蒙澤，插楥亦扶傾。", "陰穎夕房斂，陽條夏花明。", "悅翫從茲始，日夕繞庭行。", "州民自寡訟，養閑非政成。"]'),
('a2ed61bf-cd93-4c2c-85b2-0f279429e616','西澗種柳','韋應物','唐','唐诗','tang','','[]','宰邑乖所願，僶俛愧昔人。',72,'全唐诗/poet.tang.9000.json','["宰邑乖所願，僶俛愧昔人。", "聊將休暇日，種柳西澗濱。", "置鍤息微倦，臨流睇歸雲。", "封壤自人力，生條在陽春。", "成陰豈自取，爲茂屬佗辰。", "延詠留佳賞，山水變夕曛。"]'),
('87551cc4-0323-44a0-a659-830299c47265','種瓜','韋應物','唐','唐诗','tang','','[]','率性方鹵莽，理生尤自疎。',72,'全唐诗/poet.tang.9000.json','["率性方鹵莽，理生尤自疎。", "今年學種瓜，園圃多荒蕪。", "衆草同雨露，新苗獨翳如。", "直以春窘迫，過時不得鋤。", "田家笑枉費，日夕轉空虛。", "信非吾儕事，且讀古人書。"]'),
('ccb95bc6-fe19-4fa6-a604-fd880a5ebab8','喜園中茶生','韋應物','唐','唐诗','tang','','[]','潔性不可汙，爲飲滌塵煩。',48,'全唐诗/poet.tang.9000.json','["潔性不可汙，爲飲滌塵煩。", "此物信靈味，本自出山原。", "聊因理郡餘，率爾植荒園。", "喜隨衆草長，得與幽人言。"]'),
('c780ea99-ebfe-492b-b8ea-7fc3cff4a8f1','移海榴','韋應物','唐','唐诗','tang','','[]','葉有苦寒色，山中霜霰多。',24,'全唐诗/poet.tang.9000.json','["葉有苦寒色，山中霜霰多。", "雖此蒙陽景，移根意如何。"]'),
('a02bab3f-dba5-4886-9eec-158c2f4942c0','郡齋移杉','韋應物','唐','唐诗','tang','','[]','[擢]幹方數尺，幽姿已蒼然。',50,'全唐诗/poet.tang.9000.json','["[擢]幹方數尺，幽姿已蒼然。", "結根西山寺，來植郡齋前。", "新含野露氣，稍靜高窗眠。", "雖爲賞心遇，豈有巖中緣。"]'),
('dd1ada14-4196-4abe-b782-f0184f090fa7','花徑','韋應物','唐','唐诗','tang','','[]','山花夾徑幽，古甃生苔澀。',48,'全唐诗/poet.tang.9000.json','["山花夾徑幽，古甃生苔澀。", "胡牀理事餘，玉琴承露濕。", "朝與詩人賞，夜攜禪客入。", "自是塵外蹤，無令吏趨急。"]'),
('df16b03f-209f-4e52-a3b4-894f05198158','慈恩寺南池秋荷詠','韋應物','唐','唐诗','tang','','[]','對殿含涼氣，裁規覆清沼。',48,'全唐诗/poet.tang.9000.json','["對殿含涼氣，裁規覆清沼。", "衰紅受露多，餘馥依人少。", "蕭蕭遠塵跡，颯颯凌秋曉。", "節謝客來稀，迴塘方獨遶。"]'),
('3d501bb4-f56d-487c-8fa3-e3d4177f8ad1','題桐葉','韋應物','唐','唐诗','tang','','[]','參差剪綠綺，瀟灑覆瓊柯。',24,'全唐诗/poet.tang.9000.json','["參差剪綠綺，瀟灑覆瓊柯。", "憶在灃東寺，偏書此葉多。"]'),
('cd917e9c-a0d8-4159-b1f4-8487f79e5258','題石橋','韋應物','唐','唐诗','tang','','[]','遠學臨海嶠，橫此莓苔石。',48,'全唐诗/poet.tang.9000.json','["遠學臨海嶠，橫此莓苔石。", "郡齋三四峰，如有靈仙跡。", "方愁暮雲滑，始照寒池碧。", "自與幽人期，逍遙竟朝夕。"]'),
('42a7a1c7-ec22-425d-b373-8205a06a4c9d','池上','韋應物','唐','唐诗','tang','','[]','郡中臥病久，池上一來賒。',24,'全唐诗/poet.tang.9000.json','["郡中臥病久，池上一來賒。", "榆柳飄枯葉，風雨倒橫查。"]'),
('0ae0e3bd-a32e-481f-9719-b283da2da964','滁州西澗','韋應物','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6625", "\u5c71\u6c34", "\u5199\u666f", "\u6292\u60c5", "\u521d\u4e2d\u53e4\u8bd7"]','獨憐幽草澗邊生，上有黃鸝深樹鳴。',32,'全唐诗/poet.tang.9000.json','["獨憐幽草澗邊生，上有黃鸝深樹鳴。", "春潮帶雨晚來急，野渡無人舟自橫。"]'),
('087b899d-85a7-4b25-9821-23734600e2bd','西塞山','韋應物','唐','唐诗','tang','','[]','勢從千里奔，直入江中斷。',24,'全唐诗/poet.tang.9000.json','["勢從千里奔，直入江中斷。", "嵐橫秋塞雄，地束驚流滿。"]'),
('22fdd1b1-e517-4ac6-8e9e-1853be5d94ab','山耕叟','韋應物','唐','唐诗','tang','','[]','蕭蕭垂白髮，默默詎知情。',36,'全唐诗/poet.tang.9000.json','["蕭蕭垂白髮，默默詎知情。", "獨放寒林燒，多尋虎跡行。", "暮歸何處宿？來此空山耕。"]'),
('1669cfc7-496d-4dac-b9a8-06d2398d9184','上方僧','韋應物','唐','唐诗','tang','','[]','見月出東山，上方高處禪。',36,'全唐诗/poet.tang.9000.json','["見月出東山，上方高處禪。", "空林無宿火，獨夜汲寒泉。", "不下藍溪寺，今年三十年。"]'),
('aeb20f84-e730-44d4-93a6-8dd8c137e2c7','煙際鐘','韋應物','唐','唐诗','tang','','[]','隱隱起何處，迢迢送落暉。',36,'全唐诗/poet.tang.9000.json','["隱隱起何處，迢迢送落暉。", "蒼茫隨思遠，蕭散逐煙微。", "秋野寂云晦，望山僧獨歸。"]'),
('b7d7eb34-aa54-485c-8555-d9841b6ada06','始聞夏蟬','韋應物','唐','唐诗','tang','','[]','徂夏暑未晏，蟬鳴景已曛。',48,'全唐诗/poet.tang.9000.json','["徂夏暑未晏，蟬鳴景已曛。", "一聽知何處，高樹但侵雲。", "響悲遇衰齒，節謝屬離羣。", "還憶郊園日，獨向澗中聞。"]'),
('4efc6b54-f7ba-4c18-8fbd-b02ebb9d85cf','射雉','韋應物','唐','唐诗','tang','','[]','走馬上東岡，朝日照野田。',72,'全唐诗/poet.tang.9000.json','["走馬上東岡，朝日照野田。", "野田雙雉起，翻射斗迴鞭。", "雖無百發中，聊取一笑妍。", "羽分繡臆碎，頭弛錦鞘懸。", "方將悅羈旅，非關學少年。", "弢弓一長嘯，憶在灞城阡。"]'),
('a4a377b0-921e-4314-a0c3-9aec9f2a0087','夜聞獨鳥啼','韋應物','唐','唐诗','tang','','[]','失侶度山覓，投林舍北啼。',24,'全唐诗/poet.tang.9000.json','["失侶度山覓，投林舍北啼。", "今將獨夜意，偏知對影栖。"]'),
('cd9cee3d-3e21-4a4a-af21-a3d5fc329e34','述園鹿','韋應物','唐','唐诗','tang','','[]','野性本難畜，翫習亦逾年。',72,'全唐诗/poet.tang.9000.json','["野性本難畜，翫習亦逾年。", "麑班始力直，麚角已蒼然。", "仰首嚼園柳，俯身飲清泉。", "見人若閑暇，蹶起忽低騫。", "茲獸有高貌，凡類寧比肩。", "不得遊山澤，跼促誠可憐。"]'),
('6020c5b9-5845-4210-bfcc-9bedda58bc46','聞鴈','韋應物','唐','唐诗','tang','','["\u79cb\u5929", "\u601d\u4e61", "\u5927\u96c1"]','故園眇何處，歸思方悠哉。',24,'全唐诗/poet.tang.9000.json','["故園眇何處，歸思方悠哉。", "淮南秋雨夜，高齋聞鴈來。"]'),
('79e39705-ed7f-4afa-8c9b-0c02a5487d48','子規啼','韋應物','唐','唐诗','tang','','[]','高林滴露夏夜清，南山子規啼一聲。',32,'全唐诗/poet.tang.9000.json','["高林滴露夏夜清，南山子規啼一聲。", "鄰家孀婦抱兒泣，我獨展轉何時明。"]'),
('e8f429fc-5a2d-4878-b1cf-055c7e106960','始建射侯','韋應物','唐','唐诗','tang','','[]','男子本懸弧，有志在四方。',72,'全唐诗/poet.tang.9000.json','["男子本懸弧，有志在四方。", "虎竹忝明命，熊侯始張皇。", "賓登時事畢，諸將備戎裝。", "星飛的屢破，鼓譟武更揚。", "曾習鄒魯學，亦陪鴛鷺翔。", "一朝願投筆，世難激中腸。"]'),
('bbb74454-abe1-4097-81a9-c47833e2374b','仙人祠','韋應物','唐','唐诗','tang','','[]','蒼岑古仙子，清廟閟華容。',36,'全唐诗/poet.tang.9000.json','["蒼岑古仙子，清廟閟華容。", "千載去寥廓，白雲遺舊蹤。", "歸來灞陵上，猶見最高峰。"]'),
('b62b3e31-6ada-4039-8a3a-ddd7ccce210e','鷓鴣啼','韋應物','唐','唐诗','tang','','[]','可憐鷓鴣飛，飛向樹南枝。',84,'全唐诗/poet.tang.9000.json','["可憐鷓鴣飛，飛向樹南枝。", "南枝日照暖，北枝霜露滋。", "露滋不堪栖，使我夜常啼。", "願逢雲中鶴，銜我向寥廓。", "願作城上烏，一年生九雛。", "何不舊巢住，枝弱不得去。", "何意道苦辛，客子常畏人。"]'),
('5c773ccd-f0a2-4a99-ad24-1e989012e084','長安道','韋應物','唐','唐诗','tang','','[]','漢家宮殿含雲煙，兩宮十里相連延。',224,'全唐诗/poet.tang.9000.json','["漢家宮殿含雲煙，兩宮十里相連延。", "晨霞出沒弄丹闕，春雨依微自甘泉。", "春雨依微春尚早，長安貴遊愛芳草。", "寶馬橫來下建章，香車却轉避馳道。", "貴遊誰最貴，衛霍世難比。", "何能蒙主恩，幸遇邊塵起。", "歸來甲第拱皇居，朱門峨峨臨九衢。", "中有流蘇合歡之寶帳，一百二十鳳凰羅列含明珠。", "下有錦鋪翠被之粲爛，博山吐香五雲散。", "麗人綺閣情飄颻，頭上鴛釵雙翠翹。", "低鬟曳袖迴春雪，聚黛一聲愁碧霄。", "山珍海錯棄藩籬，烹犢炰羔如折葵。", "既請列侯封部曲，還將金印授廬兒。", "歡榮若此何所苦，但苦白日西南馳。"]'),
('8113bae4-1323-4460-82ed-6191665933c0','行路難','韋應物','唐','唐诗','tang','','[]','荆山之白玉兮，良工琱琢雙環連，月蝕中央鏡心穿。',99,'全唐诗/poet.tang.9000.json','["荆山之白玉兮，良工琱琢雙環連，月蝕中央鏡心穿。", "故人贈妾初相結，恩在環中尋不絕。", "人情厚薄苦須臾，昔似連環今似玦。", "連環可碎不可離，如何物在人自移。", "上客勿遽歡，聽妾歌路難。", "旁人見環環可憐，不知中有長恨端。"]'),
('192eac98-eebf-4e96-accf-b411ae927ab9','橫塘行','韋應物','唐','唐诗','tang','','[]','妾家住橫塘，夫壻郗家郎。',76,'全唐诗/poet.tang.9000.json','["妾家住橫塘，夫壻郗家郎。", "玉盤的歷雙白魚，寶簟玲瓏透象牀。", "象牀可寢魚可食，不知郎意何南北。", "岸上種蓮豈得生，池中種槿豈得成。", "丈夫一去花落樹，妾獨夜長心未平。"]'),
('90cd8dbb-6261-4fea-8106-3f419ea2d176','貴遊行','韋應物','唐','唐诗','tang','','[]','漢帝外家子，恩澤少封侯。',120,'全唐诗/poet.tang.9000.json','["漢帝外家子，恩澤少封侯。", "垂楊拂白馬，曉日上青樓。", "上有顏如玉，高情世無儔。", "輕裾含碧煙，窈窕似雲浮。", "良時無還景，促節爲我謳。", "忽聞豔陽曲，四坐亦已柔。", "賓友仰稱歎，一生何所求。", "平明擊鍾食，入夜樂未休。", "風雨愆歲候，兵戎橫九州。", "焉知坐上客，草草心所憂。"]'),
('9b3b6833-a9f9-44ec-a726-53f7d18fa4c5','酒肆行','韋應物','唐','唐诗','tang','','[]','豪家沽酒長安陌，一旦起樓高百尺。',156,'全唐诗/poet.tang.9000.json','["豪家沽酒長安陌，一旦起樓高百尺。", "碧疏玲瓏含春風，銀題彩幟邀上客。", "迴瞻丹鳳闕，直視樂遊苑。", "四方稱賞名已高，五陵車馬無近遠。", "晴景悠揚三月天，桃花飄俎柳垂筵。", "繁絲急管一時合，他壚鄰肆何寂然。", "主人無厭且專利，百斛須臾一壺費。", "初醲後薄爲大偷，飲者知名不知味。", "深門潛醞客來稀，終歲醇醲味不移。", "長安酒徒空擾擾，路傍過去那得知。"]'),
('5bff86ed-d336-4e6f-8015-5708452e8e05','相逢行','韋應物','唐','唐诗','tang','','[]','二十登漢朝，英聲邁今古。',72,'全唐诗/poet.tang.9000.json','["二十登漢朝，英聲邁今古。", "適從東方來，又欲謁明主。", "猶酣新豐酒，尚帶灞陵雨。", "邂逅兩相逢，別來問寒暑。", "寧知白日晚，暫向花間語。", "忽聞長樂鐘，走馬東西去。"]'),
('469ea255-c1b9-4513-912f-2bc355d80a5c','烏引雛','韋應物','唐','唐诗','tang','','[]','日出照東城，春烏鵶鵶雛和鳴。',93,'全唐诗/poet.tang.9000.json','["日出照東城，春烏鵶鵶雛和鳴。", "雛和鳴，羽猶短，巢在深林春正寒，引飛欲集東城暖。", "羣雛䙰褷睥睨高，舉翅不及墜蓬蒿。", "雄雌來去飛又引，音聲上下懼鷹隼。", "引雛烏，爾心急將何如，何得比日搜索雀卵噉爾雛。"]'),
('f720b24e-5184-41cf-82ce-ec0332116604','鳶奪巢','韋應物','唐','唐诗','tang','','[]','野鵲野鵲巢林梢，鴟鳶恃力奪鵲巢。',80,'全唐诗/poet.tang.9000.json','["野鵲野鵲巢林梢，鴟鳶恃力奪鵲巢。", "吞鵲之肝啄鵲腦，竊食偷居還自保。", "鳳凰五色百鳥尊，知鳶爲害何不言？", "霜鸇野鷂得殘肉，同啄羶腥不肯逐。", "可憐百鳥紛縱橫，雖有深林何處宿。"]'),
('534e29b1-8ad8-4805-98d3-557c8a119798','燕啣泥','韋應物','唐','唐诗','tang','','[]','啣泥燕，聲嘍嘍。',97,'全唐诗/poet.tang.9000.json','["啣泥燕，聲嘍嘍。", "尾涎涎，秋去何所歸。", "春來復相見，豈不解決絕高飛碧雲裏。", "何爲地上啣泥滓，銜泥雖賤意有營。", "杏梁朝日巢欲成，不見百鳥畏人林野宿。", "翻遭網羅俎其肉，未若銜泥入華屋。", "燕銜泥，百鳥之智莫與齊。"]'),
('929fca67-0dce-4856-b8fc-3e54cd684c75','鼙鼓行','韋應物','唐','唐诗','tang','','[]','淮海生雲暮慘澹，廣陵城頭顰鼓暗。',88,'全唐诗/poet.tang.9000.json','["淮海生雲暮慘澹，廣陵城頭顰鼓暗。", "寒聲坎坎風動邊，忽似孤城萬里絕，四望無人煙。", "又如虜騎截遼水，胡馬不食仰朔天。", "座中亦有燕趙士，聞顰不語客心死。", "何況鰥孤火絕無晨炊，獨婦夜泣官有期。"]'),
('a4525113-a4f7-4a15-a6d0-2b86eea66bca','古劍行','韋應物','唐','唐诗','tang','','[]','千年土中兩刃鐵，土蝕不入金星滅。',88,'全唐诗/poet.tang.9000.json','["千年土中兩刃鐵，土蝕不入金星滅。", "沈沈青脊鱗甲滿，蛟龍無足蛇尾斷。", "忽欲飛動中有靈，豪士得之敵國寶。", "仇家舉意半夜鳴，小兒女子不可近。", "龍蛇變化此中隱，夏雲奔走雷闐闐，恐成霹靂飛上天。"]'),
('f2688eb3-6879-420a-ac30-40e174d85346','金谷園歌','韋應物','唐','唐诗','tang','','[]','石氏滅，金谷園中水流絕。',122,'全唐诗/poet.tang.9000.json','["石氏滅，金谷園中水流絕。", "當時豪右爭驕侈，錦爲步障四十里。", "東風吹花雪滿川，紫氣凝閣朝景妍。", "洛陽陌上人迴首，絲竹飄颻入青天。", "晉武平吳恣歡燕，餘風靡靡朝廷變。", "嗣世衰微誰肯憂，二十四友日日空追遊。", "追遊詎可足，共惜年華促。", "禍端一發埋恨長，百草無情春自綠。"]'),
('42a7ccb7-50b2-485d-8d11-c660de93bdd2','溫泉行','韋應物','唐','唐诗','tang','','[]','出身天寶今年幾，頑鈍如鎚命如紙。',192,'全唐诗/poet.tang.9000.json','["出身天寶今年幾，頑鈍如鎚命如紙。", "作官不了却來歸，還是杜陵一男子。", "北風慘慘投溫泉，忽憶先皇遊幸年。", "身騎廐馬引天仗，直入華清列御前。", "玉林瑤雪滿寒山，上昇玄閣遊絳煙。", "平明羽衛朝萬國，車馬合沓溢四鄽。", "蒙恩每浴華池水，扈獵不蹂渭北田。", "朝廷無事共歡燕，美人絲管從九天。", "一朝鑄鼎降龍馭，小臣髯絕不得去。", "今來蕭瑟萬井空，唯見蒼山起煙霧。", "可憐蹭蹬失風波，仰天大呌無奈何。", "弊裘羸馬凍欲死，賴遇主人杯酒多。"]'),
('41b5ff73-9671-418e-9e25-33281e711d80','學仙二首 一','韋應物','唐','唐诗','tang','','[]','昔有道士求神仙，靈真下試心確然。',66,'全唐诗/poet.tang.9000.json','["昔有道士求神仙，靈真下試心確然。", "千[鈞]巨石一髮懸，臥之石下十三年。", "存道忘身一試過，名奏玉皇乃升天。", "雲氣冉冉漸不見，留語弟子但精堅。"]'),
('cf0af819-4f06-47cd-b4fc-de8192c8e7d0','學仙二首 二','韋應物','唐','唐诗','tang','','[]','石上鑿井欲到水，惰心一起中路止。',103,'全唐诗/poet.tang.9000.json','["石上鑿井欲到水，惰心一起中路止。", "豈不見古來三人俱弟兄，結茅深山讀仙經。", "上有青冥倚天之絕壁，下有颼飀萬壑之松聲。", "仙人變化爲白鹿，二弟翫之兄誦讀。", "讀多七過可乞言，爲子心精得神仙。", "可憐二弟仰天泣，一失毫釐千萬年。"]'),
('24e9b6ac-a1d7-4377-b3e0-3d4046815763','廣陵行','韋應物','唐','唐诗','tang','','[]','雄藩鎮楚郊，地勢鬱岧嶢。',108,'全唐诗/poet.tang.9000.json','["雄藩鎮楚郊，地勢鬱岧嶢。", "雙旌擁萬戟，中有霍嫖姚。", "海雲助兵氣，寶貨益軍饒。", "嚴城動寒角，晚騎踏霜橋。", "翕習英豪集，振奪士卒驍。", "列郡何足數，趨拜等卑寮。", "日宴方云罷，人逸馬蕭蕭。", "忽如京洛間，遊子風塵飄。", "歸來視寶劍，功名豈一朝。"]'),
('5c129a80-f0f2-48fe-aefc-bd834d041d27','萼綠華歌','韋應物','唐','唐诗','tang','','[]','有一人兮昇紫霞，書名玉牒兮蕚綠華。',69,'全唐诗/poet.tang.9000.json','["有一人兮昇紫霞，書名玉牒兮蕚綠華。", "仙容矯矯兮雜瑤珮，輕衣重重兮蒙絳紗。", "雲雨愁思兮望淮海，鼓吹蕭條兮駕龍車。", "世淫濁兮不可降，胡不來兮玉斧家。"]'),
('6dc10d77-a040-400a-ad15-159ede44b808','王母歌','韋應物','唐','唐诗','tang','','[]','衆仙翼神母，羽蓋隨雲起。',60,'全唐诗/poet.tang.9000.json','["衆仙翼神母，羽蓋隨雲起。", "上遊玄極杳冥中，下看東海一盃水。", "海畔種桃經幾時，千年開花千年子。", "玉顏眇眇何處尋，世上茫茫人自死。"]'),
('6bebeb2f-fd6c-4d6f-aabc-b7bf6fd8c31e','馬明生遇神女歌','韋應物','唐','唐诗','tang','','[]','學仙貴功亦貴精，神女變化感馬生。',162,'全唐诗/poet.tang.9000.json','["學仙貴功亦貴精，神女變化感馬生。", "石壁千尋啓雙檢，中有玉堂鋪玉簟。", "立之一隅不與言，玉體安隱三日眠。", "馬生一立心轉堅，知其丹白蒙哀憐。", "安期先生來起居，請示金鐺玉佩天皇書。", "神女呵責不合見，仙子謝過手足戰。", "大瓜玄棗冷如冰，海上摘來朝霞凝。", "賜仙復坐對食訖，頷之使去隨煙升。", "乃言馬生合不死，少姑教勅令付爾。", "安期再拜將生出，一授素書天地畢。"]'),
('eb75e135-e11d-4e5d-97a3-856632ab2a78','石鼓歌','韋應物','唐','唐诗','tang','','[]','周宣大獵兮岐之陽，刻石表功兮煒煌煌。',132,'全唐诗/poet.tang.9000.json','["周宣大獵兮岐之陽，刻石表功兮煒煌煌。", "石如鼓形數止十，風雨缺訛苔蘚澀。", "今人濡紙脫其文，既擊既埽白黑分。", "忽開滿卷不可識，驚潛動蟄走云云。", "喘逶迤，相糾錯，乃是宣王之臣史籀作。", "一書遺此天地間，精意長存世冥寞。", "秦家祖龍還刻石，碣石之罘李斯跡。", "世人好古猶共傳，持來比此殊懸隔。"]'),
('34524caf-3aa9-4e98-b10e-3290b1c88ce2','寶觀主白鸜鵒歌','韋應物','唐','唐诗','tang','','[]','鸜鵒鸜鵒，衆皆如漆，爾獨如玉。',147,'全唐诗/poet.tang.9000.json','["鸜鵒鸜鵒，衆皆如漆，爾獨如玉。", "鸜之鵒之，衆皆蓬蒿下。", "爾自三山來，三山處子下人間。", "綽約不妝冰雪顏，仙鳥隨飛來掌上。", "來掌上，時拂拭。", "人心鳥意自無猜，玉指霜毛本同色。", "有時一去凌蒼蒼，朝遊汗漫暮玉堂。", "巫峽雨中飛暫濕，杏花林裏過來香。", "日夕依仁全羽翼，空欲銜環非報德。", "豈不及阿母之家青鳥兒，漢宮來往傳消息。"]'),
('5ebc1dc2-353e-40f8-b184-a0ebb82651f1','彈棊歌','韋應物','唐','唐诗','tang','','[]','圓天方地局，二十四氣子。',142,'全唐诗/poet.tang.9000.json','["圓天方地局，二十四氣子。", "劉生絕藝難對曹，客爲歌其能。", "請從中央起，中央轉鬬破欲闌。", "零落勢背誰能彈，此中舉一得六七。", "旋風忽散霹靂疾，履機乘變安可當。", "置之死地翻取強，不見短兵反掌收已盡。", "唯有猛士守四方，四方又何難。", "橫擊且緣邊，豈如昆明與碣石。", "一箭飛中隔遠天，神安志愜動十全，滿堂驚視誰得然。"]'),
('daabbb07-d867-42c4-8907-e18ad56c4a60','聽鶯曲','韋應物','唐','唐诗','tang','','[]','東方欲曙花冥冥，啼鶯相喚亦可聽。',178,'全唐诗/poet.tang.9000.json','["東方欲曙花冥冥，啼鶯相喚亦可聽。", "乍去乍來時近遠，纔聞南陌又東城。", "忽似上林翻下苑，綿綿蠻蠻如有情。", "欲囀不囀意自嬌，羌兒弄笛曲未調。", "前聲後聲不相及，秦女學箏指猶澀。", "須臾風暖朝日暾，流音變作百鳥喧。", "誰家懶婦驚殘夢，何處愁人憶故園？", "伯勞飛過聲跼促，戴勝下時桑田綠。", "不及流鶯日日啼花間，能使萬家春意閑。", "有時斷續聽不了，飛去花枝猶裊裊。", "還栖碧樹鎖千門，春漏方殘一聲曉。"]'),
('2ea64e1a-3207-47ba-8508-f1a8e72cf3f0','白沙亭逢吳叟歌','韋應物','唐','唐诗','tang','','[]','龍池宮裏上皇時，羅衫寶帶香風吹。',144,'全唐诗/poet.tang.9000.json','["龍池宮裏上皇時，羅衫寶帶香風吹。", "滿朝豪士今已盡，欲話舊遊人不知。", "白沙亭上逢吳叟，愛客脫衣且沽酒。", "問之執戟亦先朝，零落艱難却負樵。", "親觀文物蒙雨露，見我昔年侍丹霄。", "冬狩春祠無一事，歡遊洽宴多頒賜。", "嘗陪月夕竹宮齋，每返溫泉灞陵醉。", "星歲再周十二辰，爾來不語今爲君。", "盛時忽去良可恨，一生坎壈何足云。"]'),
('9754faca-c7b1-456a-8077-01d741ab5c8d','送褚校書歸舊山歌','韋應物','唐','唐诗','tang','','[]','握珠不返泉，匣玉不歸山。',152,'全唐诗/poet.tang.9000.json','["握珠不返泉，匣玉不歸山。", "明皇重士亦如此，忽怪褚生何得還。", "方稱羽獵賦，未拜蘭臺職。", "漢篋亡書已暗傳，嵩丘遺簡還能識。", "朝朝待詔青鏁闈，中有萬年之樹蓬萊池。", "世人仰望棲此地，生獨徘徊意何爲。", "故山可往薇可採，一自人間星歲改。", "藏書壁中苔半侵，洗藥泉中月還在。", "春風飲餞灞陵原，莫厭歸來朝市喧。", "不見東方朔，避世從容金馬門。"]'),
('77eede30-2ace-4640-a038-740e60a9b0e6','五弦行','韋應物','唐','唐诗','tang','','[]','美人爲我彈五弦，塵埃忽靜心悄然。',132,'全唐诗/poet.tang.9000.json','["美人爲我彈五弦，塵埃忽靜心悄然。", "古刀幽磬初相觸，千珠貫斷落寒玉。", "中曲又不喧，徘徊夜長月當軒。", "如伴風流縈豔雪，更逐落花飄御園。", "獨鳳寥寥有時隱，碧霄來下聽還近。", "燕姬有恨楚客愁，言之不盡聲能盡。", "末曲感我情，解幽釋結和樂生。", "壯士有仇未得報，拔劍欲去憤已平。", "夜寒酒多愁遽明。"]'),
('c254bbb4-a234-4959-9830-fbb58b9679c5','驪山行','韋應物','唐','唐诗','tang','','[]','君不見開元至化垂衣裳，厭坐明堂朝萬方。',323,'全唐诗/poet.tang.9000.json','["君不見開元至化垂衣裳，厭坐明堂朝萬方。", "訪道靈山降聖祖，沐浴華池集百祥。", "千乘萬騎被原野，雲霞草木相輝光。", "禁仗圍山曉霜切，離宮積翠夜漏長。", "玉堦寂歷朝無事，碧樹萎蕤寒更芳。", "三清小鳥傳仙語，九華真人奉瓊漿。", "下元昧爽漏恆秩，登山朝禮玄元室。", "翠華稍隱天半雲，丹閣光明海中日。", "羽旗旄節憩瑤臺，清絲妙管從空來。", "萬井九衢皆仰望，彩雲白鶴方徘徊。", "憑高覽古嗟寰宇，造化茫茫思悠哉。", "秦川八水長繚繞，漢氏五陵空崔嵬。", "乃言聖祖奉丹經，以年爲日億萬齡。", "蒼生咸壽陰陽泰，高謝前王出塵外。", "英豪共理天下晏，戎夷讋伏兵無戰。", "時豐賦斂未告勞，海闊珍奇亦來獻。", "干戈一起文武乖，歡娛已極人事變。", "聖皇弓劍墜幽泉，古木蒼山閉宮殿。", "纘承鴻業聖明君，威震六合驅妖氛。", "太平遊幸今可待，湯泉嵐嶺還氛氳。"]'),
('b0c3a566-1b2f-4819-9cef-4bb861f80b97','漢武帝雜歌三首 一','韋應物','唐','唐诗','tang','','[]','漢武好神仙，黃金作臺與天近。',206,'全唐诗/poet.tang.9000.json','["漢武好神仙，黃金作臺與天近。", "王母摘桃海上還，感之西過聊問訊。", "欲來不來夜未央，殿前青鳥先迴翔。", "綠鬢縈雲裾曳霧，雙節飄颻下仙步。", "白日分明到世間，碧空何處來時路。", "玉盤捧桃將獻君，踟躕未去留彩雲。", "海水桑田幾翻覆，中間此桃四五熟。", "可憐穆滿瑤池燕，正值花開不得薦。", "花開子熟安可期，邂逅能當漢武時。", "顏如芳華潔如玉，心念我皇多嗜欲。", "雖留桃核桃有靈，人間糞土種不生。", "由來在道豈在藥，徒勞方士海上行。", "掩扇一言相謝去，如煙非煙不知處。"]'),
('243a1044-6bbc-41c3-91d9-df2a60fb9b8f','漢武帝雜歌三首 二','韋應物','唐','唐诗','tang','','[]','金莖孤峙兮凌紫煙，漢宮美人望杳然。',155,'全唐诗/poet.tang.9000.json','["金莖孤峙兮凌紫煙，漢宮美人望杳然。", "通天臺上月初出，承露盤中珠正圓。", "珠可飲，壽可永，武皇南面曙欲分。", "從空下來玉杯冷，世間綵翠亦作囊。", "八月一日仙人方，仙方稱上藥。", "靜者服之常綽約，柏梁沈飲自傷神，猶聞駐顏七十春。", "乃知甘醲皆是腐腸物，獨有淡泊之水能益人。", "千載金盤竟何處，當時鑄金恐不固。", "蔓草生來春復秋，碧天何言空墜露。"]'),
('ff024b4f-8993-4796-b9f1-2ef66bec9e80','漢武帝雜歌三首 三','韋應物','唐','唐诗','tang','','[]','漢天子，觀風自南國。',163,'全唐诗/poet.tang.9000.json','["漢天子，觀風自南國。", "浮舟大江屹不前，蛟龍索鬬風波黑。", "春秋方壯雄武才，彎弧叱浪連山開。", "愕然觀者千萬衆，舉麾齊呼一矢中。", "死蛟浮出不復靈，舳艫千里江水清。", "鼓顰餘響數日在，天吳深入魚鼈驚。", "左有佽飛落霜翮，右有孤兒貫犀革。", "何爲臨深親射蛟，示威以奪諸侯魄。", "威可畏，皇可尊，平田校獵書猶陳。", "此日從臣何不言，獨有威聲振千古，君不見後嗣尊爲武。"]'),
('56277ac5-db9b-4349-af50-9b01cba24df2','椶櫚蠅拂歌','韋應物','唐','唐诗','tang','','[]','椶櫚爲拂登君席，青蠅掩亂飛四壁。',84,'全唐诗/poet.tang.9000.json','["椶櫚爲拂登君席，青蠅掩亂飛四壁。", "文如輕羅散如髮，馬尾氂牛不能絜。", "柄出湘江之竹碧玉寒，上有纖羅縈縷尋未絕。", "左揮右灑繁暑清，孤松一枝風有聲。", "麗人紈素可憐色，安能點白還爲黑。"]'),
('e05a9b1a-c0f9-405f-9604-d1dd129da3bd','信州錄事參軍常曾古鼎歌','韋應物','唐','唐诗','tang','','[]','三年糾一郡，獨飲寒泉井。',92,'全唐诗/poet.tang.9000.json','["三年糾一郡，獨飲寒泉井。", "江南鑄器多鑄銀，罷官無物唯古鼎。", "雕螭刻篆相錯盤，地中歲久青苔寒。", "左對蒼山右流水，云有古來葛仙子。", "葛仙埋之何不還，耕者鎗然得其間。", "持示世人不知寶，勸君鍊丹永壽考。"]'),
('a9d43686-4b30-4010-976e-5a7ceb94e168','夏冰歌','韋應物','唐','唐诗','tang','','[]','出自玄泉杳杳之深井，汲在朱明赫赫之炎辰。',116,'全唐诗/poet.tang.9000.json','["出自玄泉杳杳之深井，汲在朱明赫赫之炎辰。", "九天含露未銷鑠，閶闔初開賜貴人。", "碎如墜瓊方截璐，粉壁生寒象筵布。", "玉壺紈扇亦玲瓏，座有麗人色俱素。", "咫尺炎涼變四時，出門焦灼君詎知。", "肥羊甘醴心悶悶，飲此瑩然何所思。", "當念闌干鑿者苦，臘月深井汗如雨。"]'),
('602a348a-64ac-453a-a85f-d5761aa4961c','黿頭山神女歌','韋應物','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','黿頭之山，直上洞庭連青天。',269,'全唐诗/poet.tang.9000.json','["黿頭之山，直上洞庭連青天。", "蒼蒼煙樹閉古廟，中有蛾眉成水仙。", "水府沈沈行路絕，蛟龍出沒無時節。", "魂同魍魎潛太陰，身與空山長不滅。", "東晉永和今幾代，雲髮素顏猶盼睞。", "陰深靈氣靜凝美，的礫龍綃雜瓊珮。", "山精木魅不敢親，昏明想像如有人。", "蕙蘭瓊芳積煙露，碧窗松月無冬春。", "舟客經過奠椒醑，巫女南音歌激楚。", "碧水冥空惟鳥飛，長天何處雲隨雨。", "紅渠綠蘋芳意多，玉靈蕩漾凌清波。", "孤峰絕島儼相向，鬼嘯猿啼垂女蘿。", "皓雪瓊枝殊異色，北方絕代徒傾國。", "雲沒煙銷不可期，明堂翡翠無人得。", "精靈變態狀無方，游龍宛轉驚鴻翔。", "湘妃獨立九疑暮，漢女菱歌春日長。", "始知仙事無不有，可惜吳宮空白首。"]'),
('99afd192-5306-4638-8fdc-0aaae349ca2d','寇季膺古刀歌','韋應物','唐','唐诗','tang','','[]','古刀寒鋒青槭槭，少年交結平陵客。',234,'全唐诗/poet.tang.9000.json','["古刀寒鋒青槭槭，少年交結平陵客。", "求之時代不可知，千痕萬穴如星離。", "重疊泥沙更剝落，縱橫鱗甲相參差。", "古物有靈知所適，貂裘拂之橫廣席。", "陰森白日掩雲虹，錯落池光動金碧。", "知君寶此誇絕代，求之不得心常愛。", "厭見今時繞指柔，片鋒折刃猶堪佩。", "高山成谷蒼海填，英豪埋沒誰所捐。", "吳鉤斷馬不知處，幾度煙塵今獨全。", "夜光投人人不畏，知君獨識精靈器。", "酬恩結思心自知，死生好惡不相棄。", "白虎司秋金氣清，高天寥落雲崢嶸。", "月肅風淒古堂淨，精芒切切如有聲。", "何不跨蓬萊，斬長鯨？", "世人所好殊遼闊，千金買鉛徒一割。"]'),
('ebed5508-9ff3-45ad-9cc0-6405873f96ba','凌霧行','韋應物','唐','唐诗','tang','','[]','秋城海霧重，職事凌晨出。',72,'全唐诗/poet.tang.9000.json','["秋城海霧重，職事凌晨出。", "浩浩合元天，溶溶迷朗日。", "纔看含鬢白，稍視霑衣密。", "道騎全不分，郊樹都如失。", "霏微誤噓吸，膚腠生寒慄。", "歸當飲一杯，庶用蠲斯疾。"]'),
('7aa80b4e-7e90-46bd-8c3b-e052518ae727','樂燕行','韋應物','唐','唐诗','tang','','[]','良辰且燕樂，樂往不再來。',96,'全唐诗/poet.tang.9000.json','["良辰且燕樂，樂往不再來。", "趙瑟正高張，音響清塵埃。", "一彈和妙謳，吹去繞瑤臺。", "豔雲凌空散，舞羅起徘徊。", "輝輝發衆顏，灼灼歎令才。", "當喧既無寂，中飲亦停杯。", "華燈何遽升，馳景忽西頹。", "高節亦云立，安能滯不迴。"]'),
('854d1f98-08a0-4427-a203-084859da79c9','采玉行','韋應物','唐','唐诗','tang','','[]','官府徵白丁，言采藍谿玉。',36,'全唐诗/poet.tang.9000.json','["官府徵白丁，言采藍谿玉。", "絕嶺夜無家，深榛雨中宿。", "獨婦餉糧還，哀哀舍南哭。"]'),
('41dac3f9-ad09-4995-91f2-54da1531657e','難言','韋應物','唐','唐诗','tang','','[]','掬土移山望山盡，投石填海望海滿。',46,'全唐诗/poet.tang.9000.json','["掬土移山望山盡，投石填海望海滿。", "持索捕風幾時得，將刀斫水幾時斷。", "未若不相知，中心萬仞何由款。"]'),
('21916b99-d0e3-4113-a735-94b01d9b72f1','易言','韋應物','唐','唐诗','tang','','[]','洪爐熾炭燎一毛，大鼎炊湯沃殘雪。',46,'全唐诗/poet.tang.9000.json','["洪爐熾炭燎一毛，大鼎炊湯沃殘雪。", "疾影隨形不覺至，千鈞引縷不知絕。", "未若同心言，一言和同解千結。"]'),
('64f66003-29a2-473f-9448-f16c88ecea95','三臺二首 一','韋應物','唐','唐诗','tang','','[]','一年一年老去，明日後日花開。',28,'全唐诗/poet.tang.9000.json','["一年一年老去，明日後日花開。", "未報長安平定，萬國豈得銜杯。"]'),
('6e490c35-1187-4e2b-b8c8-fdf051ac64c6','三臺二首 二','韋應物','唐','唐诗','tang','','[]','冰泮寒塘始綠，雨餘百草皆生。',28,'全唐诗/poet.tang.9000.json','["冰泮寒塘始綠，雨餘百草皆生。", "朝來門閤無事，晚下高齋有情。"]'),
('d6682456-fbbf-4d0c-8247-718faa3d238f','上皇三臺','韋應物','唐','唐诗','tang','','[]','不寐倦長更，披衣出戶行。',24,'全唐诗/poet.tang.9000.json','["不寐倦長更，披衣出戶行。", "月寒秋竹冷，風切夜窗聲。"]'),
('ea1773af-78f4-4b65-be08-701d0ccc5e3a','荅暢參軍','韋應物','唐','唐诗','tang','','[]','秉筆振芳步，少年且吏遊。',96,'全唐诗/poet.tang.9000.json','["秉筆振芳步，少年且吏遊。", "官閑高興生，夜直河漢秋。", "念與清賞遇，方抱沈疾憂。", "嘉言忽見贈，良藥同所瘳。", "高樹起栖鴉，晨鐘滿皇州。", "淒清露華動，曠朗景氣浮。", "偶宦心非累，處喧道自幽。", "空虛爲世薄，子獨意綢繆。"]'),
('4da435a7-fbdf-40dc-8525-8ff575881363','南池宴錢子辛賦得科斗','韋應物','唐','唐诗','tang','','[]','臨池見科斗，美爾樂有餘。',36,'全唐诗/poet.tang.9000.json','["臨池見科斗，美爾樂有餘。", "不憂網與鉤，幸得免爲魚。", "且願充文字，登君尺素書。"]'),
('7a4c1134-9483-4f4a-99e4-c1fd82a3c933','詠徐正字畫青蠅','韋應物','唐','唐诗','tang','','[]','誤點能成物，迷真許一時。',48,'全唐诗/poet.tang.9000.json','["誤點能成物，迷真許一時。", "筆端來已久，座上去何遲。", "顧白曾無變，聽雞不復疑。", "詎勞才子賞，爲入國人詩。"]'),
('f17d5250-4117-49cf-916c-857102803f2d','虞獲子鹿','韋應物','唐','唐诗','tang','','[]','虞獲子鹿，畜之城陬。',40,'全唐诗/poet.tang.9000.json','["虞獲子鹿，畜之城陬。", "園有美草，池有清流。", "但見蹶蹶，亦聞呦呦。", "誰知其思，巖谷云游。"]'),
('69b44b0f-a238-4d0c-890c-dac1ca608b27','陪王郎中尋孔徵君','韋應物','唐','唐诗','tang','','[]','俗吏閑居少，同人會面難。',48,'全唐诗/poet.tang.9000.json','["俗吏閑居少，同人會面難。", "偶隨香署客，來訪竹林歡。", "暮館花微落，春城雨暫寒。", "甕間聊共酌，莫使宦情闌。"]'),
('78c80a77-9253-478b-bac1-3af5d5b982f6','送宮人入道','韋應物','唐','唐诗','tang','','[]','捨寵求仙畏色衰，辭天素面立天墀。',64,'全唐诗/poet.tang.9000.json','["捨寵求仙畏色衰，辭天素面立天墀。", "金丹擬駐千年貌，寶鏡休勻八字眉。", "公主與收珠翠後，君王看戴角冠時。", "從來宮女皆相妒，說著瑤臺總淚垂。"]'),
('b67ddf05-43fb-4859-a1a9-34f95d45aabf','和晉陵陸丞早春遊望','韋應物','唐','唐诗','tang','','["\u6625\u5929", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4f24\u6000", "\u548c\u8bd7", "\u601d\u4e61", "\u4e94\u8a00\u5f8b\u8bd7"]','獨有宦遊人，偏驚物候新。',48,'全唐诗/poet.tang.9000.json','["獨有宦遊人，偏驚物候新。", "雲霞出海曙，梅柳渡江春。", "淑氣催黃鳥，晴光照綠蘋。", "忽聞歌苦調，歸思欲霑巾。"]'),
('abcb9031-9112-4abe-8499-d996a5d38ab0','九日','韋應物','唐','唐诗','tang','','[]','一爲吳郡守，不覺菊花開。',24,'全唐诗/poet.tang.9000.json','["一爲吳郡守，不覺菊花開。", "始有故園思，且喜衆賓來。"]'),
('ef512eca-b9b4-40d4-9bd1-41396376e80e','元次山居武昌之樊山新春大雪以詩問之','孟彥深','唐','唐诗','tang','','[]','江山十日雪，雪深江霧濃。',72,'全唐诗/poet.tang.9000.json','["江山十日雪，雪深江霧濃。", "起來望樊山，但見羣玉峰。", "林鶯却不語，野獸翻有蹤。", "山中應大寒，短褐何以完。", "皓氣凝書帳，清著釣魚竿。", "懷君欲進謁，谿滑渡舟難。"]'),
('9fa8f206-ddb6-40f9-9d5a-cc5e174284ca','出塞曲','劉灣','唐','唐诗','tang','','[]','將軍在重圍，音信絕不通。',96,'全唐诗/poet.tang.9000.json','["將軍在重圍，音信絕不通。", "羽書如流星，飛入甘泉宮。", "倚是幷州兒，少年心膽雄。", "一朝隨召募，百戰爭王公。", "去年桑乾北，今年桑乾東。", "死是征人死，功是將軍功。", "汗馬牧秋月，疲卒臥霜風。", "仍聞左賢王，更將圍雲中。"]'),
('1f8dd04e-98d0-44c6-ab36-03677e8e16b3','雲南曲','劉灣','唐','唐诗','tang','','[]','百蠻亂南方，羣盜如蝟起。',96,'全唐诗/poet.tang.9000.json','["百蠻亂南方，羣盜如蝟起。", "騷然疲中原，征戰從此始。", "白門太和城，來往一萬里。", "去者無全生，十人九人死。", "岱馬臥陽山，燕兵哭瀘水。", "妻行求死夫，父行求死子。", "蒼天滿愁雲，白骨積空壘。", "哀哀雲南行，十萬同已矣。"]'),
('3813dedc-c18a-44c8-84e4-c51b607610ba','李陵別蘇武','劉灣','唐','唐诗','tang','','[]','漢武愛邊功，李陵提步卒。',132,'全唐诗/poet.tang.9000.json','["漢武愛邊功，李陵提步卒。", "轉戰單于庭，身隨漢軍沒。", "李陵不愛死，心存歸漢闕。", "誓欲還國恩，不爲匈奴屈。", "身辱家已無，長居虎狼窟。", "胡天無春風，虜地多積雪。", "窮陰愁殺人，況與蘇武別。", "發聲天地哀，執手肺腸絕。", "白日爲我愁，陰雲爲我結。", "生爲漢宮臣，死爲胡地骨。", "萬里長相思，終身望南月。"]'),
('a0087ac2-4096-4fb9-8342-3776b9677768','虹縣嚴孝子墓','劉灣','唐','唐诗','tang','','[]','至性教不及，因心天所資。',96,'全唐诗/poet.tang.9000.json','["至性教不及，因心天所資。", "禮聞三年喪，爾獨終身期。", "下由骨肉恩，上報父母慈。", "禮聞哭有卒，汝獨哀無時。", "前有松柏林，荆蓁結朦朧。", "墓門白日閉，泣血黃泉中。", "草服蔽枯骨，垢容戴飛蓬。", "舉聲哭蒼天，萬木皆悲風。"]'),
('6e56279e-18ff-4da4-926a-bbb2ab10abb1','對雨愁悶寄錢大郎中','劉灣','唐','唐诗','tang','','[]','積雨細紛紛，飢寒命不分。',48,'全唐诗/poet.tang.9000.json','["積雨細紛紛，飢寒命不分。", "攬衣愁見肘，窺鏡覓從文。", "九陌成泥海，千山盡濕雲。", "龍鍾驅欵段，到處倍思君。"]'),
('696256d1-68da-4821-8a42-372916db0244','即席賦露中菊','劉灣','唐','唐诗','tang','','[]','衆芳春競發，寒菊露偏滋。',48,'全唐诗/poet.tang.9000.json','["衆芳春競發，寒菊露偏滋。", "受氣何曾異，開花獨自遲。", "晚成猶有分，欲採未過時。", "勿棄東籬下，看隨秋草衰。"]'),
('f699d2a4-bc4b-4f9d-8b62-5abab4c283a3','遇旅鶴','孫昌胤','唐','唐诗','tang','','[]','靈鶴產絕境，昂昂無與儔。',96,'全唐诗/poet.tang.9000.json','["靈鶴產絕境，昂昂無與儔。", "羣飛滄海曙，一叫雲山秋。", "野性方自得，人寰何所求。", "時因戲祥風，偶爾來中州。", "中州帝王宅，園沼深且幽。", "希君惠稻粱，欲幷離丹丘。", "不然奮飛去，將適汗漫游。", "肯作池上鶩，年年空沈浮。"]'),
('fd1d6bdc-40d7-4fc8-ac2d-814f0eb5da43','清明','孫昌胤','唐','唐诗','tang','','[]','清明暮春裏，悵望北山陲。',48,'全唐诗/poet.tang.9000.json','["清明暮春裏，悵望北山陲。", "燧火開新焰，桐花發故枝。", "沈冥慙歲物，歡宴阻朋知。", "不及林間鳥，遷喬並羽儀。"]'),
('0b82553b-521d-4ced-a2da-2cf6b5d61764','和司空曙劉眘虛九日送人','孫昌胤','唐','唐诗','tang','','[]','京邑歎離羣，江樓喜遇君。',48,'全唐诗/poet.tang.9000.json','["京邑歎離羣，江樓喜遇君。", "開筵當九日，汎菊外浮雲。", "朗詠山川霽，酣歌物色新。", "君看酒中意，未肯喪斯文。"]'),
('6725b27b-58a5-48bf-bc23-0d93108ba140','越裳獻白翟','孫昌胤','唐','唐诗','tang','','[]','聖哲符休運，伊臯列上台。',72,'全唐诗/poet.tang.9000.json','["聖哲符休運，伊臯列上台。", "覃恩丹徼遠，入貢素翬來。", "北闕欣初見，南枝顧未迴。", "斂容殘雪淨，矯翼片雲開。", "馴擾將無懼，翻飛幸莫猜。", "甘從上苑裏，飲啄自裴回。"]'),
('31e70583-ad36-4d3b-80df-84383a27f226','綿州越王樓即事','喬琳','唐','唐诗','tang','','[]','三蜀澄清郡政閑，登樓攜酌日躋攀。',64,'全唐诗/poet.tang.9000.json','["三蜀澄清郡政閑，登樓攜酌日躋攀。", "頓覺胷懷無俗事，迴看掌握是人寰。", "灘聲曲折涪州水，雲影低銜富樂山。", "行雁南飛似鄉信，忽然西笑向秦關。"]'),
('9119857e-a741-49af-a746-33429a2815fd','牡丹','柳渾','唐','唐诗','tang','','[]','近來無奈牡丹何，數十千錢買一顆。',32,'全唐诗/poet.tang.9000.json','["近來無奈牡丹何，數十千錢買一顆。", "今朝始得分明見，也共戎葵不校多。"]'),
('ad33b0a5-c7b0-4377-ab30-6c1a27e5d5d8','讀後漢逸人傳二首 一','張謂','唐','唐诗','tang','','[]','子陵沒已久，讀史思其賢。',120,'全唐诗/poet.tang.9000.json','["子陵沒已久，讀史思其賢。", "誰謂潁陽人，千秋如比肩。", "嘗聞漢皇帝，曾是曠周旋。", "名位苟無心，對君猶可眠。", "東過富春渚，樂此佳山川。", "夜臥松下月，朝看江上煙。", "釣時如有待，釣罷應忘筌。", "生事在林壑，悠悠經暮年。", "于今七里瀨，遺迹尚依然。", "高臺竟寂寞，流水空潺湲。"]'),
('9dd2e3b6-ed49-426d-9129-ce8e1ed04a83','讀後漢逸人傳二首 二','張謂','唐','唐诗','tang','','[]','龐公南郡人，家在襄陽里。',96,'全唐诗/poet.tang.9000.json','["龐公南郡人，家在襄陽里。", "何處偏來往，襄陽東陂是。", "誓將業田種，終得保妻子。", "何言二千石，乃欲勸吾仕。", "鸛鵲巢茂林，黿鼉穴深水。", "萬物從所欲，吾心亦如此。", "不見鹿門山，朝朝白雲起。", "采藥復采樵，優游終暮齒。"]'),
('cdd8924d-da5d-4665-8a13-91b52379f3d8','同孫構免官後登薊樓','張謂','唐','唐诗','tang','','[]','昔在五陵時，年少心亦壯。',144,'全唐诗/poet.tang.9000.json','["昔在五陵時，年少心亦壯。", "嘗矜有奇骨，必是封侯相。", "東走到營州，投身似邊將。", "一朝去鄉國，十載履亭障。", "部曲皆武夫，功成不相讓。", "猶希虜塵動，更取林胡帳。", "去年大將軍，忽負樂生謗。", "北別傷士卒，南遷死炎瘴。", "濩落悲無成，行登薊丘上。", "長安三千里，日夕西南望。", "寒沙榆塞沒，秋水灤河漲。", "策馬從此辭，雲山保閑放。"]'),
('50e3f3b1-bdf4-4af6-82b3-1b31b2c6a2e0','代北州老翁荅','張謂','唐','唐诗','tang','','[]','負薪老翁往北州，北望鄉關生客愁。',128,'全唐诗/poet.tang.9000.json','["負薪老翁往北州，北望鄉關生客愁。", "自言老翁有三子，兩人已向黃沙死。", "如今小兒新長成，明年聞道又徵兵。", "定知此別必零落，不及相隨同死生。", "盡將田宅借鄰伍，且復伶俜去鄉士。", "在生本求多子孫，及有誰知更辛苦。", "近傳天子尊武臣，強兵直欲靜胡塵。", "安邊自合有長策，何必流離中國人。"]'),
('474cca5c-e923-468b-92bd-8210ab38457e','湖上對酒行','張謂','唐','唐诗','tang','','[]','夜坐不厭湖上月，晝行不厭湖上山。',96,'全唐诗/poet.tang.9000.json','["夜坐不厭湖上月，晝行不厭湖上山。", "眼前一尊又長滿，心中萬事如等閑。", "主人有黍百餘石，濁醪數斗應不惜。", "即今相對不盡歡，別後相思復何益。", "茱萸灣頭歸路賒，願君且宿黃公家。", "風光若此人不醉，參差辜負東園花。"]'),
('a4e45d98-0ebd-4cdd-b326-f1326548d8ef','贈喬琳','張謂','唐','唐诗','tang','','[]','去年上策不見收，今年寄食仍淹留。',80,'全唐诗/poet.tang.9000.json','["去年上策不見收，今年寄食仍淹留。", "羨君有酒能便醉，羨君無錢能不憂。", "如今五侯不愛客，羨君不問五侯宅。", "如今七貴方自尊，羨君不過七貴門。", "丈夫會應有知己，世上悠悠何足論。"]'),
('7c155807-0def-4fd4-9df9-fc34d0bb012f','邵陵作','張謂','唐','唐诗','tang','','[]','嘗聞虞帝苦憂人，祗爲蒼生不爲身。',96,'全唐诗/poet.tang.9000.json','["嘗聞虞帝苦憂人，祗爲蒼生不爲身。", "已道一朝辭北闕，何須五月更南巡。", "昔時文武皆銷鑠，今日精靈常寂寞。", "斑竹年來笋自生，白蘋春盡花空落。", "遙望零陵見舊丘，蒼梧雲起至今愁。", "惟餘帝子千行淚，添作瀟湘萬里流。"]'),
('f243b3bd-afa2-47a6-be17-8b8caba05c69','寄李侍御','張謂','唐','唐诗','tang','','[]','柱下聞周史，書中慰越吟。',36,'全唐诗/poet.tang.9000.json','["柱下聞周史，書中慰越吟。", "近看三歲字，遙見百年心。", "價以吹噓長，恩從顧盼深。"]'),
('eb3f5948-c01e-43b7-aa99-048cdcbc451e','寄崔灃州','張謂','唐','唐诗','tang','','[]','共襆臺郎被，俱褰郡守帷。',48,'全唐诗/poet.tang.9000.json','["共襆臺郎被，俱褰郡守帷。", "罰金殊往日，鳴玉幸同時。", "五馬來何晚，雙魚贈已遲。", "江頭望鄉月，無夜不相思。"]'),
('09242aca-4cbb-40d2-bb3f-8a189a4495db','送裴侍御歸上都','張謂','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','楚地勞行役，秦城罷鼓鼙。',48,'全唐诗/poet.tang.9000.json','["楚地勞行役，秦城罷鼓鼙。", "舟移洞庭岸，路出武陵谿。", "江月隨人影，山花趁馬蹄。", "離魂將別夢，先已到關西。"]'),
('e2b498aa-228d-444e-b9e6-b663796ff42e','送青龍一公','張謂','唐','唐诗','tang','','[]','事佛輕金印，勤王度玉關。',48,'全唐诗/poet.tang.9000.json','["事佛輕金印，勤王度玉關。", "不知從樹下，還肯到人間。", "楚水青蓮淨，吳門白日閑。", "聖朝須助理，絕莫愛東山。"]'),
('68a913e4-f3e8-4110-83b1-5706048ec2c6','送韋侍御赴上都','張謂','唐','唐诗','tang','','[]','天朝辟書下，風憲取才難。',48,'全唐诗/poet.tang.9000.json','["天朝辟書下，風憲取才難。", "更謁麒麟殿，重簪獬豸冠。", "月明湘水夜，霜重桂林寒。", "別後頭堪白，時時鏡裏看。"]'),
('b2e40dec-928a-4504-82a2-e611b052bf76','餞田尚書還兗州','張謂','唐','唐诗','tang','','[]','忠義三朝許，威名四海聞。',48,'全唐诗/poet.tang.9000.json','["忠義三朝許，威名四海聞。", "更乘歸魯詔，猶憶破胡勳。", "別路逢霜雨，行營對雪雲。", "明朝郭門外，長揖大將軍。"]'),
('726e30df-7002-4b27-8c2d-054dfee858a5','送杜侍御赴上都','張謂','唐','唐诗','tang','','[]','避馬臺中貴，登車嶺外遙。',48,'全唐诗/poet.tang.9000.json','["避馬臺中貴，登車嶺外遙。", "還因貢賦禮，來謁大明朝。", "地入商山路，鄉連渭水橋。", "承恩返南越，尊酒重相邀。"]'),
('ad833649-16f9-416a-980f-22f31f373775','道林寺送莫侍御','張謂','唐','唐诗','tang','','[]','何處堪留客，香林隔翠微。',48,'全唐诗/poet.tang.9000.json','["何處堪留客，香林隔翠微。", "薜蘿通驛騎，山竹挂朝衣。", "霜引臺烏集，風驚塔鴈飛。", "飲茶勝飲酒，聊以送將歸。"]'),
('33719a7f-eaec-48ab-8fd3-99f035c54968','別睢陽故人','張謂','唐','唐诗','tang','','[]','少小客遊梁，依然似故鄉。',48,'全唐诗/poet.tang.9000.json','["少小客遊梁，依然似故鄉。", "城池經戰陣，人物恨存亡。", "夏雨桑條綠，秋風麥穗黃。", "有書無寄處，相送一霑裳。"]'),
('e7060551-6241-4ac7-8e7b-affb30c61e88','郡南亭子宴','張謂','唐','唐诗','tang','','[]','亭子春城外，朱門向綠林。',48,'全唐诗/poet.tang.9000.json','["亭子春城外，朱門向綠林。", "柳枝經雨重，松色帶烟深。", "漉酒迎山客，穿池集水禽。", "白雲常在眼，聊足慰人心。"]'),
('58510152-6736-42b3-a285-890a9b46a75f','早春陪崔中丞浣花溪宴得暄字','張謂','唐','唐诗','tang','','[]','旌節臨溪口，寒郊斗覺暄。',48,'全唐诗/poet.tang.9000.json','["旌節臨溪口，寒郊斗覺暄。", "紅亭移酒席，畫鷁逗江村。", "雲帶歌聲颺，風飄舞袖翻。", "花間催秉燭，川上欲黃昏。"]'),
('49273c42-b969-4f81-915d-9d1e8422f3d9','讌鄭伯璵宅','張謂','唐','唐诗','tang','','[]','正月風光好，逢君上客稀。',48,'全唐诗/poet.tang.9000.json','["正月風光好，逢君上客稀。", "曉風催鳥囀，春雪帶花飛。", "堂上吹金管，庭前試舞衣。", "俸錢供酒債，行子未須歸。"]'),
('c1cd5d9a-6b52-4f98-a761-f754635e2ab1','夜同宴用人字','張謂','唐','唐诗','tang','','[]','北斗回新歲，東園值早春。',48,'全唐诗/poet.tang.9000.json','["北斗回新歲，東園值早春。", "竹風能醒酒，花月解留人。", "邑宰陶元亮，山家鄭子真。", "平生頗同道，相見日相親。"]'),
('fa083f14-5488-41b7-af8b-9855f2571276','過從弟制疑官舍竹齋','張謂','唐','唐诗','tang','','[]','羨爾方爲吏，衡門獨[晏]如。',50,'全唐诗/poet.tang.9000.json','["羨爾方爲吏，衡門獨[晏]如。", "野猨偷紙筆，山鳥污圖書。", "竹裏藏公事，花間隱使車。", "不妨垂釣坐，時膾小江魚。"]'),
('f67c0a6a-f81d-4458-a6b7-b14df3f06146','揚州雨中張十七宅觀妓','張謂','唐','唐诗','tang','','[]','夜色帶寒煙，燈花拂更然。',48,'全唐诗/poet.tang.9000.json','["夜色帶寒煙，燈花拂更然。", "殘妝添石黛，豔舞落金鈿。", "掩笑須欹扇，迎歌乍動弦。", "不知巫峽雨，何事海西邊。"]'),
('887d8ba9-bf18-4923-86cb-b175ef7530e4','登金陵臨江驛樓','張謂','唐','唐诗','tang','','[]','古戍依重險，高樓見五梁。',48,'全唐诗/poet.tang.9000.json','["古戍依重險，高樓見五梁。", "山根盤驛道，河水浸城牆。", "庭樹巢鸚鵡，園花隱麝香。", "忽然江浦上，憶作捕魚郎。"]'),
('ec6c90eb-0349-4206-ad18-52204a036b60','同王徵君湘中有懷','張謂','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929", "\u601d\u4e61"]','八月洞庭秋，瀟湘水北流。',48,'全唐诗/poet.tang.9000.json','["八月洞庭秋，瀟湘水北流。", "還家萬里夢，爲客五更愁。", "不用開書帙，偏宜上酒樓。", "故人京洛滿，何日復同遊。"]'),
('631932b3-98a4-4939-bea2-f73f808f57f0','官舍早梅','張謂','唐','唐诗','tang','','[]','堦下雙梅樹，春來畫不成。',48,'全唐诗/poet.tang.9000.json','["堦下雙梅樹，春來畫不成。", "晚時花未落，陰處葉難生。", "摘子防人到，攀枝畏鳥驚。", "風光先占得，桃李莫相輕。"]'),
('12cab6c3-4e6c-49b6-831d-fff96cf48e36','玉清公主挽歌','張謂','唐','唐诗','tang','','[]','學鳳年猶小，乘龍日尚賒。',48,'全唐诗/poet.tang.9000.json','["學鳳年猶小，乘龍日尚賒。", "初封千戶邑，忽駕五雲車。", "地接金人岸，山通玉女家。", "秋風何太早，吹落禁園花。"]'),
('753e44dc-4ea6-416e-b967-5e1ab7a9acf9','別韋郎中','張謂','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','星軺計日赴岷峨，雲樹連天阻笑歌。',64,'全唐诗/poet.tang.9000.json','["星軺計日赴岷峨，雲樹連天阻笑歌。", "南入洞庭隨鴈去，西過巫峽聽猨多。", "崢嶸洲上飛黃蝶，灩澦堆邊起白波。", "不醉郎中桑落酒，教人無奈別離何。"]'),
('e4233265-dd8f-414c-b0d7-0a691d9924dd','送皇甫齡宰交河','張謂','唐','唐诗','tang','','[]','將軍帳下來從客，小邑彈琴不易逢。',64,'全唐诗/poet.tang.9000.json','["將軍帳下來從客，小邑彈琴不易逢。", "樓上胡笳傳別怨，尊中臘酒爲誰濃。", "行人醉出雙門道，少婦愁看七里烽。", "今日相如輕武騎，多應朝暮客臨卭。"]'),
('4da49282-f103-418e-bfd6-d9f79aaabcb1','杜侍御送貢物戲贈','張謂','唐','唐诗','tang','','[]','銅柱朱崖道路難，伏波橫海舊登壇。',64,'全唐诗/poet.tang.9000.json','["銅柱朱崖道路難，伏波橫海舊登壇。", "越人自貢珊瑚樹，漢使何勞獬豸冠。", "疲馬山中愁日晚，孤舟江上畏春寒。", "由來此貨稱難得，多恐君王不忍看。"]'),
('0c87dc6f-4f7f-4205-badb-8d2eca6d6c08','春園家宴','張謂','唐','唐诗','tang','','[]','南園春色正相宜，大婦同行少婦隨。',64,'全唐诗/poet.tang.9000.json','["南園春色正相宜，大婦同行少婦隨。", "竹裏登樓人不見，花間覓路鳥先知。", "櫻桃解結垂簷子，楊柳能低入戶枝。", "山簡醉來歌一曲，參差笑殺郢中兒。"]'),
('27d32896-4fcb-4800-b7ed-46df2d8dfe9d','西亭子言懷','張謂','唐','唐诗','tang','','[]','數叢芳草在堂陰，幾處閑花映竹林。',64,'全唐诗/poet.tang.9000.json','["數叢芳草在堂陰，幾處閑花映竹林。", "攀樹玄猨呼郡吏，傍谿白鳥應家禽。", "青山看景知高下，流水聞聲覺淺深。", "官屬不令拘禮數，時時緩步一相尋。"]'),
('5f8a119a-fd44-47e9-8803-a04f0f1c4e77','辰陽即事','張謂','唐','唐诗','tang','','[]','青楓落葉正堪悲，黃菊殘花欲待誰。',64,'全唐诗/poet.tang.9000.json','["青楓落葉正堪悲，黃菊殘花欲待誰。", "水近偏逢寒氣早，山深常見日光遲。", "愁中卜命看周易，病裏招魂讀楚詞。", "自恨不如湘浦鴈，春來即是北歸時。"]'),
('19433bd7-61c2-4618-892a-ddd7b71c082f','送僧','張謂','唐','唐诗','tang','','[]','童子學修道，誦經求出家。',96,'全唐诗/poet.tang.9000.json','["童子學修道，誦經求出家。", "手持貝多葉，心念優曇花。", "得度北州近，隨緣東路賒。", "一身求清淨，百毳納袈裟。", "鍾嶺更飛錫，爐峰期結跏。", "深心大海水，廣願恆河沙。", "此去不堪別，彼行安可涯。", "殷勤結香火，來世上牛車。"]'),
('a169d7cc-0e41-4b7d-9c77-6ffc3bafc48a','同諸公遊雲公禪寺','張謂','唐','唐诗','tang','','[]','共許尋雞足，誰能惜馬蹄。',72,'全唐诗/poet.tang.9000.json','["共許尋雞足，誰能惜馬蹄。", "長空淨雲雨，斜日半虹霓。", "簷下千峰轉，窗前萬木低。", "看花尋徑遠，聽鳥入林迷。", "地與喧聞隔，人將物我齊。", "不知樵客意，何事武陵谿。"]'),
('f5ff1ab1-139e-47c0-8239-aeaf72f76813','哭護國上人','張謂','唐','唐诗','tang','','[]','昔喜三身淨，今悲萬劫長。',72,'全唐诗/poet.tang.9000.json','["昔喜三身淨，今悲萬劫長。", "不應歸北斗，應是向西方。", "舍利衆生得，袈裟弟子將。", "鼠行殘藥椀，蟲網舊繩牀。", "別起千花塔，空留一草堂。", "支公何處在，神理竟茫茫。"]'),
('e1956bb6-2c19-43b2-8bb5-114aa240a2ce','送盧舉使河源','張謂','唐','唐诗','tang','','[]','故人行役向邊州，匹馬今朝不少留。',32,'全唐诗/poet.tang.9000.json','["故人行役向邊州，匹馬今朝不少留。", "長路關山何日盡，滿堂絲竹爲君愁。"]'),
('30a060f1-a54f-4c16-b417-c853d5f58a61','題長安壁主人','張謂','唐','唐诗','tang','','["\u54f2\u7406", "\u53cb\u60c5"]','世人結交須黃金，黃金不多交不深。',32,'全唐诗/poet.tang.9000.json','["世人結交須黃金，黃金不多交不深。", "縱令然諾暫相許，終是悠悠行路心。"]'),
('169b4f35-be20-4383-a122-6a013526aca2','長安失火後戲題蓮花寺','張謂','唐','唐诗','tang','','[]','金園寶剎半長沙，燒劫旁延一萬家。',32,'全唐诗/poet.tang.9000.json','["金園寶剎半長沙，燒劫旁延一萬家。", "樓殿縱隨煙焰去，火中何處出蓮花。"]'),
('26b9926a-007c-446d-b544-89d3be0c721e','早梅','張謂','唐','唐诗','tang','','["\u6885\u82b1", "\u548f\u7269", "\u548f\u7269\u8bd7"]','一樹寒梅白玉條，逈臨林村傍谿橋。',32,'全唐诗/poet.tang.9000.json','["一樹寒梅白玉條，逈臨林村傍谿橋。", "不知近水花先發，疑是經春雪未銷。"]'),
('2c3bf7b9-afa8-47dd-afe4-7ff4cba4a1c4','贈趙使君美人','張謂','唐','唐诗','tang','','[]','紅粉青蛾映楚雲，桃花馬上石榴裙。',32,'全唐诗/poet.tang.9000.json','["紅粉青蛾映楚雲，桃花馬上石榴裙。", "羅敷獨向東方去，漫學他家作使君。"]'),
('3e6cf7b0-a4ab-47aa-9374-fb7e8545cd16','句','張謂','唐','唐诗','tang','','[]','[稽]山賀老麤知名，吳郡張顛曾不易。',34,'全唐诗/poet.tang.9000.json','["[稽]山賀老麤知名，吳郡張顛曾不易。", "奔蛇走虺勢入坐，驟雨旋風聲滿堂。"]'),
('80e5e243-1539-4787-af87-ea299c03f4ae','北庭西郊候封大夫受降回軍獻上','岑參','唐','唐诗','tang','','["\u5199\u4eba", "\u6b4c\u9882", "\u8a00\u5fd7", "\u5199\u4eba\u8bd7"]','胡地苜蓿美，輪臺征馬肥。',204,'全唐诗/poet.tang.9000.json','["胡地苜蓿美，輪臺征馬肥。", "大夫討匈奴，前月西出師。", "甲兵未得戰，降虜來如歸。", "橐駞何連連，穹帳亦纍纍。", "陰山烽火滅，劒水羽書稀。", "却笑霍嫖姚，區區徒爾爲。", "西郊候中軍，平沙懸落暉。", "驛馬從西來，雙節夾路馳。", "喜鵲捧金印，蛟龍盤畫旗。", "如公未四十，富貴能及時。", "直上排青雲，傍看疾若飛。", "前年斬樓蘭，去歲平月支。", "天子日殊寵，朝廷方見推。", "何幸一書生，忽蒙國士知。", "側身佐戎幕，斂袵事邊陲。", "自逐定遠侯，亦著短後衣。", "近來能走馬，不弱幷州兒。"]'),
('f1be7622-2154-4000-8e72-fddd66ccd05a','初至西虢官舍南池呈左右省及南宮諸故人','岑參','唐','唐诗','tang','','[]','黜官自西掖，待罪臨下陽。',120,'全唐诗/poet.tang.9000.json','["黜官自西掖，待罪臨下陽。", "空積犬馬戀，豈思鵷鷺行。", "素多江湖意，偶佐山水鄉。", "滿院池月靜，捲簾溪雨涼。", "軒窓竹翠濕，案牘荷花香。", "白鳥上衣桁，青苔生筆牀。", "數公不可見，一別盡相忘。", "敢恨青瑣客，無情華省郎。", "早年迷進退，晚節悟行藏。", "他日能相訪，嵩南舊草堂。"]'),
('5f30f719-46f0-4afa-a81a-b46e457655f8','過梁州奉贈張尚書大夫公','岑參','唐','唐诗','tang','','[]','漢中二良將，今昔各一時。',288,'全唐诗/poet.tang.9000.json','["漢中二良將，今昔各一時。", "韓信此登壇，尚書復來斯。", "手把銅虎符，身總丈人師。", "錯落北斗星，照耀黑水湄。", "英雄若神授，大材濟時危。", "頃歲遇雷雲，精神感靈祇。", "勳業振青史，恩德繼鴻私。", "羌虜昔未平，華陽積僵屍。", "人煙絕墟落，鬼火依城池。", "巴漢空水流，襃斜惟鳥飛。", "自公布德政，此地生光輝。", "百堵創里閭，千家恤惸嫠。", "層城重鼓角，甲士如熊羆。", "坐嘯風自調，行春雨仍隨。", "芃芃麥苗長，藹藹桑葉肥。", "浮客相與來，羣盜不敢窺。", "何幸承嘉惠，小年即相知。", "富貴情易疎，相逢心不移。", "置酒宴高館，嬌歌雜青絲。", "錦席繡拂廬，玉盤金屈巵。", "春景透高戟，江雲篲長麾。", "櫪馬嘶柳陰，美人映花枝。", "門傳大夫印，世擁上將旗。", "承家令名揚，許國苦節施。"]'),
('cc4df0e9-5056-4457-9d2d-2699416cb6c8','登北庭北樓呈幕中諸公','岑參','唐','唐诗','tang','','[]','嘗讀西域傳，漢家得輪臺。',120,'全唐诗/poet.tang.9000.json','["嘗讀西域傳，漢家得輪臺。", "古塞千年空，陰山獨崔嵬。", "二庭近西海，六月秋風來。", "日暮上北樓，殺氣凝不開。", "大荒無鳥飛，但見白龍塠。", "舊國眇天末，歸心日悠哉。", "上將新破胡，西郊絕煙埃。", "邊城寂無事，撫劒空徘徊。", "幸得趨幕中，託身廁羣才。", "早知安邊計，未盡平生懷。"]'),
('59d1e9d7-b42a-460c-a2c7-8c7f7c8abc0c','初過隴山途中呈宇文判官','岑參','唐','唐诗','tang','','["\u6218\u58eb", "\u751f\u6d3b", "\u8fb9\u585e"]','一驛過一驛，驛騎如星流。',180,'全唐诗/poet.tang.9000.json','["一驛過一驛，驛騎如星流。", "平明發咸陽，暮及隴山頭。", "隴水不可聽，嗚咽令人愁。", "沙塵撲馬汗，霧露凝貂裘。", "西來誰家子，自道新封侯。", "前月發安西，路上無停留。", "都護猶未到，來時在西州。", "十日過沙磧，終朝風不休。", "馬走碎石中，四蹄皆血流。", "萬里奉王事，一身無所求。", "也知塞垣苦，豈爲妻子謀。", "山口月欲出，先照關城樓。", "谿流與松風，靜夜相颼飀。", "別家賴歸夢，山塞多離憂。", "與子且攜手，不愁前路脩。"]'),
('d7721ae6-c4b9-4a81-9fb5-7e8572d16b19','陪狄員外早秋登府西樓因呈院中諸公','岑參','唐','唐诗','tang','','[]','常愛張儀樓，西山正相當。',168,'全唐诗/poet.tang.9000.json','["常愛張儀樓，西山正相當。", "千峰帶積雪，百里臨城牆。", "煙氛掃晴空，草樹映朝光。", "車馬隘百井，里閈盤二江。", "亞相自登壇，時危安此方。", "威聲振蠻貊，惠化鍾華陽。", "旌節羅廣庭，戈鋌凜秋霜。", "階下貔虎士，幕中鵷鷺行。", "今我忽登臨，顧恩不望鄉。", "知己猶未報，鬢毛颯已蒼。", "時命難自知，功業豈暫忘。", "蟬鳴秋城夕，鳥去江天長。", "兵馬休戰爭，風塵尚蒼茫。", "誰當共攜手，賴有冬官郎。"]'),
('e8c17b80-741c-4b1e-a113-59663326839e','冬夜宿仙遊寺南涼堂呈謙道人','岑參','唐','唐诗','tang','','[]','太乙連太白，兩山知幾重。',216,'全唐诗/poet.tang.9000.json','["太乙連太白，兩山知幾重。", "路盤石門窄，匹馬行才通。", "日西倒山寺，林下逢支公。", "昨夜山北時，星星聞此鐘。", "秦女去已久，仙臺在中峰。", "簫聲不可聞，此地留遺蹤。", "石潭積黛色，每歲投金龍。", "亂流爭迅湍，噴薄如雷風。", "夜來聞清磬，月出蒼山空。", "空山滿清光，水樹相玲瓏。", "迴廊映密竹，秋殿隱深松。", "燈影落前谿，夜宿水聲中。", "愛茲林巒好，結宇向谿東。", "相識唯山僧，鄰家一釣翁。", "林晚栗初拆，枝寒梨已紅。", "物幽興易愜，事勝趣彌濃。", "願謝區中緣，永依金人宮。", "寄報乘輦客，簪裾爾何容。"]'),
('0a419c9e-d1ad-4f57-b636-672095a86f3b','潼關鎮國軍句覆使院早春寄王同州','岑參','唐','唐诗','tang','','[]','胡寇尚未盡，大軍鎮關門。',144,'全唐诗/poet.tang.9000.json','["胡寇尚未盡，大軍鎮關門。", "旌旗遍草木，兵馬如雲屯。", "聖朝正用武，諸將皆承恩。", "不見征戰功，但聞歌吹喧。", "儒生有長策，閉口不敢言。", "昨從關東來，思與故人論。", "何爲廊廟器，至今居外藩。", "黃霸寧淹留，蒼生望騰鶱。", "卷簾見西岳，仙掌明朝暾。", "昨夜聞春風，戴勝過後園。", "各自限官守，何由敘涼溫。", "離憂不可忘，襟背思樹萱。"]'),
('b28661ed-66ab-4aae-a48d-43d551d0d933','青山峽口泊舟懷狄侍御','岑參','唐','唐诗','tang','','[]','峽口秋水壯，沙邊且停橈。',144,'全唐诗/poet.tang.9000.json','["峽口秋水壯，沙邊且停橈。", "奔濤振石壁，峰勢如動搖。", "九月蘆花新，彌令客心焦。", "誰念在江島，故人滿天朝。", "無處豁心胸，憂來醉能銷。", "往來巴山道，三見秋草彫。", "狄生新相知，才調凌雲霄。", "賦詩析造化，入幕生風飆。", "把筆判甲兵，戰士不敢驕。", "皆云梁公後，遇鼎還能調。", "離別倏經時，音塵殊寂寥。", "何當見夫子，不歎鄉關遙。"]'),
('f25d4cb7-db31-40c4-9cd7-920435bef9ce','寄青城龍谿奐道人','岑參','唐','唐诗','tang','','[]','五嶽之丈人，西望青瞢瞢。',108,'全唐诗/poet.tang.9000.json','["五嶽之丈人，西望青瞢瞢。", "雲開露崖嶠，百里見石稜。", "龍谿盤中峰，上有蓮華僧。", "絕頂小蘭若，四時嵐氣凝。", "身同雲虛無，心與谿清澄。", "誦戒龍每聽，賦詩人則稱。", "杉風吹袈裟，石壁懸孤燈。", "久欲謝微祿，誓將歸大乘。", "願聞開士說，庶以心相應。"]'),
('c5351c2c-243c-4630-a4f6-c6bd98dc6860','梁州對雨懷麴二秀才便呈麴大判官時疾贈余新詩','岑參','唐','唐诗','tang','','[]','江上雲氣黑，𡷛山昨夜雷。',132,'全唐诗/poet.tang.9000.json','["江上雲氣黑，𡷛山昨夜雷。", "水惡平明飛，雨從嶓冢來。", "濛濛隨風過，蕭颯鳴庭槐。", "隔簾濕衣巾，當暑涼幽齋。", "麴生住相近，言語阻且乖。", "臥疾不見人，午時門始開。", "終日看本草，藥苗滿前堦。", "兄弟早有名，甲科皆秀才。", "二人事慈母，不弱古老萊。", "昨歎攜手遲，未盡平生懷。", "愛君有佳句，一日吟幾迴。"]'),
('093a4462-a81f-40b5-b2eb-a02f1682271c','潼關使院懷王七季友','岑參','唐','唐诗','tang','','[]','王生今才子，時輩咸所仰。',96,'全唐诗/poet.tang.9000.json','["王生今才子，時輩咸所仰。", "何當見顏色，終日勞夢想。", "驅車到關下，欲往阻河廣。", "滿日徒春華，思君罷心賞。", "開門見太華，朝日映高掌。", "忽覺蓮花峰，別來更如長。", "無心顧微祿，有意在獨往。", "不負林中期，終當出塵網。"]'),
('1b0019bd-e3e0-437c-bdf2-e5a819c3b314','至大梁却寄匡城主人','岑參','唐','唐诗','tang','','["\u5199\u4eba", "\u54c1\u683c", "\u5199\u666f", "\u5199\u4eba\u8bd7"]','一從棄魚釣，十載干明王。',120,'全唐诗/poet.tang.9000.json','["一從棄魚釣，十載干明王。", "無由謁天階，却欲歸滄浪。", "仲秋至東郡，遂見天雨霜。", "昨日夢故山，蕙草色已黃。", "平明辭鐵丘，薄暮遊大梁。", "仲秋蕭條景，拔刺飛鵝鶬。", "四郊陰氣閉，萬里無晶光。", "長風吹白茅，野火燒枯桑。", "故人南燕吏，籍籍名更香。", "聊以玉壺贈，置之君子堂。"]'),
('52ce2e8b-37ae-4dc2-b1f5-bf257ffbe51d','宿華陰東郭客舍憶閻防','岑參','唐','唐诗','tang','','[]','次舍山郭近，解鞍鳴鐘時。',72,'全唐诗/poet.tang.9000.json','["次舍山郭近，解鞍鳴鐘時。", "主人炊新粒，行子充夜飢。", "關月生首陽，照見華陰祠。", "蒼茫秋山晦，蕭瑟寒松悲。", "久從園廬別，遂與朋知辭。", "舊壑蘭杜晚，歸軒今已遲。"]'),
('a0a108f5-821c-42c2-bbcc-1369e9e30764','宿東谿王屋李隱者','岑參','唐','唐诗','tang','','[]','山店不鑿井，百家同一泉。',48,'全唐诗/poet.tang.9000.json','["山店不鑿井，百家同一泉。", "晚來南村黑，雨色和人煙。", "霜畦吐寒菜，沙鴈噪河田。", "隱者不可見，天壇飛鳥邊。"]'),
('a09ccee7-816d-49a2-998e-c25782c69cb1','郊行寄杜位','岑參','唐','唐诗','tang','','[]','崷崪空城煙，淒清寒山景。',48,'全唐诗/poet.tang.9000.json','["崷崪空城煙，淒清寒山景。", "秋風引歸夢，昨夜到汝潁。", "近寺聞鐘聲，映陂見樹影。", "所思何由見，東北徒引領。"]'),
('916ae70b-5bcd-42b2-9d84-d1000dd6a07f','懷葉縣關操姚曠韓涉李叔齊','岑參','唐','唐诗','tang','','[]','數子皆故人，一時吏宛葉。',48,'全唐诗/poet.tang.9000.json','["數子皆故人，一時吏宛葉。", "經年總不見，書札徒滿篋。", "斜日半空庭，旋風走梨葉。", "去君千里地，言笑何時接。"]'),
('5af598c7-93ad-448c-bb5b-19ed6bbbce58','西蜀旅舍春歎寄朝中故人呈狄評事','岑參','唐','唐诗','tang','','[]','春與人相乖，柳青頭轉白。',192,'全唐诗/poet.tang.9000.json','["春與人相乖，柳青頭轉白。", "生平未得意，覽鏡私自惜。", "四海猶未安，一身無所適。", "自從兵戈動，遂覺天地窄。", "功業悲後時，光陰歎虛擲。", "却爲文章累，幸有開濟策。", "何負當途人，無心矜窘厄。", "回瞻後來者，皆欲肆轥轢。", "起草思南宮，寄言憶西掖。", "時危任舒卷，身退知損益。", "窮巷草轉深，閑門日將夕。", "橋西暮雨黑，籬外春江碧。", "昨者初識君，相看俱是客。", "聲華同道術，世業通往昔。", "早須歸天階，不得安孔席。", "吾先稅歸鞅，舊國如咫尺。"]'),
('64c3300d-73dd-4024-9e2b-0bab33293496','太白東溪張老舍即事寄舍弟姪等','岑參','唐','唐诗','tang','','[]','渭上秋雨過，北風何騷騷。',96,'全唐诗/poet.tang.9000.json','["渭上秋雨過，北風何騷騷。", "天晴諸山出，太白峰最高。", "主人東溪老，兩耳生長毫。", "遠近知百歲，子孫皆二毛。", "中庭井蘭上，一架獮猴桃。", "石泉飯香粳，酒甕開新槽。", "愛茲田中趣，始悟世上勞。", "我行有勝事，書此寄爾曹。"]'),
('b0b43182-da20-43f9-9f94-83e45d4c4050','上嘉州青衣山中峰題惠淨上人幽居寄兵部楊郎中','岑參','唐','唐诗','tang','','["\u5e90\u5c71"]','青衣誰開鑿，獨在水中央。',192,'全唐诗/poet.tang.9000.json','["青衣誰開鑿，獨在水中央。", "浮舟一躋攀，側逕緣穹蒼。", "絕頂詣老僧，豁然登上方。", "諸嶺一何小，三江奔茫茫。", "蘭若向西開，峨眉正相當。", "猿鳥樂鐘磬，松蘿泛天香。", "江雲入袈裟，山月吐繩牀。", "早知清淨理，久乃機心忘。", "尚以名宦拘，聿來夷獠鄉。", "吾友不可見，鬱爲尚書郎。", "早歲愛丹經，留心向青囊。", "渺渺雲智遠，幽幽海懷長。", "勝賞欲與俱，引領遙相望。", "爲政媿無術，分憂幸時康。", "君子滿天朝，老夫憶滄浪。", "況值廬山遠，抽簪歸法王。"]'),
('1bad4e4c-2743-4e74-898f-686a36ef8989','入劒門作寄杜楊二郎中時二公並爲杜元帥判官','岑參','唐','唐诗','tang','','[]','不知造化初，此山誰開坼。',240,'全唐诗/poet.tang.9000.json','["不知造化初，此山誰開坼。", "雙崖倚天立，萬仞從地劈。", "雲飛不到頂，鳥去難過壁。", "速駕畏巖傾，單行愁路窄。", "平明地仍黑，停午日暫赤。", "凜凜三伏寒，巉巉五丁迹。", "與時忽開閉，作固或順逆。", "磅礴跨岷峨，巍蟠限蠻貊。", "星當觜參分，地處西南僻。", "陡覺煙景殊，杳將華夏隔。", "劉氏昔顛覆，公孫曾敗績。", "始知德不脩，恃此險何益。", "相公總師旅，遠近罷金革。", "杜母來何遲，蜀人應更惜。", "暫回丹青慮，少用開濟策。", "二友華省郎，俱爲幕中客。", "良籌佐戎律，精理皆碩畫。", "高文出詩騷，奧學窮討賾。", "聖朝無外戶，寰宇被德澤。", "四海今一家，徒然劒門石。"]'),
('472882fa-ac49-477b-a7f9-61337a5f436f','鞏北秋興寄崔明允','岑參','唐','唐诗','tang','','["\u601d\u5ff5", "\u79cb\u5929"]','白露披梧桐，玄蟬晝夜號。',72,'全唐诗/poet.tang.9000.json','["白露披梧桐，玄蟬晝夜號。", "秋風萬里動，日暮黃雲高。", "君子佐休明，小人事蓬蒿。", "所適在魚鳥，焉能徇錐刀。", "孤舟向廣武，一鳥歸成臯。", "勝概日相與，思君心鬱陶。"]'),
('9fe04a44-cbf9-497a-9e90-9f1b877e4398','春遇南使貽趙知音','岑參','唐','唐诗','tang','','[]','端居春心醉，襟背思樹萱。',72,'全唐诗/poet.tang.9000.json','["端居春心醉，襟背思樹萱。", "美人在南州，爲爾歌北門。", "北風吹煙物，戴勝鳴中園。", "枯楊長新條，芳草滋舊根。", "網絲結寶琴，塵埃被空樽。", "適遇江海信，聊與南客論。"]'),
('bccdfe82-5844-42f7-87a4-ed22c385f72c','冀州客舍酒酣貽王綺寄題南樓','岑參','唐','唐诗','tang','','[]','夫子傲常調，詔書下徵求。',192,'全唐诗/poet.tang.9000.json','["夫子傲常調，詔書下徵求。", "知君欲謁帝，秣馬趨西周。", "逸足何駸駸，美聲實風流。", "學富贍清詞，下筆不能休。", "君家一何盛，赫奕難爲儔。", "伯父四五人，同時爲諸侯。", "憶昨始相值，值君客貝丘。", "相看復乘興，攜手到冀州。", "前日在南縣，與君上北樓。", "野曠不見山，白日落草頭。", "客舍梨花繁，深花隱鳴鳩。", "南鄰新酒熟，有女彈箜篌。", "醉後或狂歌，酒醒滿離憂。", "主人不相識，此地難淹留。", "吾廬終南下，堪與王孫遊。", "何當肯相尋，澧上一孤舟。"]'),
('2bbc6eab-07e3-4735-a4f5-02553e20c5c2','終南雲際精舍尋法澄上人不遇歸高冠東潭石淙望秦嶺微雨作貽友人','岑參','唐','唐诗','tang','','[]','昨夜雲際宿，旦從西峰回。',108,'全唐诗/poet.tang.9000.json','["昨夜雲際宿，旦從西峰回。", "不見林中僧，微雨潭上來。", "諸峰皆青翠，秦嶺獨不開。", "石鼓有時鳴，秦王安在哉。", "東南雲開處，突兀獮猴臺。", "崖口懸瀑流，半空白皚皚。", "噴壁四時雨，傍村終日雷。", "北瞻長安道，日夕生塵埃。", "若訪張仲蔚，衡門滿蒿萊。"]'),
('8c8dbeec-c8f3-4fbe-8621-e571aa2edcb5','敬酬杜華淇上見贈兼呈熊曜','岑參','唐','唐诗','tang','','[]','杜侯實才子，盛名不可及。',168,'全唐诗/poet.tang.9000.json','["杜侯實才子，盛名不可及。", "祗曾效一官，今已年四十。", "是君同時者，已有尚書郎。", "憐君獨未遇，淹泊在他鄉。", "我從京師來，到此喜相見。", "共論窮途事，不覺淚滿面。", "憶昨癸未歲，吾兄自江東。", "得君江湖詩，骨氣凌謝公。", "熊生尉淇上，開館常待客。", "喜我二人來，歡笑朝復夕。", "縣樓壓春岸，戴勝鳴花枝。", "吾徒在舟中，縱酒兼彈棊。", "三月猶未還，寒愁滿春草。", "賴蒙瑤華贈，諷詠慰懷抱。"]'),
('ffc4b9fb-e4d3-4834-a32b-421e7447aec7','酬成少尹駱谷行見呈','岑參','唐','唐诗','tang','','[]','聞君行路難，惆悵臨長衢。',228,'全唐诗/poet.tang.9000.json','["聞君行路難，惆悵臨長衢。", "豈不憚險艱，王程剩相拘。", "憶昨蓬萊宮，新授刺史符。", "明主仍賜衣，價直千萬餘。", "何幸承命日，得與夫子俱。", "攜手出華省，連鑣赴長途。", "五馬當路嘶，按節投蜀都。", "千崖信縈折，一徑何盤紆。", "層冰滑征輪，密竹礙隼旟。", "深林迷昏旦，棧道凌空虛。", "飛雪縮馬毛，烈風擘我膚。", "峰攢望天小，亭午見日初。", "夜宿月近人，朝行雲滿車。", "泉澆石罅坼，火入松心枯。", "亞尹同心者，風流賢大夫。", "榮祿上及親，之官隨板輿。", "高價振臺閣，清詞出應徐。", "成都春酒香，且用俸錢沽。", "浮名何足道，海上堪乘桴。"]'),
('bb46a46b-7333-4bd7-a0b9-c2ae942ad5a1','虢中酬陝西甄判官見贈','岑參','唐','唐诗','tang','','[]','微才棄散地，拙宦慙清時。',144,'全唐诗/poet.tang.9000.json','["微才棄散地，拙宦慙清時。", "白髮徒自負，青雲難可期。", "胡塵暗東洛，亞相方出師。", "分陝振鼓鼙，二崤滿旌旗。", "夫子廊廟器，迥然青冥姿。", "閫外佐戎律，幕中吐兵奇。", "前者驛使來，忽枉行軍詩。", "晝吟庭花落，夜諷山月移。", "昔君隱蘇門，浪跡不可羈。", "詔書自徵用，令譽天下知。", "別來春草長，東望轉相思。", "寂寞山城暮，空聞畫角悲。"]'),
('25849a42-a664-4d42-915d-62487e326b3c','送許子擢第歸江寧拜親因寄王大昌齡','岑參','唐','唐诗','tang','','[]','建業控京口，金陵款滄溟。',276,'全唐诗/poet.tang.9000.json','["建業控京口，金陵款滄溟。", "君家臨秦淮，傍對石頭城。", "十年自勤學，一鼓遊上京。", "青春登甲科，動地聞香名。", "解榻皆五侯，結交盡羣英。", "六月槐花飛，忽思蓴菜羹。", "跨馬出國門，丹陽返柴荆。", "楚雲引歸帆，淮水浮客程。", "到家拜親時，入門有光榮。", "鄉人盡來賀，置酒相邀迎。", "閑眺北顧樓，醉眠湖上亭。", "月從海門出，照見茅山青。", "昔爲帝王州，今幸天地平。", "五朝變人世，千載空江聲。", "玄元告靈符，丹洞獲其銘。", "皇帝受玉冊，羣臣羅天庭。", "喜氣薄太陽，祥光徹窅冥。", "奔走朝萬國，崩騰集百靈。", "王兄尚謫宦，屢見秋雲生。", "孤城帶後湖，心與湖水清。", "一縣無諍辭，有時開道經。", "黃鶴垂兩翅，徘徊但悲鳴。", "相思不可見，空望牛女星。"]'),
('85667af2-aebc-4bf5-bae4-e276799fb52e','武威送劉單判官赴安西行營便呈高開府','岑參','唐','唐诗','tang','','[]','熱海亙鐵門，火山赫金方。',288,'全唐诗/poet.tang.9000.json','["熱海亙鐵門，火山赫金方。", "白草磨天涯，湖沙奔茫茫。", "夫子佐戎幕，其鋒利如霜。", "中歲學兵符，不能守文章。", "功業須及時，立身有行藏。", "男兒感忠義，萬里忘越鄉。", "孟夏邊候遲，胡國草木長。", "馬疾過飛鳥，天窮超夕陽。", "都護新出師，五月發軍裝。", "甲兵二百萬，錯落黃金光。", "揚旗拂崑崙，伐鼓震蒲昌。", "太白引官軍，天威臨大荒。", "西望雲似蛇，戎夷知喪亡。", "渾驅大宛馬，繫取樓蘭王。", "曾到交河城，風土斷人腸。", "寒驛遠如點，邊烽互相望。", "赤亭多飃風，鼓怒不可當。", "有時無人行，沙石亂飄揚。", "夜靜天蕭條，鬼哭夾道傍。", "地上多髑髏，皆是古戰場。", "置酒高館夕，邊城月蒼蒼。", "軍中宰肥牛，堂上羅羽觴。", "紅淚金燭盤，嬌歌豔新妝。", "望君仰青冥，短翮難可翔。"]'),
('6f4c5101-f4f8-470c-97cc-aa67d313658c','送王大昌齡赴江寧','岑參','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b", "\u795d\u798f", "\u6000\u624d\u4e0d\u9047"]','對酒寂不語，悵然悲送君。',144,'全唐诗/poet.tang.9000.json','["對酒寂不語，悵然悲送君。", "明時未得用，白首徒攻文。", "澤國從一官，滄波幾千里。", "羣公滿天闕，獨去過淮水。", "舊家富春渚，嘗憶臥江樓。", "自聞君欲行，頻望南徐州。", "窮巷獨閉門，寒燈靜深屋。", "北風吹微雪，抱被肯同宿。", "君行到京口，正是桃花時。", "舟中饒孤興，湖上多新詩。", "潛虯且深蟠，黃鵠舉未晚。", "惜君青雲器，努力加餐飯。"]'),
('a16ba513-8718-4ac8-9e1a-2af11487636e','送祈樂歸河東','岑參','唐','唐诗','tang','','[]','祁樂後來秀，挺身出河東。',156,'全唐诗/poet.tang.9000.json','["祁樂後來秀，挺身出河東。", "往年詣驪山，獻賦溫泉宮。", "天子不召見，揮鞭遂從戎。", "前月還長安，囊中金已空。", "有時忽乘興，畫出江上峰。", "牀頭蒼梧雲，簾下天台松。", "忽如高堂上，颯颯生清風。", "五月火雲屯，氣燒天地紅。", "鳥且不敢飛，子行如轉蓬。", "少華與首陽，隔河勢爭雄。", "新月河上出，清光滿關中。", "置酒灞亭別，高歌披心胸。", "君到故山時，爲謝五老翁。"]'),
('f6ea9a3b-2112-4d16-a7f7-e4bdf913a3e1','北庭貽宗學士道別','岑參','唐','唐诗','tang','','[]','萬事不可料，歎君在軍中。',180,'全唐诗/poet.tang.9000.json','["萬事不可料，歎君在軍中。", "讀書破萬卷，何事來從戎。", "曾逐李輕車，西征出太蒙。", "荷戈月窟外，擐甲崑崙東。", "兩度皆破胡，朝廷輕戰功。", "十年祗一命，萬里如飄蓬。", "容鬢老胡塵，衣裘脆邊風。", "忽來輪臺下，相見披心胸。", "飲酒對春草，彈棊聞夜鐘。", "今且還龜茲，臂上懸角弓。", "平沙向旅館，匹馬隨飛鴻。", "孤城倚大磧，海氣迎邊空。", "四月猶自寒，天山雪濛濛。", "君有賢主將，何謂泣途窮。", "時來整六翮，一舉凌蒼穹。"]'),
('dcbc6ae9-8edb-4965-95f5-c438601feb85','送許拾遺恩歸江寧拜親','岑參','唐','唐诗','tang','','[]','詔書下青瑣，駟馬還吳洲。',144,'全唐诗/poet.tang.9000.json','["詔書下青瑣，駟馬還吳洲。", "束帛仍賜衣，恩波漲滄流。", "微祿將及親，向家非遠遊。", "看君五斗米，不謝萬戶侯。", "適出西掖垣，如到南徐州。", "歸心望海日，鄉夢登江樓。", "大江盤金陵，諸山橫石頭。", "楓樹隱茅屋，橘林繫漁舟。", "種藥疏故畦，釣魚垂舊鈎。", "對月京口夕，觀濤海門秋。", "天子憐諫官，論事不可休。", "早來丹墀下，高駕無淹留。"]'),
('89ef5d9b-c0ea-4fc9-899f-941ff0c06830','虢州郡齋南池幽興因與閻二侍御道別','岑參','唐','唐诗','tang','','[]','池色淨天碧，水涼雨淒淒。',168,'全唐诗/poet.tang.9000.json','["池色淨天碧，水涼雨淒淒。", "快風從東南，荷葉翻向西。", "性本愛魚鳥，未能返巖谿。", "中歲徇微官，遂令心賞睽。", "及茲佐山郡，不異尋幽棲。", "小吏趨竹徑，訟庭侵藥畦。", "胡塵暗河洛，二陝震鼓鼙。", "故人佐戎軒，逸翮凌雲霓。", "行軍在函谷，兩度聞鶯啼。", "相看紅旗下，飲酒白日低。", "聞君欲朝天，駟馬臨道嘶。", "仰望浮與沈，忽如雲與泥。", "夜眠驛樓月，曉發關城雞。", "惆悵西郊暮，鄉書對君題。"]'),
('36e31945-0de1-4cb6-9948-2e16fc32ecc8','青龍招提歸一上人遠遊吳楚別詩','岑參','唐','唐诗','tang','','[]','久交應真侶，最歎青龍僧。',192,'全唐诗/poet.tang.9000.json','["久交應真侶，最歎青龍僧。", "棄官向二年，削髮歸一乘。", "了然瑩心身，潔念樂空寂。", "名香泛牕戶，幽磬清曉夕。", "往年仗一劒，由是佐二庭。", "於焉久從戎，兼復解論兵。", "世人猶未知，天子願相見。", "朝從青蓮宇，暮入白虎殿。", "宮女擎錫杖，御筵出香爐。", "說法開藏經，論邊窮陣圖。", "忘機厭塵喧，浪迹向江海。", "思師石可訪，惠遠峰猶在。", "今旦飛錫去，何時持鉢還。", "湖煙冷吳門，淮月銜楚山。", "一身如浮雲，萬里過江水。", "相思眇天末，南望無窮已。"]'),
('ad00d03e-77ae-4459-82a1-6e5430e5d3b6','送李翥遊江外','岑參','唐','唐诗','tang','','[]','相識應十載，見君只一官。',120,'全唐诗/poet.tang.9000.json','["相識應十載，見君只一官。", "家貧祿尚薄，霜降衣仍單。", "惆悵秋草死，蕭條芳歲闌。", "且尋滄洲路，遙指吳雲端。", "匹馬關塞遠，孤舟江海寬。", "夜眠楚煙濕，曉飯湖山寒。", "砧淨紅鱠落，袖香朱橘團。", "帆前見禹廟，枕底聞嚴灘。", "便獲賞心趣，豈歌行路難。", "青門須醉別，少爲解征鞍。"]'),
('be42f392-f4eb-4aff-b047-eea46f845f25','送王著作赴淮西幕府','岑參','唐','唐诗','tang','','[]','燕子與百勞，一西復一東。',192,'全唐诗/poet.tang.9000.json','["燕子與百勞，一西復一東。", "天空信寥廓，翔集何時同。", "知己悵難遇，良朋非易逢。", "憐君心相親，與我家又通。", "言笑日無度，書札凡幾封。", "湛湛萬頃陂，森森千丈松。", "不知有機巧，無事干心胸。", "滿堂皆酒徒，豈復羨王公。", "早年抱將略，累歲依幕中。", "昨者從淮西，歸來奏邊功。", "承恩長樂殿，醉出明光宮。", "逆旅悲寒蟬，客夢驚飛鴻。", "發家見春草，却去聞秋風。", "月色冷楚城，淮光透霜空。", "各自務功業，當須激深衷。", "別後能相思，何嗟山水重。"]'),
('409c2864-271b-4d97-a1da-4a8baf032136','送張秘書充劉相公通汴河判官便赴江外覲省','岑參','唐','唐诗','tang','','[]','前年見君時，見君正泥蟠。',194,'全唐诗/poet.tang.9000.json','["前年見君時，見君正泥蟠。", "去年見君處，見君已風[摶]。", "朝趨赤墀前，高視青雲端。", "新登麒麟閣，適脫獬豸冠。", "劉公領舟楫，汴水揚波瀾。", "萬里江海通，九州天地寬。", "昨夜動使星，今旦送征鞍。", "老親在吳郡，令弟雙同官。", "鱸鱠賸堪憶，蓴羹殊可餐。", "既參幕中畫，復展膝下歡。", "因送故人行，試歌行路難。", "何處路最難，最難在長安。", "長安多權貴，珂珮聲珊珊。", "儒生直如弦，權貴不須干。", "斗酒取一醉，孤琴爲君彈。", "臨岐欲有贈，持以握中蘭。"]'),
('1d101f32-fe42-4d24-b83a-b00b0a23ba8c','冬宵家會餞李郎司兵赴同州','岑參','唐','唐诗','tang','','["\u534e\u5c71"]','急管雜青絲，玉瓶金屈巵。',168,'全唐诗/poet.tang.9000.json','["急管雜青絲，玉瓶金屈巵。", "寒天高堂夜，撲地飛雪時。", "賀君關西掾，新綬腰下垂。", "白面皇家郎，逸翮青雲姿。", "明旦之官去，他辰良會稀。", "惜別冬夜短，務歡盃行遲。", "季女猶自小，老夫未令歸。", "且看匹馬行，不得鳴鳳飛。", "昔歲到馮翊，人煙接京師。", "曾上月樓頭，遙見西嶽祠。", "沙苑逼官舍，蓮峰壓城池。", "多暇或自公，讀書復彈棊。", "州縣信徒勞，雲霄亦可期。", "應須力爲政，聊慰此相思。"]'),
('8f16a15a-54fd-41bc-8302-167f7d94399d','送顏平原','岑參','唐','唐诗','tang','','[]','天子念黎庶，詔書換諸侯。',180,'全唐诗/poet.tang.9000.json','["天子念黎庶，詔書換諸侯。", "仙郎授剖符，華省輟分憂。", "置酒會前殿，賜錢若山丘。", "天章降三光，聖澤該九州。", "吾兄鎮河朔，拜命宣皇猷。", "駟馬辭國門，一星東北流。", "夏雲照銀印，暑雨隨行輈。", "赤筆仍在篋，鑪香惹衣裘。", "此地鄰東溟，孤城弔滄洲。", "海風掣金戟，道吏呼鳴騶。", "郊原北連燕，剽劫風未休。", "魚鹽隘里巷，桑柘盈田疇。", "爲郡豈淹旬，政成應未秋。", "易俗去猛虎，化人似馴鷗。", "蒼生已望君，黃霸寧久留。"]'),
('c0fa8e6b-0422-4a12-9311-8c931d5657c2','送狄員外巡按西山軍','岑參','唐','唐诗','tang','','[]','兵馬守西山，中國非得計。',132,'全唐诗/poet.tang.9000.json','["兵馬守西山，中國非得計。", "不知何代策，空使蜀人弊。", "八州崖谷深，千里雲雪閉。", "泉澆閣道滑，水凍繩橋脆。", "戰士常苦飢，糗粮不相繼。", "胡兵猶不歸，空山積年歲。", "儒生識損益，言事皆審諦。", "狄子幕府郎，有謀必康濟。", "胸中懸明鏡，照耀無巨細。", "莫辭冒險艱，可以裨節制。", "相思江樓夕，愁見月澄霽。"]'),
('d543fbde-e2c5-4d37-aaae-c9df0fd3df65','虢州送鄭興宗弟歸扶風別廬','岑參','唐','唐诗','tang','','[]','佐郡已三載，豈能長後時。',84,'全唐诗/poet.tang.9000.json','["佐郡已三載，豈能長後時。", "出關少親友，賴汝常相隨。", "今旦忽言別，愴然俱淚垂。", "平生滄洲意，獨有青山知。", "州縣不敢說，雲霄誰敢期。", "因懷東谿老，最憶南峰緇。", "爲我多種藥，還山應未遲。"]'),
('d8b581ae-5778-4e40-8bc0-2c3fa3767944','澧頭送蔣侯','岑參','唐','唐诗','tang','','[]','君住澧水北，我家澧水西。',48,'全唐诗/poet.tang.9000.json','["君住澧水北，我家澧水西。", "兩村辨喬木，五里聞鳴雞。", "飲酒溪雨過，彈棊山月低。", "徒聞蔣生徑，爾去誰相攜。"]'),
('0c0909fb-47ab-48d7-81d6-1c92db828a6f','送永壽王贊府逕歸縣','岑參','唐','唐诗','tang','','[]','當官接閑暇，暫得歸林泉。',48,'全唐诗/poet.tang.9000.json','["當官接閑暇，暫得歸林泉。", "百里路不宿，兩鄉山復連。", "夜深露濕簟，月出風驚蟬。", "且盡主人酒，爲君從醉眠。"]'),
('c2ffc9dd-697f-4fb4-9108-dc7772317111','南池宴餞辛子賦得蝌斗子','岑參','唐','唐诗','tang','','[]','臨池見蝌斗，羨爾樂有餘。',36,'全唐诗/poet.tang.9000.json','["臨池見蝌斗，羨爾樂有餘。", "不憂網與釣，幸得免爲魚。", "且願充文字，登君尺素書。"]'),
('09abdb47-df32-4c61-8835-624e2b018077','登嘉州凌雲寺作','岑參','唐','唐诗','tang','','[]','寺出飛鳥外，青峰戴朱樓。',132,'全唐诗/poet.tang.9000.json','["寺出飛鳥外，青峰戴朱樓。", "搏壁躋半空，喜得登上頭。", "始知宇宙闊，下看三江流。", "天晴見峨眉，如向波上浮。", "迥曠煙景豁，陰森椶枏稠。", "願割區中緣，永從塵外遊。", "迴風吹虎穴，片雨當龍湫。", "僧房雲濛濛，夏月寒颼颼。", "回合俯近郭，寥落見遠舟。", "勝概無端倪，天宮可淹留。", "一官詎足道，欲去令人愁。"]'),
('93d82a12-5e4d-45c2-b837-d0c54447fba3','與高適薛據慈恩寺浮圖','岑參','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u666f\u70b9", "\u5199\u666f", "\u5fe7\u601d", "\u5199\u5854"]','塔勢如湧出，孤高聳天宮。',132,'全唐诗/poet.tang.9000.json','["塔勢如湧出，孤高聳天宮。", "登臨出世界，磴道盤虛空。", "突兀壓神州，崢嶸如鬼工。", "四角礙白日，七層摩蒼穹。", "下窺指高鳥，俯聽聞驚風。", "連山若波濤，奔湊似朝東。", "青槐夾馳道，宮館何玲瓏。", "秋色從西來，蒼然滿關中。", "五陵北原上，萬古青濛濛。", "淨理了可悟，勝因夙所宗。", "誓將挂冠去，覺道資無窮。"]'),
('1d015d5d-e928-4a58-8897-b42765cefc31','登千福寺楚金禪師法華院多寶塔','岑參','唐','唐诗','tang','','["\u6cf0\u5c71"]','多寶滅已久，蓮華付吾師。',120,'全唐诗/poet.tang.9000.json','["多寶滅已久，蓮華付吾師。", "寶塔凌太空，忽如湧出時。", "數年功不成，一志堅自持。", "明主親夢見，世人今始知。", "千家獻黃金，萬匠磨琉璃。", "既空泰山木，亦罄天府貲。", "焚香如雲屯，蟠蓋珊珊垂。", "悉窣神繞護，衆魔不敢窺。", "作禮覩靈境，焚香方證疑。", "庶割區中緣，脫身恆在茲。"]'),
('c5847653-9150-4041-929e-b97ff6516554','出關經華嶽寺訪法華雲公','岑參','唐','唐诗','tang','','["\u534e\u5c71"]','野寺聊解鞍，偶見法華僧。',120,'全唐诗/poet.tang.9000.json','["野寺聊解鞍，偶見法華僧。", "開門對西嶽，石壁青稜層。", "竹徑厚蒼苔，松門盤紫藤。", "長廊列古畫，高殿懸孤燈。", "五月山雨熱，三峰火雲蒸。", "側聞樵人言，深谷猶積冰。", "久願尋此山，至今嗟未能。", "謫官忽東走，王程苦相仍。", "欲去戀雙樹，何由窮一乘。", "月輪吐山郭，夜色空清澄。"]'),
('5057de82-fb98-474d-9b78-e76138f6ff59','春半與羣公同遊元處士別業','岑參','唐','唐诗','tang','','[]','郭南處士宅，門外羅羣峰。',96,'全唐诗/poet.tang.9000.json','["郭南處士宅，門外羅羣峰。", "勝概忽相引，春華今正濃。", "山廚竹裏爨，野碓藤間舂。", "對酒雲數片，捲簾花萬重。", "巖泉嗟到晚，州縣欲歸慵。", "草色帶朝雨，灘聲兼夜鐘。", "愛茲清俗慮，何事老塵容。", "況有林下約，轉懷方外蹤。"]'),
('da22ce8d-121e-4d5d-b2d4-7b4684b19bdd','陪羣公龍岡寺泛舟','岑參','唐','唐诗','tang','','[]','漢水天一色，寺樓波底看。',72,'全唐诗/poet.tang.9000.json','["漢水天一色，寺樓波底看。", "鐘鳴長空夕，月出孤舟寒。", "映酒見山火，隔簾聞夜灘。", "紫鱗掣芳餌，紅燭然金盤。", "良友興正愜，勝遊情未闌。", "此中堪倒載，須盡主人歡。"]'),
('26328360-9008-44f2-8c81-8cfd2097f669','終南山雙峰草堂作','岑參','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','斂跡歸山田，息心謝時輩。',144,'全唐诗/poet.tang.9000.json','["斂跡歸山田，息心謝時輩。", "晝還草堂臥，但與雙峰對。", "興來恣佳遊，事愜符勝槩。", "著書高牕下，日夕見城內。", "曩爲世人誤，遂負平生愛。", "久與林壑辭，及來松杉大。", "偶茲近精廬，屢得名僧會。", "有時逐樵漁，盡日不冠帶。", "崖口上新月，石門破蒼靄。", "色向羣木深，光搖一潭碎。", "緬懷鄭生谷，頗憶嚴子瀨。", "勝事猶可追，斯人邈千載。"]'),
('84bfdc76-9061-4af1-990b-617bca9bd33f','左僕射相國冀公東齋幽居','岑參','唐','唐诗','tang','','[]','丞相百僚長，兩朝居此官。',122,'全唐诗/poet.tang.9000.json','["丞相百僚長，兩朝居此官。", "成功雲雷際，翊聖天地安。", "不矜南宮貴，祗向東山看。", "宅占鳳城勝，牕中雲嶺寬。", "午時松軒夕，六月藤齋寒。", "玉珮罥女蘿，金印耀牡丹。", "山蟬上衣桁，野鼠緣藥盤。", "有時披道書，竟日不著冠。", "幸得趨省闈，常欣在門闌。", "何當復持衡，短翮期風[摶]。"]'),
('fc8561fc-e31a-4601-a247-988488ca72be','過緱山王處士黑石谷隱居','岑參','唐','唐诗','tang','','[]','舊居緱山下，偏識緱山雲。',72,'全唐诗/poet.tang.9000.json','["舊居緱山下，偏識緱山雲。", "處士久不還，見雲如見君。", "別來逾十秋，兵馬日紛紛。", "青谿開戰場，黑谷屯行軍。", "遂令巢由輩，遠逐麋鹿羣。", "獨有南澗水，潺湲如昔聞。"]'),
('0786fae3-fe55-4095-b9f9-28675422adce','緱山西峰草堂作','岑參','唐','唐诗','tang','','[]','結廬對中嶽，青翠常在門。',144,'全唐诗/poet.tang.9000.json','["結廬對中嶽，青翠常在門。", "遂耽水木興，盡作漁樵言。", "頃來闕章句，但欲閒心魂。", "日色隱空谷，蟬聲喧暮村。", "曩聞道士語，偶見清淨源。", "隱几閱吹葉，乘秋眺歸根。", "獨遊念求仲，開徑招王孫。", "片雨下南澗，孤峰出東原。", "棲遲慮益澹，脫略道彌敦。", "野靄晴拂枕，客帆遙入軒。", "尚平今何在，此意誰與論。", "佇立雲去盡，蒼蒼月開園。"]'),
('48e2508f-1adb-4fdc-a9c3-af8b164d6c38','觀楚國寺璋上人寫一切經院南有曲池深竹','岑參','唐','唐诗','tang','','[]','璋公不出院，羣木閉深居。',96,'全唐诗/poet.tang.9000.json','["璋公不出院，羣木閉深居。", "誓寫一切經，欲向萬卷餘。", "揮毫散林鵲，研墨警池魚。", "音翻四句偈，字譯五天書。", "鳴鐘竹陰晚，汲水桐花初。", "雨氣潤衣鉢，香煙泛庭除。", "此地日清淨，諸天應未如。", "不知將錫杖，早晚躡空虛。"]'),
('cd8be159-308b-4ee0-a3b8-84a9a15dbdc3','尋鞏縣南李處士別業','岑參','唐','唐诗','tang','','[]','先生近南郭，茅屋臨東川。',48,'全唐诗/poet.tang.9000.json','["先生近南郭，茅屋臨東川。", "桑葉隱村戶，蘆花映釣船。", "有時著書暇，盡日牕中眠。", "且喜閭井近，灌田同一泉。"]'),
('302a3538-2ba1-42ce-be55-f8a3920d4e27','聞崔十二侍御灌口夜宿報恩寺','岑參','唐','唐诗','tang','','[]','聞君尋野寺，便宿支公房。',48,'全唐诗/poet.tang.9000.json','["聞君尋野寺，便宿支公房。", "溪月冷深殿，江雲擁迴廊。", "然燈松林靜，煮茗柴門香。", "勝事不可接，相思幽興長。"]'),
('a3695034-cb53-40cb-9e95-96368130d979','自潘陵尖還少室居止秋夕憑眺','岑參','唐','唐诗','tang','','[]','草堂近少室，夜靜聞風松。',144,'全唐诗/poet.tang.9000.json','["草堂近少室，夜靜聞風松。", "月出潘陵尖，照見十六峰。", "九月山葉赤，谿雲淡秋容。", "火點伊陽村，煙深嵩角鐘。", "尚子不可見，蔣生難再逢。", "勝愜只自知，佳趣爲誰濃。", "昨詣山僧期，上到天壇東。", "向下望雷雨，雲間見回龍。", "夕與人羣疎，轉愛丘壑中。", "心澹水木會，興幽魚鳥通。", "稀微了自釋，出處乃不同。", "況本無宦情，誓將依道風。"]'),
('6aeae05e-ce10-44b3-9aac-ff880bd1077b','南池夜宿思王屋青蘿舊齋','岑參','唐','唐诗','tang','','[]','池上臥煩暑，不櫛復不巾。',72,'全唐诗/poet.tang.9000.json','["池上臥煩暑，不櫛復不巾。", "有時清風來，自謂羲皇人。", "天晴雲歸盡，雨洗月色新。", "公事常不閑，道書日生塵。", "早年家王屋，五別青蘿春。", "安得還舊山，東谿垂釣綸。"]'),
('2f676e64-f490-4806-b4bb-86bd304415e0','過王判官西津所居','岑參','唐','唐诗','tang','','[]','勝迹不在遠，愛君池館幽。',120,'全唐诗/poet.tang.9000.json','["勝迹不在遠，愛君池館幽。", "素懷巖中諾，宛得塵外遊。", "何必到清谿，忽來見滄洲。", "潛移岷山石，暗引巴江流。", "樹密晝先夜，竹深夏已秋。", "沙鳥上筆牀，谿花篲簾鈎。", "夫子賤簪冕，注心向林丘。", "落日出公堂，垂綸乘釣舟。", "賦詩憶楚老，載酒隨江鷗。", "翛然一傲吏，獨在西津頭。"]'),
('528e55a1-c0c1-4091-8667-3bd46c15a26c','因假歸白閣西草堂','岑參','唐','唐诗','tang','','[]','雷聲傍太白，雨在八九峰。',96,'全唐诗/poet.tang.9000.json','["雷聲傍太白，雨在八九峰。", "東望白閣雲，半入紫閣松。", "勝概紛滿目，衡門趣彌濃。", "幸有數畝田，得延二仲蹤。", "早聞達士語，偶與心相通。", "誤徇一微官，還山愧塵容。", "釣竿不復把，野碓無人舂。", "惆悵飛鳥盡，南谿聞夜鐘。"]'),
('dd0a584f-0999-46d9-9ca3-ce92955e138b','題華嚴寺瓌公禪房','岑參','唐','唐诗','tang','','[]','寺南幾十峰，峰翠晴可掬。',60,'全唐诗/poet.tang.9000.json','["寺南幾十峰，峰翠晴可掬。", "朝從老僧飯，昨日崖口宿。", "錫杖倚枯松，繩牀暎深竹。", "東谿草堂路，來往行自熟。", "生事在雲山，誰能復羈束。"]'),
('16a97993-feed-4148-bf82-dacf5fcb71de','東歸留題太常徐卿草堂','岑參','唐','唐诗','tang','','[]','不謝古名將，吾知徐太常。',180,'全唐诗/poet.tang.9000.json','["不謝古名將，吾知徐太常。", "年纔三十餘，勇冠西南方。", "頃曾策匹馬，獨出持兩鎗。", "虜騎無數來，見君不敢當。", "漢將小衛霍，蜀將凌關張。", "卿月益清澄，將星轉光芒。", "復居少城北，遙對岷山陽。", "車馬日盈門，賓客常滿堂。", "曲池蔭高樹，小徑穿叢篁。", "江鳥飛入簾，山雲來到牀。", "題詩芭蕉滑，對酒椶花香。", "諸將射獵時，君在翰墨場。", "聖主賞勳業，邊城最輝光。", "與我情綢繆，相知久芬芳。", "忽作萬里別，東歸三峽長。"]'),
('fb6a8afe-08b7-4182-9867-e8e3eea4d51b','太一石鱉崖口潭舊廬招王學士','岑參','唐','唐诗','tang','','[]','驟雨鳴淅瀝，颼飀谿谷寒。',120,'全唐诗/poet.tang.9000.json','["驟雨鳴淅瀝，颼飀谿谷寒。", "碧潭千餘尺，下見蛟龍蟠。", "石門吞衆流，絕岸呀層巒。", "幽趣倏萬變，奇觀非一端。", "偶逐干祿徒，十年皆小官。", "抱板尋舊圃，弊廬臨迅湍。", "君子滿清朝，小人思挂冠。", "釀酒漉松子，引泉通竹竿。", "何必濯滄浪，不能釣嚴灘。", "此地可遺老，勸君來考槃。"]'),
('384fd5e8-ba72-4a81-8516-32234490db05','林臥','岑參','唐','唐诗','tang','','[]','偶得魚鳥趣，復茲水木涼。',48,'全唐诗/poet.tang.9000.json','["偶得魚鳥趣，復茲水木涼。", "遠峰帶雨色，落日搖川光。", "臼中西山藥，袖裏淮南方。", "唯愛隱几時，獨遊無何鄉。"]'),
('ec37bf03-b0e4-46b7-afd1-af9988d9f07a','驪姬墓下作','岑參','唐','唐诗','tang','','[]','驪姬北原上，閉骨已千秋。',72,'全唐诗/poet.tang.9000.json','["驪姬北原上，閉骨已千秋。", "澮水日東注，惡名終不流。", "獻公恣耽惑，視子如仇讎。", "此事成蔓草，我來逢古丘。", "蛾眉山月苦，蟬鬢野雲愁。", "欲弔二公子，橫汾無輕舟。"]'),
('f2d792d4-690b-483a-9dc9-6c1bc308d479','東歸晚次潼關懷古','岑參','唐','唐诗','tang','','["\u6000\u53e4", "\u6292\u60c5", "\u767b\u9ad8", "\u611f\u6168", "\u9ec4\u6cb3"]','暮春別鄉樹，晚景低津樓。',72,'全唐诗/poet.tang.9000.json','["暮春別鄉樹，晚景低津樓。", "伯夷在首陽，欲往無輕舟。", "遂登關城望，下見洪河流。", "自從巨靈開，流血千萬秋。", "行行潘生賦，赫赫曹公謀。", "川上多往事，淒涼滿空洲。"]'),
('a489626c-115e-42b8-9a2e-e955ccd2032b','楚夕旅泊古興','岑參','唐','唐诗','tang','','[]','獨鶴唳江月，孤帆凌楚雲。',48,'全唐诗/poet.tang.9000.json','["獨鶴唳江月，孤帆凌楚雲。", "秋風冷蕭瑟，蘆荻花紛紛。", "忽思湘川老，欲訪雲中君。", "騏驎息悲鳴，愁見豺虎羣。"]'),
('ab0af607-4847-45d7-b0b0-3da583eda41a','先主武侯廟','岑參','唐','唐诗','tang','','[]','先主與武侯，相逢雲雷際。',36,'全唐诗/poet.tang.9000.json','["先主與武侯，相逢雲雷際。", "感通君臣分，義激魚水契。", "遺廟空蕭然，英靈貫千歲。"]'),
('dca469b5-a92f-408f-a8ab-0815e898e216','文公講堂','岑參','唐','唐诗','tang','','[]','文公不可見，空使蜀人傳。',36,'全唐诗/poet.tang.9000.json','["文公不可見，空使蜀人傳。", "講席何時散，高臺豈復全。", "豐碑文字滅，冥漠不知年。"]'),
('56fc6e91-1a4d-4e55-948e-3e919ccf85b0','楊雄草玄臺','岑參','唐','唐诗','tang','','[]','吾悲子雲居，寂寞人已去。',36,'全唐诗/poet.tang.9000.json','["吾悲子雲居，寂寞人已去。", "娟娟西江月，猶照草玄處。", "精怪喜無人，睢盱藏老樹。"]'),
('38bed822-d6be-4418-b1a0-81bbeed3ef36','司馬相如琴臺','岑參','唐','唐诗','tang','','[]','相如琴臺古，人去臺亦空。',36,'全唐诗/poet.tang.9000.json','["相如琴臺古，人去臺亦空。", "臺上寒蕭條，至今多悲風。", "荒臺漢時月，色與舊時同。"]'),
('9af61cdf-9699-4c8e-b8f7-711a73567e9f','嚴君平卜肆','岑參','唐','唐诗','tang','','[]','君平曾賣卜，卜肆蕪已久。',36,'全唐诗/poet.tang.9000.json','["君平曾賣卜，卜肆蕪已久。", "至今杖頭錢，時時地上有。", "不知支機石，還在人間否。"]'),
('f2188df7-af62-4e04-8368-cc74b5aba800','張儀樓','岑參','唐','唐诗','tang','','[]','傳是秦時樓，巍巍至今在。',36,'全唐诗/poet.tang.9000.json','["傳是秦時樓，巍巍至今在。", "樓南兩江水，千古長不改。", "曾聞昔時人，歲月不相待。"]'),
('13b23d9f-8c1f-4ec3-8812-0287a2508498','昇仙橋','岑參','唐','唐诗','tang','','[]','長橋題柱去，猶是未達時。',36,'全唐诗/poet.tang.9000.json','["長橋題柱去，猶是未達時。", "及乘駟馬車，却從橋上歸。", "名共東流水，滔滔無盡期。"]'),
('ce27c3e3-309b-4319-9550-e9dc125e8478','萬里橋','岑參','唐','唐诗','tang','','[]','成都與維揚，相去萬里地。',36,'全唐诗/poet.tang.9000.json','["成都與維揚，相去萬里地。", "滄江東流疾，帆去如鳥翅。", "楚客過此橋，東看盡垂淚。"]'),
('ac0c59d6-2aac-4c7a-964b-461d8ad87a21','石犀','岑參','唐','唐诗','tang','','[]','江水初蕩潏，蜀人幾爲魚。',36,'全唐诗/poet.tang.9000.json','["江水初蕩潏，蜀人幾爲魚。", "向無爾石犀，安得有邑居。", "始知李太守，伯禹亦不如。"]'),
('1cf8593b-c22e-47e4-ad29-9c5744343b90','龍女祠','岑參','唐','唐诗','tang','','[]','龍女何處來，來時乘風雨。',36,'全唐诗/poet.tang.9000.json','["龍女何處來，來時乘風雨。", "祠堂青林下，宛宛如相語。", "蜀人競祈恩，捧酒仍擊鼓。"]'),
('7c6fc61f-438f-4d0d-81a3-cfa15a53e955','使交河郡郡在火山脚其地苦熱無雨雪獻封大夫','岑參','唐','唐诗','tang','','[]','奉使按胡俗，平明發輪臺。',120,'全唐诗/poet.tang.9000.json','["奉使按胡俗，平明發輪臺。", "暮投交河城，火山赤崔巍。", "九月尚流汗，炎風吹沙埃。", "何事陰陽工，不遣雨雪來。", "吾君方憂邊，分閫資大才。", "昨者新破胡，安西兵馬回。", "鐵關控天涯，萬里何遼哉。", "煙塵不敢飛，白草空皚皚。", "軍中日無事，醉舞傾金罍。", "漢代李將軍，微功合可咍。"]'),
('bc87acf3-d083-44a0-9e44-eb849eefe780','與鮮于庶子自梓州成都少尹自襃城同行至利州道中作','岑參','唐','唐诗','tang','','[]','剖竹向西蜀，岷峨眇天涯。',144,'全唐诗/poet.tang.9000.json','["剖竹向西蜀，岷峨眇天涯。", "空深北闕戀，豈憚南路賒。", "前日登七盤，曠然見三巴。", "漢水出嶓冢，梁山控襃斜。", "棧道籠迅湍，行人貫層崖。", "巖傾劣通馬，石窄難容車。", "深林怯魑魅，洞穴防龍蛇。", "水種新插秧，山田正燒畬。", "夜猿嘯山雨，曙鳥鳴江花。", "過午方始飯，經時旋及瓜。", "數公各遊宦，千里皆辭家。", "言笑忘羈旅，還如在京華。"]'),
('6c5306db-2975-4d15-967f-43cf50d6522a','下外江舟懷終南舊居','岑參','唐','唐诗','tang','','[]','杉冷曉猿悲，楚客心欲絕。',108,'全唐诗/poet.tang.9000.json','["杉冷曉猿悲，楚客心欲絕。", "孤舟巴山雨，萬里陰臺月。", "水宿已淹時，蘆花白如雪。", "顏容老難赬，把鏡悲鬢髮。", "早年好金丹，方士傳口訣。", "敝廬終南下，久與真侶別。", "道書誰更開，藥竈煙遂滅。", "頃來壓塵網，安得有仙骨。", "巖壑歸去來，公卿是何物。"]'),
('14e8178c-20eb-4e34-bf06-0eb43c0e8e23','安西館中思長安','岑參','唐','唐诗','tang','','[]','家在日出處，朝來起東風。',96,'全唐诗/poet.tang.9000.json','["家在日出處，朝來起東風。", "風從帝鄉來，不異家信通。", "絕域地欲盡，孤城天遂窮。", "彌年但走馬，終日隨飄蓬。", "寂寞不得意，辛勤方在公。", "胡塵淨古塞，兵氣屯邊空。", "鄉路眇天外，歸期如夢中。", "遙憑長房術，爲縮天山東。"]'),
('55e59dfb-2711-40cf-8e15-dbf3b40c322c','暮秋山行','岑參','唐','唐诗','tang','','["\u79cb\u5929", "\u5c71\u6797", "\u5199\u666f", "\u60b2\u6101"]','疲馬臥長坂，夕陽下通津。',72,'全唐诗/poet.tang.9000.json','["疲馬臥長坂，夕陽下通津。", "山風吹空林，颯颯如有人。", "蒼旻霽涼雨，石路無飛塵。", "千念集暮節，萬籟悲蕭晨。", "鶗鴂昨夜鳴，蕙草色已陳。", "況在遠行客，自然多苦辛。"]'),
('82cf958f-aba0-41ba-a01e-fee89c0c5d2b','赴犍爲經龍閣道','岑參','唐','唐诗','tang','','[]','側徑轉青壁，危梁透滄波。',72,'全唐诗/poet.tang.9000.json','["側徑轉青壁，危梁透滄波。", "汗流出鳥道，膽碎窺龍渦。", "驟雨暗谿口，歸雲網松蘿。", "屢聞羌兒笛，厭聽巴童歌。", "江路險復永，夢魂愁更多。", "聖朝幸典郡，不敢嫌岷峨。"]'),
('e51f3b2f-cd90-4b0c-985a-a681d5aab870','江上阻風雨','岑參','唐','唐诗','tang','','[]','江上風欲來，泊舟未能發。',72,'全唐诗/poet.tang.9000.json','["江上風欲來，泊舟未能發。", "氣昏雨已過，突兀山復出。", "積浪成高丘，盤渦爲嵌窟。", "雲低岸花掩，水漲灘草沒。", "老樹蛇蛻皮，崩崖龍退骨。", "平生抱忠信，艱險殊可忽。"]'),
('3392e070-4cd4-4e46-b1f5-7d7c9b4cdfdf','經火山','岑參','唐','唐诗','tang','','["\u5199\u5c71", "\u8a00\u5fd7", "\u5199\u666f", "\u63cf\u5199\u5c71"]','火山今始見，突兀蒲昌東。',60,'全唐诗/poet.tang.9000.json','["火山今始見，突兀蒲昌東。", "赤焰燒虜雲，炎氛蒸塞空。", "不知陰陽炭，何獨然此中。", "我來嚴冬時，山下多炎風。", "人馬盡汗流，孰知造化功。"]'),
('173fb26f-eb55-4a3b-bbc9-b8f672c7baa4','題鐵門關樓','岑參','唐','唐诗','tang','','[]','鐵關天西涯，極目少行客。',48,'全唐诗/poet.tang.9000.json','["鐵關天西涯，極目少行客。", "關門一小吏，終日對石壁。", "橋跨千仞危，路盤兩崖窄。", "試登西樓望，一望頭欲白。"]'),
('2f6ecab4-18c7-4258-8534-da1b858ca1ba','早上五盤嶺','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','平旦驅駟馬，曠然出五盤。',72,'全唐诗/poet.tang.9000.json','["平旦驅駟馬，曠然出五盤。", "江迴兩崖鬬，日隱羣峰攢。", "蒼翠煙景曙，森沈雲樹寒。", "松疎露孤驛，花密藏迴灘。", "棧道谿雨滑，畬田原草乾。", "此行爲知己，不覺蜀道難。"]'),
('92a22684-9363-45c9-b869-2fbee3986059','峨眉東脚臨江聽猿懷二室舊廬','岑參','唐','唐诗','tang','','[]','峨眉煙翠新，昨夜秋雨洗。',48,'全唐诗/poet.tang.9000.json','["峨眉煙翠新，昨夜秋雨洗。", "分明峰頭樹，倒插秋江底。", "久別二室間，圖他五斗米。", "哀猿不可聽，北客欲流涕。"]'),
('fae37351-bc37-48df-8f77-3014e4477b6f','東歸發犍爲至泥谿舟中作','岑參','唐','唐诗','tang','','[]','前日解侯印，泛舟歸山東。',144,'全唐诗/poet.tang.9000.json','["前日解侯印，泛舟歸山東。", "平旦發犍爲，逍遙信回風。", "七月江水大，滄波漲秋空。", "復有峨眉僧，誦經在舟中。", "夜泊防虎豹，朝行逼魚龍。", "一道鳴迅湍，兩邊走連峰。", "猿拂岸花落，鳥啼簷樹重。", "煙靄吳楚連，泝沿湖海通。", "憶昨在西掖，復曾入南宮。", "日出朝聖人，端笏陪羣公。", "不意今棄置，何由豁心胸。", "吾當海上去，且學乘桴翁。"]'),
('87b7f79f-5b83-460c-9c0b-c224d2db37c6','阻戎瀘間羣盜','岑參','唐','唐诗','tang','','[]','南州林莽深，亡命聚其間。',180,'全唐诗/poet.tang.9000.json','["南州林莽深，亡命聚其間。", "殺人無昏曉，屍積填江灣。", "餓虎銜髑髏，飢烏啄心肝。", "腥裛灘草死，血流江水殷。", "夜雨風蕭蕭，鬼哭連楚山。", "三江行人絕，萬里無征船。", "唯有白鳥飛，空見秋月園。", "罷官自南蜀，假道來茲川。", "瞻望陽臺雲，惆悵不敢前。", "帝鄉北近日，瀘口南連蠻。", "何當遇長房，縮地到京關。", "願得隨琴高，騎魚向雲煙。", "明主每憂人，節使恆在邊。", "兵革方禦寇，爾惡胡不悛。", "吾竊悲爾徒，此生安得全。"]'),
('3c977192-db7d-4ad1-af6a-ef4defb1d1fa','郡齋閑坐','岑參','唐','唐诗','tang','','[]','負郭無良田，屈身狥微祿。',84,'全唐诗/poet.tang.9000.json','["負郭無良田，屈身狥微祿。", "平生好疎曠，何事就羈束。", "幸曾趨丹墀，數得侍黃屋。", "故人盡榮寵，誰念此幽獨。", "州縣非宿心，雲山欣滿目。", "頃來廢章句，終日披案牘。", "佐郡竟何成，自悲徒碌碌。"]'),
('e87e6eca-3a0d-46f8-869e-ce53a6bc8876','衙郡守還','岑參','唐','唐诗','tang','','[]','世事何反覆，一身難可料。',48,'全唐诗/poet.tang.9000.json','["世事何反覆，一身難可料。", "頭白翻折腰，還家私自笑。", "所嗟無產業，妻子嫌不調。", "五斗米留人，東谿憶垂釣。"]'),
('24316fda-83a7-4bfe-bb3b-ea652f727463','行軍詩二首 一','岑參','唐','唐诗','tang','','[]','吾竊悲此生，四十幸未老。',144,'全唐诗/poet.tang.9000.json','["吾竊悲此生，四十幸未老。", "一朝逢世亂，終日不自保。", "胡兵奪長安，宮殿生野草。", "傷心五陵樹，不見二京道。", "我皇在行軍，兵馬日浩浩。", "胡雛尚未滅，諸將懇征討。", "昨聞咸陽敗，殺戮淨如掃。", "積屍若丘山，流血漲豐鎬。", "干戈礙鄉國，豺虎滿城堡。", "村落皆無人，蕭條空桑棗。", "儒生有長策，無處豁懷抱。", "塊然傷時人，舉首哭蒼昊。"]'),
('5de0ee9b-7d0b-478a-8781-4f719d822dcb','行軍詩二首 二','岑參','唐','唐诗','tang','','[]','早知逢世亂，少小謾讀書。',84,'全唐诗/poet.tang.9000.json','["早知逢世亂，少小謾讀書。", "悔不學彎弓，向東射狂胡。", "偶從諫官列，謬向丹墀趨。", "未能匡吾君，虛作一丈夫。", "撫劒傷世路，哀歌泣良圖。", "功業今已遲，覽鏡悲白鬚。", "平生抱忠義，不敢私微軀。"]'),
('28203ee8-58e9-4486-bc10-4ff96f93eb01','秋夕聽羅山人彈三峽流泉','岑參','唐','唐诗','tang','','[]','皤皤岷山老，抱琴鬢蒼然。',160,'全唐诗/poet.tang.9000.json','["皤皤岷山老，抱琴鬢蒼然。", "衫袖拂玉徽，爲彈三峽泉。", "此曲彈未半，高堂如空山。", "石林何[颼飀]，忽在窗戶間。", "繞指弄嗚咽，青絲激潺湲。", "演漾怨楚雲，虛徐韻秋煙。", "疑兼陽臺雨，似雜巫山猿。", "幽引鬼神聽，淨令耳目便。", "楚客腸欲斷，湘妃淚斑斑。", "誰裁青桐枝，絚以朱絲絃。", "能含古人曲，遞與今人傳。", "知音難再逢，惜君方年老。", "曲終月已落，惆[悵]東齋眠。"]'),
('e4f4c725-be05-446d-a355-4d5ba576a907','尹相公京兆府中棠樹降甘露詩','岑參','唐','唐诗','tang','','[]','相國尹京兆，政成人不欺。',170,'全唐诗/poet.tang.9000.json','["相國尹京兆，政成人不欺。", "甘露降府庭，上天表無私。", "非無他人家，豈少羣木枝。", "被茲甘棠樹，美掩召伯詩。", "團團甜如[蜜]，皛皛凝若脂。", "千柯玉光碎，萬葉珠顆垂。", "崑崙何時來，慶雲相逐飛。", "魏宮銅盤貯，漢帝金掌持。", "王澤布人和，精心動靈祇。", "君臣日同德，禎瑞方潛施。", "何術令大臣，感通能及茲。", "忽驚政化理，暗與神物期。", "却笑趙張輩，徒稱今古稀。", "爲君天下酒，麴糵將用時。"]'),
('855d1e36-5a93-4f76-b6bc-e349130a9276','劉相公中書江山畫障','岑參','唐','唐诗','tang','','[]','相府徵墨妙，揮毫天地窮。',144,'全唐诗/poet.tang.9000.json','["相府徵墨妙，揮毫天地窮。", "始知丹青筆，能奪造化功。", "瀟湘在簾間，廬壑橫座中。", "忽疑鳳凰池，暗與江海通。", "粉白湖上雲，黛青天際峰。", "晝日恆見月，孤帆如有風。", "巖花不飛落，澗草無春冬。", "擔錫香鑪緇，釣魚滄浪翁。", "如何平津意，尚想塵外蹤。", "富貴心獨輕，山林興彌濃。", "喧幽趣頗異，出處事不同。", "請君爲蒼生，未可追赤松。"]'),
('c4cf8ffd-04a4-46bd-9e43-e873cf37f361','精衛','岑參','唐','唐诗','tang','','[]','負劒出北門，乘桴適東溟。',60,'全唐诗/poet.tang.9000.json','["負劒出北門，乘桴適東溟。", "一鳥海上飛，云是帝女靈。", "玉顏溺水死，精衛空爲名。", "怨積徒有志，力微竟不成。", "西山木石盡，巨壑何時平。"]'),
('5005e6f9-54b2-48ee-a17e-93a1ee74fc49','石上藤','岑參','唐','唐诗','tang','','[]','石上生孤藤，弱蔓依石長。',36,'全唐诗/poet.tang.9000.json','["石上生孤藤，弱蔓依石長。", "不逢高枝引，未得凌空上。", "何處堪託身，爲君長萬丈。"]'),
('1134b996-462c-450f-a34c-656487d68bb7','臨河客舍呈狄明府兄留題縣南樓','岑參','唐','唐诗','tang','','[]','黎陽城南雪正飛，黎陽渡頭人未歸。',96,'全唐诗/poet.tang.9000.json','["黎陽城南雪正飛，黎陽渡頭人未歸。", "河邊酒家堪寄宿，主人小女能縫衣。", "故人高臥黎陽縣，一別三年不相見。", "邑中雨雪偏着時，隔河東郡人遙羨。", "鄴都唯見古時丘，漳水還如舊日流。", "城上望鄉應不見，朝來好是嬾登樓。"]'),
('65cbc848-38e4-46f6-aba6-226de39a3a3c','客舍悲秋有懷兩省舊遊呈幕中諸公','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u6101\u82e6", "\u611f\u6168", "\u5b64\u5bc2", "\u58ee\u5fd7\u672a\u916c"]','三度爲郎便白頭，一從出守五經秋。',64,'全唐诗/poet.tang.9000.json','["三度爲郎便白頭，一從出守五經秋。", "莫言聖主長不用，其那蒼生應未休。", "人間歲月如流水，客舍秋風今又起。", "不知心事向誰論，江上蟬鳴空滿耳。"]'),
('294bc7b2-b4f8-4a53-be17-a40ded4afd1a','白雪歌送武判官歸京','岑參','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u96ea", "\u53cb\u60c5", "\u548f\u7269", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5185)", "\u9001\u522b"]','北風捲地白草折，胡天八月即飛雪。',144,'全唐诗/poet.tang.9000.json','["北風捲地白草折，胡天八月即飛雪。", "忽然一夜春風來，千樹萬樹梨花開。", "散入珠簾濕羅幕，狐裘不煖錦衾薄。", "將軍角弓不得控，都護鐵衣冷難着。", "瀚海闌干百丈冰，愁雲黲淡萬里凝。", "中軍置酒飲歸客，胡琴琵琶與羌笛。", "紛紛暮雪下轅門，風掣紅旗凍不翻。", "輪臺東門送君去，去時雪滿天山路。", "山迴路轉不見君，雪上空留馬行處。"]'),
('760788a0-b091-414b-bf9f-291cec928701','熱海行送崔侍御還京','岑參','唐','唐诗','tang','','["\u5199\u666f", "\u9001\u522b", "\u8fb9\u585e", "\u5e26\u6709\u5730\u540d", "\u5730\u540d"]','側聞陰山胡兒語，西頭熱海水如煮。',128,'全唐诗/poet.tang.9000.json','["側聞陰山胡兒語，西頭熱海水如煮。", "海上衆鳥不敢飛，中有鯉魚長且肥。", "岸傍青草常不歇，空中白雪遙旋滅。", "蒸沙爍石然虜雲，沸浪炎波煎漢月。", "陰火潛燒天地鑪，何事偏烘西一隅。", "勢吞月窟侵太白，氣連赤坂通單于。", "送君一醉天山郭，正見夕陽海邊落。", "柏臺霜威寒逼人，熱海炎氣爲之薄。"]'),
('d129dc0f-cec9-4073-bb89-cb9312564d9d','輪臺歌奉送封大夫出師西征','岑參','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6218\u4e89", "\u751f\u6d3b", "\u4e03\u8a00\u53e4\u8bd7", "\u8d5e\u626c", "\u8fb9\u585e"]','輪臺城頭夜吹角，輪臺城北旄頭落。',144,'全唐诗/poet.tang.9000.json','["輪臺城頭夜吹角，輪臺城北旄頭落。", "羽書昨夜過渠黎，單于已在金山西。", "戍樓西望煙塵黑，漢兵屯在輪臺北。", "上將擁旄西出征，平明吹笛大軍行。", "四邊伐鼓雪海湧，三軍大呼陰山動。", "虜塞兵氣連雲屯，戰場白骨纏草根。", "劒河風急雪片闊，沙口石凍馬蹄脫。", "亞相勤王甘苦辛，誓將報主靜邊塵。", "古來青史誰不見，今見功名勝古人。"]'),
('93639a7d-ea8a-451b-8cd7-5531e9ccf86c','敷水歌送竇漸入京','岑參','唐','唐诗','tang','','[]','羅敷昔時秦氏女，千載無人空處所。',128,'全唐诗/poet.tang.9000.json','["羅敷昔時秦氏女，千載無人空處所。", "昔時流水至今流，萬事皆逐東流去。", "此水東流無盡期，水聲還似舊來時。", "岸花仍自羞紅臉，隄柳猶能學翠眉。", "春去秋來不相待，水中月色長不改。", "羅敷養蠶空耳聞，使君五馬今何在？", "九月霜天水正寒，故人西去度征鞍。", "水底鯉魚幸無數，願君別後垂尺素。"]'),
('e9e5e359-1e63-48bd-ae4d-9239aad418fa','天山雪歌送蕭治歸京','岑參','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u96ea", "\u96ea", "\u8d5e\u7f8e", "\u53cb\u60c5"]','天山有雪常不開，千峰萬嶺雪崔嵬。',128,'全唐诗/poet.tang.9000.json','["天山有雪常不開，千峰萬嶺雪崔嵬。", "北風夜捲赤亭口，一夜天山雪更厚。", "能兼漢月照銀山，復逐胡風過鐵關。", "交河城邊飛鳥絕，輪臺路上馬蹄滑。", "晻靄寒氛萬里凝，闌干陰崖千丈冰。", "將軍狐裘臥不暖，都護寶刀凍欲斷。", "正是天山雪下時，送君走馬歸京師。", "雪中何以贈君別，惟有青青松樹枝。"]'),
('76009aa6-c0bb-43e5-9ee6-fa163bc901d8','火山雲歌送別','岑參','唐','唐诗','tang','','["\u5199\u4e91", "\u9001\u522b", "\u5199\u666f", "\u8fb9\u585e"]','火山突兀赤亭口，火山五月火雲厚。',80,'全唐诗/poet.tang.9000.json','["火山突兀赤亭口，火山五月火雲厚。", "火雲滿山凝未開，飛鳥千里不敢來。", "平明乍逐胡風斷，薄暮渾隨塞雨回。", "繚繞斜吞鐵關樹，氛氳半掩交河戍。", "迢迢征路火山東，山上孤雲隨馬去。"]'),
('881c4241-c0a0-4c31-a0ba-2f87b4290c44','青門歌送東臺張判官','岑參','唐','唐诗','tang','','[]','青門金鎖平旦開，城頭日出使車回。',146,'全唐诗/poet.tang.9000.json','["青門金鎖平旦開，城頭日出使車回。", "青門柳枝正堪折，路傍一日幾人別。", "東出青門路不窮，驛樓官樹灞陵東。", "花撲征衣看似繡，雲隨去馬色疑驄。", "胡姬酒壚日未午，絲繩玉缸酒如乳。", "灞頭落花沒馬蹄，昨夜微雨花成泥。", "黃鸝翅濕飛轉低，關東尺書醉嬾題。", "須臾望君不可見，揚鞭飛鞚疾如箭。", "借問使乎何時來，莫作東飛伯勞西飛燕。"]'),
('7233ba7b-301d-4ca8-bf61-928eac520dfc','梁園歌送河南王說判官','岑參','唐','唐诗','tang','','[]','君不見梁孝王脩竹園，頹牆隱轔勢仍存。',146,'全唐诗/poet.tang.9000.json','["君不見梁孝王脩竹園，頹牆隱轔勢仍存。", "嬌娥曼臉成草蔓，羅帷珠簾空竹根。", "大梁一旦人代改，秋月春風不相待。", "池中幾度雁新來，洲上千年鶴應在。", "梁園二月梨花飛，却似梁王雪下時。", "當時置酒延枚叟，肯料平臺狐兔走。", "萬事翻覆如浮雲，昔人空在今人口。", "單父古來稱宓生，祗今爲政有吾兄。", "輶軒若過梁園道，應傍琴臺聞政聲。"]'),
('f5e021d7-ea56-4341-947c-8fd024018e1c','走馬川行奉送出師西征','岑參','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u9a6c", "\u5199\u98ce", "\u9001\u522b", "\u521d\u4e2d\u53e4\u8bd7", "\u4e03\u8a00\u53e4\u8bd7"]','君不見走馬川行雪海邊，平沙莽莽黃入天。',139,'全唐诗/poet.tang.9000.json','["君不見走馬川行雪海邊，平沙莽莽黃入天。", "輪臺九月風夜吼，一川碎石大如斗，隨風滿地石亂走。", "匈奴草黃馬正肥，金山西見煙塵飛。", "漢家大將西出師，將軍金甲夜不脫。", "半夜軍行戈相撥，風頭如刀面如割。", "馬毛帶雪汗氣蒸，五花連錢旋作冰。", "幕中草檄硯水凝，虜騎聞之應膽懾。", "料知短兵不敢接，車師西門佇獻捷。"]'),
('ad7e0050-66f9-4366-97d1-1dc1f69286bd','函谷關歌送劉評事使關西','岑參','唐','唐诗','tang','','[]','君不見函谷關，崩城毀壁至今在。',127,'全唐诗/poet.tang.9000.json','["君不見函谷關，崩城毀壁至今在。", "樹根草蔓遮古道，空谷千年長不改。", "寂寞無人空舊山，聖朝無外不須關。", "白馬公孫何處去，青牛老人更不還。", "蒼苔白骨空滿地，月與古時長相似。", "野花不省見行人，山鳥何曾識關吏。", "故人方乘使者車，吾知郭丹却不如。", "請君時憶關外客，行到關西多致書。"]'),
('d784999c-efd0-4bf8-a06e-4c931be04042','胡笳歌送顏真卿使赴河隴','岑參','唐','唐诗','tang','','[]','君不聞胡笳聲最悲，紫髯綠眼胡人吹。',97,'全唐诗/poet.tang.9000.json','["君不聞胡笳聲最悲，紫髯綠眼胡人吹。", "吹之一曲猶未了，愁殺樓蘭征戍兒。", "涼秋八月蕭關道，北風吹斷天山草。", "崑崙山南月欲斜，胡人向月吹胡笳。", "胡笳怨兮將送君，秦山遙望隴山雲。", "邊城夜夜多愁夢，向月胡笳誰喜聞。"]'),
('e3998e24-86de-480a-b799-38a302164f24','秦箏歌送外甥蕭正歸京','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u60c6\u6005"]','汝不聞秦箏聲最苦，五色纏弦十三柱。',81,'全唐诗/poet.tang.9000.json','["汝不聞秦箏聲最苦，五色纏弦十三柱。", "怨調慢聲如欲語，一曲未終日移午。", "紅亭水木不知暑，忽彈黃鐘和白紵。", "清風颯來雲不去，聞之酒醒淚如雨。", "汝歸秦兮彈秦聲，秦聲悲兮聊送汝。"]'),
('a9e9a370-25c2-4030-8b4f-2f7abc5e353a','與獨孤漸道別長句兼呈嚴八侍御','岑參','唐','唐诗','tang','','[]','輪臺客舍春草滿，潁陽歸客腸堪斷。',290,'全唐诗/poet.tang.9000.json','["輪臺客舍春草滿，潁陽歸客腸堪斷。", "窮荒絕漠鳥不飛，萬磧千山夢猶嬾。", "憐君白面一書生，讀書千卷未成名。", "五侯貴門脚不到，數畝山田身自耕。", "興來浪跡無遠近，及至辭家憶鄉信。", "無事垂鞭信馬頭，西南幾欲窮天盡。", "[奉]使三年獨未歸，邊頭詞客舊來稀。", "借問君來得幾日，到家不覺換春衣。", "高齋清晝卷帷幕，紗帽接䍦慵不着。", "中酒朝眠日色高，彈棋夜半燈花落。", "冰片高堆金錯盤，滿堂凜凜五月寒。", "桂林蒲萄新吐蔓，武城刺蜜未可餐。", "軍中置酒夜撾鼓，錦筵紅燭月未午。", "花門將軍善胡歌，葉河蕃王能漢語。", "知爾園林壓渭濱，夫人堂上泣羅帬。", "魚龍川北盤谿雨，鳥鼠山西洮水雲。", "臺中嚴公於我厚，別後新詩滿人口。", "自憐棄置天西頭，因君爲問相思否。"]'),
('d04b4104-01c2-4de2-b5fb-f659a6586bc4','送費子歸武昌','岑參','唐','唐诗','tang','','[]','漢陽歸客悲秋草，旅舍葉飛愁不掃。',192,'全唐诗/poet.tang.9000.json','["漢陽歸客悲秋草，旅舍葉飛愁不掃。", "秋來倍憶武昌魚，夢着只在巴陵道。", "曾隨上將過祁連，離家十年恆在邊。", "劒鋒可惜虛用盡，馬蹄無事今已穿。", "知君開館常愛客，樗蒱百金每一擲。", "平生有錢將與人，江上故園空四壁。", "吾觀費子毛骨奇，廣眉大口仍赤髭。", "看君失路尚如此，人生貴賤那得知。", "高秋八月歸南楚，東門一壺聊出祖。", "路指鳳皇山北雲，衣沾鸚鵡洲邊雨。", "勿歎蹉跎白髮新，應須守道勿羞貧。", "男兒何必戀妻子，莫向江村老却人。"]'),
('c2d1a310-f9bf-43fc-af1e-38eb0762b0de','送韓巽入都覲省便赴舉','岑參','唐','唐诗','tang','','[]','槐葉蒼蒼柳葉黃，秋高八月天欲霜。',64,'全唐诗/poet.tang.9000.json','["槐葉蒼蒼柳葉黃，秋高八月天欲霜。", "青門百壺送韓侯，白雲千里連嵩丘。", "北堂倚門望君憶，東歸扇枕後秋色。", "洛陽才子能幾人，明年桂枝是君得。"]'),
('acd3df17-14f0-4fba-99a8-8ed70a83a1ad','送李副使赴磧西官車','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u8c6a\u8fc8", "\u9001\u522b", "\u8bae\u8bba", "\u996e\u9152"]','火山六月應更熱，赤亭道口行人絕。',64,'全唐诗/poet.tang.9000.json','["火山六月應更熱，赤亭道口行人絕。", "知君慣度祁連城，豈能愁見輪臺月。", "脫鞍暫入酒家壚，送君萬里西擊胡。", "功名祗向馬上取，真是英雄一丈夫。"]'),
('580e95b9-b4ec-4224-ab4d-1cc5484a1539','涼州館中與諸判官夜集','岑參','唐','唐诗','tang','','["\u6708\u4eae", "\u5bb4\u4f1a", "\u53cb\u60c5", "\u8c6a\u8fc8", "\u5730\u70b9"]','彎彎月出挂城頭，城頭月出照梁州。',96,'全唐诗/poet.tang.9000.json','["彎彎月出挂城頭，城頭月出照梁州。", "涼州七里十萬家，胡人半解彈琵琶。", "琵琶一曲腸堪斷，風蕭蕭兮夜漫漫。", "河西幕中多故人，故人別來三五春。", "花門樓前見秋草，豈能貧賤相看老。", "一生大笑能幾迴，斗酒相逢須醉倒。"]'),
('0623c5c6-0a91-4048-b267-cb6dd0d0e667','酒泉太守席上醉後作','岑參','唐','唐诗','tang','','[]','琵琶長笛曲相和，羌兒胡雛齊唱歌。',48,'全唐诗/poet.tang.9000.json','["琵琶長笛曲相和，羌兒胡雛齊唱歌。", "渾炙犂牛烹野駝，交河美酒歸叵羅。", "三更醉後軍中寢，無奈秦山歸夢何。"]'),
('35fcaec7-8450-4f81-be58-ee56634cf1ba','偃師東與韓樽同詣景雲暉上人即事','岑參','唐','唐诗','tang','','[]','山陰老僧解楞伽，潁陽歸客遠相過。',64,'全唐诗/poet.tang.9000.json','["山陰老僧解楞伽，潁陽歸客遠相過。", "煙深草濕昨夜雨，雨後秋風渡漕河。", "空山終日塵事少，平郊遠見行人小。", "尚書磧上黃昏鐘，別駕渡頭一歸鳥。"]'),
('189fc6a0-4f1c-425a-bedb-5e894a75b5d0','醉題匡城周少府廳壁','岑參','唐','唐诗','tang','','[]','婦姑城南風雨秋，婦姑城中人獨愁。',64,'全唐诗/poet.tang.9000.json','["婦姑城南風雨秋，婦姑城中人獨愁。", "愁雲遮却望鄉處，數日不上西南樓。", "故人薄暮公事閑，玉壺美酒琥珀殷。", "潁陽秋草今黃盡，醉臥君家猶未還。"]'),
('11d89263-29a6-4a47-838e-28f415c64cf0','燉煌太守後庭歌','岑參','唐','唐诗','tang','','[]','燉煌太守才且賢，郡中無事高枕眠。',120,'全唐诗/poet.tang.9000.json','["燉煌太守才且賢，郡中無事高枕眠。", "太守到來山出泉，黃砂磧裏人種田。", "燉煌耆舊鬢皓然，願留太守更五年。", "城頭月出星滿天，曲房置酒張錦筵。", "美人紅妝色正鮮，側垂高髻插金鈿。", "醉坐藏鉤紅燭前，不知鈎在若箇邊。", "爲君手把珊瑚鞭，射得半段黃金錢，此中樂事亦已偏。"]'),
('9b4aa31f-6abb-4987-8b52-3d2cdd107287','喜韓樽相過','岑參','唐','唐诗','tang','','[]','三月灞陵春已老，故人相逢耐醉倒。',80,'全唐诗/poet.tang.9000.json','["三月灞陵春已老，故人相逢耐醉倒。", "甕頭春酒黃花脂，祿米只充沽酒資。", "長安城中足年少，獨共韓侯開口笑。", "桃花點地紅斑斑，有酒留君且莫還。", "與君兄弟日攜手，世上虛名好是閑。"]'),
('0bc49eb1-cde3-4aba-a939-871e3d178484','銀山磧西館','岑參','唐','唐诗','tang','','[]','銀山磧口風似箭，鐵門關西月如練。',48,'全唐诗/poet.tang.9000.json','["銀山磧口風似箭，鐵門關西月如練。", "雙雙愁淚沾馬毛，颯颯胡沙迸人面。", "丈夫三十未富貴，安能終日守筆硯。"]'),
('1dc6ff35-ae2b-4d66-bae4-04770eda11c1','感遇','岑參','唐','唐诗','tang','','[]','五花驄馬七香車，云是平陽帝子家。',64,'全唐诗/poet.tang.9000.json','["五花驄馬七香車，云是平陽帝子家。", "鳳皇城頭日欲斜，門前高樹鳴春鴉。", "漢家魯元君不聞，今作城西一古墳。", "昔來唯有秦王女，獨自吹蕭乘白雲。"]'),
('58f90338-5fad-40bc-9071-3f83658c46a0','太白胡僧歌','岑參','唐','唐诗','tang','','[]','聞有胡僧在太白，蘭若去天三百尺。',128,'全唐诗/poet.tang.9000.json','["聞有胡僧在太白，蘭若去天三百尺。", "一持楞伽入中峰，世人難見但聞鐘。", "牕邊錫杖解兩虎，牀下鉢盂藏一龍。", "草衣不鍼復不線，兩耳垂肩眉覆面。", "此僧年幾那得知，手種青松今十圍。", "心將流水同清淨，身與浮雲無是非。", "商山老人已曾識，願一見之何由得。", "山中有僧人不知，城裏看山空黛色。"]'),
('c5dfd013-1975-4f54-a7ad-d94ee8073191','衛節度赤驃馬歌','岑參','唐','唐诗','tang','','[]','君家赤驃畫不得，一團旋風桃花色。',224,'全唐诗/poet.tang.9000.json','["君家赤驃畫不得，一團旋風桃花色。", "紅纓紫鞚珊瑚鞭，玉鞍錦韉黃金勒。", "請君鞲出看君騎，尾長窣地如紅絲。", "自矜諸馬皆不及，却憶百金新買時。", "香街紫陌鳳城內，滿城見者誰不愛。", "揚鞭驟急白汗流，弄影行驕碧蹄碎。", "紫髯胡雛金剪刀，平明剪出三鬉高。", "櫪上看時獨意氣，衆中牽出偏雄豪。", "騎將獵向南山口，城南孤兔不復有。", "草頭一點疾如飛，卻使蒼鷹翻向後。", "憶昨看君朝未央，鳴珂擁蓋滿路香。", "始知邊將真富貴，可憐人馬相輝光。", "男兒稱意得如此，駿馬長鳴北風起。", "待君東去埽胡塵，爲君一日行千里。"]'),
('78bcf1fa-7303-4196-9911-49533efcfd88','田使君美人舞如蓮花北鋋歌','岑參','唐','唐诗','tang','','[]','美人舞如蓮花旋，世人有眼應未見。',160,'全唐诗/poet.tang.9000.json','["美人舞如蓮花旋，世人有眼應未見。", "高堂滿地紅氍毹，試舞一曲天下無。", "此曲胡人傳入漢，諸客見之驚且歎。", "慢臉嬌娥纖復穠，輕羅金縷花葱蘢。", "回裾轉袖若飛雪，左鋋右鋋生旋風。", "琵琶橫笛和未匝，花門山頭黃雲合。", "忽作出塞入塞聲，白草胡沙寒颯颯。", "翻身入破如有神，前見後見回回新。", "始知諸曲不可比，采蓮落梅徒聒耳。", "世人學舞祗是舞，恣態豈能得如此。"]'),
('5923c05c-cacd-4dae-b93f-baee6db3ba94','裴將軍宅蘆管歌','岑參','唐','唐诗','tang','','[]','遼東九月蘆葉斷，遼東小兒采蘆管。',160,'全唐诗/poet.tang.9000.json','["遼東九月蘆葉斷，遼東小兒采蘆管。", "可憐新管清且悲，一曲風飄海頭滿。", "海樹蕭索天雨霜，管聲寥亮月蒼蒼。", "白狼河北堪愁恨，玄兔城南皆斷腸。", "遼東將軍長安宅，美人蘆管會佳客。", "弄調啾颼勝洞簫，發聲窈窕欺橫笛。", "夜半高堂客未回，祗將蘆管送君杯。", "巧能陌上驚楊柳，復向園中誤落梅。", "諸客愛之聽未足，高捲珠簾列紅燭。", "將軍醉舞不肯休，更使美人吹一曲。"]'),
('b15f3808-4d29-40cb-97f7-7465843ae7b0','韋員外家花樹歌','岑參','唐','唐诗','tang','','[]','今年花似去年好，去年人到今年老。',64,'全唐诗/poet.tang.9000.json','["今年花似去年好，去年人到今年老。", "始知人老不如花，可惜落花君莫埽。", "君家兄弟不可當，列卿御史尚書郎。", "朝回花底恆會客，花撲玉缸春酒香。"]'),
('126694de-4b58-4ebd-9028-cd0633031927','醉後戲與趙歌兒','岑參','唐','唐诗','tang','','[]','秦州歌兒歌調苦，偏能立唱濮陽女。',48,'全唐诗/poet.tang.9000.json','["秦州歌兒歌調苦，偏能立唱濮陽女。", "座中醉客不得意，聞之一聲淚如雨。", "向使逢着漢帝憐，董賢氣咽不能語。"]'),
('9baec5a9-b39b-41e6-8259-637d2cd3336c','范公叢竹歌','岑參','唐','唐诗','tang','','[]','世人見竹不解愛，知君種竹府城內。',129,'全唐诗/poet.tang.9000.json','["世人見竹不解愛，知君種竹府城內。", "此君託根幸得地，種來幾時聞已大。", "盛暑翛翛叢色寒，閑宵槭槭葉聲乾。", "能清案牘簾下見，宜對琴書窗外看。", "爲君成陰將蔽日，迸笋穿堦踏還出。", "守節偏凌御史霜，虛心願比郎官筆。", "君莫愛南山松樹枝，竹色四時也不移。", "寒天草木黃落盡，猶自青青君始知。"]'),
('fc7cf78b-a1fc-4c9b-8b2e-1cbb16916842','玉門關蓋將軍歌','岑參','唐','唐诗','tang','','["\u5199\u4eba", "\u5c06\u519b", "\u5bb4\u4f1a", "\u5199\u4eba\u8bd7"]','蓋將軍，真丈夫，行年三十執金吾，身長七尺頗有鬚。',264,'全唐诗/poet.tang.9000.json','["蓋將軍，真丈夫，行年三十執金吾，身長七尺頗有鬚。", "玉門關城迥且孤，黃沙萬里白草枯。", "南鄰犬戎北接胡，將軍到來備不虞。", "五千甲兵膽力麤，軍中無事但歡娛。", "暖屋繡簾紅地爐，織成壁衣花氍毹。", "燈前侍婢瀉玉壺，金鐺亂點野酡酥。", "紫紱金章左右趨，問着只是蒼頭奴。", "美人一雙閑且都，朱脣翠眉映明矑。", "清歌一曲世所無，今日喜聞鳳將雛。", "可憐絕勝秦羅敷，使君五馬謾踟躕。", "野草繡窠紫羅襦，紅牙縷馬對樗蒱。", "玉盤纖手撒作盧，衆中誇道不曾輸。", "櫪上昂昂皆駿駒，桃花叱撥價最殊。", "騎將獵向城南隅，臘日射殺千年狐。", "我來塞外按邊儲，爲君取醉酒剩沽。", "醉爭酒盞相喧呼，忽憶咸陽舊酒徒。"]'),
('8379d844-617f-478f-afa4-64ff67f2929a','贈酒泉韓太守','岑參','唐','唐诗','tang','','[]','太守有能政，遙聞如古人。',56,'全唐诗/poet.tang.9000.json','["太守有能政，遙聞如古人。", "俸錢盡供客，家計常清貧。", "酒泉西望玉關道，千山萬磧皆白草。", "辭君走馬歸長安，憶君倏忽令人老。"]'),
('dd4f0e0b-9e65-435e-b46e-bde6466aaecd','贈西嶽山人李岡','岑參','唐','唐诗','tang','','["\u534e\u5c71"]','君隱處，當一星，蓮花峰頭飯黃精，仙人掌上演丹經。',56,'全唐诗/poet.tang.9000.json','["君隱處，當一星，蓮花峰頭飯黃精，仙人掌上演丹經。", "鳥可到，人莫攀，隱來十年不下山。", "袖中短書誰爲達，華陰道士賣藥還。"]'),
('1ac853aa-b238-4769-a90d-5d9cb067b63c','送張獻心充副使歸河西雜句','岑參','唐','唐诗','tang','','[]','將門子弟君獨賢，一從受命常在邊。',152,'全唐诗/poet.tang.9000.json','["將門子弟君獨賢，一從受命常在邊。", "未至三十已高位，腰間金印色赭然。", "前日承恩白虎殿，歸來見者誰不羨。", "篋中賜衣十重餘，案上軍書十二卷。", "看君謀智若有神，愛君詞句皆清新。", "澄湖萬頃深見底，清冰一片光照人。", "雲中昨夜使星動，西門驛樓出相送。", "玉瓶素蟻臘酒香，金鞭白馬紫遊韁。", "花門南，燕支北，張掖城頭雲正黑，送君一去天外憶。"]'),
('a1a60665-ddc0-4b05-99a2-393d5910852e','送郭乂雜言','岑參','唐','唐诗','tang','','[]','地上青草出，經冬今始歸。',160,'全唐诗/poet.tang.9000.json','["地上青草出，經冬今始歸。", "博陵無近信，猶未換春衣。", "憐汝不忍別，送汝上酒樓。", "初行莫早發，且宿霸橋頭。", "功名須及早，歲月莫虛擲。", "早年已工詩，近日兼注易。", "何時過東洛，早晚度盟津。", "朝歌城邊柳嚲地，邯鄲道上花撲人。", "去年四月初，我正在河朔。", "曾上君家縣北樓，樓上分明見恆嶽。", "中山明府待君來，須計行程及早回。", "到家速覓長安使，待汝書封我自開。"]'),
('cf44d412-33f8-475e-ba60-a95e321fb35e','送魏升卿擢第歸東都因懷魏校書陸渾喬潭','岑參','唐','唐诗','tang','','[]','井上桐葉雨，灞亭卷秋風。',187,'全唐诗/poet.tang.9000.json','["井上桐葉雨，灞亭卷秋風。", "故人適戰勝，匹馬歸山東。", "問君今年三十幾，能使香名滿人耳。", "君不見三峰直上五千仞，見君文章亦如此。", "如君兄弟天下稀，雄辭健筆皆若飛。", "將軍金印嚲紫綬，御史鐵冠重繡衣。", "喬生作尉別來久，因君爲問平安否。", "魏侯校理復何如，前日人來不得書。", "陸渾山下佳可賞，蓬閣閑時日應往。", "自料青雲未有期，誰知白髮偏能長。", "壚頭青絲白玉瓶，別時相顧酒如傾。", "搖鞭舉袂忽不見，千樹萬樹空蟬鳴。"]'),
('7f054e33-b7bb-4334-b1fa-37a96ddb3ec0','送魏四落第還鄉','岑參','唐','唐诗','tang','','[]','東歸不稱意，客舍戴勝鳴。',88,'全唐诗/poet.tang.9000.json','["東歸不稱意，客舍戴勝鳴。", "臘酒飲未盡，春衫縫已成。", "長安柳枝春欲來，洛陽梨花在前開。", "魏侯池館今尚在，猶有太師歌舞臺。", "君家盛德豈徒然，時人注意在吾賢。", "莫令別後無佳句，祗向壚頭空醉眠。"]'),
('f59863d1-e0b2-46a5-b431-4a5cf38a50fc','送宇文南金放後歸太原寓居因呈太原郝主簿','岑參','唐','唐诗','tang','','[]','歸去不得意，北京關路賒。',80,'全唐诗/poet.tang.9000.json','["歸去不得意，北京關路賒。", "却投晉山老，愁見汾陽花。", "翻作灞陵客，憐君丞相家。", "夜眠旅舍雨，曉辭春城鴉。", "送君繫馬青門口，胡姬壚頭勸君酒。", "爲問太原賢主人，春來更有新詩否。"]'),
('1758b66b-ae92-4eb1-bbb3-fcfe3aa8dece','西亭子送李司馬','岑參','唐','唐诗','tang','','[]','高高亭子郡城西，直上千尺與雲齊。',104,'全唐诗/poet.tang.9000.json','["高高亭子郡城西，直上千尺與雲齊。", "盤崖緣壁試攀躋，羣山向下飛鳥低。", "使君五馬天半嘶，絲繩玉壺爲君提。", "坐來一望無端倪，紅花綠柳鶯亂啼。", "千家萬井連迴谿，酒行未醉聞暮雞，點筆操紙爲君題。", "爲君題，惜解攜，草萋萋，沒馬蹄。"]'),
('71a414a4-8939-48fc-90f6-d18b9e4bac57','漁父','岑參','唐','唐诗','tang','','[]','扁舟滄浪叟，心與滄浪清。',80,'全唐诗/poet.tang.9000.json','["扁舟滄浪叟，心與滄浪清。", "不自道鄉里，無人知姓名。", "朝從灘上飯，暮向蘆中宿。", "歌竟還復歌，手持一竿竹。", "竿頭釣絲長丈餘，鼓栧乘流無定居。", "世人那得識深意，此翁取適非取魚。"]'),
('3a1e9614-6afb-4c44-a30c-aaf3e9ead632','登古鄴城','岑參','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u767b\u9ad8", "\u5199\u666f", "\u6000\u53e4"]','下馬登鄴城，城空復何見。',56,'全唐诗/poet.tang.9000.json','["下馬登鄴城，城空復何見。", "東風吹野火，暮入飛雲殿。", "城隅南對望陵臺，漳水東流不復回。", "武帝宮中人去盡，年年春色爲誰來。"]'),
('1d9969c4-babf-4e5c-bf13-0a31d533d69e','邯鄲客舍歌','岑參','唐','唐诗','tang','','[]','客從長安來，驅馬邯鄲道。',72,'全唐诗/poet.tang.9000.json','["客從長安來，驅馬邯鄲道。", "傷心叢臺下，一帶生蔓草。", "客舍門臨漳水邊，垂楊下繫釣魚船。", "邯鄲女兒夜沽酒，對客挑燈誇數錢。", "酪酊醉時日正午，一曲狂歌壚上眠。"]'),
('d2582b61-2240-40ce-8268-54f96edfdfe6','宿蒲關東店憶杜陵別業','岑參','唐','唐诗','tang','','[]','關門鎖歸客，一夜夢還家。',40,'全唐诗/poet.tang.9000.json','["關門鎖歸客，一夜夢還家。", "月落河上曉，遙聞秦樹鴉。", "長安二月歸正好，杜陵樹邊純是花。"]'),
('430a141d-b995-4db4-875e-47838b3123cb','感遇','岑參','唐','唐诗','tang','','[]','北山有芳杜，靡靡花正發。',59,'全唐诗/poet.tang.9000.json','["北山有芳杜，靡靡花正發。", "未及得采之，秋風忽吹殺。", "君不見拂雲百丈青松柯，縱使秋風無奈何。", "四時常作青黛色，可憐杜花不相識。"]'),
('0a77b437-f3b1-486b-9fa8-909215ed7044','優鉢羅花歌','岑參','唐','唐诗','tang','','["\u5199\u82b1", "\u6292\u6000", "\u6000\u624d\u4e0d\u9047", "\u82b1"]','白山南，赤山北，其間有花人不識。',110,'全唐诗/poet.tang.9000.json','["白山南，赤山北，其間有花人不識。", "綠莖碧葉好顏色，葉六瓣，花九房，夜掩朝開多異香，何不生彼中國兮生西方？移根在庭，媚我公堂，恥與衆草之爲伍，何亭亭而獨芳？何不爲人之所賞兮？深山窮谷委嚴霜。", "吾竊悲陽關道路長，曾不得獻于君王。"]'),
('4d2ee883-5b18-43aa-9826-81b372388bb8','蜀葵花歌','岑參','唐','唐诗','tang','','["\u5199\u82b1", "\u751f\u6d3b", "\u6292\u6000", "\u82b1"]','昨日一花開，今日一花開。',72,'全唐诗/poet.tang.9000.json','["昨日一花開，今日一花開。", "今日花正好，昨日花已老。", "始知人老不如花，可惜落花君莫埽。", "人生不得長少年，莫惜牀頭沽酒錢。", "請君有錢向酒家，君不見，蜀葵花。"]'),
('9f53d562-10fa-4259-9030-9bcb93654af9','題李士曹廳壁畫度雨雲歌','岑參','唐','唐诗','tang','','[]','似出棟梁裏，如和風雨飛。',28,'全唐诗/poet.tang.9000.json','["似出棟梁裏，如和風雨飛。", "掾曹有時不敢歸，謂言雨過濕人衣。"]'),
('6cad2c5a-ed2d-41c5-bd69-9d0a74ff8f43','入蒲關先寄秦中故人','岑參','唐','唐诗','tang','','[]','秦山數點似青黛，渭上一條如白練。',32,'全唐诗/poet.tang.9000.json','["秦山數點似青黛，渭上一條如白練。", "京師故人不可見，寄將兩眼看飛燕。"]'),
('a673ef6a-62a4-4fa1-80c4-4054785395e2','長門怨','岑參','唐','唐诗','tang','','[]','君王嫌妾妬，閉妾在長門。',48,'全唐诗/poet.tang.9000.json','["君王嫌妾妬，閉妾在長門。", "舞袖垂新寵，愁眉結舊恩。", "綠錢侵履跡，紅粉濕啼痕。", "羞被夭桃笑，看春獨不言。"]'),
('2779f710-4ab4-46cb-a2b6-1889752f26c2','寄左省杜拾遺','岑參','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4ed5\u9014", "\u4e94\u8a00\u5f8b\u8bd7", "\u611f\u6168"]','聯步趨丹陛，分曹限紫微。',48,'全唐诗/poet.tang.9000.json','["聯步趨丹陛，分曹限紫微。", "曉隨天仗入，暮惹御香歸。", "白髮悲花落，青雲羨鳥飛。", "聖朝無闕事，自覺諫書稀。"]'),
('c72b5a28-601c-4169-9a39-bc8a57171223','歲暮磧外寄元撝','岑參','唐','唐诗','tang','','[]','西風傳戍鼓，南望見前軍。',48,'全唐诗/poet.tang.9000.json','["西風傳戍鼓，南望見前軍。", "沙磧人愁月，山城犬吠雲。", "別家逢逼歲，出塞獨離羣。", "髮到陽關白，書今遠報君。"]'),
('a0924c48-5e6f-44c9-a658-4d79e8053f76','寄宇文判官','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u6101\u82e6"]','西行殊未已，東望何時還。',48,'全唐诗/poet.tang.9000.json','["西行殊未已，東望何時還。", "終日風與雪，連天沙復山。", "二年領公事，兩度過陽關。", "相憶不可見，別來頭已斑。"]'),
('c2a142e8-d1c6-4d24-8b48-1a11b54c5823','宿關西客舍寄東山嚴許二山人時天寶初七月初三日在內學見有高道舉徵','岑參','唐','唐诗','tang','','[]','雲送關西雨，風傳渭北秋。',48,'全唐诗/poet.tang.9000.json','["雲送關西雨，風傳渭北秋。", "孤燈然客夢，寒杵搗鄉愁。", "灘上思嚴子，山中憶許由。", "蒼生今有望，飛詔下林丘。"]'),
('836b5f1f-eb4a-4ea9-a733-d06943297d45','丘中春臥寄王子','岑參','唐','唐诗','tang','','[]','田中開白室，林下閉玄關。',48,'全唐诗/poet.tang.9000.json','["田中開白室，林下閉玄關。", "卷跡人方處，無心雲自閑。", "竹深喧暮鳥，花缺露春山。", "勝事那能說，王孫去未還。"]'),
('c2e4bc2b-bcc0-46a2-9330-d72de872f4ce','江行夜宿龍吼灘臨眺思峨眉隱者兼寄幕中諸公','岑參','唐','唐诗','tang','','[]','官舍臨江口，灘聲人慣聞。',48,'全唐诗/poet.tang.9000.json','["官舍臨江口，灘聲人慣聞。", "水煙晴吐月，山火夜燒雲。", "且欲尋方士，無心戀使君。", "異鄉何可住，況復久離羣。"]'),
('280ffd6c-823e-4834-844a-e1e02b67d57b','漢川山行呈成少尹','岑參','唐','唐诗','tang','','[]','西蜀方攜手，南宮憶比肩。',48,'全唐诗/poet.tang.9000.json','["西蜀方攜手，南宮憶比肩。", "平生猶不淺，羈旅轉相憐。", "山店雲迎客，江村犬吠船。", "秋來取一醉，須待月光眠。"]'),
('4f477b9d-fe17-40e5-8f75-ae047f37fccc','奉和杜相公初發京城作','岑參','唐','唐诗','tang','','[]','按節辭黃閣，登壇戀赤墀。',48,'全唐诗/poet.tang.9000.json','["按節辭黃閣，登壇戀赤墀。", "銜恩期報主，授律遠行師。", "野鵲迎金印，郊雲拂畫旗。", "叨陪幕中客，敢和出車詩。"]'),
('81bbbd9c-12f3-4c30-b7f3-d4c5874244f5','敬酬李判官使院即事見呈','岑參','唐','唐诗','tang','','[]','公府日無事，吾徒只是閑。',48,'全唐诗/poet.tang.9000.json','["公府日無事，吾徒只是閑。", "草根侵柱礎，苔色上門關。", "飲硯時見鳥，卷簾晴對山。", "新詩吟未足，昨夜夢東還。"]'),
('1454d21c-0fd8-4011-b297-d9f33690150d','虢州酬辛侍御見贈','岑參','唐','唐诗','tang','','[]','門柳葉已大，春花今復闌。',48,'全唐诗/poet.tang.9000.json','["門柳葉已大，春花今復闌。", "鬢毛方二色，愁緒日千端。", "夫子屢新命，鄙夫仍舊官。", "相思難見面，時展尺書看。"]'),
('25ee70e2-5059-4e8d-a748-64c9e2c9147a','酬崔十三侍御登玉壘山思故園見寄','岑參','唐','唐诗','tang','','[]','玉壘天晴望，諸峰盡覺低。',48,'全唐诗/poet.tang.9000.json','["玉壘天晴望，諸峰盡覺低。", "故園江樹北，斜日巔雲西。", "曠野看人小，長空共鳥齊。", "高山徒仰止，不得日攀躋。"]'),
('9fd7ed37-4b8d-4aab-aab1-d9a8862f0d77','南樓送衛憑','岑參','唐','唐诗','tang','','[]','近縣多過客，似君誠亦稀。',48,'全唐诗/poet.tang.9000.json','["近縣多過客，似君誠亦稀。", "南樓取涼好，便送故人歸。", "鳥向望中滅，雨侵晴處飛。", "應須乘月去，且爲解征衣。"]'),
('021bc793-64cc-4fbe-b992-d079e1d201ca','送王伯倫應制授正字歸','岑參','唐','唐诗','tang','','[]','當年最稱意，數子不如君。',48,'全唐诗/poet.tang.9000.json','["當年最稱意，數子不如君。", "戰勝時偏許，名高人共聞。", "半天城北雨，斜日灞西雲。", "科斗皆成字，無令錯古文。"]'),
('d8b1ae0b-d5a2-4aa4-b665-119d5420c723','送宇文舍人出宰元城','岑參','唐','唐诗','tang','','[]','雙鳧出未央，千里過河陽。',48,'全唐诗/poet.tang.9000.json','["雙鳧出未央，千里過河陽。", "馬帶新行色，衣聞舊御香。", "縣花迎墨綬，關柳拂銅章。", "別後能爲政，相思淇水長。"]'),
('3c721211-73ff-44c1-96a1-559aba4ef143','崔駙馬山池重送宇文明府','岑參','唐','唐诗','tang','','[]','竹裏過紅橋，花間藉綠苗。',36,'全唐诗/poet.tang.9000.json','["竹裏過紅橋，花間藉綠苗。", "池涼醒別酒，山翠拂行鑣。", "鳳去妝樓閉，鳧飛葉縣遙。"]'),
('7de7975b-5efb-4f14-9a1b-2fc667e5b328','送李郎尉武康','岑參','唐','唐诗','tang','','[]','潘郎腰綬新，霅上縣花春。',48,'全唐诗/poet.tang.9000.json','["潘郎腰綬新，霅上縣花春。", "山色低官舍，湖光映吏人。", "不須嫌邑小，莫即恥家貧。", "更作東征賦，知君有老親。"]'),
('2f2699d2-b060-43af-bcee-ee8abea39ade','磧西頭送李判官入京','岑參','唐','唐诗','tang','','["\u79bb\u522b", "\u601d\u4e61", "\u52b1\u5fd7", "\u8fb9\u585e"]','一身從遠使，萬里向安西。',48,'全唐诗/poet.tang.9000.json','["一身從遠使，萬里向安西。", "漢月垂鄉淚，胡沙費馬蹄。", "尋河愁地盡，過磧覺天低。", "送子軍中飲，家書醉裏題。"]'),
('e174b765-a22d-4b24-8438-544098fde00b','陪使君早春西亭送王贊府赴選','岑參','唐','唐诗','tang','','[]','西亭繫五馬，爲送故人歸。',48,'全唐诗/poet.tang.9000.json','["西亭繫五馬，爲送故人歸。", "客舍草新出，關門花欲飛。", "到來逢歲酒，却去換春衣。", "吏部應相待，如君才調稀。"]'),
('4fc0f637-f65f-4352-ae9d-ea1189a9047e','送劉郎將歸河東','岑參','唐','唐诗','tang','','[]','借問虎賁將，從軍凡幾年。',48,'全唐诗/poet.tang.9000.json','["借問虎賁將，從軍凡幾年。", "殺人寶刀缺，走馬貂裘穿。", "山雨醒別酒，關雲迎渡船。", "謝君賢主將，豈忘輪臺邊。"]'),
('7b413861-1cb9-4680-aed8-236f710f29c3','滻水東店送唐子歸嵩陽','岑參','唐','唐诗','tang','','[]','野店臨官路，重城壓御隄。',48,'全唐诗/poet.tang.9000.json','["野店臨官路，重城壓御隄。", "山開灞水北，雨過杜陵西。", "歸夢秋能作，鄉書醉嬾題。", "橋回忽不見，征馬尚聞嘶。"]'),
('4a9abb11-67ab-48df-b22a-f72b744d4aaf','西亭送蔣侍御還京','岑參','唐','唐诗','tang','','[]','忽聞驄馬至，喜見故人來。',48,'全唐诗/poet.tang.9000.json','["忽聞驄馬至，喜見故人來。", "欲語多時別，先愁計日回。", "山河宜晚眺，雲霧待君開。", "爲報烏臺客，須憐白髮催。"]'),
('1c696cba-6230-4cbc-b41e-b25aa10aa2df','水亭送劉顒使還歸節度','岑參','唐','唐诗','tang','','[]','無計留君住，應須絆馬蹄。',48,'全唐诗/poet.tang.9000.json','["無計留君住，應須絆馬蹄。", "紅亭莫惜醉，白日眼看低。", "解帶憐高柳，移牀愛小谿。", "此來相見少，正事各東西。"]'),
('533b0fd0-935f-4a9b-b80e-81f92af96165','送楊錄事充潼關判官','岑參','唐','唐诗','tang','','[]','夫子方寸裏，秋天澄霽江。',48,'全唐诗/poet.tang.9000.json','["夫子方寸裏，秋天澄霽江。", "關西望第一，郡內政無雙。", "狹室下珠箔，連宵傾玉缸。", "平明猶未醉，斜月隱書牕。"]'),
('36f35944-c98f-4456-839f-92a6d792463f','送裴判官自賊中再歸河陽幕府','岑參','唐','唐诗','tang','','[]','東郊未解圍，忠義似君稀。',48,'全唐诗/poet.tang.9000.json','["東郊未解圍，忠義似君稀。", "誤落胡塵裏，能持漢節歸。", "卷簾山對酒，上馬雪沾衣。", "却向嫖姚幕，翩翩去若飛。"]'),
('159fa3a6-de23-4c08-844d-434ce30093cc','送陝縣王主簿赴襄陽成親','岑參','唐','唐诗','tang','','[]','六月襄山道，三星漢水邊。',48,'全唐诗/poet.tang.9000.json','["六月襄山道，三星漢水邊。", "求鳳應不遠，去馬賸須鞭。", "野店愁中雨，江城夢裏蟬。", "襄陽多故事，爲我訪先賢。"]'),
('71634838-149c-4fde-9fe0-aa1c528376ca','送李卿賦得孤島石','岑參','唐','唐诗','tang','','[]','一片他山石，巉巉映小池。',48,'全唐诗/poet.tang.9000.json','["一片他山石，巉巉映小池。", "綠窠攢剝蘚，尖碩坐鸕鷀。", "水底看常倒，花邊勢欲欹。", "君心能不轉，卿月豈相離。"]'),
('7828a7c6-eeb4-4336-afea-3f9015fecfc4','送王錄事卻歸華陰','岑參','唐','唐诗','tang','','["\u9ec4\u6cb3"]','相送欲狂歌，其如此別何。',48,'全唐诗/poet.tang.9000.json','["相送欲狂歌，其如此別何。", "攀轅人共惜，解印日無多。", "仙掌雲重見，關門路再過。", "雙魚莫不寄，縣外是黃河。"]'),
('aa02a951-2237-4352-b209-821e4edd79cd','送二十二兄北遊尋羅中','岑參','唐','唐诗','tang','','[]','斗柄欲東指，吾兄方北遊。',48,'全唐诗/poet.tang.9000.json','["斗柄欲東指，吾兄方北遊。", "無媒謁明主，失計干諸侯。", "夜雪入穿履，朝霜凝敝裘。", "遙知客舍飲，醉裏聞春鳩。"]'),
('488ac7aa-03f4-4da7-a627-b926aa9cac3b','送鄭堪歸東京氾水別業','岑參','唐','唐诗','tang','','[]','客舍見春草，忽聞思舊山。',48,'全唐诗/poet.tang.9000.json','["客舍見春草，忽聞思舊山。", "看君灞陵去，匹馬成臯還。", "對酒風與雪，向家河復關。", "因悲宦遊子，終歲無時閑。"]'),
('aaea0c4a-fff0-4282-9d71-87e636d4b673','送崔全被放歸都覲省','岑參','唐','唐诗','tang','','["\u540c\u60c5", "\u5199\u4eba", "\u6000\u624d\u4e0d\u9047", "\u5199\u4eba\u8bd7"]','夫子不自衒，世人知者稀。',48,'全唐诗/poet.tang.9000.json','["夫子不自衒，世人知者稀。", "來傾阮氏酒，去着老萊衣。", "渭北草新出，關東花欲飛。", "楚王猶自惑，宋玉且將歸。"]'),
('140531c1-b825-4405-b56c-a8daca14221f','送孟孺卿落第歸濟陽','岑參','唐','唐诗','tang','','[]','獻賦頭欲白，還家衣已穿。',48,'全唐诗/poet.tang.9000.json','["獻賦頭欲白，還家衣已穿。", "羞過灞陵樹，歸種汶陽田。", "客舍少鄉信，牀頭無酒錢。", "聖朝徒側席，濟上獨遺賢。"]'),
('6f06a9e7-55a8-4c0f-ac67-cb42a46e116a','送裴校書從大夫淄川覲省','岑參','唐','唐诗','tang','','[]','尚書未出守，愛子向青州。',48,'全唐诗/poet.tang.9000.json','["尚書未出守，愛子向青州。", "一路通關樹，孤城近海樓。", "懷中江橘熟，倚處戟門秋。", "更奉輕軒去，知君無客愁。"]'),
('a232cacc-23f1-4c99-b1ea-7fdda56249d1','送楊千牛趂歲赴汝南郡覲省便成婚','岑參','唐','唐诗','tang','','[]','問吉轉征鞍，安仁道姓潘。',48,'全唐诗/poet.tang.9000.json','["問吉轉征鞍，安仁道姓潘。", "歸期明主賜，別酒故人歡。", "珠箔障爐煖，孤裘耐臘寒。", "汝南遙倚望，蚤去及春盤。"]'),
('97c78d0d-bbc3-49ad-889e-d0252e6b7849','送胡象落第歸王屋別業','岑參','唐','唐诗','tang','','[]','看君尚少年，不第莫悽然。',48,'全唐诗/poet.tang.9000.json','["看君尚少年，不第莫悽然。", "可即疲獻賦，山村歸種田。", "野花迎短褐，河柳拂長鞭。", "置酒聊相送，青門一醉眠。"]'),
('46b36db7-76c4-4424-9e1b-f4519b8ac02a','送顏韶','岑參','唐','唐诗','tang','','[]','遷客猶未老，聖朝今復歸。',48,'全唐诗/poet.tang.9000.json','["遷客猶未老，聖朝今復歸。", "一從襄陽住，幾度梨花飛。", "世事了可見，憐君人亦稀。", "相逢貪醉臥，未得作春衣。"]'),
('a8c56579-fd4e-438d-a072-455ed608a07f','送杜佐下第歸陸渾別業','岑參','唐','唐诗','tang','','[]','正月今欲半，陸渾花未開。',48,'全唐诗/poet.tang.9000.json','["正月今欲半，陸渾花未開。", "出關見青草，春色正東來。", "夫子且歸去，明時方愛才。", "還須及秋賦，莫即隱嵩萊。"]'),
('d0247050-b161-4b3e-ae32-0d79b2b611d7','送張郎中赴隴右覲省卿公','岑參','唐','唐诗','tang','','[]','中郎鳳一毛，世上獨賢豪。',48,'全唐诗/poet.tang.9000.json','["中郎鳳一毛，世上獨賢豪。", "弱冠已銀印，出身唯寶刀。", "還家卿月迥，度隴將星高。", "幕下多相識，邊書醉嬾操。"]'),
('a6634baf-1b44-4cf3-9fab-0333330d986f','送楚丘麴少府赴官','岑參','唐','唐诗','tang','','[]','青袍美少年，黃綬一神仙。',48,'全唐诗/poet.tang.9000.json','["青袍美少年，黃綬一神仙。", "微子城東面，梁王苑北邊。", "桃花色似馬，榆莢小於錢。", "單父聞相近，家書早爲傳。"]'),
('15058957-c82e-4381-99db-8ba10dc2daa0','送蜀郡李掾','岑參','唐','唐诗','tang','','[]','飲酒俱未醉，一言聊贈君。',48,'全唐诗/poet.tang.9000.json','["飲酒俱未醉，一言聊贈君。", "功曹善爲政，明主還應聞。", "夜宿劒門月，朝行巴水雲。", "江城菊花發，滿道香氛氳。"]'),
('206c827e-5527-4ba7-a3cb-9b50d827b020','送鄭少府赴滏陽','岑參','唐','唐诗','tang','','[]','子真河朔尉，邑里帶清漳。',48,'全唐诗/poet.tang.9000.json','["子真河朔尉，邑里帶清漳。", "春草迎袍色，晴花拂綬香。", "青山入官舍，黃鳥度宮牆。", "若到銅臺上，應憐魏寢荒。"]'),
('1c65ae3f-33b4-4815-be75-50927a8b7df3','還高冠潭口留別舍弟','岑參','唐','唐诗','tang','','["\u601d\u5ff5", "\u6292\u60c5", "\u95f2\u9002", "\u5144\u5f1f"]','昨日山有信，祗今耕種時。',48,'全唐诗/poet.tang.9000.json','["昨日山有信，祗今耕種時。", "遙傳杜陵叟，怪我還山遲。", "獨向潭上酌，無人林下棊。", "東谿憶汝處，閑臥對鸕鷀。"]'),
('ef601522-2609-43fd-bb82-aad1abff7669','醴泉東谿送程皓元鏡微入蜀','岑參','唐','唐诗','tang','','[]','蜀郡路漫漫，梁州過七盤。',48,'全唐诗/poet.tang.9000.json','["蜀郡路漫漫，梁州過七盤。", "二人來信宿，一縣醉衣冠。", "谿逼春衫冷，林交宴席寒。", "西南如噴酒，遙向雨中看。"]'),
('61aadf8a-d87b-44f8-8519-e07915791beb','夏初醴泉南樓送太康顏少府','岑參','唐','唐诗','tang','','[]','何地堪相餞，南樓出萬家。',48,'全唐诗/poet.tang.9000.json','["何地堪相餞，南樓出萬家。", "可憐高處送，遠見故人車。", "野果新成子，庭槐欲作花。", "愛君兄弟好，書向潁中誇。"]'),
('243385c4-42fd-4352-8621-e966de6fd7cc','送嚴詵擢第歸蜀','岑參','唐','唐诗','tang','','[]','巴江秋月新，閣道發征輪。',48,'全唐诗/poet.tang.9000.json','["巴江秋月新，閣道發征輪。", "戰勝真才子，名高動世人。", "工文能似舅，擢第去榮親。", "十月天官待，應須早赴秦。"]'),
('9b9070aa-2450-436a-abe9-09e68ccef4b3','送張直公歸南鄭拜省','岑參','唐','唐诗','tang','','[]','夫子思何速，世人皆歎奇。',48,'全唐诗/poet.tang.9000.json','["夫子思何速，世人皆歎奇。", "萬言不加點，七步猶嫌遲。", "對酒落日後，還家飛雪時。", "北堂應久待，鄉夢促征期。"]'),
('37083527-cecd-4dac-a3da-e567dc28473a','送周子落第遊荆南','岑參','唐','唐诗','tang','','[]','足下復不第，家貧尋故人。',48,'全唐诗/poet.tang.9000.json','["足下復不第，家貧尋故人。", "且傾湘南酒，羞對關西塵。", "山店橘花發，江城楓葉新。", "若從巫峽過，應見楚王神。"]'),
('419a6b58-3fda-4ea3-b78c-4cf70c97440b','送薛彥偉擢第東歸','岑參','唐','唐诗','tang','','[]','時輩似君稀，青春戰勝歸。',48,'全唐诗/poet.tang.9000.json','["時輩似君稀，青春戰勝歸。", "名登郄詵第，身着老萊衣。", "稱意人皆羨，還家馬若飛。", "一枝誰不折，棣蕚獨相輝。"]'),
('58214442-7fdc-4e08-a03c-663f722f739c','送楊瑗尉南海','岑參','唐','唐诗','tang','','[]','不擇南州尉，高堂有老親。',48,'全唐诗/poet.tang.9000.json','["不擇南州尉，高堂有老親。", "樓臺重蜃氣，邑里雜鮫人。", "海暗三山雨，花明五嶺春。", "此鄉多寶玉，慎莫厭清貧。"]'),
('2ed43de4-918c-4a9b-99dd-20757e2aad13','鳳翔府行軍送程使君赴成州','岑參','唐','唐诗','tang','','[]','程侯新出守，好日發行軍。',48,'全唐诗/poet.tang.9000.json','["程侯新出守，好日發行軍。", "拜命時人羨，能官聖主聞。", "江樓黑塞雨，山郭冷秋雲。", "竹馬諸童子，朝朝待使君。"]'),
('c664e8ce-59c0-4f63-96b6-e8ec2b85b050','送張昇卿宰新滏','岑參','唐','唐诗','tang','','[]','官柳葉尚小，長安春未濃。',48,'全唐诗/poet.tang.9000.json','["官柳葉尚小，長安春未濃。", "送君潯陽宰，把酒青門鐘。", "水驛楚雲冷，山城江樹重。", "遙知南湖上，只對香爐峰。"]'),
('60527424-7af4-4f9b-a318-c99b4e01ac61','送陳子歸陸渾別業','岑參','唐','唐诗','tang','','[]','雖不舊相識，知君丞相家。',48,'全唐诗/poet.tang.9000.json','["雖不舊相識，知君丞相家。", "故園伊川上，夜夢方山花。", "種藥畏春過，出關愁路賒。", "青門酒壚別，日暮東城鴉。"]'),
('eac4a1de-dfbc-41ea-8e53-44111648bbd8','稠桑驛喜逢嚴河南中丞便別','岑參','唐','唐诗','tang','','[]','駟馬映花枝，人人夾路窺。',48,'全唐诗/poet.tang.9000.json','["駟馬映花枝，人人夾路窺。", "離心且莫問，春草自應知。", "不謂青雲客，猶思紫禁時。", "別君能幾日，看取鬢成絲。"]'),
('feb6d17f-1f93-4acc-8498-8303ec15057d','送蒲秀才擢第歸蜀','岑參','唐','唐诗','tang','','[]','去馬疾如飛，看君戰勝歸。',48,'全唐诗/poet.tang.9000.json','["去馬疾如飛，看君戰勝歸。", "新登郄詵第，更著老萊衣。", "漢水行人少，巴山客舍稀。", "向南風候暖，臘月見春輝。"]'),
('d889671b-32ce-4339-96df-8223c6d3008d','送郭司馬赴伊吾郡請示李明府','岑參','唐','唐诗','tang','','[]','安西美少年，脫劒卸弓弦。',48,'全唐诗/poet.tang.9000.json','["安西美少年，脫劒卸弓弦。", "不倚將軍勢，皆稱司馬賢。", "秋山城北面，古治郡東邊。", "江上舟中月，遙思李郭仙。"]'),
('f5f45910-131f-4781-ab15-04030dd42120','送滕亢擢第歸蘇州拜親','岑參','唐','唐诗','tang','','[]','送爾姑蘇客，滄波秋正涼。',48,'全唐诗/poet.tang.9000.json','["送爾姑蘇客，滄波秋正涼。", "橘懷三箇去，桂折一枝將。", "湖上山當舍，天邊水是鄉。", "江村人事少，時作捕魚郎。"]'),
('6e1243ee-98d9-4d44-989b-bd0addd325ac','送任郎中出守明州','岑參','唐','唐诗','tang','','[]','罷起郎官草，初封刺史符。',48,'全唐诗/poet.tang.9000.json','["罷起郎官草，初封刺史符。", "城邊樓枕海，郭裏樹侵湖。", "郡政傍連楚，朝恩獨借吳。", "觀濤秋正好，莫不上姑蘇。"]'),
('67a554f7-a0db-40b2-b9ca-06d85e21c235','臨洮客舍留別祁四','岑參','唐','唐诗','tang','','[]','無事向邊外，至今仍不歸。',48,'全唐诗/poet.tang.9000.json','["無事向邊外，至今仍不歸。", "三年絕鄉信，六月未春衣。", "客舍洮水聒，孤城胡雁飛。", "心知別君後，開口笑應稀。"]'),
('ecef8d02-193f-415c-a8fe-38bd9fdd8f5d','送弘文李校書往漢南拜親','岑參','唐','唐诗','tang','','[]','未識已先聞，清辭果出羣。',48,'全唐诗/poet.tang.9000.json','["未識已先聞，清辭果出羣。", "如逢禰處士，似見鮑參軍。", "夢暗巴山雨，家連漢水雲。", "慈親思愛子，幾度泣霑帬。"]'),
('7ccd0fc6-775c-441e-b147-7f4751ad2913','送李別將攝伊吾令充使赴武威便寄崔員外','岑參','唐','唐诗','tang','','[]','詞賦滿書囊，胡爲在戰場。',48,'全唐诗/poet.tang.9000.json','["詞賦滿書囊，胡爲在戰場。", "行間脫寶劒，邑里挂銅章。", "馬疾飛千里，鳧飛向五涼。", "遙知竹林下，星使對星郎。"]'),
('198e7e9b-4df9-4717-a097-cdbfff71088b','送四鎮薛侍御東歸','岑參','唐','唐诗','tang','','["\u9001\u522b", "\u601d\u4e61", "\u6101\u82e6"]','相送淚沾衣，天涯獨未歸。',48,'全唐诗/poet.tang.9000.json','["相送淚沾衣，天涯獨未歸。", "將軍初得罪，門客復何依。", "夢去湖山闊，書停隴雁稀。", "園林幸接近，一爲到柴扉。"]'),
('d0485439-df87-4157-a93d-3d3182421a1c','送張都尉東歸','岑參','唐','唐诗','tang','','[]','白羽綠弓弦，年年只在邊。',48,'全唐诗/poet.tang.9000.json','["白羽綠弓弦，年年只在邊。", "還家劒鋒盡，出塞馬蹄穿。", "逐虜西踰海，平胡北到天。", "封侯應不遠，燕頷豈徒然。"]'),
('66de4228-f223-4ed1-8247-f0581d19fa19','送樊侍御使丹陽便覲','岑參','唐','唐诗','tang','','[]','臥病窮巷晚，忽驚驄馬來。',48,'全唐诗/poet.tang.9000.json','["臥病窮巷晚，忽驚驄馬來。", "知君京口去，借問幾時回。", "驛舫江風引，鄉書海雁催。", "慈親應倍喜，愛子在霜臺。"]'),
('be250398-698d-4578-9c92-38a03d12b674','送張卿郎君赴硤石尉','岑參','唐','唐诗','tang','','[]','卿家送愛子，愁見灞頭春。',48,'全唐诗/poet.tang.9000.json','["卿家送愛子，愁見灞頭春。", "草羨青袍色，花隨黃綬新。", "縣西函谷路，城北大陽津。", "日暮征鞍去，東郊一片塵。"]'),
('9d9d22a6-554a-4ae2-ae04-7c8270c81564','送顏少府投鄭陳州','岑參','唐','唐诗','tang','','[]','一尉便垂白，數年唯草玄。',48,'全唐诗/poet.tang.9000.json','["一尉便垂白，數年唯草玄。", "出關策匹馬，逆旅聞秋蟬。", "愛客多酒債，罷官無俸錢。", "知君羈思少，所適主人賢。"]'),
('4c95f2fb-72a4-4b94-b310-a0a29e25837c','趙少尹南亭送鄭侍御歸東臺','岑參','唐','唐诗','tang','','[]','紅亭酒甕香，白面繡衣郎。',48,'全唐诗/poet.tang.9000.json','["紅亭酒甕香，白面繡衣郎。", "砌冷蟲喧坐，簾疎雨到牀。", "鐘催離興急，絃逐醉歌長。", "關樹應先落，隨君滿鬢霜。"]'),
('2f8d79d6-22e4-4eea-aab8-eee493f9783a','祁四再赴江南別詩','岑參','唐','唐诗','tang','','[]','萬里來又去，三湘東復西。',48,'全唐诗/poet.tang.9000.json','["萬里來又去，三湘東復西。", "別多人換鬢，行遠馬穿蹄。", "山驛秋雲冷，江帆暮雨低。", "憐君不解說，相憶在書題。"]'),
('1eb17488-6566-4e1c-b95c-fefea67389f6','送許員外江外置常平倉','岑參','唐','唐诗','tang','','[]','詔置海陵倉，朝推畫省郎。',48,'全唐诗/poet.tang.9000.json','["詔置海陵倉，朝推畫省郎。", "還家錦服貴，出使繡衣香。", "水驛風催舫，江樓月透牀。", "仍懷陸氏橘，歸獻老親嘗。"]'),
('591de27e-b6fd-4ef1-9e8f-8752159bbc94','送秘省虞校書赴虞鄉丞','岑參','唐','唐诗','tang','','[]','花綬傍腰新，關東縣欲春。',48,'全唐诗/poet.tang.9000.json','["花綬傍腰新，關東縣欲春。", "殘書厭科斗，舊閣別麒麟。", "虞坂臨官舍，條山映吏人。", "看君有知己，坦腹向平津。"]'),
('1ce69ecd-3b11-47a2-8b60-89171fb032fb','送江陵泉少府赴任便呈衛荆州','岑參','唐','唐诗','tang','','[]','神仙吏姓梅，人吏待君來。',48,'全唐诗/poet.tang.9000.json','["神仙吏姓梅，人吏待君來。", "渭北草新出，江南花已開。", "城邊宋玉宅，峽口楚王臺。", "不畏無知己，荆州甚愛才。"]'),
('f2ad53f7-18e4-484b-b9a0-ad05d136563d','奉送李太保兼御史大夫充渭北節度使','岑參','唐','唐诗','tang','','[]','詔出未央宮，登壇近總戎。',48,'全唐诗/poet.tang.9000.json','["詔出未央宮，登壇近總戎。", "上公周太保，副相漢司空。", "弓抱關西月，旗翻渭北風。", "弟兄皆許國，天地荷成功。"]'),
('3918d69c-4a7c-4001-9d86-050b98b4e3d1','送江陵黎少府','岑參','唐','唐诗','tang','','[]','悔繫腰間綬，翻爲膝下愁。',48,'全唐诗/poet.tang.9000.json','["悔繫腰間綬，翻爲膝下愁。", "那堪漢水遠，更值楚山秋。", "新橘香官舍，征帆拂縣樓。", "王城不敢住，豈是愛荆州。"]'),
('ce711110-1b21-4a18-ac8e-6287f395c3f7','虢州送天平何丞入京市馬','岑參','唐','唐诗','tang','','["\u9001\u522b"]','關樹晚蒼蒼，長安近夕陽。',48,'全唐诗/poet.tang.9000.json','["關樹晚蒼蒼，長安近夕陽。", "回風醒別酒，細雨濕行裝。", "習戰邊塵黑，防秋塞草黃。", "知君市駿馬，不是學燕王。"]'),
('db346c45-7693-4606-b44c-4eab9b7d1c11','送揚州王司馬','岑參','唐','唐诗','tang','','[]','君家舊淮水，水上到揚州。',48,'全唐诗/poet.tang.9000.json','["君家舊淮水，水上到揚州。", "海樹青官舍，江雲黑郡樓。", "東南隨去鳥，人吏待行舟。", "爲報吾兄道，如今已白頭。"]'),
('99363abb-17d8-426a-9f85-0ade96a3cf83','陝州月城樓送辛判官入奏','岑參','唐','唐诗','tang','','[]','送客飛鳥外，城頭樓最高。',48,'全唐诗/poet.tang.9000.json','["送客飛鳥外，城頭樓最高。", "樽前遇風雨，牕裏動波濤。", "謁帝向金殿，隨身唯寶刀。", "相思灞陵月，祗有夢偏勞。"]'),
('21470562-7e1f-4787-8ffd-a8a8167f2413','送王七錄事赴虢州','岑參','唐','唐诗','tang','','[]','早歲即相知，嗟君最後時。',48,'全唐诗/poet.tang.9000.json','["早歲即相知，嗟君最後時。", "青雲仍未達，白髮欲成絲。", "小店關門樹，長河華岳祠。", "弘農人吏待，莫使馬行遲。"]'),
('a58320b6-241f-4493-a16b-07548852a4f1','閿鄉送上官秀才歸關西別業','岑參','唐','唐诗','tang','','["\u9ec4\u6cb3"]','風塵奈汝何，終日獨波波。',48,'全唐诗/poet.tang.9000.json','["風塵奈汝何，終日獨波波。", "親老無官養，家貧在外多。", "醉眼輕白髮，春夢渡黃河。", "相去關城近，何時更肯過。"]'),
('6c930ad8-7e4a-4cb3-896e-bcac8a90e366','送羽林長孫將軍赴歙州','岑參','唐','唐诗','tang','','[]','剖竹向江濆，能名計日聞。',48,'全唐诗/poet.tang.9000.json','["剖竹向江濆，能名計日聞。", "隼旗新刺史，虎劒舊將軍。", "驛舫宿湖月，州城浸海雲。", "青門酒樓上，欲別醉醺醺。"]'),
('a12ebde7-17c1-4657-b20e-64841a6a9c1a','送崔主簿赴夏陽','岑參','唐','唐诗','tang','','["\u9ec4\u6cb3"]','常愛夏陽縣，往年曾再過。',48,'全唐诗/poet.tang.9000.json','["常愛夏陽縣，往年曾再過。", "縣中饒白鳥，郭外是黃河。", "地近行程少，家貧酒債多。", "知君新稱意，好得奈春何。"]'),
('c5c5f6b9-be0c-47d6-8dac-10586a2ba00b','送梁判官歸女几舊廬','岑參','唐','唐诗','tang','','[]','女几知君憶，春雲相逐歸。',48,'全唐诗/poet.tang.9000.json','["女几知君憶，春雲相逐歸。", "草堂開藥裹，苔壁取荷衣。", "老竹移時少，新花舊處飛。", "可憐真傲吏，塵事到山稀。"]'),
('ed6531c4-32e3-409a-9c1c-7a3d07fe4765','送懷州吳別駕','岑參','唐','唐诗','tang','','[]','灞上柳枝黃，壚頭酒正香。',48,'全唐诗/poet.tang.9000.json','["灞上柳枝黃，壚頭酒正香。", "春流飲去馬，暮雨濕行裝。", "驛路通函谷，州城接太行。", "覃懷人總喜，別駕得王祥。"]'),
('5c060b80-d568-48e9-9bdd-8bd686764b7a','送人歸江寧','岑參','唐','唐诗','tang','','[]','楚客憶鄉信，向家湖水長。',48,'全唐诗/poet.tang.9000.json','["楚客憶鄉信，向家湖水長。", "住愁春草綠，去喜桂枝香。", "海月迎歸楚，江雲引到鄉。", "吾兄應借問，爲報鬢毛霜。"]'),
('f3ebe151-f22e-43d0-8936-edd8555afc91','送襄州任別駕','岑參','唐','唐诗','tang','','[]','別乘向襄州，蕭條楚地秋。',48,'全唐诗/poet.tang.9000.json','["別乘向襄州，蕭條楚地秋。", "江聲官舍裏，山色郡城頭。", "莫羨黃公蓋，須乘彥伯舟。", "高陽諸醉客，唯見古時丘。"]'),
('c714722f-dfa3-4c65-84a2-4ad47395ed29','送李司諫歸京','岑參','唐','唐诗','tang','','[]','別酒爲誰香，春官駁正郎。',48,'全唐诗/poet.tang.9000.json','["別酒爲誰香，春官駁正郎。", "醉經秦樹遠，夢怯漢川長。", "雨過風頭黑，雲開日脚黃。", "知君解起草，早去入文昌。"]'),
('bdbe7199-8194-4036-b1e2-25940455925f','送緜州李司馬秩滿歸京因呈李兵部','岑參','唐','唐诗','tang','','[]','久客厭江月，罷官思早歸。',48,'全唐诗/poet.tang.9000.json','["久客厭江月，罷官思早歸。", "眼看春光老，羞見梨花飛。", "劒北山居小，巴南音信稀。", "因君報兵部，愁淚日沾衣。"]'),
('f4ba6980-9371-4c36-af22-0d3d12449c1d','送崔員外入秦因訪故園','岑參','唐','唐诗','tang','','[]','欲謁明光殿，先趨建禮門。',48,'全唐诗/poet.tang.9000.json','["欲謁明光殿，先趨建禮門。", "仙郎去得意，亞相正承恩。", "竹裏巴山道，花間漢水源。", "憑將兩行淚，爲訪邵平園。"]'),
('3289abaf-561f-4f52-bc3b-474ba34426c3','送柳錄事赴梁州','岑參','唐','唐诗','tang','','[]','英掾柳家郎，離亭酒甕香。',48,'全唐诗/poet.tang.9000.json','["英掾柳家郎，離亭酒甕香。", "折腰思漢北，隨傳過巴陽。", "江樹連官舍，山雲到臥牀。", "知君歸夢積，去去劒川長。"]'),
('8ef9886d-e69b-4b6a-84d4-1bbb914cb0f3','送韋侍御先歸京','岑參','唐','唐诗','tang','','[]','聞欲朝龍闕，應須拂豸冠。',48,'全唐诗/poet.tang.9000.json','["聞欲朝龍闕，應須拂豸冠。", "風霜隨馬去，炎暑爲君寒。", "客淚題書落，鄉愁對酒寬。", "先憑報親友，後月到長安。"]'),
('00b1cc10-cea3-480e-b521-534bed2bfca6','送裴侍御赴歲入京','岑參','唐','唐诗','tang','','[]','羨他驄馬郎，元日謁明光。',48,'全唐诗/poet.tang.9000.json','["羨他驄馬郎，元日謁明光。", "立處聞天語，朝回惹御香。", "臺寒柏樹綠，江暖柳條黃。", "惜別津亭暮，揮戈憶魯陽。"]'),
('bbec112f-e996-40af-a921-e6c50b8f4916','送顏評事入京','岑參','唐','唐诗','tang','','[]','顏子人歎屈，宦遊今未遲。',48,'全唐诗/poet.tang.9000.json','["顏子人歎屈，宦遊今未遲。", "佇聞明主用，豈負青雲姿。", "江柳秋吐葉，山花寒滿枝。", "知君客愁處，月滿巴川時。"]'),
('00d1b5fb-ef26-4bee-b087-1e8f4b475ea3','送趙侍御歸上都','岑參','唐','唐诗','tang','','[]','驄馬五花毛，青雲歸處高。',48,'全唐诗/poet.tang.9000.json','["驄馬五花毛，青雲歸處高。", "霜隨驅夏暑，風逐振江濤。", "執簡皆推直，勤王豈告勞。", "帝城誰不戀，回望動離騷。"]'),
('f081e39e-395a-485f-970b-0bb9570bddbf','送楊子','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u996e\u9152", "\u9001\u522b"]','斗酒渭城邊，壚頭耐醉眠。',48,'全唐诗/poet.tang.9000.json','["斗酒渭城邊，壚頭耐醉眠。", "梨花千樹雪，楊葉萬條煙。", "惜別添壺酒，臨岐贈馬鞭。", "看君潁上去，新月到家圓。"]'),
('64e47b56-6f5f-46a8-a02b-c0830a25d881','送人赴安西','岑參','唐','唐诗','tang','','["\u6218\u4e89", "\u7231\u56fd", "\u8d5e\u7f8e", "\u79bb\u522b", "\u53cb\u4eba"]','上馬帶胡鈎，翩翩度隴頭。',48,'全唐诗/poet.tang.9000.json','["上馬帶胡鈎，翩翩度隴頭。", "小來思報國，不是愛封侯。", "萬里鄉爲夢，三邊月作愁。", "早須清黠虜，無事莫經秋。"]'),
('a1a9d048-cd4a-44b2-b8fc-9be5c34b1c1b','發臨洮將赴北庭留別','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','聞說輪臺路，連年見雪飛。',48,'全唐诗/poet.tang.9000.json','["聞說輪臺路，連年見雪飛。", "春風曾不到，漢使亦應稀。", "白草通疎勒，青山過武威。", "勤王敢道遠，私向夢中歸。"]'),
('1751b2ac-e010-467b-9331-dab0c0618096','臨洮泛舟趙仙舟自北庭罷使還京','岑參','唐','唐诗','tang','','[]','白髮輪臺使，邊功竟不成。',48,'全唐诗/poet.tang.9000.json','["白髮輪臺使，邊功竟不成。", "雲沙萬里地，孤負一書生。", "池上風迴舫，橋西雨過城。", "醉眠鄉夢罷，東望羨歸程。"]'),
('e2564b5f-f65c-43e9-b07a-a3385ff0e96e','春日醴泉杜明府承恩五品宴席上賦詩','岑參','唐','唐诗','tang','','[]','鳧舃舊稱仙，鴻私降自天。',48,'全唐诗/poet.tang.9000.json','["鳧舃舊稱仙，鴻私降自天。", "青袍移草色，朱綬奪花然。", "邑裏雷仍震，臺中星欲懸。", "吾兄此棲棘，因得賀初筵。"]'),
('e857891d-2247-488e-b445-2ecdb3e3cb1b','早春陪崔中丞同泛浣花谿宴','岑參','唐','唐诗','tang','','[]','旌節臨谿口，塞郊陡覺暄。',48,'全唐诗/poet.tang.9000.json','["旌節臨谿口，塞郊陡覺暄。", "紅亭移酒席，畫舸逗江村。", "雲帶歌聲颺，風飄舞袖翻。", "花間催秉燭，川上欲黃昏。"]'),
('e36fc6e9-0c5c-4846-b18a-0ba7d4ea30fe','喜華陰王少府使到南池宴集','岑參','唐','唐诗','tang','','[]','有客至鈴下，自言身姓梅。',48,'全唐诗/poet.tang.9000.json','["有客至鈴下，自言身姓梅。", "仙人掌裏使，黃帝鼎邊來。", "竹影拂棋局，荷香隨酒杯。", "池前堪醉臥，待月未須回。"]'),
('2dfe9475-04eb-4193-8178-e2af2e0ac0bf','行軍雪後月夜宴王卿家','岑參','唐','唐诗','tang','','[]','子夜雪華餘，卿家月影初。',48,'全唐诗/poet.tang.9000.json','["子夜雪華餘，卿家月影初。", "酒香薰枕席，爐氣煖軒除。", "晚歲宦情薄，行軍歡宴疎。", "相逢剩取醉，身外盡空虛。"]'),
('efe34525-547b-4c45-bd64-b198bd29b01f','梁州陪趙行軍龍岡寺北庭泛舟宴王侍御','岑參','唐','唐诗','tang','','[]','誰宴霜臺使，行軍粉署郎。',48,'全唐诗/poet.tang.9000.json','["誰宴霜臺使，行軍粉署郎。", "唱歌江鳥沒，吹笛岸花香。", "酒影搖新月，灘聲聒夕陽。", "江鐘聞已暮，歸櫂綠川長。"]'),
('64d6a39b-839b-4fee-85a8-c44141947ae0','奉陪封大夫宴得征字時封公兼鴻臚卿','岑參','唐','唐诗','tang','','[]','西邊虜盡平，何處更專征。',48,'全唐诗/poet.tang.9000.json','["西邊虜盡平，何處更專征。", "幕下人無事，軍中政已成。", "座參殊俗語，樂雜異方聲。", "醉裏東樓月，偏能照列卿。"]'),
('8f94823d-3aee-4815-a360-c6444d2fa79b','陪封大夫宴瀚海亭納涼','岑參','唐','唐诗','tang','','[]','細管雜青絲，千杯倒接䍦。',48,'全唐诗/poet.tang.9000.json','["細管雜青絲，千杯倒接䍦。", "軍中乘興出，海上納涼時。", "日沒鳥飛急，山高雲過遲。", "吾從大夫後，歸路擁旌旗。"]'),
('e76f8af5-cc6e-4358-b62f-faefbc105c25','虢州西亭陪端公宴集','岑參','唐','唐诗','tang','','[]','紅亭出鳥外，駿馬繫雲端。',48,'全唐诗/poet.tang.9000.json','["紅亭出鳥外，駿馬繫雲端。", "萬嶺牕前睥，千家肘底看。", "開瓶酒色嫩，踏地葉聲乾。", "爲逼霜臺使，重裘也覺寒。"]'),
('201f9fdc-32b3-4760-bf45-fdf64e609d10','陪使君早春東郊遊眺','岑參','唐','唐诗','tang','','[]','太守擁朱輪，東郊物候新。',48,'全唐诗/poet.tang.9000.json','["太守擁朱輪，東郊物候新。", "鶯聲隨坐嘯，柳色喚行春。", "谷口雲迎馬，谿邊水照人。", "郡中叨佐理，何幸接芳塵。"]'),
('a6e8b764-028a-4f37-ad86-79b7771901c8','雪後與羣公過慈恩寺','岑參','唐','唐诗','tang','','[]','乘興忽相招，僧房暮與朝。',48,'全唐诗/poet.tang.9000.json','["乘興忽相招，僧房暮與朝。", "雪融雙樹濕，沙闇一燈燒。", "竹外山低塔，藤間院隔橋。", "歸家如欲嬾，俗慮向來銷。"]'),
('cab002c4-20bf-4655-816b-42285672ac52','與鄠縣羣官泛渼陂','岑參','唐','唐诗','tang','','[]','萬頃浸天色，千尋窮地根。',48,'全唐诗/poet.tang.9000.json','["萬頃浸天色，千尋窮地根。", "舟移城入樹，岸闊水浮村。", "閑鷺驚簫管，潛蚪傍酒樽。", "暝來呼小吏，列火儼歸軒。"]'),
('855e941b-a519-4c21-881e-f02b787c781b','與鄠縣源少府泛渼陂','岑參','唐','唐诗','tang','','[]','載酒入天色，水涼難醉人。',48,'全唐诗/poet.tang.9000.json','["載酒入天色，水涼難醉人。", "清搖縣郭動，碧洗雲山新。", "吹笛驚白鷺，垂竿跳紫鱗。", "憐君公事後，陂上日娛賓。"]'),
('8caa72e6-fb8a-4eec-b10c-b9c8e5aa604f','終南東谿中作','岑參','唐','唐诗','tang','','[]','谿水碧於草，潺潺花底流。',48,'全唐诗/poet.tang.9000.json','["谿水碧於草，潺潺花底流。", "沙平堪濯足，石淺不勝舟。", "洗藥朝與暮，釣魚春復秋。", "興來從所適，還欲向滄洲。"]'),
('1d3ee014-4685-411f-a355-c61fb8f1c60f','與鮮于庶子泛漢江','岑參','唐','唐诗','tang','','[]','急管更須吹，杯行莫遣遲。',50,'全唐诗/poet.tang.9000.json','["急管更須吹，杯行莫遣遲。", "酒光紅琥珀，江色碧琉璃。", "日影浮歸櫂，蘆花罥釣絲。", "山公醉不醉，問取葛[彊]知。"]'),
('8b5dace5-0190-47bd-9ccb-753d02586841','晦日陪侍御泛北池','岑參','唐','唐诗','tang','','[]','春池滿復寬，晦節耐邀歡。',48,'全唐诗/poet.tang.9000.json','["春池滿復寬，晦節耐邀歡。", "月帶蝦蟆冷，霜隨獬豸寒。", "水雲低錦席，岸柳拂金盤。", "日暮舟中散，都人夾道看。"]'),
('a9386166-3c09-4fe5-8729-211522fed11c','登涼州尹臺寺','岑參','唐','唐诗','tang','','["\u6625\u5929", "\u8fb9\u585e", "\u751f\u6d3b"]','胡地三月半，梨花今始開。',48,'全唐诗/poet.tang.9000.json','["胡地三月半，梨花今始開。", "因從老僧飯，更上夫人臺。", "清唱雲不去，彈弦風颯來。", "應須一倒載，還似山公回。"]'),
('942207f5-4f44-4a17-be61-d8c1d920e15b','登總持閣','岑參','唐','唐诗','tang','','[]','高閣逼諸天，登臨近日邊。',48,'全唐诗/poet.tang.9000.json','["高閣逼諸天，登臨近日邊。", "晴開萬井樹，愁看五陵煙。", "檻外低秦嶺，牕中小渭川。", "蚤知清淨理，常願奉金仙。"]'),
('93d374e6-a2de-40d6-8693-00d9f2f12735','奉陪封大夫九日登高','岑參','唐','唐诗','tang','','["\u5c06\u58eb", "\u601d\u4e61", "\u91cd\u9633\u8282", "\u996e\u9152", "\u767b\u9ad8"]','九日黃花酒，登高會昔聞。',48,'全唐诗/poet.tang.9000.json','["九日黃花酒，登高會昔聞。", "霜威逐亞相，殺氣傍中軍。", "橫笛驚征雁，嬌歌落塞雲。", "邊頭幸無事，醉舞荷吾君。"]'),
('dadc890d-8b50-4436-a24b-ebbab78de0ac','郡齋平望江山','岑參','唐','唐诗','tang','','[]','水路東連楚，人煙北接巴。',48,'全唐诗/poet.tang.9000.json','["水路東連楚，人煙北接巴。", "山光圍一郡，江月照千家。", "庭樹純栽橘，園畦半種茶。", "夢魂知憶處，無夜不京華。"]'),
('dec866d2-fe96-49ae-b85c-b496ece796c1','宿岐州北郭嚴給事別業','岑參','唐','唐诗','tang','','[]','郭外山色暝，主人林館秋。',48,'全唐诗/poet.tang.9000.json','["郭外山色暝，主人林館秋。", "疎鐘入臥內，片月到牀頭。", "遙夜惜已半，清言殊未休。", "君雖在青瑣，心不忘滄洲。"]'),
('10be75fb-88f4-48bd-9c47-693b105abeb9','暮秋會嚴京兆後廳竹齋','岑參','唐','唐诗','tang','','[]','京兆小齋寬，公庭半藥闌。',48,'全唐诗/poet.tang.9000.json','["京兆小齋寬，公庭半藥闌。", "甌香茶色嫩，牕冷竹聲乾。", "盛德中朝貴，清風畫省寒。", "能將吏部鏡，照取寸心看。"]'),
('475e4fe0-2285-48fa-934c-45a953968c98','省中即事','岑參','唐','唐诗','tang','','[]','華省謬爲郎，蹉跎鬢已蒼。',48,'全唐诗/poet.tang.9000.json','["華省謬爲郎，蹉跎鬢已蒼。", "到來恆襆被，隨例且含香。", "竹影遮牕暗，花陰拂簟涼。", "君王新賜筆，草奏向明光。"]'),
('e501217e-860a-4c75-97a4-acd950c32a3b','尋陽七郎中宅即事','岑參','唐','唐诗','tang','','[]','萬事信蒼蒼，機心久已忘。',48,'全唐诗/poet.tang.9000.json','["萬事信蒼蒼，機心久已忘。", "無端來出守，不是厭爲郎。", "雨滴芭蕉赤，霜催橘子黃。", "逢君開口笑，何處有他鄉。"]'),
('a9482ea5-89a4-4ad7-967c-b65206c8cc87','攜琴酒尋閻防崇濟寺所居僧院','岑參','唐','唐诗','tang','','[]','相訪但尋鐘，門寒古殿松。',48,'全唐诗/poet.tang.9000.json','["相訪但尋鐘，門寒古殿松。", "彈琴醒暮酒，卷幔引諸峰。", "事愜林中語，人幽物外蹤。", "吾廬幸接近，茲地興偏慵。"]'),
('89b4aaae-3a69-4e0a-98bc-87dbed3aad15','春尋河陽陶處士別業','岑參','唐','唐诗','tang','','[]','風煖日暾暾，黃鸝飛近村。',48,'全唐诗/poet.tang.9000.json','["風煖日暾暾，黃鸝飛近村。", "花明潘子縣，柳暗陶公門。", "藥椀搖山影，魚竿帶水痕。", "南橋車馬客，何事苦喧喧。"]'),
('6f7dc274-b65b-4444-90a7-0990b53cf412','晚過盤石寺禮鄭和尚','岑參','唐','唐诗','tang','','["\u7985\u610f", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','暫詣高僧話，來尋野寺孤。',48,'全唐诗/poet.tang.9000.json','["暫詣高僧話，來尋野寺孤。", "岸花藏水碓，谿水映風爐。", "頂上巢新鵲，衣中帶舊珠。", "談禪未得去，輟櫂且踟躕。"]'),
('e1c394cb-ae30-4e58-b94b-b7ccff9cea5f','尋少室張山人聞與偃師周明府同入都','岑參','唐','唐诗','tang','','[]','中峰鍊金客，昨日遊人間。',48,'全唐诗/poet.tang.9000.json','["中峰鍊金客，昨日遊人間。", "葉縣鳧共去，葛陂龍暫還。", "春雲湊深水，秋雨懸空山。", "寂寂清谿上，空餘丹竈閑。"]'),
('2bc9be69-d53b-40c5-8ace-163dbfa5260c','虢州臥疾喜劉判官相過水亭','岑參','唐','唐诗','tang','','[]','臥疾嘗晏起，朝來頭未梳。',48,'全唐诗/poet.tang.9000.json','["臥疾嘗晏起，朝來頭未梳。", "見君勝服藥，清話病能除。", "低柳共繫馬，小池堪釣魚。", "觀棋不覺暝，月出水亭初。"]'),
('d986d292-aede-419a-b03b-2c685e32ff3e','武威春暮聞宇文判官西使還已到晉昌','岑參','唐','唐诗','tang','','["\u601d\u4e61", "\u53cb\u60c5", "\u8fb9\u585e", "\u65f6\u5149", "\u611f\u4f24"]','岸雨過城頭，黃鸝上戍樓。',48,'全唐诗/poet.tang.9000.json','["岸雨過城頭，黃鸝上戍樓。", "塞北飄客淚，邊柳挂鄉愁。", "白髮悲明鏡，青春換敝裘。", "君從萬里使，聞已到瓜州。"]'),
('9d1230ef-8c29-49f7-b013-8fcf3f94ea0d','虢州南池候嚴中丞不至','岑參','唐','唐诗','tang','','[]','池上日相待，知君殊未回。',48,'全唐诗/poet.tang.9000.json','["池上日相待，知君殊未回。", "徒教柳葉長，漫使梨花開。", "駟馬去不見，雙魚空往來。", "思想不解說，孤負舟中杯。"]'),
('7575d20e-1b62-4590-b21a-70f42191a8a8','春興思南山舊廬招柳建正字','岑參','唐','唐诗','tang','','[]','終歲不得意，春風今復來。',48,'全唐诗/poet.tang.9000.json','["終歲不得意，春風今復來。", "自憐蓬鬢改，羞見梨花開。", "西掖誠可戀，南山思早回。", "園廬幸接近，相與歸蒿萊。"]'),
('9a5fac36-da93-494c-a93f-5d10c1735cb4','郡齋南池招楊轔','岑參','唐','唐诗','tang','','[]','郡僻人事少，雲山常眼前。',48,'全唐诗/poet.tang.9000.json','["郡僻人事少，雲山常眼前。", "偶從池上醉，便向舟中眠。", "與子居最近，周官情又偏。", "閑時耐相訪，正有牀頭錢。"]'),
('606b154c-402d-4a13-a560-7e7fa8535dae','高冠谷口招鄭鄠','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u8bbf\u53cb", "\u5199\u666f", "\u9690\u5c45"]','谷口來相訪，空齋不見君。',48,'全唐诗/poet.tang.9000.json','["谷口來相訪，空齋不見君。", "澗花然暮雨，潭樹煖春雲。", "門徑稀人迹，簷峰下鹿羣。", "衣裳與枕席，山靄碧氛氳。"]'),
('da097e8a-3f7b-4c3c-a17d-125314cf6895','題新鄉王釜廳壁','岑參','唐','唐诗','tang','','[]','憐君守一尉，家計復清貧。',48,'全唐诗/poet.tang.9000.json','["憐君守一尉，家計復清貧。", "祿米嘗不足，俸錢供與人。", "城頭蘇門樹，陌上黎陽塵。", "不是舊相識，聲同心自親。"]'),
('06d036e4-4c05-4000-83ff-0f208c4fa367','題山寺僧房','岑參','唐','唐诗','tang','','[]','牕影搖羣木，牆陰載一峰。',48,'全唐诗/poet.tang.9000.json','["牕影搖羣木，牆陰載一峰。", "野爐風自爇，山碓水能舂。", "勤學翻知誤，爲官好欲慵。", "高僧暝不見，月出但聞鐘。"]'),
('45f168f2-81ab-4773-ab03-010f78d082b5','漢上題韋氏莊','岑參','唐','唐诗','tang','','[]','結茅聞楚客，卜築漢江邊。',48,'全唐诗/poet.tang.9000.json','["結茅聞楚客，卜築漢江邊。", "日落數歸鳥，夜深聞扣舷。", "水痕侵岸柳，山翠借廚煙。", "調笑提筐婦，春來蠶幾眠。"]'),
('075c697f-4e90-48f3-8dcc-625a6fdb8ed4','題永樂韋少府廳壁','岑參','唐','唐诗','tang','','[]','大河南郭外，終日氣昏昏。',48,'全唐诗/poet.tang.9000.json','["大河南郭外，終日氣昏昏。", "白鳥下公府，青山當縣門。", "故人是邑尉，過客駐征軒。", "不憚煙波闊，思君一笑言。"]'),
('8838562d-a64b-4e02-a707-ed044254e8b2','題金城臨河驛樓','岑參','唐','唐诗','tang','','[]','古戍依重險，高樓見五涼。',48,'全唐诗/poet.tang.9000.json','["古戍依重險，高樓見五涼。", "山根盤驛道，河水浸城牆。", "庭樹巢鸚鵡，園花隱麝香。", "忽如江浦上，憶作捕魚郎。"]'),
('af278a58-b504-4703-a2f0-eb6f5a31160a','初授官題高冠草堂','岑參','唐','唐诗','tang','','["\u6292\u60c5"]','三十始一命，宦情多欲闌。',48,'全唐诗/poet.tang.9000.json','["三十始一命，宦情多欲闌。", "自憐無舊業，不敢恥微官。", "澗水吞樵路，山花醉藥欄。", "秪緣五斗米，辜負一漁竿。"]'),
('c5d991e6-38fa-40dc-ac49-acf47534095c','題虢州西樓','岑參','唐','唐诗','tang','','[]','錯料一生事，蹉跎今白頭。',48,'全唐诗/poet.tang.9000.json','["錯料一生事，蹉跎今白頭。", "縱橫皆失計，妻子也堪羞。", "明主雖然棄，丹心亦未休。", "愁來無去處，祗上郡西樓。"]'),
('941f0750-3bb4-449e-b184-c7fb60bbcecf','夜過盤石隔河望永樂寄閨中效齊梁體','岑參','唐','唐诗','tang','','[]','盈盈一水隔，寂寂二更初。',48,'全唐诗/poet.tang.9000.json','["盈盈一水隔，寂寂二更初。", "波上思羅襪，魚邊憶素書。", "月如眉已畫，雲似鬢新梳。", "春物知人意，桃花笑索居。"]'),
('1e8c6ead-4285-4dfc-bbe2-7907d66ecd60','河西春暮憶秦中','岑參','唐','唐诗','tang','','[]','渭北春已老，河西人未歸。',48,'全唐诗/poet.tang.9000.json','["渭北春已老，河西人未歸。", "邊城細草出，客館梨花飛。", "別後鄉夢數，昨來家信稀。", "涼州三月半，猶未脫寒衣。"]'),
('34c6e792-41b4-4961-8841-50dddc9afc0d','過酒泉憶杜陵別業','岑參','唐','唐诗','tang','','[]','昨夜宿[祈]連，今朝過酒泉。',50,'全唐诗/poet.tang.9000.json','["昨夜宿[祈]連，今朝過酒泉。", "黃沙西際海，白草北連天。", "愁裏難消日，歸期尚隔年。", "陽關萬里夢，知處杜陵田。"]'),
('799bb8ec-001a-4658-aa27-ce9b43b3af79','早發焉耆懷終南別業','岑參','唐','唐诗','tang','','["\u7f81\u65c5", "\u6292\u60c5", "\u8fb9\u585e", "\u601d\u4e61"]','曉笛別鄉淚，秋冰鳴馬蹄。',48,'全唐诗/poet.tang.9000.json','["曉笛別鄉淚，秋冰鳴馬蹄。", "一身虜雲外，萬里胡天西。", "終日見征戰，連年聞鼓鼙。", "故山在何處，昨日夢清谿。"]'),
('65370061-0dee-4946-8001-72968f6ba4cf','宿鐵關西館','岑參','唐','唐诗','tang','','["\u6000\u4e61", "\u6292\u6000", "\u8fb9\u585e"]','馬汗踏成泥，朝馳幾萬蹄。',48,'全唐诗/poet.tang.9000.json','["馬汗踏成泥，朝馳幾萬蹄。", "雪中行地角，火處宿天倪。", "塞迥心常怯，鄉遙夢亦迷。", "那知故園月，也到鐵關西。"]'),
('b2fc35c7-6fc6-467f-860d-57258912f837','首秋輪臺','岑參','唐','唐诗','tang','','["\u8fb9\u585e", "\u6292\u6000", "\u5199\u666f", "\u58ee\u5fd7\u672a\u916c"]','異域陰山外，孤城雪海邊。',48,'全唐诗/poet.tang.9000.json','["異域陰山外，孤城雪海邊。", "秋來唯有雁，夏盡不聞蟬。", "雨拂氊牆濕，風搖毳幕羶。", "輪臺萬里地，無事歷三年。"]'),
('56829847-cde6-43e5-a01f-9a35ed3b4f75','北庭作','岑參','唐','唐诗','tang','','[]','雁塞通鹽澤，龍堆接醋溝。',48,'全唐诗/poet.tang.9000.json','["雁塞通鹽澤，龍堆接醋溝。", "孤城天北畔，絕域海西頭。", "秋雪春仍下，朝風夜不休。", "可知年四十，猶自未對侯。"]'),
('4e7379f3-1485-48e1-adb5-c55a4a0fa0d6','輪臺即事','岑參','唐','唐诗','tang','','[]','輪臺風物異，地是古單于。',48,'全唐诗/poet.tang.9000.json','["輪臺風物異，地是古單于。", "三月無青草，千家盡白榆。", "蕃書文字別，胡俗語音殊。", "愁見流沙北，天西海一隅。"]'),
('2a69f46d-4f3e-4702-bec3-f558896c639a','還東山洛上作','岑參','唐','唐诗','tang','','[]','春流急不淺，歸栧去何遲。',48,'全唐诗/poet.tang.9000.json','["春流急不淺，歸栧去何遲。", "愁客葉舟裏，夕陽花水時。", "雲晴開螮蝀，櫂發起鸕鷀。", "莫道東山遠，衡門在夢思。"]'),
('ede5d2f0-2250-4ce0-928a-189b8f78be3a','楊固店','岑參','唐','唐诗','tang','','[]','客舍梨葉赤，鄰家聞擣衣。',48,'全唐诗/poet.tang.9000.json','["客舍梨葉赤，鄰家聞擣衣。", "夜來嘗有夢，墜淚緣思歸。", "洛水行欲盡，緱山看漸微。", "長安祗千里，何事信音稀。"]'),
('a0180137-77aa-45ae-bcef-bcb9871b16cf','巴南舟中思陸渾別業','岑參','唐','唐诗','tang','','[]','瀘水南州遠，巴山北客稀。',48,'全唐诗/poet.tang.9000.json','["瀘水南州遠，巴山北客稀。", "嶺雲撩亂起，谿鷺等閑飛。", "鏡裏愁衰鬢，舟中換旅衣。", "夢魂知憶處，無夜不先歸。"]'),
('bc644572-a42e-4f61-a13b-14ec8b31d6cb','晚發五渡','岑參','唐','唐诗','tang','','[]','客厭巴南地，鄉鄰劒北天。',48,'全唐诗/poet.tang.9000.json','["客厭巴南地，鄉鄰劒北天。", "江村片雨外，野寺夕陽邊。", "芋葉藏山徑，蘆花雜渚田。", "舟行未可住，乘月且須牽。"]'),
('df0c041e-296c-4d2d-aacc-a3cd2a3ea5ce','巴南舟中夜市','岑參','唐','唐诗','tang','','[]','渡口欲黃昏，歸人爭渡喧。',48,'全唐诗/poet.tang.9000.json','["渡口欲黃昏，歸人爭渡喧。", "近鐘清野寺，遠火點江村。", "見雁思鄉信，聞猿積淚痕。", "孤舟萬里外，秋月不堪論。"]'),
('090d3800-346b-438e-b46f-3721f5e98c9a','江上春歎','岑參','唐','唐诗','tang','','[]','臘月江上煖，南橋新柳枝。',48,'全唐诗/poet.tang.9000.json','["臘月江上煖，南橋新柳枝。", "春風觸處到，憶得故園時。", "終日不如意，出門何所之。", "從人覓顏色，自笑弱男兒。"]'),
('9d6c53a6-b931-415f-b64b-d5865fbdc3dd','初至犍爲作','岑參','唐','唐诗','tang','','[]','山色軒檻內，灘聲枕席間。',48,'全唐诗/poet.tang.9000.json','["山色軒檻內，灘聲枕席間。", "草生公府靜，花落訟庭閒。", "雲雨連三峽，風塵接百蠻。", "到來能幾日，不覺鬢毛斑。"]'),
('9f1e6bb4-4e9f-4b79-bac6-235db11ae50f','使院中新栽柏樹子呈李十五栖筠','岑參','唐','唐诗','tang','','[]','愛爾青青色，移根此地來。',48,'全唐诗/poet.tang.9000.json','["愛爾青青色，移根此地來。", "不曾臺上種，留向磧中栽。", "脆葉欺門柳，狂花笑院梅。", "不須愁歲晚，霜露豈能摧。"]'),
('897e5256-c002-441c-80de-af184c77a3bd','詠郡齋壁畫片雲','岑參','唐','唐诗','tang','','[]','雲片何人畫，塵侵粉色微。',48,'全唐诗/poet.tang.9000.json','["雲片何人畫，塵侵粉色微。", "未曾行雨去，不見逐風歸。", "只怪偏凝壁，回看欲惹衣。", "丹青忽借便，移向帝鄉飛。"]'),
('1d9dc1c0-b0af-4ff4-ba99-29168239d1f1','臨洮龍興寺玄上人院同詠青木香叢','岑參','唐','唐诗','tang','','[]','移根自遠方，種得在僧房。',48,'全唐诗/poet.tang.9000.json','["移根自遠方，種得在僧房。", "六月花新吐，三春葉已長。", "抽莖高錫杖，引影到繩牀。", "只爲能除疾，傾心向藥王。"]'),
('ff6e3381-70ea-49e4-bffd-3529930e9eca','成王挽歌','岑參','唐','唐诗','tang','','[]','幽山悲舊桂，長坂愴餘蘭。',48,'全唐诗/poet.tang.9000.json','["幽山悲舊桂，長坂愴餘蘭。", "地底孤燈冷，泉中一鏡寒。", "銘旌門客送，騎吹路人看。", "漫作琉璃椀，淮王誤合丹。"]'),
('07facfea-c701-45af-bc84-2f86c5bbbbb9','苗侍中挽歌二首 一','岑參','唐','唐诗','tang','','[]','攝政朝章重，持衡國相尊。',48,'全唐诗/poet.tang.9000.json','["攝政朝章重，持衡國相尊。", "筆端通造化，掌內運乾坤。", "青史遺芳滿，黃樞故事存。", "空悲渭橋路，誰對漢皇言。"]'),
('7c9bc07f-1133-41c2-8654-e367b8b3af4f','苗侍中挽歌二首 二','岑參','唐','唐诗','tang','','[]','天子悲元老，都人惜上公。',48,'全唐诗/poet.tang.9000.json','["天子悲元老，都人惜上公。", "優賢几杖在，會葬市朝空。", "丹旐飛斜日，清笳怨暮風。", "平生門下客，繼美廟堂中。"]'),
('80968441-1503-4a6d-87be-31a5b7a6480b','故僕射裴公挽歌三首 一','岑參','唐','唐诗','tang','','[]','盛德資邦傑，嘉謨作世程。',48,'全唐诗/poet.tang.9000.json','["盛德資邦傑，嘉謨作世程。", "門瞻駟馬貴，時仰八龍名。", "罷市秦人送，還鄉絳老迎。", "莫埋丞相印，留着付玄成。"]'),
('8cc8ca36-fce5-425c-afda-bccb6fd979a1','故僕射裴公挽歌三首 二','岑參','唐','唐诗','tang','','[]','五府瞻高位，三台喪大賢。',48,'全唐诗/poet.tang.9000.json','["五府瞻高位，三台喪大賢。", "禮容還故絳，寵贈冠新田。", "氣歇汾陰鼎，魂飛京兆阡。", "先時劒已沒，隴樹久蒼然。"]'),
('7b743f03-a8c1-4949-af0f-c979c820fc39','故僕射裴公挽歌三首 三','岑參','唐','唐诗','tang','','[]','富貴徒言久，鄉閭歿後歸。',48,'全唐诗/poet.tang.9000.json','["富貴徒言久，鄉閭歿後歸。", "錦衣都未着，丹旐忽先飛。", "哀挽辭秦塞，悲笳出帝畿。", "遙知九原上，漸覺弔人稀。"]'),
('b626c58d-f3c4-437d-af00-d7827fac12b7','河西太守杜公挽歌四首 一','岑參','唐','唐诗','tang','','[]','蒙叟悲藏壑，殷宗惜濟川。',48,'全唐诗/poet.tang.9000.json','["蒙叟悲藏壑，殷宗惜濟川。", "長安非舊日，京兆是新阡。", "黃霸官猶屈，蒼生望已愆。", "唯餘卿月在，留向杜陵懸。"]'),
('bd376965-fe7e-48ab-ab69-f88275a08101','河西太守杜公挽歌四首 二','岑參','唐','唐诗','tang','','[]','鼓角城中出，墳塋郭外新。',48,'全唐诗/poet.tang.9000.json','["鼓角城中出，墳塋郭外新。", "雨隨思太守，雲從送夫人。", "蒿里埋雙劒，松門閉萬春。", "回瞻北堂上，金印已生塵。"]'),
('bcd03ce6-61c8-4fcd-9f14-59f4856e28d5','河西太守杜公挽歌四首 三','岑參','唐','唐诗','tang','','[]','憶昨明光殿，新承天子恩。',48,'全唐诗/poet.tang.9000.json','["憶昨明光殿，新承天子恩。", "剖符移北地，授鉞領西門。", "塞草迎軍幕，邊雲拂使軒。", "至今聞隴外，戎虜尚亡魂。"]'),
('1ac4a3c1-ccb0-4d25-8a4e-c76b6a384b74','河西太守杜公挽歌四首 四','岑參','唐','唐诗','tang','','[]','漫漫澄波闊，沈沈大廈深。',48,'全唐诗/poet.tang.9000.json','["漫漫澄波闊，沈沈大廈深。", "秉心常匪席，行義每揮金。", "汲引窺蘭室，招攜入翰林。", "多君有令子，猶注世人心。"]'),
('c2e7488b-3c97-4739-9e36-6c28452295d9','故河南尹岐國公贈工部尚書蘇公挽歌二首 一','岑參','唐','唐诗','tang','','[]','河尹恩榮舊，尚書寵贈新。',48,'全唐诗/poet.tang.9000.json','["河尹恩榮舊，尚書寵贈新。", "一門傳畫戟，幾世駕朱輪。", "夜色何時曉，泉臺不復春。", "唯餘朝服在，金印已生塵。"]'),
('61ac11ab-471c-4bcc-bac8-33ffb6f7ccdf','故河南尹岐國公贈工部尚書蘇公挽歌二首 二','岑參','唐','唐诗','tang','','[]','白日扃泉戶，青春掩夜臺。',48,'全唐诗/poet.tang.9000.json','["白日扃泉戶，青春掩夜臺。", "舊堂階草長，空院砌花開。", "山晚銘旌去，郊寒騎吹回。", "三川難可見，應惜庾公才。"]'),
('9a19de5f-182b-4dcc-865d-e73c67806460','韓員外夫人清河縣君崔氏挽歌二首 一','岑參','唐','唐诗','tang','','[]','令德當時重，高門舉世推。',48,'全唐诗/poet.tang.9000.json','["令德當時重，高門舉世推。", "從夫榮已絕，封邑寵難追。", "陌上人皆惜，花間鳥亦悲。", "仙郎看隴月，猶憶畫眉時。"]'),
('11d10305-fe34-4447-9547-149db5c95acc','韓員外夫人清河縣君崔氏挽歌二首 二','岑參','唐','唐诗','tang','','[]','遽聞傷別劒，忽復歎藏舟。',48,'全唐诗/poet.tang.9000.json','["遽聞傷別劒，忽復歎藏舟。", "燈冷泉中夜，衣寒地下秋。", "青松弔客淚，丹旐路人愁。", "徒有清河在，空悲逝水流。"]'),
('f2b7e556-c319-4639-ae99-50a9f1957998','西河郡太原守張夫人挽歌','岑參','唐','唐诗','tang','','[]','鵲印慶仍傳，魚軒寵莫先。',48,'全唐诗/poet.tang.9000.json','["鵲印慶仍傳，魚軒寵莫先。", "從夫元凱貴，訓子孟軻賢。", "龍是雙歸日，鸞非獨舞年。", "哀容今共盡，悽愴杜陵田。"]'),
('bd39dd1e-3fad-4c0e-b3b1-dacc6e1c0ba7','南溪別業','岑參','唐','唐诗','tang','','[]','結宇依青嶂，開軒對翠疇。',48,'全唐诗/poet.tang.9000.json','["結宇依青嶂，開軒對翠疇。", "樹交花兩色，溪合水重流。", "竹徑春來埽，蘭樽夜不收。", "逍遙自得意，鼓腹醉中遊。"]'),
('8df8e94b-ffe4-4930-af4c-491d7cb04651','奉和中書舍人賈至早朝大明宮','岑參','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u5531\u548c"]','雞鳴紫陌曙光寒，鶯囀皇州春色闌。',64,'全唐诗/poet.tang.9000.json','["雞鳴紫陌曙光寒，鶯囀皇州春色闌。", "金闕曉鐘開萬戶，玉階仙仗擁千官。", "花迎劒珮星初落，柳拂旌旗露未乾。", "獨有鳳皇池上客，陽春一曲和皆難。"]'),
('0fd481a8-ef2b-4d69-9dd6-f1f25ebb3d3d','和祠部王員外雪後早朝即事','岑參','唐','唐诗','tang','','[]','長安雪後似春歸，積素凝華連曙暉。',64,'全唐诗/poet.tang.9000.json','["長安雪後似春歸，積素凝華連曙暉。", "色借玉珂迷曉騎，光添銀燭晃朝衣。", "西山落月臨天仗，北闕晴雲捧禁闈。", "聞道仙郎歌白雪，由來此曲和人稀。"]'),
('33b81898-2637-46c9-a34f-b2c15de78aac','奉和相公發益昌','岑參','唐','唐诗','tang','','[]','相[國]臨戎別帝京，擁麾持節遠橫行。',66,'全唐诗/poet.tang.9000.json','["相[國]臨戎別帝京，擁麾持節遠橫行。", "朝登劒閣雲隨馬，夜渡巴江雨洗兵。", "山花萬朵迎征蓋，川柳千條拂去旌。", "暫到蜀城應計日，須知明主待持衡。"]'),
('2fef49ff-5115-4129-88e1-e484fecf236e','秋夕讀書幽興獻兵部李侍郎','岑參','唐','唐诗','tang','','[]','年紀蹉跎四十強，自憐頭白始爲郎。',64,'全唐诗/poet.tang.9000.json','["年紀蹉跎四十強，自憐頭白始爲郎。", "雨滋苔蘚侵堦綠，秋颯梧桐覆井黃。", "驚蟬也解求高樹，旅雁還應厭後行。", "覽卷試穿鄰舍壁，明燈何惜借餘光。"]'),
('59a041cd-30cd-473c-a70e-9b0328ad56df','使君席夜送嚴河南赴長水','岑參','唐','唐诗','tang','','[]','嬌歌急管雜青絲，銀燭金杯映翠眉。',64,'全唐诗/poet.tang.9000.json','["嬌歌急管雜青絲，銀燭金杯映翠眉。", "使君地主能相送，河尹天明坐莫辭。", "春城月出人皆醉，野戍花深馬去遲。", "寄聲報爾山翁道，今日河南勝昔時。"]'),
('5750096c-2a14-421b-ba44-a45fd3069ce9','暮春虢州東亭送李司馬歸扶風別廬','岑參','唐','唐诗','tang','','[]','柳嚲鶯嬌花復殷，紅亭綠酒送君還。',64,'全唐诗/poet.tang.9000.json','["柳嚲鶯嬌花復殷，紅亭綠酒送君還。", "到來函谷愁中月，歸去磻谿夢裏山。", "簾前春色應須惜，世上浮名好是閑。", "西望鄉關腸欲斷，對君衫袖淚痕斑。"]'),
('66c7a0ea-52b7-4f2d-b60d-bf0fc5540b83','九日使君席奉餞衛中丞赴長水','岑參','唐','唐诗','tang','','[]','節使橫行西出師，鳴弓擐甲羽林兒。',64,'全唐诗/poet.tang.9000.json','["節使橫行西出師，鳴弓擐甲羽林兒。", "臺上霜風凌草木，軍中殺氣傍旌旗。", "預知漢將宣威日，正是胡塵欲滅時。", "爲報使君多泛菊，更將絃管醉東籬。"]'),
('9ed73287-c270-4b17-bab5-5f1208f81a41','西掖省即事','岑參','唐','唐诗','tang','','[]','西掖重雲開曙暉，北山疎雨點朝衣。',64,'全唐诗/poet.tang.9000.json','["西掖重雲開曙暉，北山疎雨點朝衣。", "千門柳色連青瑣，三殿花香入紫微。", "平明端笏陪鵷列，薄暮垂鞭信馬歸。", "官拙自悲頭白盡，不如巖下偃荆扉。"]'),
('91ceccfa-e17f-4894-9173-eda8431da244','首春渭西郊行呈藍田張二主簿','岑參','唐','唐诗','tang','','[]','迥風度雨渭城西，細草新花踏作泥。',64,'全唐诗/poet.tang.9000.json','["迥風度雨渭城西，細草新花踏作泥。", "秦女峰頭雪未盡，胡公阪上日初低。", "愁窺白髮羞微祿，悔別青山憶舊谿。", "聞道輞川多勝事，玉壺春酒正堪攜。"]'),
('144d614b-8719-4abb-9912-a49938f9f478','赴嘉州過城固縣尋永安超禪師房','岑參','唐','唐诗','tang','','[]','滿寺枇杷冬着花，老僧相見具袈裟。',64,'全唐诗/poet.tang.9000.json','["滿寺枇杷冬着花，老僧相見具袈裟。", "漢王城北雪初霽，韓信臺西日欲斜。", "門外不須催五馬，林中且聽演三車。", "豈料巴川多勝事，爲君書此報京華。"]'),
('6326e769-0ca2-40d1-99ca-5e390fc4f6d4','酬暢當嵩山尋麻道士見寄','岑參','唐','唐诗','tang','','[]','聞逐樵夫閑看棋，忽逢人世是秦時。',64,'全唐诗/poet.tang.9000.json','["聞逐樵夫閑看棋，忽逢人世是秦時。", "開雲種玉嫌山淺，渡海傳書怪鶴遲。", "陰洞石幢微有字，古壇松樹半無枝。", "煩君遠示青囊錄，願得相從一問師。"]'),
('01655f93-334b-4946-a837-251f48544016','和刑部成員外秋夜寓直寄臺省知己','岑參','唐','唐诗','tang','','[]','列宿光三署，仙郎直五宵。',122,'全唐诗/poet.tang.9000.json','["列宿光三署，仙郎直五宵。", "時衣天子賜，廚膳大官調。", "長樂鐘應近，明光漏不遙。", "黃門持被覆，侍女捧香燒。", "筆爲題詩點，燈緣起草挑。", "竹喧交砌葉，柳嚲拂牕條。", "粉署榮新命，霜臺憶舊僚。", "名香播蘭蕙，重價蘊瓊瑤。", "擊水翻滄海，[摶]風透赤霄。", "微才喜同舍，何幸忽聞韶。"]'),
('9735cba2-2b9c-4adf-b091-6e780b070121','送廬郎中除杭州赴任','岑參','唐','唐诗','tang','','[]','罷起郎官草，初分刺史符。',72,'全唐诗/poet.tang.9000.json','["罷起郎官草，初分刺史符。", "海雲迎過楚，江月引歸吳。", "城低濤聲震，樓端蜃氣孤。", "千家窺驛舫，五馬飲春湖。", "柳色供詩用，鶯聲送酒須。", "知君望鄉處，枉道上姑蘇。"]'),
('1200b978-8036-48a0-8309-f7025e346885','奉送李賓客荆南迎親','岑參','唐','唐诗','tang','','[]','迎親辭舊苑，恩詔下儲闈。',72,'全唐诗/poet.tang.9000.json','["迎親辭舊苑，恩詔下儲闈。", "昨見雙魚去，今看駟馬歸。", "驛帆湘水闊，客舍楚山稀。", "手把黃香扇，身披萊子衣。", "鵲隨金印喜，烏傍板輿飛。", "勝作東征賦，還家滿路輝。"]'),
('c708dbc3-03b5-4fe6-a1f6-329ffb39f227','送嚴維下第還江東','岑參','唐','唐诗','tang','','[]','勿歎今不第，似君殊未遲。',72,'全唐诗/poet.tang.9000.json','["勿歎今不第，似君殊未遲。", "且歸滄洲去，相送青門時。", "望鳥指鄉遠，問人愁路疑。", "敝裘沾暮雪，歸櫂帶流澌。", "嚴子灘復在，謝公文可追。", "江臯如有信，莫不寄新詩。"]'),
('2432b538-f6fd-44d6-a85e-d2f8f69705ea','六月三十日水亭送華陰王少府還縣','岑參','唐','唐诗','tang','','[]','亭晚人將別，池涼酒未酣。',72,'全唐诗/poet.tang.9000.json','["亭晚人將別，池涼酒未酣。", "關門勞夕夢，仙掌引歸驂。", "荷葉藏魚艇，藤花罥客簪。", "殘雲收夏暑，新雨帶秋嵐。", "失路情無適，離懷思不堪。", "賴茲庭戶裏，別有小江潭。"]'),
('aa61f46a-6f87-4787-9c14-396fc42ec775','餞王岑判官赴襄陽道','岑參','唐','唐诗','tang','','[]','故人漢陽使，走馬向南荆。',72,'全唐诗/poet.tang.9000.json','["故人漢陽使，走馬向南荆。", "不厭楚山路，祗憐襄水清。", "津頭習氏宅，江上夫人城。", "夜入橘花宿，朝穿桐葉行。", "害羣應自懾，持法固須平。", "暫得青門醉，斜光速去程。"]'),
('ca455938-5c6f-435c-bbea-02c8c5ec4987','送薛弁歸河東','岑參','唐','唐诗','tang','','[]','薛侯故鄉處，五老峰西頭。',72,'全唐诗/poet.tang.9000.json','["薛侯故鄉處，五老峰西頭。", "歸路秦樹滅，到鄉河水流。", "看君馬首去，滿耳蟬聲愁。", "獻賦今未售，讀書凡幾秋。", "應過伯夷廟，爲上關城樓。", "樓上能相憶，西南指雍州。"]'),
('b2bd2129-8c45-436a-a416-e3e2d811020b','送薛播擢第歸河東','岑參','唐','唐诗','tang','','[]','歸去新戰勝，盛名人共聞。',72,'全唐诗/poet.tang.9000.json','["歸去新戰勝，盛名人共聞。", "鄉連渭川樹，家近條山雲。", "夫子能好學，聖朝全用文。", "弟兄負世譽，詞賦超人羣。", "雨氣醒別酒，城陰低暮曛。", "遙知出關後，更有一終軍。"]'),
('2a225898-8d65-4977-b443-30f10dbde0bf','送陶銑棄舉荆南覲省','岑參','唐','唐诗','tang','','[]','明時不愛璧，浪跡東南遊。',72,'全唐诗/poet.tang.9000.json','["明時不愛璧，浪跡東南遊。", "何必世人識，知君輕五侯。", "采蘭度漢水，問絹過荆州。", "異國有歸興，去鄉無客愁。", "天寒楚塞雨，月淨襄陽秋。", "坐見吾道遠，令人看白頭。"]'),
('58fedb5e-7b8a-4fdb-9529-aca2cb8eb60b','送史司馬赴崔相公幕','岑參','唐','唐诗','tang','','[]','崢嶸丞相府，清切鳳皇池。',72,'全唐诗/poet.tang.9000.json','["崢嶸丞相府，清切鳳皇池。", "羨爾瑤臺鶴，高棲瓊樹枝。", "歸飛晴日好，吟弄惠風吹。", "正有乘軒樂，初當學舞時。", "珍禽在羅網，微命若遊絲。", "願託周南羽，相銜谿水湄。"]'),
('f4e10b1f-bafb-4ea4-92f3-d40856ddd214','送嚴黃門拜御史大夫再鎮蜀川兼覲省','岑參','唐','唐诗','tang','','[]','授鉞辭金殿，承恩戀玉墀。',96,'全唐诗/poet.tang.9000.json','["授鉞辭金殿，承恩戀玉墀。", "登壇漢主用，講德蜀人思。", "副相韓安國，黃門向子期。", "刀州重入夢，劒閣再題詞。", "春草連青綬，晴花間赤旗。", "山鶯朝送酒，江月夜供詩。", "許國分憂日，榮親色養時。", "蒼生望已久，來去不應遲。"]'),
('b8a68313-8ad3-4163-b301-e22f493e45de','送郭僕射節制劒南','岑參','唐','唐诗','tang','','[]','鐵馬擐紅纓，幡旗出禁城。',96,'全唐诗/poet.tang.9000.json','["鐵馬擐紅纓，幡旗出禁城。", "明王親授鉞，丞相欲專征。", "玉饌天廚送，金杯御酒傾。", "劒門乘嶮過，閣道踏空行。", "山鳥驚吹笛，江猿看洗兵。", "曉雲隨去陣，夜月逐行營。", "南仲今時往，西戎計日平。", "將心感知己，萬里寄懸旌。"]'),
('fc961fb7-c7d3-418f-8b14-7bb120d3f7ba','早秋與諸子登虢州西亭觀眺','岑參','唐','唐诗','tang','','[]','亭高出鳥外，客到與雲齊。',74,'全唐诗/poet.tang.9000.json','["亭高出鳥外，客到與雲齊。", "樹點千家小，天圍萬嶺低。", "殘[虹]挂陝北，急雨過關西。", "酒榼緣青壁，瓜田傍綠谿。", "微官何足道，愛客且相攜。", "唯有鄉園處，依依望不迷。"]'),
('ecb34154-60f1-4f8d-a167-489f2cd60b56','佐郡思舊遊','岑參','唐','唐诗','tang','','[]','幸得趨紫殿，却憶侍丹墀。',72,'全唐诗/poet.tang.9000.json','["幸得趨紫殿，却憶侍丹墀。", "史筆衆推直，諫書人莫窺。", "平生恆自負，垂老此安卑。", "同類皆先達，非才獨後時。", "庭槐宿鳥亂，階草夜蟲悲。", "白髮今無數，青雲未有期。"]'),
('8aa486cf-d745-4fca-90c4-799fa58f6c6f','滅胡曲','岑參','唐','唐诗','tang','','["\u751f\u6d3b", "\u8c6a\u8fc8", "\u8fb9\u585e"]','都護新滅胡，士馬氣亦麤。',24,'全唐诗/poet.tang.9000.json','["都護新滅胡，士馬氣亦麤。", "蕭條虜塵淨，突兀天山孤。"]'),
('e9d8fa1b-854c-4aa5-aba7-aad8e5bb0860','尚書念舊垂賜袍衣率題絕句獻上以申感謝','岑參','唐','唐诗','tang','','[]','富貴情還在，相逢豈間然。',24,'全唐诗/poet.tang.9000.json','["富貴情還在，相逢豈間然。", "綈袍更有贈，猶荷故人憐。"]'),
('76a7946a-8034-45df-a629-e75080215821','憶長安曲二章寄龐{氵寉} 一','岑參','唐','唐诗','tang','','[]','東望望長安，正值日初出。',24,'全唐诗/poet.tang.9000.json','["東望望長安，正值日初出。", "長安不可見，喜見長安日。"]'),
('a1a56379-8eca-4fc8-8b53-d5b756292ff1','憶長安曲二章寄龐{氵寉} 二','岑參','唐','唐诗','tang','','[]','長安何處在，只在馬蹄下。',24,'全唐诗/poet.tang.9000.json','["長安何處在，只在馬蹄下。", "明日歸長安，爲君急走馬。"]'),
('68d87256-cfc3-4a7f-b4e8-4d630f7127f7','寄韓樽','岑參','唐','唐诗','tang','','[]','夫子素多疾，別來未得書。',24,'全唐诗/poet.tang.9000.json','["夫子素多疾，別來未得書。", "北庭苦寒地，體內今何如。"]'),
('83bd1fb1-c1db-4146-8f33-af165bbd365c','醉裏送裴子赴鎮西','岑參','唐','唐诗','tang','','[]','醉後未能別，待醒方送君。',24,'全唐诗/poet.tang.9000.json','["醉後未能別，待醒方送君。", "看君走馬去，直上天山雲。"]'),
('bad85cd5-0c5a-44a9-b54d-d228171e0703','題井陘雙谿李道士所居','岑參','唐','唐诗','tang','','[]','五粒松花酒，雙谿道士家。',24,'全唐诗/poet.tang.9000.json','["五粒松花酒，雙谿道士家。", "唯求縮却地，鄉路莫教賒。"]'),
('4eac84d5-a708-48f4-a104-da60f83fa21c','題雲際南峰眼上人讀經堂','岑參','唐','唐诗','tang','','[]','結宇題三藏，焚香老一峰。',24,'全唐诗/poet.tang.9000.json','["結宇題三藏，焚香老一峰。", "雲間獨坐臥，祗是對山松。"]'),
('90c23748-9d7c-4387-9822-3961851ae508','題梁鍠城中高居','岑參','唐','唐诗','tang','','[]','高住最高處，千家恆眼前。',24,'全唐诗/poet.tang.9000.json','["高住最高處，千家恆眼前。", "題詩飲酒後，只對諸峰眠。"]'),
('bb899b8b-f88d-4114-9041-e72fa5857add','題三會寺蒼頡造字臺','岑參','唐','唐诗','tang','','[]','野寺荒臺晚，寒天古木悲。',24,'全唐诗/poet.tang.9000.json','["野寺荒臺晚，寒天古木悲。", "空堦有鳥跡，猶似造書時。"]'),
('1b5c5e60-b396-4124-bffe-89034bba8da2','日沒賀延磧作','岑參','唐','唐诗','tang','','[]','沙上見日出，沙上見日沒。',24,'全唐诗/poet.tang.9000.json','["沙上見日出，沙上見日沒。", "悔向萬里來，功名是何物。"]'),
('c69f17df-0d79-4631-bac2-100b3b02e7a4','西過渭州見渭水思秦川','岑參','唐','唐诗','tang','','["\u79bb\u522b", "\u63cf\u5199\u6c34", "\u601d\u4e61", "\u5199\u6c34"]','渭水東流去，何時到雍州。',24,'全唐诗/poet.tang.9000.json','["渭水東流去，何時到雍州。", "憑添兩行淚，寄向故園流。"]'),
('dbccfefb-be87-4032-ab99-f3c01b3d3aaf','經隴頭分水','岑參','唐','唐诗','tang','','[]','隴水何年有，潺潺逼路傍。',24,'全唐诗/poet.tang.9000.json','["隴水何年有，潺潺逼路傍。", "東西流不歇，曾斷幾人腸。"]'),
('1befd532-6d9d-4c86-9d3a-d65ebcf74f1c','秋思','岑參','唐','唐诗','tang','','[]','那知芳歲晚，坐見寒葉墮。',24,'全唐诗/poet.tang.9000.json','["那知芳歲晚，坐見寒葉墮。", "吾不如腐草，翻飛作螢火。"]'),
('da3b4635-ab06-48e2-b59f-478803c7fb19','行軍九日思長安故園','岑參','唐','唐诗','tang','','["\u767b\u9ad8", "\u83ca\u82b1", "\u601d\u4e61", "\u91cd\u9633\u8282"]','強欲登高去，無人送酒來。',24,'全唐诗/poet.tang.9000.json','["強欲登高去，無人送酒來。", "遙憐故園菊，應傍戰場開。"]'),
('82c4ddaa-0284-40bf-9c93-d9d222fe1ad5','戲題關門','岑參','唐','唐诗','tang','','[]','來亦一布衣，去亦一布衣。',24,'全唐诗/poet.tang.9000.json','["來亦一布衣，去亦一布衣。", "羞見關城吏，還從舊路歸。"]'),
('bfa3e9ee-7dce-4085-af9f-e634f83c4426','歎白髮','岑參','唐','唐诗','tang','','[]','白髮生偏速，交人不奈何。',24,'全唐诗/poet.tang.9000.json','["白髮生偏速，交人不奈何。", "今朝兩鬢上，更較數莖多。"]'),
('60ef952f-0009-429a-bf08-6e787f06221f','題平陽郡汾橋邊柳樹','岑參','唐','唐诗','tang','','["\u548f\u7269", "\u67f3\u6811", "\u6292\u6000", "\u548f\u7269\u8bd7"]','此地曾居住，今來宛似歸。',24,'全唐诗/poet.tang.9000.json','["此地曾居住，今來宛似歸。", "可憐汾上柳，相見也依依。"]'),
('19aa71bb-253b-4a46-9562-d669ef15e5a6','失題','岑參','唐','唐诗','tang','','[]','帝鄉北近日，瀘口南連蠻。',24,'全唐诗/poet.tang.9000.json','["帝鄉北近日，瀘口南連蠻。", "何當遇長房，縮地到京關。"]'),
('772e35bb-d32e-46cf-90dd-2dc214094b28','獻封大夫破播仙凱歌六首 一','岑參','唐','唐诗','tang','','[]','漢將承恩西破戎，捷書先奏未央宮。',32,'全唐诗/poet.tang.9000.json','["漢將承恩西破戎，捷書先奏未央宮。", "天子預開麟閣待，祗今誰數貳師功。"]'),
('a63b4c45-1a19-4ba1-ac68-55fa1a556680','獻封大夫破播仙凱歌六首 二','岑參','唐','唐诗','tang','','[]','官軍西出過樓蘭，營幕傍臨月窟寒。',32,'全唐诗/poet.tang.9000.json','["官軍西出過樓蘭，營幕傍臨月窟寒。", "蒲海曉霜凝馬尾，葱山夜雪撲旌竿。"]'),
('07f6c6be-9cba-41a2-8977-501e4f6a4e7a','獻封大夫破播仙凱歌六首 三','岑參','唐','唐诗','tang','','[]','鳴笳疊鼓擁回軍，破國平蕃昔未聞。',32,'全唐诗/poet.tang.9000.json','["鳴笳疊鼓擁回軍，破國平蕃昔未聞。", "丈夫鵲印搖邊月，大將龍旗掣海雲。"]'),
('d43e23b5-21f6-4242-a5df-4135367a1465','獻封大夫破播仙凱歌六首 四','岑參','唐','唐诗','tang','','[]','日落轅門鼓角鳴，千羣面縛出蕃城。',32,'全唐诗/poet.tang.9000.json','["日落轅門鼓角鳴，千羣面縛出蕃城。", "洗兵魚海雲迎陣，秣馬龍堆月照營。"]'),
('4254a7b3-9e7e-499c-a8fd-9ae75962cf07','獻封大夫破播仙凱歌六首 五','岑參','唐','唐诗','tang','','[]','蕃軍遙見漢家營，滿谷連山遍哭聲。',32,'全唐诗/poet.tang.9000.json','["蕃軍遙見漢家營，滿谷連山遍哭聲。", "萬箭千刀一夜殺，平明流血浸空城。"]'),
