('1075d5a8-384f-4b8b-a3b5-3832b468a2f7','赴北庭度隴思家','岑參','唐','唐诗','tang','','[]','西向輪臺萬里馀，也知鄉信日應疎。',32,'全唐诗/poet.tang.9000.json','["西向輪臺萬里馀，也知鄉信日應疎。", "隴山鸚鵡能言語，爲報家人數寄書。"]'),
('b740324c-29e9-4cba-b1db-dece09859ea5','胡歌','岑參','唐','唐诗','tang','','["\u6218\u58eb", "\u8fb9\u585e"]','黑姓蕃王貂鼠裘，葡萄宮錦醉纏頭。',32,'全唐诗/poet.tang.9000.json','["黑姓蕃王貂鼠裘，葡萄宮錦醉纏頭。", "關西老將能苦戰，七十行兵仍未休。"]'),
('0c790d18-27ef-40d3-a456-7e72161aad46','趙將軍歌','岑參','唐','唐诗','tang','','["\u5199\u4eba", "\u5c06\u519b", "\u8fb9\u585e"]','九月天山風似刀，城南獵馬縮寒毛。',32,'全唐诗/poet.tang.9000.json','["九月天山風似刀，城南獵馬縮寒毛。", "將軍縱博場場勝，賭得單于貂鼠袍。"]'),
('2e9f5ac2-4631-4b79-80d1-3111f8caf8b8','醉戲竇子美人','岑參','唐','唐诗','tang','','[]','朱脣一點桃花殷，宿妝嬌羞偏髻鬟。',32,'全唐诗/poet.tang.9000.json','["朱脣一點桃花殷，宿妝嬌羞偏髻鬟。", "細看只似陽臺女，醉着莫許歸巫山。"]'),
('7447d48d-2f26-4359-8818-4da63b04ae93','秋夜聞笛','岑參','唐','唐诗','tang','','[]','天門街西聞搗帛，一夜愁殺湘南客。',32,'全唐诗/poet.tang.9000.json','["天門街西聞搗帛，一夜愁殺湘南客。", "長安城中百萬家，不知何人吹夜笛。"]'),
('c016ed11-0403-48a8-962d-ab72b53ad672','戲問花門酒家翁','岑參','唐','唐诗','tang','','["\u6292\u60c5", "\u751f\u6d3b"]','老人七十仍沽酒，千壺百甕花門口。',32,'全唐诗/poet.tang.9000.json','["老人七十仍沽酒，千壺百甕花門口。", "道傍榆莢仍似錢，摘來沽酒君肯否。"]'),
('ea65262c-da6d-4dd8-a8b3-01b6679f9600','春夢','岑參','唐','唐诗','tang','','["\u601d\u5ff5"]','洞房昨夜春風起，故人尚隔湘江水。',32,'全唐诗/poet.tang.9000.json','["洞房昨夜春風起，故人尚隔湘江水。", "枕上片時春夢中，行盡江南數千里。"]'),
('d9a9f785-80e0-49ca-9a0a-3655b89f92b5','冬夕','岑參','唐','唐诗','tang','','["\u601d\u4e61", "\u51ac\u5b63", "\u8fb9\u585e"]','浩汗霜風刮天地，溫泉火井無生意。',32,'全唐诗/poet.tang.9000.json','["浩汗霜風刮天地，溫泉火井無生意。", "澤國龍蛇凍不伸，南山瘦柏消殘翠。"]'),
('594804c8-cde2-49ac-9a7c-247580612be0','句','岑參','唐','唐诗','tang','','[]','初程莫早發，且宿灞橋頭。',12,'全唐诗/poet.tang.9000.json','["初程莫早發，且宿灞橋頭。"]'),
('b4de4511-6b01-4351-ace2-e815683cd9fd','武陽送別','沈宇','唐','唐诗','tang','','[]','菊黃蘆白雁初飛，羌笛胡笳淚滿衣。',32,'全唐诗/poet.tang.9000.json','["菊黃蘆白雁初飛，羌笛胡笳淚滿衣。", "送君腸斷秋江水，一去東流何日歸。"]'),
('7084f140-821f-484d-803d-264dd8b3f38e','擣衣','沈宇','唐','唐诗','tang','','[]','日暮遠天青，霜風入後庭。',24,'全唐诗/poet.tang.9000.json','["日暮遠天青，霜風入後庭。", "洞房寒未掩，砧杵夜泠泠。"]'),
('5659042a-a8b9-4273-9933-9ed6f029ec53','代閨人','沈宇','唐','唐诗','tang','','[]','楊柳青青鳥亂吟，春風香靄洞房深。',32,'全唐诗/poet.tang.9000.json','["楊柳青青鳥亂吟，春風香靄洞房深。", "百花簾下朝窺鏡，明月窗前夜理琴。"]'),
('d3207ad7-1469-4972-aa85-401f32839694','江南遇雨','張鼎','唐','唐诗','tang','','[]','江天寒意少，冬月雨仍飛。',48,'全唐诗/poet.tang.9000.json','["江天寒意少，冬月雨仍飛。", "出戶愁爲聽，從風灑客衣。", "旅魂驚處斷，鄉信意中微。", "幾日應晴去，孤舟且欲歸。"]'),
('75f7f55a-0a4c-4143-b875-9eb6748524a7','鄴城引','張鼎','唐','唐诗','tang','','[]','君不見漢家失統三靈變，魏武爭雄六龍戰。',99,'全唐诗/poet.tang.9000.json','["君不見漢家失統三靈變，魏武爭雄六龍戰。", "盪海吞江制中國，迴天運斗應南面。", "隱隱都城紫陽開，迢迢分野黃星見。", "流年不駐漳河水，明月俄終鄴國宴。", "文章猶入管弦新，帷座空銷狐兔塵。", "可惜望陵歌舞處，松風四面暮愁人。"]'),
('7a45af21-cd88-4ab5-9d93-2e8223009b0f','僧舍小池','張鼎','唐','唐诗','tang','','[]','引出白雲根，潺潺漲蘚痕。',48,'全唐诗/poet.tang.9000.json','["引出白雲根，潺潺漲蘚痕。", "冷光搖砌錫，疎影露枝猿。", "淨帶凋霜葉，香通洗藥源。", "貝多文字古，宜向此中翻。"]'),
('14f08803-4994-4388-b9f2-ecc9d5afaf44','擬古','薛奇童','唐','唐诗','tang','','[]','沙塵朝蔽日，失道還相遇。',72,'全唐诗/poet.tang.9000.json','["沙塵朝蔽日，失道還相遇。", "寒影波上雲，秋聲月前樹。", "川氣生曉夕，野陰乍煙霧。", "沈沈滮池水，人馬不敢渡。", "吮癰世所薄，挾纊恩難顧。", "不見古時人，中宵淚橫注。"]'),
('83de871a-bfe4-427e-b8ec-7970c03bdb02','和李起居秋夜之作','薛奇童','唐','唐诗','tang','','[]','過庭聞禮日，趨侍記言回。',72,'全唐诗/poet.tang.9000.json','["過庭聞禮日，趨侍記言回。", "獨臥玉窗前，卷簾殘雨來。", "高秋南斗轉，涼夜北堂開。", "水影入朱戶，螢光生綠苔。", "簡成良史筆，年是洛陽才。", "莫重白雲意，時人許上台。"]'),
('c6e46fc0-bd5e-4430-8362-a4fe114aa64a','吳聲子夜歌','薛奇童','唐','唐诗','tang','','[]','淨掃黃金堦，飛霜皓如雪。',24,'全唐诗/poet.tang.9000.json','["淨掃黃金堦，飛霜皓如雪。", "下簾彈箜篌，不忍見秋月。"]'),
('5f430f46-2fa6-451a-9c5a-184ebc38291c','塞下曲','薛奇童','唐','唐诗','tang','','[]','驕虜初南下，煙塵暗國中。',96,'全唐诗/poet.tang.9000.json','["驕虜初南下，煙塵暗國中。", "獨召李將軍，夜開甘泉宮。", "一身許明主，萬里總元戎。", "霜甲臥不暖，夜半聞邊風。", "胡天早飛雪，荒徼多轉蓬。", "寒雲覆水重，秋氣連海空。", "金鞍誰家子，上馬鳴角弓。", "自是幽幷客，非論愛立功。"]'),
('2d713366-1776-4789-aafa-11c9c859e818','雲中行','薛奇童','唐','唐诗','tang','','[]','雲中小兒吹金管，向晚因風一川滿。',144,'全唐诗/poet.tang.9000.json','["雲中小兒吹金管，向晚因風一川滿。", "塞北雲高心已悲，城南木落腸堪斷。", "憶昔魏家都此方，涼風觀前朝百王。", "千門曉映山川色，雙闕遙連日月光。", "舉杯稱壽永相保，日夕歌鐘徹清昊。", "將軍汗馬百戰塲，天子射獸五原草。", "寂寞金輿去不歸，陵上黃塵滿路飛。", "河邊不語傷流水，川上含情歎落暉。", "此時獨立無所見，日暮寒風吹客衣。"]'),
('6baf8d34-95ce-48e8-92dc-4fb311733d65','楚宮詞二首 一','薛奇童','唐','唐诗','tang','','[]','禁苑春風起，流鶯繞合歡。',48,'全唐诗/poet.tang.9000.json','["禁苑春風起，流鶯繞合歡。", "玉窗通日氣，珠箔捲輕寒。", "楊葉垂陰砌，梨花入井闌。", "君王好長袖，新作舞衣寬。"]'),
('441151ec-b4e4-46ed-9e6f-da73a66d4726','楚宮詞二首 二','薛奇童','唐','唐诗','tang','','[]','日晚梧桐落，微寒入禁垣。',48,'全唐诗/poet.tang.9000.json','["日晚梧桐落，微寒入禁垣。", "月懸三雀觀，霜度萬秋門。", "豔舞矜新寵，愁容泣舊恩。", "不堪深殿裏，簾外欲黃昏。"]'),
('950b38bc-861c-42f8-baf8-1a49ccdd642a','長孫十一東山春夜見贈','楊諫','唐','唐诗','tang','','[]','故人謝城闕，揮手碧雲期。',48,'全唐诗/poet.tang.9000.json','["故人謝城闕，揮手碧雲期。", "谿月照隱處，松風生興時。", "舊林日云暮，芳草歲空滋。", "甘與子成夢，請君同所思。"]'),
('26fca58d-fd6f-4950-a2f5-041536701426','贈知己','楊諫','唐','唐诗','tang','','[]','江南折芳草，江北贈佳期。',48,'全唐诗/poet.tang.9000.json','["江南折芳草，江北贈佳期。", "江闊水復急，過江常苦遲。", "蘋白蘭葉青，恐度先香時。", "美人碧雲外，寧見長相思。"]'),
('9f7cb262-1b86-4ee6-bf4f-7dd4fe870f1e','東溪待蘇戶曹不至','張萬頃','唐','唐诗','tang','','[]','洛陽城東伊水西，千花萬竹使人迷。',48,'全唐诗/poet.tang.9000.json','["洛陽城東伊水西，千花萬竹使人迷。", "臺上柳枝臨岸低，門前荷葉與橋齊。", "日暮待君君不見，長風吹雨過青溪。"]'),
('6d50cfa2-8adb-45da-b0da-c55b4b596f08','登天目山下作','張萬頃','唐','唐诗','tang','','[]','去歲離秦望，今冬使楚關。',48,'全唐诗/poet.tang.9000.json','["去歲離秦望，今冬使楚關。", "淚添天目水，髮變海頭山。", "別母烏南逝，辭兄雁北還。", "宦遊偏不樂，長爲憶慈顏。"]'),
('709b7db4-b6be-4473-b68a-392ea987f02c','送裴少府','張萬頃','唐','唐诗','tang','','[]','夕膳望東周，晨裝不少留。',48,'全唐诗/poet.tang.9000.json','["夕膳望東周，晨裝不少留。", "酒中同樂事，關外越離憂。", "座濕秦山雨，庭寒渭水秋。", "何當鷹隼擊，來拂故林游。"]'),
('626af69c-a8ce-4e3b-b32e-cac4fad660f4','旅次灞亭','沈頌','唐','唐诗','tang','','[]','閑琴開旅思，清夜有愁心。',48,'全唐诗/poet.tang.9000.json','["閑琴開旅思，清夜有愁心。", "圓月正當戶，微風猶在林。", "蒼茫孤亭上，歷亂多秋音。", "言念待明發，東山幽意深。"]'),
('f47b9fd7-99c3-42d9-9c0d-b0b955bd014f','春旦歌','沈頌','唐','唐诗','tang','','[]','常聞嬴女玉簫臺，奏曲情深彩鳳來。',32,'全唐诗/poet.tang.9000.json','["常聞嬴女玉簫臺，奏曲情深彩鳳來。", "欲登此地銷歸恨，却羨雙飛去不回。"]'),
('cdb37947-dfae-4cdb-a0fe-5c6deff898a9','早發西山','沈頌','唐','唐诗','tang','','[]','游子空有懷，賞心杳無路。',84,'全唐诗/poet.tang.9000.json','["游子空有懷，賞心杳無路。", "前程數千里，乘夜連輕馭。", "繚繞松篠中，蒼茫猶未曙。", "遙聞孤村犬，暗指人家去。", "疲馬懷澗泉，征衣犯霜露。", "喧呼谿鳥驚，沙上或鶱翥。", "娟娟東岑月，照耀獨歸慮。"]'),
('2dc0cf8a-c8ca-44cf-b97d-850c850e49dd','送人還吳','沈頌','唐','唐诗','tang','','[]','人心不忘鄉，矧余客已久。',48,'全唐诗/poet.tang.9000.json','["人心不忘鄉，矧余客已久。", "送君江南去，秋醉洛陽酒。", "贈言幽徑蘭，別思河堤柳。", "征帆暮風急，望望空延首。"]'),
('42e6192d-b20f-4044-bc6e-c64ac79f75b6','送金文學還日東','沈頌','唐','唐诗','tang','','[]','君家東海東，君去因秋風。',48,'全唐诗/poet.tang.9000.json','["君家東海東，君去因秋風。", "漫漫指鄉路，悠悠如夢中。", "煙霧積孤島，波濤連太空。", "冒險當不懼，皇恩措爾躬。"]'),
('329cf1e6-7104-40c2-83e6-81ca6d3e414c','衛中作','沈頌','唐','唐诗','tang','','[]','衛風愉豔宜春色，淇水清泠增暮愁。',32,'全唐诗/poet.tang.9000.json','["衛風愉豔宜春色，淇水清泠增暮愁。", "總使榴花能一醉，終須萱草暫忘憂。"]'),
('a8bd0072-1837-46c0-beb3-d11bd2e81d62','天長節','梁鍠','唐','唐诗','tang','','[]','日月生天久，年年慶一迴。',48,'全唐诗/poet.tang.9000.json','["日月生天久，年年慶一迴。", "時平祥不去，壽遠節長來。", "連吹千家笛，同朝百郡杯。", "願持金殿鏡，處處照遺才。"]'),
('689bd5c2-4117-4a59-8abc-6b26a1815d51','長門怨','梁鍠','唐','唐诗','tang','','[]','妾命何偏薄，君王去不歸。',48,'全唐诗/poet.tang.9000.json','["妾命何偏薄，君王去不歸。", "欲令遙見悔，樓上試春衣。", "空殿看人入，深宮羨鳥飛。", "翻悲因買賦，索鏡照空輝。"]'),
('c3e08068-4e0d-4626-b715-0dc046132245','美人春臥','梁鍠','唐','唐诗','tang','','[]','妾家巫峽陽，羅幌寢蘭堂。',48,'全唐诗/poet.tang.9000.json','["妾家巫峽陽，羅幌寢蘭堂。", "曉日臨窗久，春風引夢長。", "落釵仍挂鬢，微汗欲消黃。", "縱使朦朧覺，魂猶逐楚王。"]'),
('0ba40038-c656-491f-b80b-5fc180d0b66c','名姝詠','梁鍠','唐','唐诗','tang','','[]','阿嬌年未多，弱體性能和。',48,'全唐诗/poet.tang.9000.json','["阿嬌年未多，弱體性能和。", "怕重愁拈鏡，憐輕喜曳羅。", "臨津雙洛浦，對月兩嫦娥。", "獨有荆王殿，時時暮雨過。"]'),
('909577b4-edeb-4ca5-a8eb-cdd9957df695','豔女詞','梁鍠','唐','唐诗','tang','','[]','露井桃花發，雙雙燕並飛。',48,'全唐诗/poet.tang.9000.json','["露井桃花發，雙雙燕並飛。", "美人姿態裏，春色上羅衣。", "自愛頻開鏡，時羞欲掩扉。", "不知行路客，遙惹五香歸。"]'),
('2c98723b-cc97-47c0-ac65-5e749b81a129','狷氏子','梁鍠','唐','唐诗','tang','','[]','杏梁初照日，碧玉後堂開。',48,'全唐诗/poet.tang.9000.json','["杏梁初照日，碧玉後堂開。", "憶事臨妝笑，春嬌滿鏡臺。", "含聲歌扉舉，顧影舞腰迴。", "別有佳期處，青樓客夜來。"]'),
('b18b37e0-813b-466a-946a-1204f4be0bc6','戲贈歌者','梁鍠','唐','唐诗','tang','','[]','白皙歌童子，哀音絕又連。',48,'全唐诗/poet.tang.9000.json','["白皙歌童子，哀音絕又連。", "楚妃臨扇學，盧女隔簾傳。", "曉燕喧喉裏，春鶯囀舌邊。", "若逢漢武帝，還是李延年。"]'),
('86de7010-c682-4574-8bc7-f8d64cc3a2a7','七夕汎舟','梁鍠','唐','唐诗','tang','','[]','雲端有靈匹，掩映拂妝臺。',48,'全唐诗/poet.tang.9000.json','["雲端有靈匹，掩映拂妝臺。", "夜久應搖珮，天高響不來。", "片歡秋始展，殘夢曉翻催。", "却怨填河鵲，留橋又不迴。"]'),
('1ed882b3-c64b-45d1-8d28-e738410abcb8','崔駙馬宅詠畫山水扇','梁鍠','唐','唐诗','tang','','[]','畫扇出秦樓，誰家贈列侯。',48,'全唐诗/poet.tang.9000.json','["畫扇出秦樓，誰家贈列侯。", "小含吳剡縣，輕帶楚揚州。", "揜作山雲暮，搖成隴樹秋。", "坐來傳與客，漢水又迴流。"]'),
('bb5da7a5-de8a-44d9-a2b0-cd8de2b53d97','觀王美人海圖障子','梁鍠','唐','唐诗','tang','','[]','宋玉東家女，常懷物外多。',48,'全唐诗/poet.tang.9000.json','["宋玉東家女，常懷物外多。", "自從圖渤海，誰爲覓湘娥。", "白鷺栖脂粉，赬魴躍綺羅。", "仍憐轉嬌眼，別恨一橫波。"]'),
('a4528be7-0af5-492f-a0d9-321fdbe4fe9e','聞百舌鳥','梁鍠','唐','唐诗','tang','','[]','百舌聞他郡，間關媚物華。',48,'全唐诗/poet.tang.9000.json','["百舌聞他郡，間關媚物華。", "斂形藏一葉，分響出千花。", "坐愛時褰幌，行藏或駐車。", "不須應獨感，三載已辭家。"]'),
('9aa1e99e-1895-425b-9937-afaf51067791','省試方士進恆春草','梁鍠','唐','唐诗','tang','','[]','東吳有靈草，生彼剡谿傍。',72,'全唐诗/poet.tang.9000.json','["東吳有靈草，生彼剡谿傍。", "既亂莓苔色，仍連菡萏香。", "掇之稱遠士，持以奉明王。", "北闕顏彌駐，南山壽更長。", "金膏徒騁妙，石髓莫矜良。", "倘使霑涓滴，還游不死方。"]'),
('4050f23a-dc25-4e82-b858-07981528ed97','代征人妻喜夫還','梁鍠','唐','唐诗','tang','','[]','征夫走馬發漁陽，少婦含嬌開洞房。',64,'全唐诗/poet.tang.9000.json','["征夫走馬發漁陽，少婦含嬌開洞房。", "千日廢臺還挂鏡，數年塵面再新妝。", "春風喜出今朝戶，明日虛眠昨夜牀。", "莫道幽閨書信隔，還衣總是舊時香。"]'),
('bc3a22df-2cf8-43a7-971b-f0dd9b51e6d6','贈李中華','梁鍠','唐','唐诗','tang','','[]','莫向嵩山去，神仙多誤人。',24,'全唐诗/poet.tang.9000.json','["莫向嵩山去，神仙多誤人。", "不如朝魏闕，天子重賢臣。"]'),
('8190cf76-f2af-400c-a09d-8877e9b25a62','詠木老人','梁鍠','唐','唐诗','tang','','[]','刻木牽絲作老翁，雞皮鶴髮與真同。',32,'全唐诗/poet.tang.9000.json','["刻木牽絲作老翁，雞皮鶴髮與真同。", "須臾弄罷寂無事，還似人生一夢中。"]');
